    # =========================================================================
    # orderLinkId Helper Functions (v2 format with extended bot ID)
    # =========================================================================

    def _build_order_link_id(
        self,
        bot_id: str,
        symbol: str,
        cycle_ts: int,
        seq: int,
        side: str,
        intent: str,
    ) -> Optional[str]:
        """
        Build orderLinkId for PnL attribution within Bybit's 36-char limit.

        Format: bv2:{bot_id_16}{ts_8}{seq:02d}{side}{intent}
        - bot_id_16: First 16 chars of UUID (no dashes) - enough for attribution
        - ts_8: Last 8 digits of millisecond timestamp (~27 hour uniqueness)
        - seq: 2-digit sequence (00-99)
        - side: B=Buy, S=Sell
        - intent: O=open, C=close

        Total: 4 + 16 + 8 + 2 + 1 + 1 = 32 chars (fits 36 limit)
        Example: bv2:a1b2c3d4e5f67890:12345678:01BO

        Args:
            bot_id: Full bot UUID
            symbol: Trading symbol (not used, for compatibility)
            cycle_ts: Cycle timestamp (milliseconds preferred)
            seq: Order sequence number (0-99)
            side: "Buy" or "Sell"
            intent: "open" or "close"

        Returns:
            orderLinkId string or None if bot_id is empty
        """
        if not bot_id:
            return None

        # Extract first 16 chars of UUID (remove dashes)
        bot_id_clean = bot_id.replace("-", "")
        bot_id_16 = bot_id_clean[:16]

        # Use last 8 digits of timestamp for ~27 hour uniqueness
        ts_8 = str(cycle_ts)[-8:].zfill(8)

        # Sequence 00-99
        seq_str = f"{seq % 100:02d}"

        side_char = "B" if side == "Buy" else "S"
        intent_char = "O" if intent == "open" else "C"

        # Format: bv2:{bot_id_16}:{ts_8}{seq}{side}{intent}
        # Total: 4 + 16 + 1 + 8 + 2 + 1 + 1 = 33 chars
        order_link_id = f"bv2:{bot_id_16}:{ts_8}{seq_str}{side_char}{intent_char}"

        return order_link_id

    @staticmethod
    def _build_close_order_link_id(bot_id: str, close_reason: str = "cls") -> str:
        """
        Build unique orderLinkId for close/TP/SL orders.

        Format: cls:{bot_id_8}:{ts_ms_8}{rand_4}{reason_4}
        - bot_id_8: First 8 chars of UUID (no dashes)
        - ts_ms_8: Last 8 digits of millisecond timestamp
        - rand_4: 4 random hex chars (prevents collision on retry)
        - reason_4: First 4 chars of close reason (SCTP, HARD, SOFT, etc.)

        Total: 4 + 8 + 1 + 8 + 4 + 4 = 29 chars (fits 36 limit)
        """
        import secrets

        bot_short = (bot_id.replace("-", "")[:8] if bot_id else "xxxxxxxx")
        ts_ms = str(int(time.time() * 1000))[-8:]
        rand_4 = secrets.token_hex(2)
        reason_4 = close_reason[:4].upper().ljust(4, "X")

        return f"cls:{bot_short}:{ts_ms}{rand_4}{reason_4}"

    @staticmethod
    def _is_ambiguous_order_result(result: Optional[Dict[str, Any]]) -> bool:
        if not isinstance(result, dict):
            return False
        # H1 audit: also treat explicit ambiguous=True (e.g. WS timeout after send)
        if result.get("ambiguous") is True:
            return True
        status = str(result.get("status") or "").strip().lower()
        return result.get("success") is None or status in {
            "in_flight",
            "unknown_outcome",
        }

    def _prune_stale_caches(self, active_bot_ids: Optional[set] = None) -> None:
        """Remove cache entries for deleted/inactive bots to prevent memory leaks."""
        if not active_bot_ids:
            return
        # Prune bot run locks for deleted bots
        with self._bot_run_locks_guard:
            stale_locks = [k for k in self._bot_run_locks if k not in active_bot_ids]
            for k in stale_locks:
                self._bot_run_locks.pop(k, None)
        # Prune instrument cache (keep max 100 entries)
        if len(self._instrument_cache) > 100:
            excess = len(self._instrument_cache) - 80
            for key in list(self._instrument_cache.keys())[:excess]:
                self._instrument_cache.pop(key, None)
        # Prune position mode cache
        if hasattr(self, '_position_mode_cache') and len(self._position_mode_cache) > 50:
            self._position_mode_cache.clear()
        # Prune price metadata for symbols no longer traded
        if hasattr(self, '_last_price_metadata_by_symbol'):
            active_symbols = {str(bid).split(':')[0] for bid in active_bot_ids}
            stale_syms = [k for k in self._last_price_metadata_by_symbol if k not in active_symbols]
            for k in stale_syms[:10]:  # gradual cleanup
                self._last_price_metadata_by_symbol.pop(k, None)

    def _prune_close_attempt_fences(self, now_ts: Optional[float] = None) -> None:
        current_ts = float(now_ts or time.time())
        expired_keys = [
            key
            for key, payload in (self._close_attempt_fences or {}).items()
            if (current_ts - float((payload or {}).get("created_at") or 0.0))
            > FULL_CLOSE_INTENT_FENCE_TTL_SEC
        ]
        for key in expired_keys:
            self._close_attempt_fences.pop(key, None)

    @staticmethod
    def _build_close_attempt_fence_key(
        *,
        bot: Optional[Dict[str, Any]],
        symbol: str,
        close_side: str,
        position_idx: Optional[int],
    ) -> str:
        bot_id = str((bot or {}).get("id") or "manual").strip() or "manual"
        return (
            f"{bot_id}:{str(symbol or '').strip().upper()}:"
            f"{str(close_side or '').strip().upper()}:{int(position_idx or 0)}"
        )

    def _get_full_close_attempt_order_link_id(
        self,
        *,
        bot: Optional[Dict[str, Any]],
        symbol: str,
        close_side: str,
        position_idx: Optional[int],
        close_reason: str = "CLOS",
    ) -> str:
        current_ts = time.time()
        self._prune_close_attempt_fences(current_ts)
        fence_key = self._build_close_attempt_fence_key(
            bot=bot,
            symbol=symbol,
            close_side=close_side,
            position_idx=position_idx,
        )
        fence = self._close_attempt_fences.get(fence_key) or {}
        order_link_id = str(fence.get("order_link_id") or "").strip()
        if order_link_id:
            fence["last_used_at"] = current_ts
            self._close_attempt_fences[fence_key] = fence
            logger.warning(
                "CLOSE_INTENT_REUSED symbol=%s bot_id=%s close_side=%s position_idx=%s order_link_id=%s",
                symbol,
                (bot or {}).get("id") or "manual",
                close_side,
                int(position_idx or 0),
                order_link_id,
            )
            return order_link_id
        bot_id = str((bot or {}).get("id") or "").strip()
        order_link_id = self._build_close_order_link_id(bot_id, close_reason)
        self._close_attempt_fences[fence_key] = {
            "order_link_id": order_link_id,
            "created_at": current_ts,
            "last_used_at": current_ts,
        }
        return order_link_id

    def _clear_full_close_attempt_fence(
        self,
        *,
        bot: Optional[Dict[str, Any]],
        symbol: str,
        close_side: Optional[str] = None,
        position_idx: Optional[int] = None,
    ) -> None:
        symbol_key = str(symbol or "").strip().upper()
        bot_id = str((bot or {}).get("id") or "manual").strip() or "manual"
        keys_to_remove = []
        for key in list((self._close_attempt_fences or {}).keys()):
            parts = key.split(":")
            if len(parts) != 4:
                continue
            fence_bot_id, fence_symbol, fence_side, fence_idx = parts
            if fence_bot_id != bot_id or fence_symbol != symbol_key:
                continue
            if close_side and fence_side != str(close_side).strip().upper():
                continue
            if position_idx is not None and fence_idx != str(int(position_idx or 0)):
                continue
            keys_to_remove.append(key)
        for key in keys_to_remove:
            self._close_attempt_fences.pop(key, None)

    @staticmethod
    def _extract_close_reason_from_order_link_id(
        order_link_id: Optional[str],
    ) -> Optional[str]:
        link_text = str(order_link_id or "").strip()
        if not link_text:
            return None
        if link_text.startswith("cls:"):
            parts = link_text.split(":")
            if len(parts) >= 3 and parts[2]:
                return parts[2][-4:]
        if link_text.startswith("recovery_so_"):
            return "SREC"
        return None

    def _build_persistent_ownership_snapshot(
        self,
        bot: Optional[Dict[str, Any]],
        *,
        order_link_id: Optional[str],
        reduce_only: bool,
        diagnostic_context: Optional[Dict[str, Any]] = None,
    ) -> Optional[Dict[str, Any]]:
        if not bot:
            return None
        link_text = str(order_link_id or "").strip()
        action = (
            str((diagnostic_context or {}).get("ownership_action") or "").strip()
            or ("reduce_only_close" if reduce_only else "entry")
        )
        source = "grid_bot_service"
        if link_text.startswith("recovery_so_"):
            action = "smart_recovery"
            source = "smart_recovery"
        snapshot = build_order_ownership_snapshot(
            bot,
            source=source,
            action=action,
            close_reason=(
                str((diagnostic_context or {}).get("close_reason") or "").strip()
                or self._extract_close_reason_from_order_link_id(link_text)
            ),
            forensic_decision_id=(
                bot.get("forensic_active_decision_id")
                or bot.get("forensic_pending_decision_id")
            ),
            forensic_trade_context_id=(
                bot.get("forensic_active_trade_context_id")
                or bot.get("forensic_pending_trade_context_id")
            ),
            forensic_decision_type=(
                bot.get("forensic_active_decision_type")
                or bot.get("forensic_pending_decision_type")
            ),
            forensic_side=(
                bot.get("forensic_active_side")
                or bot.get("forensic_pending_side")
            ),
            forensic_lifecycle_started_at=(
                bot.get("forensic_active_started_at")
                or bot.get("forensic_pending_started_at")
            ),
        )
        opening_kind = (
            str((diagnostic_context or {}).get("opening_kind") or "").strip().lower()
            or None
        )
        if reduce_only:
            experiment_tags = self._normalize_experiment_tags(
                bot.get("forensic_active_experiment_tags"),
                bot.get("runtime_experiment_tags"),
            )
            experiment_details = self._merge_experiment_details(
                bot.get("forensic_active_experiment_details"),
                bot.get("runtime_experiment_details"),
            )
            entry_story = dict(bot.get("forensic_active_entry_story") or {})
            opening_sizing = self._compact_directional_opening_sizing_fields(
                bot.get("forensic_active_opening_sizing")
            )
        else:
            experiment_tags = self._normalize_experiment_tags(
                bot.get("runtime_experiment_tags")
            )
            experiment_details = self._merge_experiment_details(
                bot.get("runtime_experiment_details")
            )
            entry_story = self._build_compact_entry_story(
                bot,
                mode=bot.get("mode"),
                opening_kind=opening_kind,
                candidate_ready=True,
            ) or {}
            opening_sizing = self._compact_directional_opening_sizing_fields(
                (diagnostic_context or {}).get("opening_sizing")
            )
        snapshot["experiment_attribution_state"] = (
            "present" if experiment_tags else "none"
        )
        if experiment_tags:
            snapshot["experiment_tags"] = experiment_tags
        if experiment_details:
            snapshot["experiment_details"] = experiment_details
        if entry_story:
            snapshot["entry_story"] = entry_story
        if opening_sizing:
            snapshot["opening_sizing"] = opening_sizing
        profit_protection_advisory = self._compact_profit_protection_payload(
            bot.get("profit_protection_advisory")
        )
        if profit_protection_advisory:
            snapshot["profit_protection_advisory"] = profit_protection_advisory
        profit_protection_shadow = self._compact_profit_protection_shadow_payload(
            bot.get("profit_protection_shadow")
        )
        if profit_protection_shadow:
            snapshot["profit_protection_shadow"] = profit_protection_shadow
        return snapshot

    @staticmethod
    def _parse_order_link_id(order_link_id: Optional[str]) -> Dict[str, Any]:
        """
        Parse orderLinkId to extract bot_id and intent.

        Supports formats:
        - v1 (old): bot:{short_id}:{ts}:{seq}
        - v2 (new): bv2:{bot_id_16}:{ts_8}{seq}{side}{intent}

        Args:
            order_link_id: The orderLinkId string from an order

        Returns:
            Dict with:
                - version: 1 or 2
                - bot_id: bot_id_16 (v2) or short_id (v1)
                - is_short_id: True if bot_id is 8 chars or less
                - intent: "open" or "close" or None
                - side: "Buy" or "Sell" or None
        """
        result = {
            "version": None,
            "bot_id": None,
            "is_short_id": False,
            "intent": None,
            "side": None,
        }

        if not order_link_id or not isinstance(order_link_id, str):
            return result

        # Check for v2 format: bv2:{bot_id_16}:{ts_8}{seq}{side}{intent}
        if order_link_id.startswith("bv2:"):
            result["version"] = 2
            parts = order_link_id.split(":")
            if len(parts) >= 2:
                result["bot_id"] = parts[1]
                # v2 uses 16-char bot_id, not a short_id
                result["is_short_id"] = len(parts[1]) <= 8

            if len(parts) == 5 and parts[4] in ("E", "X"):
                result["intent"] = "open" if parts[4] == "E" else "close"
                return result

            # Parse intent from last part: {ts_8}{seq}{side}{intent}
            # Last 2 chars are side+intent
            if len(parts) >= 3:
                last_part = parts[2]
                if last_part.endswith("O"):
                    result["intent"] = "open"
                elif last_part.endswith("C"):
                    result["intent"] = "close"

                # Parse side (second to last char)
                if len(last_part) >= 2:
                    side_char = last_part[-2]
                    if side_char == "B":
                        result["side"] = "Buy"
                    elif side_char == "S":
                        result["side"] = "Sell"

            return result

        # Check for v1 format: bot:{short_id}:{ts}:{seq}
        if order_link_id.startswith("bot:"):
            result["version"] = 1
            parts = order_link_id.split(":")
            if len(parts) >= 2:
                result["bot_id"] = parts[1]
                result["is_short_id"] = True  # v1 always uses short_id
            return result

        # Check for other known prefixes (scalp, init, qtp, etc.)
        known_prefixes = ["scalp:", "init:", "qtp:", "scalp_mkt:"]
        for prefix in known_prefixes:
            if order_link_id.startswith(prefix):
                result["version"] = 1
                parts = order_link_id.split(":")
                if len(parts) >= 2:
                    result["bot_id"] = parts[1]
                    result["is_short_id"] = True
                return result

        return result

    @staticmethod
    def _normalize_bot_id(bot_id: Optional[str]) -> str:
        """Normalize bot IDs for safe matching across full UUID, short_id, and v2 bot_id_16."""
        if not bot_id or not isinstance(bot_id, str):
            return ""
        return "".join(ch for ch in bot_id.lower() if ch.isalnum())

    @classmethod
    def _bot_id_matches_order_bot_id(
        cls, bot_id: Optional[str], order_bot_id: Optional[str]
    ) -> bool:
        """
        Match a stored bot ID against parsed orderLinkId bot ID.

        Supports:
        - full UUID from storage
        - legacy short IDs
        - v2 16-char bot IDs with dashes removed
        """
        normalized_bot_id = cls._normalize_bot_id(bot_id)
        normalized_order_bot_id = cls._normalize_bot_id(order_bot_id)

        if not normalized_bot_id or not normalized_order_bot_id:
            return False

        if normalized_order_bot_id == normalized_bot_id:
            return True

        # v1 short IDs and v2 bot_id_16 are both prefixes of the normalized UUID.
        if len(normalized_order_bot_id) >= 8 and normalized_bot_id.startswith(
            normalized_order_bot_id
        ):
            return True

        return False

    def _is_control_version_stale(self, bot: Dict[str, Any]) -> bool:
        """C1: Check if the UI changed the bot's control state since cycle start.

        Returns True when the persisted control_version is higher than the
        version recorded at cycle start, indicating the UI issued a
        stop/pause/reduce-only while the runner was mid-cycle.
        """
        bot_id = bot.get("id")
        if not bot_id:
            return False
        cycle_start_cv = int(bot.get("_cycle_start_control_version") or 0)
        if cycle_start_cv <= 0:
            return False
        try:
            try:
                fresh = self.bot_storage.get_bot_fresh(bot_id)
            except (AttributeError, TypeError):
                fresh = self.bot_storage.get_bot(bot_id)
            if not isinstance(fresh, (dict, type(None))):
                fresh = self.bot_storage.get_bot(bot_id)
            if not fresh:
                return True  # bot deleted — abort
            persisted_cv = int(fresh.get("control_version") or 0)
            if persisted_cv > cycle_start_cv:
                fresh_status = str(fresh.get("status") or "").strip().lower()
                logger.warning(
                    "[%s:%s] C1 control-version stale abort: cycle_cv=%d persisted_cv=%d persisted_status=%s",
                    bot.get("symbol", "?"),
                    str(bot_id)[:6],
                    cycle_start_cv,
                    persisted_cv,
                    fresh_status,
                )
                return True
        except Exception:
            pass
        return False

    def _get_other_active_bots_for_symbol(
        self,
        symbol: str,
        exclude_bot_id: Optional[str] = None,
    ) -> List[Dict[str, Any]]:
        if not symbol:
            return []

        try:
            bots = self.bot_storage.list_bots()
        except Exception as exc:
            logger.warning("[%s] Failed to inspect sibling bots: %s", symbol, exc)
            return []

        siblings = []
        for candidate in bots:
            if candidate.get("id") == exclude_bot_id:
                continue
            if candidate.get("symbol") != symbol:
                continue
            if candidate.get("status") not in ACTIVE_SYMBOL_CONTROL_STATUSES:
                continue
            siblings.append(candidate)
        return siblings

    def _get_shared_symbol_conflict(
        self,
        bot: Optional[Dict[str, Any]],
        symbol: str,
        action: str,
    ) -> Optional[Dict[str, Any]]:
        bot_id = str((bot or {}).get("id") or "").strip()
        if not bot_id or not symbol:
            return None

        sibling_bots = self._get_other_active_bots_for_symbol(
            symbol=symbol,
            exclude_bot_id=bot_id,
        )
        if not sibling_bots:
            return None

        sibling_ids = [candidate.get("id") for candidate in sibling_bots if candidate.get("id")]
        logger.error(
            "[%s] Refusing %s for bot %s; %d other active bots share the symbol: %s",
            symbol,
            action,
            bot_id,
            len(sibling_ids),
            ",".join(sibling_ids),
        )
        return {
            "success": False,
            "error": "shared_symbol_active_bots",
            "other_bot_ids": sibling_ids,
        }

    def _is_reduce_only_order(
        self,
        order: Dict[str, Any],
        order_link_id: Optional[str] = None,
    ) -> bool:
        """
        Determine if an order is reduce-only (closing order).

        Uses API reduceOnly field if available, otherwise infers from orderLinkId.

        Args:
            order: Order dict from Bybit API
            order_link_id: Optional orderLinkId for inference

        Returns:
            True if order is reduce-only/closing, False otherwise
        """
        # First, check API reduceOnly field (most reliable)
        reduce_only = order.get("reduceOnly")
        if reduce_only is not None:
            return bool(reduce_only)

        # Fallback: infer from orderLinkId
        link_id = order_link_id or order.get("orderLinkId")
        if link_id:
            parsed = self._parse_order_link_id(link_id)
            if parsed.get("intent") == "close":
                return True

        # Default: assume it's an opening order (safer for margin calculation)
        return False

    @staticmethod
    def _filter_levels_below_min_notional(
        levels: List[float],
        normalized_qty: Optional[float],
        min_notional_value: Optional[float],
    ) -> Tuple[List[float], int]:
        """Drop levels that can never meet exchange min notional at the current qty."""
        qty = float(normalized_qty or 0.0)
        min_notional = float(min_notional_value or 0.0)
        if qty <= 0 or min_notional <= 0:
            return list(levels), 0

        kept_levels: List[float] = []
        removed = 0
        for level in levels:
            if level > 0 and (qty * float(level)) + 1e-9 >= min_notional:
                kept_levels.append(level)
            else:
                removed += 1
        return kept_levels, removed

    @staticmethod
    def _should_skip_flat_scalp_one_sided_grid(
        flat_position: bool,
        current_opening_buy_count: int,
        current_opening_sell_count: int,
        buy_levels_needed: List[float],
        sell_levels_needed: List[float],
    ) -> Tuple[bool, Optional[str]]:
        """
        Block flat scalp placement when only one opening side remains.

        A flat scalp ladder is expected to stay balanced. If pruning removes every
        level on one side but leaves the opposite side intact, placing the
        survivor side would create a one-sided opening book.
        """
        if not flat_position:
            return False, None

        has_buy = (int(current_opening_buy_count or 0) > 0) or bool(buy_levels_needed)
        has_sell = (int(current_opening_sell_count or 0) > 0) or bool(sell_levels_needed)
        if has_buy == has_sell:
            return False, None

        return True, "buy" if not has_buy else "sell"

    def _get_client_for_bot(self, bot: Dict[str, Any]) -> BybitClient:
        """
        Get the appropriate Bybit client for a bot based on its trading_env.

        Args:
            bot: Bot dictionary containing trading_env setting

        Returns:
            BybitClient instance for the bot's environment

        Note:
            Clients are cached to avoid recreating them on every cycle.
        """
        trading_env = (bot.get("trading_env") or "mainnet").strip().lower()
        paper_trading = bool(bot.get("paper_trading", False))

        # Allow backtest mode - use the injected client (MockBybitClient)
        if trading_env == "backtest":
            return self.client

        if trading_env != "mainnet":
            raise ValueError("Testnet disabled. Mainnet only.")
        if paper_trading:
            raise ValueError("paper_trading disabled. Mainnet only.")

        # For mainnet, check cache first
        cache_key = f"{trading_env}_{paper_trading}"
        if cache_key in self._env_clients:
            client = self._env_clients[cache_key]
            self._attach_low_latency_services(client)
            return client

        # Create new client for this environment
        from services.client_factory import create_bybit_client

        client = create_bybit_client(
            trading_env=trading_env, paper_trading=paper_trading
        )
        self._attach_low_latency_services(client)
        self._env_clients[cache_key] = client
        return client

    def _attach_low_latency_services(self, client: BybitClient) -> BybitClient:
        if self.stream_service:
            client.set_stream_service(self.stream_service)
        if self.order_router and hasattr(client, "set_order_router"):
            client.set_order_router(self.order_router)
        return client

    def start_event_reactor(self) -> None:
        if not self.stream_service:
            return
        if self._stream_reaction_service is None:
            from services.stream_reaction_service import StreamReactionService

            self._stream_reaction_service = StreamReactionService(
                stream_service=self.stream_service,
                bot_storage=self.bot_storage,
                grid_bot_service=self,
            )
        self._stream_reaction_service.start()

    def stop_event_reactor(self) -> None:
        if self._stream_reaction_service:
            self._stream_reaction_service.stop()

    @staticmethod
    def _is_auto_pilot_placeholder_symbol(symbol: Any) -> bool:
        return str(symbol or "").strip().lower() == "auto-pilot"

    @classmethod
    def _is_tradeable_symbol(cls, symbol: Any) -> bool:
        normalized = str(symbol or "").strip()
        return bool(normalized) and not cls._is_auto_pilot_placeholder_symbol(
            normalized
        )

    def should_poll_fast_refill(self, bot: Dict[str, Any]) -> bool:
        if self._is_auto_pilot_placeholder_symbol(bot.get("symbol")):
            return False
        if not self._stream_reaction_service:
            return True
        return self._stream_reaction_service.should_poll_fast_refill(bot)

    def note_fast_refill_poll(self, bot: Dict[str, Any]) -> None:
        if self._stream_reaction_service:
            self._stream_reaction_service.note_fast_refill_poll(bot)

    def _stream_execution_events_or_none(
        self,
        execution_events: Optional[List[Dict[str, Any]]] = None,
    ) -> Optional[List[Dict[str, Any]]]:
        if execution_events is not None:
            return list(execution_events)
        if self.stream_service and self.stream_service.is_topic_fresh("execution"):
            return []
        return None

    def _try_acquire_bot_run_lock(
        self,
        bot_id: Optional[str],
    ) -> Tuple[bool, Optional[threading.RLock]]:
        normalized_bot_id = str(bot_id or "").strip()
        if not normalized_bot_id:
            return True, None
        with self._bot_run_locks_guard:
            lock = self._bot_run_locks.get(normalized_bot_id)
            if lock is None:
                lock = threading.RLock()
                self._bot_run_locks[normalized_bot_id] = lock
        acquired = lock.acquire(blocking=False)
        return acquired, lock

    @staticmethod
    def _release_bot_run_lock(lock: Optional[threading.RLock]) -> None:
        if lock is None:
            return
        try:
            lock.release()
        except RuntimeError:
            pass

    @staticmethod
    def _merge_cycle_runtime_context(
        target_bot: Dict[str, Any],
        incoming_bot: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        if not incoming_bot:
            return target_bot
        for key in (
            "_reevaluation_trigger_received_at",
            "_reevaluation_trigger_reason",
            "_reevaluation_trigger_path",
            "_blocked_guarded_fast_path_requested",
            "_fresh_provider_seen_before_eval",
            "_evaluation_deferred_reason",
        ):
            if key in incoming_bot:
                target_bot[key] = incoming_bot.get(key)
        return target_bot

    def _save_runtime_bot(self, bot: Dict[str, Any], **kwargs: Any) -> Dict[str, Any]:
        if hasattr(self.bot_storage, "save_runtime_bot"):
            return self.bot_storage.save_runtime_bot(bot, **kwargs)
        return self.bot_storage.save_bot(bot)

    def _save_runtime_bot_cache_only(
        self,
        bot: Dict[str, Any],
        **kwargs: Any,
    ) -> Dict[str, Any]:
        if hasattr(self.bot_storage, "save_runtime_bot"):
            return self.bot_storage.save_runtime_bot(bot, persist=False, **kwargs)
        return dict(bot)

    @staticmethod
    def _classify_reconciliation_persistence_class(reason: str) -> str:
        normalized_reason = str(reason or "").strip().lower()
        if normalized_reason in {"cycle_exception", "error_maintenance"}:
            return "error_path"
        if normalized_reason == "ambiguous_follow_up":
            return "recovery_path"
        if normalized_reason == "startup":
            return "maintenance_path"
        return "runtime_path"

    @staticmethod
    def _normalized_exchange_reconciliation_state(
        payload: Optional[Dict[str, Any]],
    ) -> Dict[str, Any]:
        normalized = dict(payload or {})
        normalized.pop("updated_at", None)
        return normalized

    @staticmethod
    def _normalized_ambiguous_follow_up_state(
        marker: Optional[Dict[str, Any]],
    ) -> Dict[str, Any]:
        normalized = dict(marker or {})
        for field in (
            "updated_at",
            "last_checked_at",
            "resolved_at",
            "last_escalated_at",
        ):
            normalized.pop(field, None)
        return normalized

    @staticmethod
    def _mark_control_state_change(bot: Dict[str, Any]) -> None:
        try:
            bot["control_version"] = int(bot.get("control_version") or 0) + 1
        except (TypeError, ValueError):
            bot["control_version"] = 1
        bot["control_updated_at"] = datetime.now(timezone.utc).isoformat()

    @staticmethod
    def _record_control_timing(
        bot: Optional[Dict[str, Any]],
        scope: str,
        **fields: Any,
    ) -> Dict[str, Any]:
        return update_bot_timing(bot, scope, **fields)

    def _mark_runner_pickup(
        self,
        bot: Dict[str, Any],
        *,
        fast_refill_tick: bool,
    ) -> None:
        start_timing = self._record_control_timing(bot, "start")
        if not start_timing or start_timing.get("runner_pickup_at"):
            return
        received_at_raw = start_timing.get("control_action_received_at") or bot.get(
            "started_at"
        )
        received_dt = self._parse_iso_datetime(received_at_raw)
        pickup_at_ts = now_ts()
        pickup_at_iso = iso_from_ts(pickup_at_ts)
        self._record_control_timing(
            bot,
            "start",
            runner_pickup_at=pickup_at_iso,
            runtime_active_at=pickup_at_iso,
            runner_pickup_lane=(
                "fast_control_lane" if fast_refill_tick else "grid_tick"
            ),
            control_action_to_runner_pickup_ms=(
                elapsed_ms(received_dt.timestamp(), pickup_at_ts)
                if received_dt is not None
                else None
            ),
            start_to_runtime_active_ms=(
                elapsed_ms(received_dt.timestamp(), pickup_at_ts)
                if received_dt is not None
                else None
            ),
            pending_runner_pickup=False,
        )

    def _record_first_start_order(
        self,
        bot: Optional[Dict[str, Any]],
        order_result: Optional[Dict[str, Any]],
        *,
        symbol: str,
        side: str,
        reduce_only: bool,
        order_link_id: Optional[str],
    ) -> None:
        if not isinstance(bot, dict) or reduce_only or not order_result or not order_result.get(
            "success"
        ):
            return
        start_timing = self._record_control_timing(bot, "start")
        if start_timing.get("first_order_submitted_at"):
            return
        order_ack_at_raw = ((order_result or {}).get("timing") or {}).get(
            "order_submit_ack_at"
        )
        order_ack_dt = self._parse_iso_datetime(order_ack_at_raw)
        received_dt = self._parse_iso_datetime(
            start_timing.get("control_action_received_at") or bot.get("started_at")
        )
        start_timing["first_order_submitted_at"] = (
            order_ack_at_raw or iso_from_ts()
        )
        start_timing["first_order_symbol"] = symbol
        start_timing["first_order_side"] = side
        start_timing["first_order_link_id"] = order_link_id
        start_timing["start_to_first_order_ms"] = (
            elapsed_ms(received_dt.timestamp(), order_ack_dt.timestamp())
            if received_dt is not None and order_ack_dt is not None
            else None
        )

    @staticmethod
    def _parse_iso_datetime(value: Any) -> Optional[datetime]:
        raw = str(value or "").strip()
        if not raw:
            return None
        try:
            parsed = datetime.fromisoformat(raw.replace("Z", "+00:00"))
        except Exception:
            return None
        if parsed.tzinfo is None:
            return parsed.replace(tzinfo=timezone.utc)
        return parsed.astimezone(timezone.utc)

    def _parse_session_timer_datetime(
        self,
        value: Any,
        *,
        reference_dt: Optional[datetime] = None,
        allow_rollover: bool = False,
    ) -> Optional[datetime]:
        raw = str(value or "").strip()
        if not raw:
            return None
        parsed = self._parse_iso_datetime(raw)
        if parsed is not None:
            return parsed
        if not re.fullmatch(r"\d{2}:\d{2}(?::\d{2})?", raw):
            return None
        parts = [int(part) for part in raw.split(":")]
        while len(parts) < 3:
            parts.append(0)
        base_dt = reference_dt or datetime.now(timezone.utc)
        resolved = base_dt.replace(
            hour=parts[0],
            minute=parts[1],
            second=parts[2],
            microsecond=0,
        )
        if allow_rollover and reference_dt is not None and resolved <= reference_dt:
            resolved += timedelta(days=1)
        return resolved

    def _get_session_timer_schedule(
        self,
        bot: Dict[str, Any],
        *,
        now_dt: Optional[datetime] = None,
    ) -> Optional[Dict[str, Any]]:
        if not bool(bot.get("session_timer_enabled")):
            return None
        now_dt = now_dt or datetime.now(timezone.utc)
        start_dt = self._parse_session_timer_datetime(
            bot.get("session_start_at"),
            reference_dt=now_dt,
        )
        stop_dt = self._parse_session_timer_datetime(
            bot.get("session_stop_at"),
            reference_dt=start_dt or now_dt,
            allow_rollover=bool(start_dt),
        )
        if stop_dt is None:
            return None
        if start_dt is not None and stop_dt <= start_dt and not re.fullmatch(
            r"\d{2}:\d{2}(?::\d{2})?",
            str(bot.get("session_stop_at") or "").strip(),
        ):
            return None
        pre_stop_min = max(
            int(self._safe_float(bot.get("session_no_new_entries_before_stop_min"), 0)),
            0,
        )
        pre_stop_dt = stop_dt - timedelta(minutes=pre_stop_min)
        return {
            "start_dt": start_dt,
            "stop_dt": stop_dt,
            "pre_stop_dt": pre_stop_dt,
        }

    def _get_session_timer_exposure_snapshot(
        self,
        bot: Dict[str, Any],
        symbol: str,
    ) -> Dict[str, Any]:
        snapshot = {
            "has_position": False,
            "position_count": 0,
            "opening_order_count": 0,
            "exit_order_count": 0,
            "position_unrealized_pnl": 0.0,
            "has_any_exposure": False,
        }
        try:
            positions_resp = self.client.get_positions(skip_cache=True)
            if positions_resp.get("success"):
                for position in (positions_resp.get("data", {}) or {}).get("list", []) or []:
                    if position.get("symbol") != symbol:
                        continue
                    if self._safe_float(position.get("size"), 0.0) <= 0:
                        continue
                    snapshot["has_position"] = True
                    snapshot["position_count"] += 1
                    snapshot["position_unrealized_pnl"] += self._safe_float(
                        position.get("unrealisedPnl"),
                        0.0,
                    )
        except Exception as exc:
            logger.debug("[%s] Session timer position snapshot failed: %s", symbol, exc)

        try:
            orders_resp = self.client.get_open_orders(
                symbol=symbol,
                limit=200,
                skip_cache=True,
            )
            if orders_resp.get("success"):
                orders = self._extract_order_list_from_response(orders_resp)
                bot_id = bot.get("id")
                for order in orders:
                    link_id = order.get("orderLinkId")
                    parsed = self._parse_order_link_id(link_id)
                    if not self._bot_id_matches_order_bot_id(bot_id, parsed.get("bot_id")):
                        continue
                    if self._is_reduce_only_order(order, link_id):
                        snapshot["exit_order_count"] += 1
                    else:
                        snapshot["opening_order_count"] += 1
        except Exception as exc:
            logger.debug("[%s] Session timer open-order snapshot failed: %s", symbol, exc)

        snapshot["has_any_exposure"] = bool(
            snapshot["has_position"] or snapshot["opening_order_count"] > 0
        )
        return snapshot

    def _update_session_timer_runtime_state(
        self,
        bot: Dict[str, Any],
        *,
        state: str,
        start_at: Optional[datetime],
        pre_stop_at: Optional[datetime],
        grace_started_at: Optional[datetime] = None,
        grace_expires_at: Optional[datetime] = None,
        completed_at: Optional[datetime] = None,
        completed_reason: Optional[str] = None,
        no_new_entries_active: bool = False,
    ) -> bool:
        if state not in SESSION_TIMER_STATES:
            state = "inactive"
        changed = False
        updates = {
            "session_timer_state": state,
            "session_timer_started_at": start_at.isoformat() if start_at else None,
            "session_timer_pre_stop_at": pre_stop_at.isoformat() if pre_stop_at else None,
            "session_timer_grace_started_at": (
                grace_started_at.isoformat() if grace_started_at else None
            ),
            "session_timer_grace_expires_at": (
                grace_expires_at.isoformat() if grace_expires_at else None
            ),
            "session_timer_completed_at": (
                completed_at.isoformat() if completed_at else None
            ),
            "session_timer_completed_reason": completed_reason,
            "session_timer_no_new_entries_active": bool(no_new_entries_active),
            "_session_timer_block_opening_orders": bool(no_new_entries_active),
        }
        for key, value in updates.items():
            if bot.get(key) != value:
                bot[key] = value
                changed = True
        return changed

    def _enable_session_timer_reduce_only(
        self,
        bot: Dict[str, Any],
        *,
        now_iso: str,
    ) -> bool:
        if not bool(bot.get("session_reduce_only_on_end")):
            return False
        if bool(bot.get("reduce_only_mode")):
            return False
        bot["reduce_only_mode"] = True
        bot["auto_stop_paused"] = True
        bot["session_timer_reduce_only_active"] = True
        bot["session_timer_end_triggered_at"] = now_iso
        self._mark_control_state_change(bot)
        return True

    def _complete_session_timer(
        self,
        bot: Dict[str, Any],
        symbol: str,
        *,
        now_dt: datetime,
        reason: str,
        event_type: str = "session_completed",
        extra_fields: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        now_iso = now_dt.isoformat()
        self._cancel_bot_orders(bot, symbol, cancel_all=True)
        if bot.get("session_timer_reduce_only_active"):
            bot["reduce_only_mode"] = False
            bot["auto_stop_paused"] = False
        bot["session_timer_reduce_only_active"] = False
        bot["session_timer_end_triggered_at"] = now_iso
        # H2 audit: verify flat before finalizing stopped
        try:
            _cleanup = self._confirm_symbol_cleanup_state(symbol)
            if not (_cleanup.get("flat") and _cleanup.get("orders_cleared")):
                logger.warning(
                    "[%s] Session timer stop: not flat yet — entering stop_cleanup_pending",
                    symbol,
                )
                bot["status"] = "stop_cleanup_pending"
                bot["stop_cleanup_reason"] = reason
                self.bot_storage.save_bot(bot)
                return bot
        except Exception as _exc:
            logger.debug("[%s] Cleanup state check failed during session stop: %s", symbol, _exc)
        bot["status"] = "stopped"
        bot["started_at"] = None
        bot["last_run_at"] = now_iso
        self._reset_auto_pilot_on_stop(bot)
        self._update_session_timer_runtime_state(
            bot,
            state="completed",
            start_at=self._parse_session_timer_datetime(bot.get("session_start_at")),
            pre_stop_at=self._parse_session_timer_datetime(bot.get("session_timer_pre_stop_at")),
            completed_at=now_dt,
            completed_reason=reason,
            no_new_entries_active=False,
        )
        self._mark_control_state_change(bot)
        fields = {
            "session_state": "completed",
            "end_mode": bot.get("session_end_mode"),
            "reason": reason,
        }
        if extra_fields:
            fields.update(extra_fields)
        self._emit_audit_event(
            bot,
            event_type=event_type,
            severity="INFO",
            symbol=symbol,
            mode=bot.get("mode"),
            throttle_key=f"{event_type}:{bot.get('id')}:{reason}",
            throttle_sec=0.0,
            **fields,
        )
        return self.bot_storage.save_bot(bot)

    def _apply_session_timer_control(
        self,
        bot: Dict[str, Any],
        symbol: str,
        *,
        now_dt: Optional[datetime] = None,
    ) -> Optional[Dict[str, Any]]:
        now_dt = now_dt or datetime.now(timezone.utc)
        now_iso = now_dt.isoformat()
        if bool(bot.get("_session_timer_skip_expired_absolute_window")):
            changed = self._update_session_timer_runtime_state(
                bot,
                state="inactive",
                start_at=None,
                pre_stop_at=None,
                no_new_entries_active=False,
            )
            if bot.get("session_timer_reduce_only_active"):
                bot["session_timer_reduce_only_active"] = False
                changed = True
            if bot.get("_session_timer_block_opening_orders"):
                bot["_session_timer_block_opening_orders"] = False
                changed = True
            if changed:
                self._save_runtime_bot(bot)
            return None
        if not bool(bot.get("session_timer_enabled")):
            changed = self._update_session_timer_runtime_state(
                bot,
                state="inactive",
                start_at=None,
                pre_stop_at=None,
                no_new_entries_active=False,
            )
            if bot.get("session_timer_reduce_only_active"):
                bot["session_timer_reduce_only_active"] = False
                changed = True
            if changed:
                self._save_runtime_bot(bot)
            return None

        schedule = self._get_session_timer_schedule(bot, now_dt=now_dt)
        if not schedule:
            return None

        start_dt = schedule.get("start_dt")
        stop_dt = schedule.get("stop_dt")
        pre_stop_dt = schedule.get("pre_stop_dt")
        previous_state = str(bot.get("session_timer_state") or "inactive").strip().lower()
        if previous_state not in SESSION_TIMER_STATES:
            previous_state = "inactive"

        if bot.get("session_timer_state") == "completed":
            return None

        if start_dt is not None and now_dt < start_dt:
            changed = self._update_session_timer_runtime_state(
                bot,
                state="scheduled_not_started",
                start_at=start_dt,
                pre_stop_at=pre_stop_dt,
                no_new_entries_active=True,
            )
            if previous_state != "scheduled_not_started":
                bot["session_timer_last_event"] = "scheduled_not_started"
                changed = True
            if changed:
                self._save_runtime_bot(bot)
            return None

        if previous_state in {"inactive", "scheduled_not_started"}:
            self._emit_audit_event(
                bot,
                event_type="session_timer_started",
                severity="INFO",
                symbol=symbol,
                mode=bot.get("mode"),
                throttle_key=f"session_timer_started:{bot.get('id')}:{stop_dt.isoformat()}",
                throttle_sec=0.0,
                state="running",
                starts_at=start_dt.isoformat() if start_dt else None,
                stops_at=stop_dt.isoformat(),
                end_mode=bot.get("session_end_mode"),
            )

        if now_dt < pre_stop_dt:
            changed = self._update_session_timer_runtime_state(
                bot,
                state="running",
                start_at=start_dt,
                pre_stop_at=pre_stop_dt,
                no_new_entries_active=False,
            )
            if changed:
                self._save_runtime_bot(bot)
            return None

        if now_dt < stop_dt:
            if previous_state != "pre_stop_no_new_entries":
                self._emit_audit_event(
                    bot,
                    event_type="session_pre_stop_armed",
                    severity="INFO",
                    symbol=symbol,
                    mode=bot.get("mode"),
                    throttle_key=f"session_pre_stop_armed:{bot.get('id')}:{stop_dt.isoformat()}",
                    throttle_sec=0.0,
                    pre_stop_at=pre_stop_dt.isoformat(),
                    stops_at=stop_dt.isoformat(),
                    end_mode=bot.get("session_end_mode"),
                )
            changed = self._update_session_timer_runtime_state(
                bot,
                state="pre_stop_no_new_entries",
                start_at=start_dt,
                pre_stop_at=pre_stop_dt,
                no_new_entries_active=True,
            )
            if changed:
                self._save_runtime_bot(bot)
            return None

        end_mode = str(bot.get("session_end_mode") or "hard_stop").strip().lower()
        if end_mode not in SESSION_TIMER_END_MODES:
            end_mode = "hard_stop"
        exposure = self._get_session_timer_exposure_snapshot(bot, symbol)
        if not bot.get("session_timer_end_triggered_at"):
            bot["session_timer_end_triggered_at"] = now_iso
            self._emit_audit_event(
                bot,
                event_type="session_end_mode_triggered",
                severity="INFO",
                symbol=symbol,
                mode=bot.get("mode"),
                throttle_key=f"session_end_mode_triggered:{bot.get('id')}:{stop_dt.isoformat()}",
                throttle_sec=0.0,
                end_mode=end_mode,
                stops_at=stop_dt.isoformat(),
                has_position=exposure.get("has_position"),
                opening_order_count=exposure.get("opening_order_count"),
            )

        if bot.get("session_cancel_pending_orders_on_end"):
            self._cancel_opening_orders_only(bot, symbol)

        if end_mode == "hard_stop":
            close_success = self._close_position_market(symbol, bot=bot)
            if not close_success:
                bot["last_error"] = "Session hard stop failed to close position safely"
                bot["session_timer_no_new_entries_active"] = True
                bot["_session_timer_block_opening_orders"] = True
                self._save_runtime_bot(bot)
                return bot
            return self._complete_session_timer(
                bot,
                symbol,
                now_dt=now_dt,
                reason="hard_stop",
            )

        if end_mode == "soft_stop":
            control_changed = self._enable_session_timer_reduce_only(bot, now_iso=now_iso)
            changed = self._update_session_timer_runtime_state(
                bot,
                state="pre_stop_no_new_entries",
                start_at=start_dt,
                pre_stop_at=pre_stop_dt,
                no_new_entries_active=True,
            )
            if not exposure.get("has_any_exposure"):
                return self._complete_session_timer(
                    bot,
                    symbol,
                    now_dt=now_dt,
                    reason="soft_stop_flat",
                )
            if control_changed:
                return self.bot_storage.save_bot(bot)
            if changed:
                self._save_runtime_bot(bot)
            return None

        grace_started_at = self._parse_iso_datetime(bot.get("session_timer_grace_started_at"))
        if grace_started_at is None:
            grace_started_at = now_dt
            grace_minutes = max(
                int(self._safe_float(bot.get("session_green_grace_min"), 0)),
                0,
            )
            grace_expires_at = now_dt + timedelta(minutes=grace_minutes)
            control_changed = self._enable_session_timer_reduce_only(bot, now_iso=now_iso)
            changed = self._update_session_timer_runtime_state(
                bot,
                state="grace_active",
                start_at=start_dt,
                pre_stop_at=pre_stop_dt,
                grace_started_at=grace_started_at,
                grace_expires_at=grace_expires_at,
                no_new_entries_active=True,
            )
            self._emit_audit_event(
                bot,
                event_type="session_grace_started",
                severity="INFO",
                symbol=symbol,
                mode=bot.get("mode"),
                throttle_key=f"session_grace_started:{bot.get('id')}:{stop_dt.isoformat()}",
                throttle_sec=0.0,
                grace_started_at=grace_started_at.isoformat(),
                grace_expires_at=grace_expires_at.isoformat(),
                end_mode=end_mode,
            )
            if not exposure.get("has_any_exposure"):
                return self._complete_session_timer(
                    bot,
                    symbol,
                    now_dt=now_dt,
                    reason="green_grace_flat",
                )
            if control_changed:
                return self.bot_storage.save_bot(bot)
            if changed:
                self._save_runtime_bot(bot)
            return None

        grace_expires_at = self._parse_iso_datetime(bot.get("session_timer_grace_expires_at"))
        if grace_expires_at is None:
            grace_expires_at = grace_started_at
        changed = self._update_session_timer_runtime_state(
            bot,
            state="grace_active",
            start_at=start_dt,
            pre_stop_at=pre_stop_dt,
            grace_started_at=grace_started_at,
            grace_expires_at=grace_expires_at,
            no_new_entries_active=True,
        )
        if changed:
            self._save_runtime_bot(bot)

        if not exposure.get("has_any_exposure"):
            return self._complete_session_timer(
                bot,
                symbol,
                now_dt=now_dt,
                reason="green_grace_flat",
            )

        if exposure.get("has_position") and self._safe_float(
            exposure.get("position_unrealized_pnl"),
            0.0,
        ) > 0:
            close_success = self._close_position_market(symbol, bot=bot)
            if close_success:
                return self._complete_session_timer(
                    bot,
                    symbol,
                    now_dt=now_dt,
                    reason="green_grace_green_exit",
                )

        max_loss_pct = self._safe_float(bot.get("session_force_close_max_loss_pct"), 0.0)
        force_close_early = False
        if max_loss_pct > 0 and exposure.get("has_position"):
            investment = self._safe_float(bot.get("investment"), 0.0)
            loss_limit = investment * (max_loss_pct / 100.0 if max_loss_pct > 1.0 else max_loss_pct)
            if loss_limit > 0 and self._safe_float(
                exposure.get("position_unrealized_pnl"),
                0.0,
            ) <= -loss_limit:
                force_close_early = True

        if now_dt >= grace_expires_at or force_close_early:
            close_success = self._close_position_market(symbol, bot=bot)
            if not close_success:
                bot["last_error"] = "Session grace force close failed to close position safely"
                self._save_runtime_bot(bot)
                return bot
            return self._complete_session_timer(
                bot,
                symbol,
                now_dt=now_dt,
                reason="green_grace_forced_close",
                event_type="session_forced_close",
                extra_fields={
                    "grace_expires_at": grace_expires_at.isoformat()
                    if grace_expires_at
                    else None,
                    "position_unrealized_pnl": round(
                        self._safe_float(exposure.get("position_unrealized_pnl"), 0.0),
                        4,
                    ),
                },
            )
        return None

    def _is_direction_change_auto_stop_enabled(self) -> bool:
        settings_service = getattr(self, "runtime_settings_service", None)
        if settings_service is None:
            return False
        try:
            return bool(settings_service.get_auto_stop_on_direction_change())
        except Exception as exc:
            logger.debug("Direction-change auto-stop setting read failed: %s", exc)
            return False

    def _snapshot_direction_change_state(
        self,
        symbol: str,
        indicators: Dict[str, Any],
    ) -> Dict[str, Any]:
        result = {
            "state": "neutral",
            "source": "trend_protection",
            "score": None,
            "detail": "Trend confidence too low",
        }
        trend_service = getattr(self, "trend_protection_service", None)
        if trend_service is None:
            result["source"] = "unavailable"
            result["detail"] = "Trend protection service unavailable"
            return result

        try:
            trend_result = trend_service.detect_trend(symbol=symbol, indicators=indicators or {})
        except Exception as exc:
            result["source"] = "error"
            result["detail"] = f"Trend snapshot failed: {exc}"
            return result

        direction = str(trend_result.get("trend_direction") or "").strip().lower()
        score = self._safe_float(trend_result.get("confidence_score"), None)
        reasons = [
            str(reason).strip()
            for reason in (trend_result.get("reasons") or [])
            if str(reason).strip()
        ]
        result["score"] = score
        if reasons:
            result["detail"] = reasons[-1]

        if trend_result.get("should_act") and direction in {"up", "down"}:
            result["state"] = "long" if direction == "up" else "short"
        return result

    def _maybe_apply_direction_change_auto_stop(
        self,
        bot: Dict[str, Any],
        symbol: str,
        indicators: Dict[str, Any],
        now_iso: str,
    ) -> Optional[Dict[str, Any]]:
        enabled = self._is_direction_change_auto_stop_enabled()
        bot["direction_change_guard_enabled"] = enabled

        snapshot = self._snapshot_direction_change_state(symbol, indicators)
        current_state = str(snapshot.get("state") or "neutral").strip().lower()
        if current_state not in {"long", "short", "neutral"}:
            current_state = "neutral"
        bot["direction_change_guard_state"] = current_state
        bot["direction_change_guard_source"] = snapshot.get("source")
        bot["direction_change_guard_score"] = snapshot.get("score")
        bot["direction_change_guard_detail"] = snapshot.get("detail")
        bot["direction_change_guard_updated_at"] = now_iso

        position_size = self._safe_float(bot.get("position_size"), 0.0)
        has_position = position_size > 0 and bool(str(bot.get("position_side") or "").strip())

        # After a safety reduce-only action, stop cleanly once the leg is flat.
        if (
            enabled
            and bool(bot.get("reduce_only_mode"))
            and bool(bot.get("auto_stop_paused"))
            and str(bot.get("direction_change_guard_last_action") or "").strip().lower() == "reduce_only"
            and not has_position
        ):
            bot["status"] = "stopped"
            bot["started_at"] = None
            bot["reduce_only_mode"] = False
            bot["auto_stop_paused"] = False
            bot["last_run_at"] = now_iso
            self._reset_auto_pilot_on_stop(bot)
            bot["direction_change_guard_last_action"] = "stopped_flat"
            bot["direction_change_guard_last_position_action"] = "flat_after_reduce_only"
            bot["direction_change_guard_last_reason"] = "Direction-change reduce-only safety completed after position flattened"
            bot["direction_change_guard_last_event_at"] = now_iso
            bot["direction_change_guard_pending_state"] = None
            bot["direction_change_guard_pending_since"] = None
            self._mark_control_state_change(bot)
            logger.warning(
                "[%s] Direction-change auto-stop: bot stopped after reduce-only position flattened",
                symbol,
            )
            return self.bot_storage.save_bot(bot)

        if not enabled:
            bot["direction_change_guard_pending_state"] = None
            bot["direction_change_guard_pending_since"] = None
            return None

        prev_state = str(bot.get("direction_change_guard_baseline_state") or "").strip().lower()
        if prev_state not in {"long", "short", "neutral"}:
            prev_state = ""

        if not prev_state:
            bot["direction_change_guard_baseline_state"] = current_state
            bot["direction_change_guard_pending_state"] = None
            bot["direction_change_guard_pending_since"] = None
            return None

        if current_state == prev_state or current_state == "neutral" or prev_state == "neutral":
            bot["direction_change_guard_baseline_state"] = current_state
            bot["direction_change_guard_pending_state"] = None
            bot["direction_change_guard_pending_since"] = None
            return None

        last_trigger_dt = self._parse_iso_datetime(
            bot.get("direction_change_guard_last_trigger_at")
        )
        if last_trigger_dt is not None:
            elapsed_since_last = (datetime.now(timezone.utc) - last_trigger_dt).total_seconds()
            if elapsed_since_last < DIRECTION_CHANGE_AUTO_STOP_COOLDOWN_SECONDS:
                return None

        pending_state = str(bot.get("direction_change_guard_pending_state") or "").strip().lower()
        if pending_state != current_state:
            bot["direction_change_guard_pending_state"] = current_state
            bot["direction_change_guard_pending_since"] = now_iso
            bot["direction_change_guard_pending_detail"] = (
                f"Confirming direction change {prev_state}->{current_state}"
            )
            return None

        pending_since_dt = self._parse_iso_datetime(
            bot.get("direction_change_guard_pending_since")
        )
        if pending_since_dt is None:
            bot["direction_change_guard_pending_since"] = now_iso
            return None

        pending_elapsed = (datetime.now(timezone.utc) - pending_since_dt).total_seconds()
        if pending_elapsed < DIRECTION_CHANGE_AUTO_STOP_CONFIRM_SECONDS:
            return None

        unrealized_pnl = self._safe_float(bot.get("unrealized_pnl"), 0.0)
        profitable_position = has_position and unrealized_pnl > 0
        shared_conflict = bool(
            self._get_shared_symbol_conflict(bot, symbol, "direction-change auto-stop")
        )
        cancelled_openings = 0
        try:
            cancelled_openings = int(self._cancel_opening_orders_only(bot, symbol) or 0)
        except Exception as exc:
            logger.warning(
                "[%s] Direction-change auto-stop failed cancelling bot openings: %s",
                symbol,
                exc,
            )

        action = "stopped"
        position_action = "flat"
        reason = (
            f"Direction change confirmed {prev_state}->{current_state}"
            f" ({snapshot.get('source')}, score={self._safe_float(snapshot.get('score'), 0.0):.0f})"
        )

        if has_position and profitable_position and not shared_conflict:
            close_result = self._close_position_or_hard_fail(
                bot,
                symbol,
                "direction_change_auto_stop",
            )
            if close_result.get("success"):
                bot["status"] = "stopped"
                bot["started_at"] = None
                bot["reduce_only_mode"] = False
                bot["auto_stop_paused"] = False
                self._reset_auto_pilot_on_stop(bot)
                action = "stopped_after_close"
                position_action = "closed_profitable"
            else:
                return None
        elif has_position:
            bot["reduce_only_mode"] = True
            bot["auto_stop_paused"] = True
            action = "reduce_only"
            position_action = (
                "shared_symbol_conflict_reduce_only"
                if shared_conflict and profitable_position
                else "kept_open_reduce_only"
            )
            if shared_conflict and profitable_position:
                reason = (
                    f"{reason}; shared-symbol ownership conflict prevented direct close"
                )
        else:
            bot["status"] = "stopped"
            bot["started_at"] = None
            bot["reduce_only_mode"] = False
            bot["auto_stop_paused"] = False
            self._reset_auto_pilot_on_stop(bot)

        bot["last_run_at"] = now_iso
        bot["direction_change_guard_prev_state"] = prev_state
        bot["direction_change_guard_baseline_state"] = current_state
        bot["direction_change_guard_pending_state"] = None
        bot["direction_change_guard_pending_since"] = None
        bot["direction_change_guard_last_action"] = action
        bot["direction_change_guard_last_position_action"] = position_action
        bot["direction_change_guard_last_reason"] = reason
        bot["direction_change_guard_last_event_at"] = now_iso
        bot["direction_change_guard_last_unrealized_pnl"] = unrealized_pnl
        bot["direction_change_guard_last_cancelled_openings"] = cancelled_openings
        bot["direction_change_guard_last_trigger_at"] = now_iso
        self._mark_control_state_change(bot)

        logger.warning(
            "[%s] Direction-change auto-stop triggered: action=%s prev=%s next=%s position_action=%s pnl=%.4f cancelled_openings=%d",
            symbol,
            action,
            prev_state,
            current_state,
            position_action,
            unrealized_pnl,
            cancelled_openings,
        )
        return self.bot_storage.save_bot(bot)


    def _ensure_stream_symbol(self, symbol: Optional[str], include_orderbook: bool = True) -> None:
        """Keep websocket subscriptions aligned with actively traded symbols."""
        if not self.stream_service or not symbol:
            return
        if str(symbol).strip().lower() == "auto-pilot":
            return
        try:
            self.stream_service.ensure_symbol(symbol, include_orderbook=include_orderbook)
        except Exception as exc:
            logger.debug("Failed to ensure stream symbol %s: %s", symbol, exc)

    # =============================================================================
    # Auto Margin Guard (Smart Add-Margin to Maintain Safe Liq Distance)
    # =============================================================================

    def _get_usdt_available_balance(self) -> float:
        """Best-effort parse of USDT available balance from /v5/account/wallet-balance."""
        try:
            resp = self.client.get_wallet_balance()
            if not resp.get("success"):
                return 0.0

            data = resp.get("data", {}) or {}
            accounts = data.get("list", []) or []
            for account in accounts:
                coins = account.get("coin", []) or []
                for coin in coins:
                    if (coin.get("coin") or "").upper() != "USDT":
                        continue

                    # Prefer availableToWithdraw (UTA field)
                    available = coin.get("availableToWithdraw")
                    if available and str(available).strip():
                        try:
                            return float(available)
                        except (TypeError, ValueError):
                            pass

                    # Calculate: walletBalance - totalPositionIM - totalOrderIM
                    try:
                        wallet_balance = float(coin.get("walletBalance", 0) or 0)
                        position_im = float(coin.get("totalPositionIM", 0) or 0)
                        order_im = float(coin.get("totalOrderIM", 0) or 0)
                        calculated = wallet_balance - position_im - order_im
                        if calculated > 0:
                            return calculated
                    except (TypeError, ValueError):
                        pass

                    return 0.0
        except Exception:
            return 0.0

        return 0.0


    def _calculate_effective_capital(
        self,
        bot: Dict[str, Any],
        investment: float,
        leverage: float,
        available_equity: Optional[float] = None,
    ) -> float:
        """
        Return reserve-adjusted notional capital for risk and sizing checks.
        """
        _, usable_investment = self._calculate_auto_margin_reserve(
            bot,
            investment,
            available_equity,
        )
        return max(0.0, usable_investment) * max(0.0, self._safe_float(leverage, 0.0))

    def _get_effective_investment(self, bot: Dict[str, Any], investment: float) -> float:
        requested = max(self._safe_float(investment), 0.0)
        capital_partition = self._safe_float(bot.get("capital_partition_usdt"), 0.0)
        if capital_partition > 0:
            requested = min(requested, capital_partition)
        bot["effective_investment_usdt"] = requested
        return requested

    def _get_fee_aware_min_step_pct(self, bot: Dict[str, Any]) -> float:
        runtime_floor = self._safe_float(bot.get("runtime_fee_aware_min_step_pct"), 0.0)
        fee_floor = (
            (2.0 * FAST_EXEC_TAKER_FEE_RATE)
            + FAST_EXEC_SLIPPAGE_BUFFER_PCT
            + FEE_AWARE_MIN_STEP_BUFFER_PCT
        )
        if not FEE_AWARE_MIN_STEP_ENABLED:
            return max(runtime_floor, GRID_STEP_PCT)
        # Fee floor enforces minimum profitability (0.26%) without clamping to
        # base GRID_STEP_PCT — allows major multiplier (0.4x) to work down to
        # fee floor instead of being nullified back to base step.
        return max(runtime_floor, fee_floor)

    def _get_volatility_derisk_profile(
        self,
        atr_pct: Optional[float],
        mode: str,
        requested_open_cap_total: int,
    ) -> Dict[str, Any]:
        cap_floor = max(1, int(requested_open_cap_total or 0))
        profile = {
            "tier": "normal",
            "step_mult": 1.0,
            "size_mult": 1.0,
            "open_cap_total": cap_floor,
            "block_opening_orders": False,
        }
        atr_value = self._safe_float(atr_pct, 0.0)
        if not VOLATILITY_DERISK_ENABLED or atr_value <= 0:
            return profile

        if atr_value >= VOLATILITY_DERISK_ATR_EXTREME:
            profile.update(
                {
                    "tier": "extreme",
                    "step_mult": VOLATILITY_DERISK_STEP_MULT_EXTREME,
                    "size_mult": VOLATILITY_DERISK_SIZE_MULT_EXTREME,
                    "open_cap_total": max(
                        2,
                        min(cap_floor, PROXIMITY_EXTREME_VOL_OPEN_ORDER_CAP_TOTAL),
                    ),
                }
            )
        elif atr_value >= VOLATILITY_DERISK_ATR_HIGH:
            profile.update(
                {
                    "tier": "high",
                    "step_mult": VOLATILITY_DERISK_STEP_MULT_HIGH,
                    "size_mult": VOLATILITY_DERISK_SIZE_MULT_HIGH,
                    "open_cap_total": max(
                        2,
                        min(cap_floor, PROXIMITY_HIGH_VOL_OPEN_ORDER_CAP_TOTAL),
                    ),
                }
            )
        elif atr_value >= VOLATILITY_DERISK_ATR_ELEVATED:
            profile.update(
                {
                    "tier": "elevated",
                    "step_mult": VOLATILITY_DERISK_STEP_MULT_ELEVATED,
                    "size_mult": VOLATILITY_DERISK_SIZE_MULT_ELEVATED,
                    "open_cap_total": max(
                        2,
                        min(cap_floor, PROXIMITY_ELEVATED_VOL_OPEN_ORDER_CAP_TOTAL),
                    ),
                }
            )

        if atr_value >= VOLATILITY_DERISK_BLOCK_NEW_ORDERS_ATR_PCT:
            profile["block_opening_orders"] = True

        if mode in ("scalp_pnl", "scalp_market"):
            profile["open_cap_total"] = cap_floor

        return profile

    def _cap_levels_by_proximity(
        self,
        buy_levels: List[float],
        sell_levels: List[float],
        last_price: float,
        max_total: int,
    ) -> Tuple[List[float], List[float]]:
        if not PROXIMITY_LADDER_ENABLED or max_total <= 0:
            return buy_levels, sell_levels

        remaining_total = max_total
        selected_buy: List[float] = []
        selected_sell: List[float] = []

        ranked_buys = sorted(
            set(buy_levels),
            key=lambda lvl: (abs(lvl - last_price), -lvl),
        )
        ranked_sells = sorted(
            set(sell_levels),
            key=lambda lvl: (abs(lvl - last_price), lvl),
        )

        if remaining_total >= 2 and ranked_buys and ranked_sells:
            selected_buy.append(ranked_buys.pop(0))
            selected_sell.append(ranked_sells.pop(0))
            remaining_total -= 2

        combined: List[Tuple[str, float]] = [
            ("buy", level) for level in ranked_buys
        ] + [("sell", level) for level in ranked_sells]
        combined.sort(
            key=lambda item: (
                abs(item[1] - last_price),
                0 if item[0] == "buy" else 1,
                item[1],
            )
        )

        for side, level in combined[: max(0, remaining_total)]:
            if side == "buy":
                selected_buy.append(level)
            else:
                selected_sell.append(level)

        return sorted(selected_buy, reverse=True), sorted(selected_sell)

    def _trim_opening_orders_to_cap(
        self,
        symbol: str,
        last_price: float,
        existing_orders_with_ids: List[Tuple[float, str, str, bool]],
        max_open_orders: int,
    ) -> set:
        if max_open_orders <= 0:
            return set()

        opening_orders = [
            (price, order_id, side)
            for price, order_id, side, is_reduce_only in existing_orders_with_ids
            if not is_reduce_only and order_id
        ]
        overflow = len(opening_orders) - max_open_orders
        if overflow <= 0:
            return set()

        opening_orders.sort(key=lambda item: abs(item[0] - last_price), reverse=True)
        cancelled_ids = set()
        for price, order_id, side in opening_orders[:overflow]:
            try:
                cancel_result = self.client.cancel_order(symbol=symbol, order_id=order_id)
            except Exception as exc:
                logger.debug("[%s] Proximity trim cancel failed for %s: %s", symbol, order_id, exc)
                continue
            if cancel_result.get("success"):
                cancelled_ids.add(order_id)
                logger.info(
                    "[%s] Proximity ladder: cancelled far %s order at %.6f to keep %d active opening orders",
                    symbol,
                    side,
                    price,
                    max_open_orders,
                )
        return cancelled_ids

    def _snapshot_open_orders(
        self, order_list: List[Dict[str, Any]], tick_size: float
    ) -> Dict[str, Any]:
        existing_order_prices = set()
        existing_order_prices_list = []
        existing_orders_with_ids = []
        current_order_count = 0
        current_opening_order_count = 0
        current_opening_buy_count = 0
        current_opening_sell_count = 0
        existing_reduce_only_buy_qty = 0.0
        existing_reduce_only_sell_qty = 0.0

        for order in order_list or []:
            price = self._safe_float(order.get("price"), 0.0)
            order_id = order.get("orderId")
            order_side = order.get("side", "")
            order_link_id = order.get("orderLinkId", "")
            order_qty = self._safe_float(order.get("leavesQty") or order.get("qty"), 0.0)
            is_reduce_only = self._is_reduce_only_order(order, order_link_id)

            current_order_count += 1
            if not is_reduce_only:
                current_opening_order_count += 1
                if order_side.lower() == "buy":
                    current_opening_buy_count += 1
                elif order_side.lower() == "sell":
                    current_opening_sell_count += 1
            if price <= 0:
                continue

            existing_order_prices_list.append(price)
            rounded_price = self._round_to_step(price, tick_size, round_down=False)
            existing_order_prices.add(rounded_price)

            if not order_id:
                continue

            existing_orders_with_ids.append((price, order_id, order_side, is_reduce_only))
            if is_reduce_only and order_qty > 0:
                if order_side.lower() == "buy":
                    existing_reduce_only_buy_qty += order_qty
                elif order_side.lower() == "sell":
                    existing_reduce_only_sell_qty += order_qty

        return {
            "existing_order_prices": existing_order_prices,
            "existing_order_prices_list": existing_order_prices_list,
            "existing_orders_with_ids": existing_orders_with_ids,
            "current_order_count": current_order_count,
            "current_opening_order_count": current_opening_order_count,
            "current_opening_buy_count": current_opening_buy_count,
            "current_opening_sell_count": current_opening_sell_count,
            "existing_reduce_only_buy_qty": existing_reduce_only_buy_qty,
            "existing_reduce_only_sell_qty": existing_reduce_only_sell_qty,
        }

    def _cancel_bot_reduce_only_orders(
        self,
        bot: Dict[str, Any],
        symbol: str,
        side: str,
    ) -> int:
        bot_id = bot.get("id")
        if not bot_id:
            return 0

        orders_resp = self.client.get_open_orders(
            symbol=symbol,
            limit=200,
            skip_cache=True,
        )
        if not orders_resp.get("success"):
            return 0

        order_list = self._extract_order_list_from_response(orders_resp)
        cancelled = 0
        target_side = str(side or "").strip().lower()

        for order in order_list:
            order_id = order.get("orderId")
            order_side = str(order.get("side") or "").strip().lower()
            order_link_id = order.get("orderLinkId")
            if not order_id or order_side != target_side:
                continue
            if not self._is_reduce_only_order(order, order_link_id):
                continue

            parsed = self._parse_order_link_id(order_link_id)
            if not self._bot_id_matches_order_bot_id(bot_id, parsed.get("bot_id")):
                continue

            try:
                cancel_result = self.client.cancel_order(symbol=symbol, order_id=order_id)
            except Exception as exc:
                logger.warning(
                    "[%s] Quick profit pre-close cancel failed for %s: %s",
                    symbol,
                    order_id,
                    exc,
                )
                continue

            if cancel_result.get("success"):
                cancelled += 1

        return cancelled

    @staticmethod
    def _extract_order_list_from_response(
        orders_resp: Optional[Dict[str, Any]],
    ) -> List[Dict[str, Any]]:
        if not isinstance(orders_resp, dict):
            return []
        data = orders_resp.get("data", {})
        if isinstance(data, dict):
            order_list = data.get("list", [])
        elif isinstance(data, list):
            order_list = data
        else:
            order_list = []
        return list(order_list or [])

    @staticmethod
    def _get_scalp_order_tolerance_pct(recommended_dist: float) -> float:
        safe_dist = max(0.0, float(recommended_dist or 0.0))
        return min(safe_dist * 0.4, 0.005)

    @staticmethod
    def _mark_scalp_fill_event(bot: Dict[str, Any], count: int = 1) -> int:
        increment = max(0, int(count or 0))
        current_seq = int(bot.get("_scalp_fill_seq", 0) or 0)
        if increment <= 0:
            return current_seq
        next_seq = current_seq + increment
        bot["_scalp_fill_seq"] = next_seq
        return next_seq

    def _resolve_locked_scalp_grid_levels(
        self,
        bot: Dict[str, Any],
        symbol: str,
        scalp_center: float,
        market_analysis: Dict[str, Any],
        tick_size: float,
        grid_count: int,
        force_balanced: bool,
        now_iso: str,
    ) -> Tuple[List[float], List[float]]:
        scalp_state = bot.get("_scalp_grid_state") or {}
        cached_center = self._safe_float(scalp_state.get("locked_center"), 0.0)
        cached_buy = [
            self._safe_float(level, 0.0)
            for level in (scalp_state.get("buy_levels") or [])
            if self._safe_float(level, 0.0) > 0
        ]
        cached_sell = [
            self._safe_float(level, 0.0)
            for level in (scalp_state.get("sell_levels") or [])
            if self._safe_float(level, 0.0) > 0
        ]
        last_fill_seq = int(scalp_state.get("last_fill_seq", 0) or 0)
        current_fill_seq = int(bot.get("_scalp_fill_seq", 0) or 0)

        center_moved = cached_center <= 0 or abs(cached_center - scalp_center) > tick_size
        fill_occurred = current_fill_seq != last_fill_seq
        no_cache = not cached_buy or not cached_sell

        if center_moved or fill_occurred or no_cache:
            buy_levels, sell_levels = self.scalp_pnl_service.get_scalp_grid_levels(
                last_price=scalp_center,
                market_analysis=market_analysis,
                tick_size=tick_size,
                grid_count=grid_count,
                force_balanced=force_balanced,
            )
            bot["_scalp_grid_state"] = {
                "locked_center": scalp_center,
                "buy_levels": list(buy_levels),
                "sell_levels": list(sell_levels),
                "last_fill_seq": current_fill_seq,
                "locked_at": now_iso,
            }
            reason = (
                "center_moved" if center_moved else "fill" if fill_occurred else "no_cache"
            )
            logger.debug(
                "[%s] Scalp grid regenerated: center=%.6f, buys=%d, sells=%d, reason=%s",
                symbol,
                scalp_center,
                len(buy_levels),
                len(sell_levels),
                reason,
            )
            return buy_levels, sell_levels

        logger.debug(
            "[%s] Scalp grid reused from cache: buys=%d, sells=%d",
            symbol,
            len(cached_buy),
            len(cached_sell),
        )
        return list(cached_buy), list(cached_sell)

    def _cleanup_stale_scalp_orders(
        self,
        symbol: str,
        scalp_center: float,
        recommended_dist: float,
        tick_size: float,
        max_open_orders: int,
        current_order_list: Optional[List[Dict[str, Any]]] = None,
    ) -> Dict[str, Any]:
        order_list = list(current_order_list or [])
        orders_cancelled = 0
        cancelled_order_ids = set()
        stale_threshold_mult = 25.0
        scalp_stale_pct = max(0.0, recommended_dist) * stale_threshold_mult

        if scalp_center > 0:
            orders_resp = self.client.get_open_orders(symbol, skip_cache=True)
            if orders_resp.get("success"):
                order_list = self._extract_order_list_from_response(orders_resp)

            for order in order_list:
                order_price = self._safe_float(order.get("price"), 0.0)
                order_id = order.get("orderId")
                if order_price <= 0 or not order_id or scalp_stale_pct <= 0:
                    continue

                distance_pct = abs(order_price - scalp_center) / scalp_center
                if distance_pct <= scalp_stale_pct:
                    continue

                try:
                    cancel_result = self.client.cancel_order(symbol=symbol, order_id=order_id)
                except Exception as exc:
                    logger.debug(
                        "[%s] Scalp stale cancel failed for %s: %s",
                        symbol,
                        order_id,
                        exc,
                    )
                    continue

                if cancel_result.get("success"):
                    orders_cancelled += 1
                    cancelled_order_ids.add(order_id)
                    logger.info(
                        f"[{symbol}] Scalp: Cancelled stale order at {order_price} "
                        f"({distance_pct * 100:.2f}% from center, limit={scalp_stale_pct * 100:.2f}%)"
                    )
                if orders_cancelled >= 3:
                    break

            if orders_cancelled > 0:
                time.sleep(0.3)
                refreshed_orders_resp = self.client.get_open_orders(
                    symbol,
                    skip_cache=True,
                )
                if refreshed_orders_resp.get("success"):
                    order_list = self._extract_order_list_from_response(
                        refreshed_orders_resp
                    )
                elif cancelled_order_ids:
                    order_list = [
                        order
                        for order in order_list
                        if order.get("orderId") not in cancelled_order_ids
                    ]

        order_snapshot = self._snapshot_open_orders(order_list, tick_size)
        current_order_count = order_snapshot["current_order_count"]
        return {
            "orders_cancelled": orders_cancelled,
            "order_list": order_list,
            "order_snapshot": order_snapshot,
            "available_slots": max(0, max_open_orders - current_order_count),
        }

    def _cancel_duplicate_bot_orders(
        self,
        bot: Dict[str, Any],
        symbol: str,
        order_list: Optional[List[Dict[str, Any]]] = None,
        include_reduce_only: bool = False,
    ) -> Dict[str, Any]:
        bot_id = str(bot.get("id") or "").replace("-", "").strip()
        if not bot_id:
            return {"cancelled_count": 0, "order_list": list(order_list or [])}

        if order_list is None:
            orders_resp = self.client.get_open_orders(
                symbol=symbol,
                limit=200,
                skip_cache=True,
            )
            if not orders_resp.get("success"):
                return {"cancelled_count": 0, "order_list": []}
            order_list = self._extract_order_list_from_response(orders_resp)

        bot_id_16 = bot_id[:16]
        grouped_orders: Dict[Tuple[str, bool, str], List[Dict[str, Any]]] = {}

        for order in list(order_list or []):
            order_link_id = str(order.get("orderLinkId") or "").strip()
            parsed = self._parse_order_link_id(order_link_id)
            if not self._bot_id_matches_order_bot_id(
                bot.get("id"), parsed.get("bot_id")
            ):
                continue
            reduce_only = self._is_reduce_only_order(order, order_link_id)
            if reduce_only and not include_reduce_only:
                continue
            side = str(order.get("side") or "").strip().lower()
            price_key = str(order.get("price") or "").strip()
            if not side or not price_key:
                continue
            group_key = (side, reduce_only, price_key)
            grouped_orders.setdefault(group_key, []).append(order)

        duplicate_orders: List[Dict[str, Any]] = []
        for orders in grouped_orders.values():
            if len(orders) <= 1:
                continue
            sorted_orders = sorted(
                orders,
                key=lambda item: (
                    int(item.get("createdTime") or 0),
                    str(item.get("orderId") or ""),
                ),
            )
            duplicate_orders.extend(sorted_orders[1:])

        cancelled_count = 0
        for order in duplicate_orders:
            order_id = order.get("orderId")
            order_link_id = order.get("orderLinkId")
            if not order_id:
                continue
            try:
                cancel_result = self.client.cancel_order(
                    symbol=symbol,
                    order_id=order_id,
                    order_link_id=order_link_id,
                )
            except Exception as exc:
                logger.warning(
                    "[%s] Failed to cancel duplicate bot order %s: %s",
                    symbol,
                    order_link_id or order_id,
                    exc,
                )
                continue
            if cancel_result.get("success"):
                cancelled_count += 1

        if cancelled_count <= 0:
            return {"cancelled_count": 0, "order_list": list(order_list or [])}

        logger.warning(
            "[%s] Cancelled %d duplicate opening order(s) for bot %s",
            symbol,
            cancelled_count,
            bot_id_16,
        )
        time.sleep(0.3)
        refreshed_orders_resp = self.client.get_open_orders(
            symbol=symbol,
            limit=200,
            skip_cache=True,
        )
        refreshed_order_list = self._extract_order_list_from_response(
            refreshed_orders_resp
        )
        return {
            "cancelled_count": cancelled_count,
            "order_list": refreshed_order_list,
        }

    def _register_failure_breaker_event(
        self,
        bot: Dict[str, Any],
        reason: str,
        now_ts: Optional[float] = None,
    ) -> bool:
        if not FAILURE_BREAKER_ENABLED:
            return False

        reason_key = str(reason or "unknown").strip().lower()
        now_ts = now_ts if now_ts is not None else time.time()
        if reason_key in {"qty_below_min", "notional_below_min"}:
            self._mark_structural_opening_fit_mismatch(
                bot,
                reason=reason_key,
                now_ts=now_ts,
            )
            return False
        state = bot.get("_failure_breaker")
        if not isinstance(state, dict):
            state = {}
            bot["_failure_breaker"] = state

        window_start = self._safe_float(state.get("window_start_ts"), 0.0)
        if window_start <= 0 or now_ts - window_start > FAILURE_BREAKER_WINDOW_SEC:
            state["window_start_ts"] = now_ts
            state["counts"] = {}

        counts = state.setdefault("counts", {})
        counts[reason_key] = int(counts.get(reason_key, 0) or 0) + 1
        state["last_reason"] = reason_key
        state["last_event_ts"] = now_ts

        margin_count = sum(
            int(counts.get(key, 0) or 0)
            for key in (
                "insufficient_margin",
                "insufficient_margin_pruned",
                "insufficient_margin_guard",
            )
        )
        notional_count = int(counts.get("notional_below_min", 0) or 0)
        one_sided_count = int(counts.get("one_sided_grid_prevented", 0) or 0)

        triggered = (
            margin_count >= FAILURE_BREAKER_MARGIN_LIMIT
            or notional_count >= FAILURE_BREAKER_NOTIONAL_LIMIT
            or one_sided_count >= FAILURE_BREAKER_ONE_SIDED_LIMIT
        )
        if triggered:
            cooldown_until_ts = now_ts + FAILURE_BREAKER_WINDOW_SEC
            state["cooldown_until_ts"] = cooldown_until_ts
            bot["last_warning"] = (
                f"Failure breaker active: {reason_key} until "
                f"{datetime.fromtimestamp(cooldown_until_ts, tz=timezone.utc).isoformat()}"
            )
            logger.warning(
                "[%s] Failure breaker armed: reason=%s counts=%s cooldown=%ss",
                bot.get("symbol"),
                reason_key,
                counts,
                FAILURE_BREAKER_WINDOW_SEC,
            )
            self._record_failure_breaker_armed_event(
                bot,
                reason=reason_key,
                counts=counts,
                cooldown_sec=FAILURE_BREAKER_WINDOW_SEC,
                cooldown_until_ts=cooldown_until_ts,
                now_ts=now_ts,
            )
        return triggered

    def _failure_breaker_skip_opening_orders(
        self,
        bot: Dict[str, Any],
        now_ts: Optional[float] = None,
    ) -> Tuple[bool, Optional[str]]:
        if not FAILURE_BREAKER_ENABLED:
            return False, None
        state = bot.get("_failure_breaker")
        if not isinstance(state, dict):
            return False, None
        now_ts = now_ts if now_ts is not None else time.time()
        cooldown_until_ts = self._safe_float(state.get("cooldown_until_ts"), 0.0)
        if cooldown_until_ts > now_ts:
            remaining = max(0, int(cooldown_until_ts - now_ts))
            reason = state.get("last_reason") or "recent failures"
            return True, f"Failure breaker cooldown ({reason}, {remaining}s remaining)"
        return False, None

    def _clear_failure_breaker(self, bot: Dict[str, Any], clear_cooldown: bool = False) -> None:
        if not FAILURE_BREAKER_ENABLED:
            return
        state = bot.get("_failure_breaker")
        if not isinstance(state, dict):
            return
        cooldown_until_ts = self._safe_float(state.get("cooldown_until_ts"), 0.0)
        if cooldown_until_ts > time.time() and not clear_cooldown:
            return
        self._record_failure_breaker_transition_event(
            bot,
            event_type="failure_breaker_cooldown_cleared",
            reason=state.get("last_reason"),
            remaining_sec=0,
        )
        bot.pop("_failure_breaker", None)

    def _clear_capital_starved_opening_block(
        self,
        bot: Optional[Dict[str, Any]],
    ) -> None:
        if not isinstance(bot, dict):
            return
        was_active = bool(bot.get("_capital_starved_block_opening_orders"))
        symbol = str(bot.get("symbol") or "").strip().upper()
        mode = bot.get("mode")
        warning = str(bot.get("_capital_starved_warning_text") or "").strip()
        if warning and str(bot.get("last_warning") or "").strip() == warning:
            bot["last_warning"] = None
        bot.pop("_capital_starved_block_opening_orders", None)
        bot.pop("_capital_starved_warning_text", None)
        bot.pop("_capital_starved_opening_signature", None)
        bot.pop("capital_starved_reason", None)
        bot.pop("capital_starved_order_notional_usdt", None)
        bot.pop("capital_starved_required_margin_usdt", None)
        bot.pop("capital_starved_available_opening_margin_usdt", None)
        bot.pop("_structural_opening_fit", None)
        summary = bot.get("watchdog_bottleneck_summary")
        if isinstance(summary, dict):
            summary["capital_starved_active"] = False
            summary["updated_at"] = datetime.now(timezone.utc).isoformat()
        if was_active and symbol:
            self._record_capital_starved_transition_event(
                bot,
                event_type="capital_starved_block_cleared",
                symbol=symbol,
                mode=mode,
            )

    def _activate_capital_starved_opening_block(
        self,
        bot: Optional[Dict[str, Any]],
        *,
        symbol: str,
        reason: str,
        side: str,
        action: str,
        opening_kind: Optional[str],
        attempted_qty: Optional[float],
        price: Optional[float],
        min_qty: Optional[float],
        min_notional_value: Optional[float],
        leverage: Optional[float],
        available_balance: Optional[float] = None,
        reserve_usd: Optional[float] = None,
        opening_order_cap: Optional[int] = None,
        current_order_count: Optional[int] = None,
        opening_order_count: Optional[int] = None,
        opening_sizing: Optional[Dict[str, Any]] = None,
    ) -> str:
        if not isinstance(bot, dict):
            return str(reason or "capital_starved")

        leverage_value = max(1.0, self._safe_float(leverage, 0.0))
        qty_value = max(0.0, self._safe_float(attempted_qty, 0.0))
        price_value = max(0.0, self._safe_float(price, 0.0))
        min_qty_value = max(0.0, self._safe_float(min_qty, 0.0))
        min_notional = max(0.0, self._safe_float(min_notional_value, 0.0))
        order_notional = qty_value * price_value if price_value > 0 else 0.0
        available_opening_margin = None
        if available_balance is not None:
            available_opening_margin = max(
                0.0,
                self._safe_float(available_balance, 0.0)
                - max(0.0, self._safe_float(reserve_usd, 0.0)),
            )
        required_margin = (
            order_notional / leverage_value if order_notional > 0 and leverage_value > 0 else None
        )

        mapped_reason = str(reason or "capital_starved").strip().lower() or "capital_starved"
        if mapped_reason == "insufficient_margin_guard":
            mapped_reason = "insufficient_margin"

        if mapped_reason == "qty_below_min":
            warning = (
                f"Capital starved: qty {qty_value:.6f} below min {min_qty_value:.6f}"
            )
        elif mapped_reason == "notional_below_min":
            warning = (
                f"Capital starved: order ${order_notional:.2f} below min ${min_notional:.2f}"
            )
        elif mapped_reason == "opening_margin_reserve":
            available_text = (
                f"${available_opening_margin:.2f}"
                if available_opening_margin is not None
                else "unknown"
            )
            required_text = (
                f"${required_margin:.2f}" if required_margin is not None else "unknown"
            )
            warning = (
                f"Reserve limited: need {required_text} opening margin, usable after reserve {available_text}"
            )
        else:
            available_text = (
                f"${available_opening_margin:.2f}"
                if available_opening_margin is not None
                else "unknown"
            )
            required_text = (
                f"${required_margin:.2f}" if required_margin is not None else "unknown"
            )
            warning = (
                f"Capital starved: need {required_text} opening margin, have {available_text}"
            )

        signature = ":".join(
            [
                mapped_reason,
                str(side or "").lower(),
                str(action or ""),
                str(opening_kind or ""),
                f"{qty_value:.8f}",
                f"{price_value:.8f}",
                f"{min_qty_value:.8f}",
                f"{min_notional:.8f}",
                f"{self._safe_float(available_opening_margin, 0.0):.8f}",
                f"{self._safe_float(required_margin, 0.0):.8f}",
                str(int(opening_order_cap or 0)),
            ]
        )

        bot["_capital_starved_block_opening_orders"] = True
        bot["_capital_starved_warning_text"] = warning
        bot["last_skip_reason"] = mapped_reason
        bot["last_warning"] = warning
        bot["last_error"] = None
        bot["capital_starved_reason"] = mapped_reason
        bot["capital_starved_order_notional_usdt"] = (
            round(order_notional, 4) if order_notional > 0 else None
        )
        bot["capital_starved_required_margin_usdt"] = (
            round(required_margin, 4) if required_margin is not None else None
        )
        bot["capital_starved_available_opening_margin_usdt"] = (
            round(available_opening_margin, 4)
            if available_opening_margin is not None
            else None
        )

        previous_signature = str(bot.get("_capital_starved_opening_signature") or "")
        if signature == previous_signature:
            summary = bot.get("watchdog_bottleneck_summary")
            if isinstance(summary, dict):
                summary["capital_starved_active"] = True
                summary["updated_at"] = datetime.now(timezone.utc).isoformat()
            return warning

        bot["_capital_starved_opening_signature"] = signature
        capital = self._get_watchdog_capital_context(bot, leverage=leverage_value)
        self._touch_watchdog_summary(
            bot,
            "capital_starved_opening_block_count",
            capital_starved_active=True,
            last_capital_starved_reason=mapped_reason,
            last_effective_investment_usdt=capital.get("effective_investment"),
            last_runtime_open_order_cap_total=capital.get("runtime_open_order_cap_total"),
            last_runtime_grid_count_cap=capital.get("runtime_grid_count_cap"),
        )

        logger.warning(
            "[%s] Capital viability blocked opening orders: reason=%s action=%s kind=%s qty=%.8f "
            "notional=%.4f min_qty=%.8f min_notional=%.4f avail_open_margin=%s required_margin=%s",
            symbol,
            mapped_reason,
            action,
            opening_kind,
            qty_value,
            order_notional,
            min_qty_value,
            min_notional,
            f"{available_opening_margin:.4f}" if available_opening_margin is not None else "n/a",
            f"{required_margin:.4f}" if required_margin is not None else "n/a",
        )

        if mapped_reason in {"qty_below_min", "notional_below_min"}:
            self._mark_structural_opening_fit_mismatch(
                bot,
                reason=mapped_reason,
                now_ts=time.time(),
            )
        if mapped_reason == "qty_below_min":
            self._record_qty_below_min_event(
                bot,
                symbol=symbol,
                side=side,
                raw_qty=qty_value,
                normalized_qty=qty_value,
                min_qty=min_qty_value,
                qty_step=None,
                price=price_value,
                min_notional_value=min_notional,
                reason="qty_below_min",
                diagnostic_context={
                    "action": action,
                    "opening_kind": opening_kind,
                    "opening_sizing": self._augment_directional_opening_sizing_fields(
                        opening_sizing,
                        final_blocker_reason="qty_below_min",
                    ),
                },
            )
        elif mapped_reason == "insufficient_margin":
            self._record_insufficient_margin_event(
                bot,
                symbol=symbol,
                side=side,
                action=action,
                attempted_qty=qty_value,
                price=price_value,
                available_balance=available_balance,
                reserve_usd=reserve_usd,
                margin_per_order=required_margin,
                current_order_count=current_order_count,
                opening_order_count=opening_order_count,
                opening_order_cap=opening_order_cap,
            )

        self._record_capital_starved_transition_event(
            bot,
            event_type="capital_starved_opening_block",
            symbol=symbol,
            mode=bot.get("mode"),
            reason=mapped_reason,
            side=side,
            action=action,
            opening_kind=opening_kind,
            available_opening_margin=available_opening_margin,
            required_margin=required_margin,
            opening_order_cap=opening_order_cap,
            opening_sizing=self._augment_directional_opening_sizing_fields(
                opening_sizing,
                final_blocker_reason=mapped_reason,
            ),
        )

        return warning

    def _get_scalp_effective_opening_order_cap(
        self, bot: Dict[str, Any], requested_cap: int
    ) -> int:
        requested_cap = max(1, int(requested_cap or 1))
        learned_cap = int(self._safe_float(bot.get("scalp_learned_opening_order_cap"), 0))
        if learned_cap <= 0:
            return requested_cap
        return max(1, min(requested_cap, learned_cap))

    def _learn_scalp_opening_order_cap(
        self,
        bot: Dict[str, Any],
        opening_order_count: int,
        requested_cap: int,
        now_iso: str,
        reason: str = "insufficient_margin",
    ) -> int:
        requested_cap = max(1, int(requested_cap or 1))
        learned_cap = max(1, min(requested_cap, int(opening_order_count or 0)))
        previous_cap = int(
            self._safe_float(bot.get("scalp_learned_opening_order_cap"), 0)
        )
        if previous_cap > 0:
            learned_cap = min(previous_cap, learned_cap)
        bot["scalp_learned_opening_order_cap"] = learned_cap
        bot["scalp_learned_opening_order_cap_at"] = now_iso
        bot["scalp_learned_opening_cap_reason"] = str(reason or "insufficient_margin")
        return learned_cap

    def _maybe_relax_scalp_opening_order_cap(
        self,
        bot: Dict[str, Any],
        current_opening_order_count: int,
        requested_cap: int,
        available_balance: float,
        reserve_usd: float,
        margin_per_order: float,
        now_iso: str,
    ) -> int:
        learned_cap = int(
            self._safe_float(bot.get("scalp_learned_opening_order_cap"), 0)
        )
        requested_cap = max(1, int(requested_cap or 1))
        if learned_cap <= 0:
            return requested_cap
        if learned_cap >= requested_cap:
            bot.pop("scalp_learned_opening_order_cap", None)
            bot.pop("scalp_learned_opening_order_cap_at", None)
            bot.pop("scalp_learned_opening_cap_reason", None)
            return requested_cap

        free_headroom = max(0.0, self._safe_float(available_balance, 0.0) - max(0.0, self._safe_float(reserve_usd, 0.0)))
        margin_per_order = max(0.0, self._safe_float(margin_per_order, 0.0))
        if margin_per_order <= 0:
            return learned_cap

        # Only relax when the bot is already pressing against the learned cap and
        # there is enough free margin for at least one more opening order.
        if current_opening_order_count < learned_cap:
            return learned_cap
        if free_headroom < (margin_per_order * 1.1):
            return learned_cap

        relaxed_cap = min(requested_cap, learned_cap + 1)
        if relaxed_cap != learned_cap:
            bot["scalp_learned_opening_order_cap"] = relaxed_cap
            bot["scalp_learned_opening_order_cap_at"] = now_iso
            bot["scalp_learned_opening_cap_reason"] = "margin_recovered"
        return relaxed_cap

    def _maybe_trigger_symbol_daily_kill_switch(
        self,
        bot: Dict[str, Any],
        symbol: str,
        now_iso: str,
        investment: float,
    ) -> Optional[Dict[str, Any]]:
        if not SYMBOL_DAILY_KILL_SWITCH_ENABLED or not self.risk_manager:
            return None

        effective_investment = self._get_effective_investment(bot, investment)
        loss_limit_usdt = effective_investment * SYMBOL_DAILY_KILL_SWITCH_LOSS_PCT_OF_INVESTMENT
        loss_limit_usdt = max(
            SYMBOL_DAILY_KILL_SWITCH_MIN_USDT,
            min(SYMBOL_DAILY_KILL_SWITCH_MAX_USDT, loss_limit_usdt),
        )
        status = self.risk_manager.check_symbol_daily_loss(symbol, loss_limit_usdt)
        if not status.get("triggered"):
            return None

        realized_loss = self._safe_float(status.get("realized_pnl"), 0.0)
        logger.warning(
            "[%s] Symbol daily kill-switch triggered: realized_pnl=%.2f limit=%.2f",
            symbol,
            realized_loss,
            loss_limit_usdt,
        )

        final_last_error = (
            f"Symbol daily loss stop triggered: ${realized_loss:.2f} <= -${loss_limit_usdt:.2f}"
        )
        cleanup_errors: List[str] = []
        if SYMBOL_DAILY_KILL_SWITCH_CLOSE_POSITION:
            try:
                close_success = self._close_position_market(symbol, bot=bot)
                if not close_success:
                    close_error = str(
                        (self._last_close_position_result or {}).get("error") or ""
                    ).strip()
                    if close_error:
                        cleanup_errors.append(close_error)
            except Exception as exc:
                logger.error("[%s] Symbol daily kill-switch close failed: %s", symbol, exc)
                cleanup_errors.append(str(exc))
        if SYMBOL_DAILY_KILL_SWITCH_CANCEL_ORDERS:
            try:
                cancel_result = self._force_cancel_all_orders(
                    symbol,
                    max_retries=3,
                    bot=bot,
                )
                if cancel_result.get("success") is not True:
                    cancel_error = str(
                        cancel_result.get("error")
                        or cancel_result.get("status")
                        or ""
                    ).strip()
                    if cancel_error:
                        cleanup_errors.append(cancel_error)
            except Exception as exc:
                logger.error("[%s] Symbol daily kill-switch cancel failed: %s", symbol, exc)
                cleanup_errors.append(str(exc))

        bot["symbol_daily_loss_limit_usdt"] = round(loss_limit_usdt, 4)
        bot["symbol_daily_loss_triggered_at"] = now_iso
        cleanup_state = self._confirm_symbol_cleanup_state(symbol)
        cleanup_error = "; ".join(
            part
            for part in [
                *cleanup_errors,
                str(cleanup_state.get("error") or "").strip(),
            ]
            if part
        )
        if cleanup_state.get("cleanup_confirmed"):
            bot["stop_cleanup_final_last_error"] = final_last_error
            return self._finalize_stop_cleanup_state(
                bot,
                target_status="stopped",
                now_iso=now_iso,
            )

        pending_message = final_last_error
        if cleanup_error:
            pending_message = f"{pending_message} (cleanup pending: {cleanup_error})"
        else:
            pending_message = (
                f"{pending_message} (cleanup pending: waiting for flat/orders clear)"
            )
        return self._mark_stop_cleanup_pending_state(
            bot,
            target_status="stopped",
            cleanup_reason="symbol_daily_kill_switch",
            pending_message=pending_message,
            final_last_error=final_last_error,
            now_iso=now_iso,
        )

    def _get_usdt_wallet_balance(self) -> float:
        """Get fresh account equity in USDT for balance-target checks."""
        try:
            resp = self.client.get_wallet_balance(skip_cache=True)
            if not resp.get("success"):
                return 0.0

            data = resp.get("data", {}) or {}
            accounts = data.get("list", []) or []
            for account in accounts:
                coins = account.get("coin", []) or []
                account_equity = float(account.get("totalEquity", 0) or 0)
                for coin in coins:
                    if (coin.get("coin") or "").upper() != "USDT":
                        continue
                    try:
                        # Use account equity for balance-target logic, not
                        # wallet balance or available balance.
                        return float(coin.get("equity", 0) or 0)
                    except (TypeError, ValueError):
                        break
                if account_equity > 0:
                    return account_equity
        except Exception:
            return 0.0
        return 0.0




    def _close_position_or_hard_fail(
        self, bot: Dict[str, Any], symbol: str, context: str
    ) -> Dict[str, Any]:
        """
        Close position via reduce-only market order and hard-fail bot on any error.
        """
        try:
            close_success = self._close_position_market(symbol, bot=bot)
        except Exception as e:
            self._hard_fail_close(bot, symbol, context, e)
            return {"success": False, "error": str(e)}

        close_result = dict(self._last_close_position_result or {})
        if self._is_ambiguous_order_result(close_result):
            logger.warning(
                "CLOSE_OUTCOME_AMBIGUOUS symbol=%s context=%s status=%s retry_safe=%s",
                symbol,
                context,
                close_result.get("status"),
                close_result.get("retry_safe"),
            )
            return close_result

        if not close_success:
            self._hard_fail_close(bot, symbol, context, "close_position_market_failed")
            return {"success": False, "error": "close_position_market_failed"}
        self._record_exit_reason(
            bot,
            symbol=symbol,
            mode=(bot or {}).get("mode"),
            reason=context,
            severity="WARN"
            if str(context or "").lower()
            in {"risk_stop", "max_loss", "out_of_range", "emergency", "emergency_partial_close"}
            else "INFO",
        )
        return {"success": True, "retCode": 0}

    def _hard_fail_close(
        self, bot: Dict[str, Any], symbol: str, close_reason: str, response: Any
    ) -> None:
        bot["_block_opening_orders"] = True
        bot["status"] = "error"
        bot["last_error"] = f"CLOSE_FAILED {close_reason}: {response}"
        self.bot_storage.save_bot(bot)

        logger.error(
            "[%s] CLOSE_FAILED bot_id=%s close_reason=%s response=%s",
            symbol,
            bot.get("id"),
            close_reason,
            response,
        )

    @staticmethod
    def _clear_stop_cleanup_pending_fields(bot: Dict[str, Any]) -> None:
        for key in (
            "stop_cleanup_pending",
            "stop_cleanup_target_status",
            "stop_cleanup_scope",
            "stop_cleanup_reason",
            "stop_cleanup_requested_at",
            "stop_cleanup_final_last_error",
        ):
            bot.pop(key, None)

    # H7: Dust position threshold — positions with notional value below this
    # are treated as flat during cleanup confirmation to prevent indefinite
    # stop_cleanup_pending states from partial fills.
    CLEANUP_DUST_NOTIONAL_USDT = 0.50

    def _confirm_symbol_cleanup_state(self, symbol: str) -> Dict[str, Any]:
        if not self._is_tradeable_symbol(symbol):
            return {
                "success": True,
                "flat": True,
                "orders_cleared": True,
                "cleanup_confirmed": True,
                "message": "skipped_non_tradeable_symbol",
            }

        errors: List[str] = []
        flat = True
        orders_cleared = True

        try:
            try:
                positions_resp = self.client.get_positions(skip_cache=True)
            except TypeError:
                positions_resp = self.client.get_positions()
            if not positions_resp.get("success"):
                errors.append(
                    str(positions_resp.get("error") or "positions_fetch_failed")
                )
                flat = False
            else:
                positions = positions_resp.get("data", {}).get("list", []) or []
                for pos in positions:
                    if pos.get("symbol") != symbol:
                        continue
                    size = self._safe_float(pos.get("size"), 0.0)
                    if size <= 0:
                        continue
                    # H7: Treat dust positions (below notional threshold) as flat
                    # so cleanup doesn't get stuck on un-closable fractional fills.
                    avg_price = self._safe_float(pos.get("avgPrice"), 0.0)
                    mark_price = self._safe_float(pos.get("markPrice"), avg_price)
                    notional = size * (mark_price if mark_price > 0 else avg_price)
                    if notional > self.CLEANUP_DUST_NOTIONAL_USDT:
                        flat = False
                        break
                    logger.info(
                        "[%s] Cleanup treating dust position as flat (size=%s notional=$%.4f)",
                        symbol,
                        size,
                        notional,
                    )
        except Exception as exc:
            errors.append(str(exc))
            flat = False

        try:
            try:
                orders_resp = self.client.get_open_orders(
                    symbol=symbol,
                    limit=200,
                    skip_cache=True,
                )
            except TypeError:
                orders_resp = self.client.get_open_orders(symbol=symbol)
            if not orders_resp.get("success"):
                errors.append(str(orders_resp.get("error") or "orders_fetch_failed"))
                orders_cleared = False
            else:
                data = orders_resp.get("data", {}) or {}
                if isinstance(data, dict):
                    orders = data.get("list", []) or []
                else:
                    orders = data or []
                orders_cleared = len(orders) == 0
        except Exception as exc:
            errors.append(str(exc))
            orders_cleared = False

        return {
            "success": not errors,
            "flat": flat,
            "orders_cleared": orders_cleared,
            "cleanup_confirmed": flat and orders_cleared,
            "error": "; ".join(errors) if errors else None,
        }

    def _mark_stop_cleanup_pending_state(
        self,
        bot: Dict[str, Any],
        *,
        target_status: str,
        cleanup_reason: str,
        pending_message: str,
        final_last_error: Optional[str],
        now_iso: str,
    ) -> Dict[str, Any]:
        self._clear_pause_runtime_state(bot)
        self._clear_stop_cleanup_pending_fields(bot)
        bot["status"] = "stop_cleanup_pending"
        bot["started_at"] = None
        bot["last_run_at"] = now_iso
        bot["reduce_only_mode"] = True
        bot["auto_stop_paused"] = True
        bot["pause_reason"] = "Stop cleanup pending"
        bot["pause_reason_type"] = "stop_cleanup_pending"
        bot["_block_opening_orders"] = True
        bot["stop_cleanup_pending"] = True
        bot["stop_cleanup_target_status"] = (
            str(target_status or "stopped").strip().lower() or "stopped"
        )
        bot["stop_cleanup_scope"] = cleanup_reason
        bot["stop_cleanup_reason"] = cleanup_reason
        bot["stop_cleanup_requested_at"] = now_iso
        bot["stop_cleanup_final_last_error"] = final_last_error
        bot["last_error"] = pending_message
        return self.bot_storage.save_bot(bot)

    def _finalize_stop_cleanup_state(
        self,
        bot: Dict[str, Any],
        *,
        target_status: str,
        now_iso: str,
    ) -> Dict[str, Any]:
        final_last_error = bot.get("stop_cleanup_final_last_error")
        self._clear_pause_runtime_state(bot)
        self._clear_stop_cleanup_pending_fields(bot)
        bot["status"] = str(target_status or "stopped").strip().lower() or "stopped"
        bot["started_at"] = None
        bot["last_run_at"] = now_iso
        bot["reduce_only_mode"] = False
        bot["auto_stop_paused"] = False
        bot["entry_orders_open"] = 0
        bot["exit_orders_open"] = 0
        bot["open_order_count"] = 0
        bot["active_long_slots"] = 0
        bot["active_short_slots"] = 0
        bot["last_error"] = final_last_error
        return self.bot_storage.save_bot(bot)

    def _apply_nlp_max_loss_stop_state(
        self,
        bot: Dict[str, Any],
        *,
        action: str,
        last_price: float,
        now_iso: str,
    ) -> Dict[str, Any]:
        confirmed_last_error = (
            str(bot.get("last_error") or "").strip()
            or f"NLP Max Loss Stop triggered at {last_price}"
        )
        if action == "max_loss_stop":
            bot["stop_cleanup_final_last_error"] = confirmed_last_error
            return self._finalize_stop_cleanup_state(
                bot,
                target_status="risk_stopped",
                now_iso=now_iso,
            )
        pending_message = (
            str(bot.get("last_error") or "").strip()
            or f"NLP Max Loss Stop cleanup pending at {last_price}"
        )
        return self._mark_stop_cleanup_pending_state(
            bot,
            target_status="risk_stopped",
            cleanup_reason="nlp_max_loss_stop",
            pending_message=pending_message,
            final_last_error=f"NLP Max Loss Stop triggered at {last_price}",
            now_iso=now_iso,
        )

    def _transition_to_stop_cleanup_state(
        self,
        bot: Dict[str, Any],
        symbol: str,
        *,
        target_status: str,
        cleanup_reason: str,
        final_last_error: str,
        now_iso: Optional[str] = None,
    ) -> Dict[str, Any]:
        current_iso = now_iso or datetime.now(timezone.utc).isoformat()
        try:
            self._close_bot_symbol(
                bot,
                hard_fail=False,
                fail_reason=cleanup_reason,
            )
        except Exception as exc:
            logger.error(
                "[%s] Protective stop cleanup failed during %s: %s",
                symbol,
                cleanup_reason,
                exc,
            )

        cleanup_state = self._confirm_symbol_cleanup_state(symbol)
        if cleanup_state.get("cleanup_confirmed"):
            bot["stop_cleanup_final_last_error"] = final_last_error
            return self._finalize_stop_cleanup_state(
                bot,
                target_status=target_status,
                now_iso=current_iso,
            )

        pending_detail = final_last_error
        cleanup_error = str(cleanup_state.get("error") or "").strip()
        if cleanup_error:
            pending_detail = f"{pending_detail} (cleanup pending: {cleanup_error})"
        else:
            pending_detail = (
                f"{pending_detail} (cleanup pending: waiting for flat/orders clear)"
            )
        return self._mark_stop_cleanup_pending_state(
            bot,
            target_status=target_status,
            cleanup_reason=cleanup_reason,
            pending_message=pending_detail,
            final_last_error=final_last_error,
            now_iso=current_iso,
        )

    def _monitor_stop_cleanup_pending(self, bot: Dict[str, Any]) -> Dict[str, Any]:
        symbol = str(bot.get("symbol") or "").strip().upper()
        target_status = str(bot.get("stop_cleanup_target_status") or "stopped").strip().lower() or "stopped"
        if not symbol:
            return self._finalize_stop_cleanup_state(
                bot,
                target_status=target_status,
                now_iso=datetime.now(timezone.utc).isoformat(),
            )

        cleanup_state = self._confirm_symbol_cleanup_state(symbol)
        if not cleanup_state.get("cleanup_confirmed"):
            return bot

        logger.warning(
            "[%s] Stop cleanup confirmed; finalizing bot %s as %s",
            symbol,
            bot.get("id"),
            target_status,
        )
        return self._finalize_stop_cleanup_state(
            bot,
            target_status=target_status,
            now_iso=datetime.now(timezone.utc).isoformat(),
        )

    @staticmethod
    def _is_position_empty_close_result(result: Optional[Dict[str, Any]]) -> bool:
        return bool(result and result.get("position_empty"))

    def _hard_fail_bot(self, bot: Dict[str, Any], symbol: str, reason: str) -> None:
        logger.error("[%s] HARD FAIL: %s", symbol, reason)
        bot["status"] = "error"
        bot["error_code"] = (
            "CLOSE_FAILED"
            if str(reason).startswith("CLOSE_FAILED")
            else bot.get("error_code")
        )
        bot["last_error"] = reason
        self.bot_storage.save_bot(bot)
        raise RuntimeError(reason)

    def _log_skip_order(
        self,
        bot: Optional[Dict[str, Any]],
        symbol: str,
        side: str,
        raw_qty: Optional[float],
        normalized_qty: Optional[float],
        min_qty: Optional[float],
        qty_step: Optional[float],
        price: Optional[float],
        min_notional_value: Optional[float] = None,
        reason: Optional[str] = None,
        diagnostic_context: Optional[Dict[str, Any]] = None,
    ) -> None:
        notional_qty = normalized_qty if normalized_qty else (raw_qty or 0)
        notional = (price or 0) * notional_qty

        bot_id = None
        if bot is not None:
            bot_id = bot.get("id")
            bot["skipped_small_qty_count"] = bot.get("skipped_small_qty_count", 0) + 1
            bot["last_skip_reason"] = reason or "qty_below_min"
            now = self.client._get_now_ts()
            skip_log_ts = bot.get("_skip_order_log_ts") or {}
            if not isinstance(skip_log_ts, dict):
                skip_log_ts = {}
            reason_key = reason or "qty_below_min"
            last_ts = skip_log_ts.get(reason_key, 0)
            if now - last_ts < SKIP_SMALL_QTY_LOG_COOLDOWN_SEC:
                bot["_skip_order_log_ts"] = skip_log_ts
                return
            skip_log_ts[reason_key] = now
            bot["_skip_order_log_ts"] = skip_log_ts

        logger.warning(
            "skip_order bot_id=%s symbol=%s side=%s reason=%s raw_qty=%s normalized_qty=%s "
            "minQty=%s qtyStep=%s minNotional=%s price=%s notional=%s",
            bot_id,
            symbol,
            side,
            reason or "qty_below_min",
            raw_qty,
            normalized_qty,
            min_qty,
            qty_step,
            min_notional_value,
            price,
            notional,
        )
        if reason == "qty_below_min":
            self._record_qty_below_min_event(
                bot,
                symbol=symbol,
                side=side,
                raw_qty=raw_qty,
                normalized_qty=normalized_qty,
                min_qty=min_qty,
                qty_step=qty_step,
                price=price,
                min_notional_value=min_notional_value,
                reason=reason,
                diagnostic_context=diagnostic_context,
            )

    def _normalize_order_qty(
        self,
        bot: Optional[Dict[str, Any]],
        symbol: str,
        side: str,
        raw_qty: Optional[float],
        price: Optional[float],
        reduce_only: bool,
        full_close_qty: Optional[float] = None,
        diagnostic_context: Optional[Dict[str, Any]] = None,
    ) -> Optional[float]:
        filters = self.client.get_qty_filters(symbol)
        min_qty = filters.get("min_qty")
        qty_step = filters.get("qty_step")

        normalized_qty = self.client.normalize_qty(symbol, raw_qty, log_skip=False)
        if not normalized_qty or (min_qty and normalized_qty < min_qty):
            self._log_skip_order(
                bot,
                symbol,
                side,
                raw_qty,
                normalized_qty,
                min_qty,
                qty_step,
                price,
                reason="qty_below_min",
                diagnostic_context=diagnostic_context,
            )

            if reduce_only and full_close_qty is not None and full_close_qty != raw_qty:
                normalized_full = self.client.normalize_qty(
                    symbol, full_close_qty, log_skip=False
                )
                if not normalized_full or (min_qty and normalized_full < min_qty):
                    self._log_skip_order(
                        bot,
                        symbol,
                        side,
                        full_close_qty,
                        normalized_full,
                        min_qty,
                        qty_step,
                        price,
                        reason="qty_below_min",
                        diagnostic_context=diagnostic_context,
                    )
                    return None
                return normalized_full

            return None

        return normalized_qty

    def _compute_reduce_only_budget(
        self,
        current_position_size: float,
        existing_reduce_only_qty: float,
        position_size_per_level: float,
        qty_step: float,
        min_order_qty: float,
        min_notional_value: float,
        last_price: float,
    ) -> Tuple[float, float]:
        """
        Return:
        - total remaining closable qty not already reserved by open reduce-only orders
        - per-order capped qty for a single reduce-only grid order
        """
        available_total = max(0.0, current_position_size - existing_reduce_only_qty)
        available_total = self._round_to_step(available_total, qty_step, round_down=True)
        if (
            available_total < min_order_qty
            or available_total * last_price < min_notional_value
        ):
            return 0.0, 0.0

        per_order_qty = min(position_size_per_level, available_total)
        per_order_qty = self._round_to_step(per_order_qty, qty_step, round_down=True)
        if (
            per_order_qty < min_order_qty
            or per_order_qty * last_price < min_notional_value
        ):
            return 0.0, 0.0

        return available_total, per_order_qty

    def _validate_order_for_batch(
        self,
        bot: Optional[Dict[str, Any]],
        symbol: str,
        side: str,
        qty: Optional[float],
        order_type: str = "Limit",
        price: Optional[float] = None,
        reduce_only: bool = False,
        time_in_force: str = "GTC",
        order_link_id: Optional[str] = None,
        position_idx: Optional[int] = None,
        diagnostic_context: Optional[Dict[str, Any]] = None,
    ) -> Optional[Dict[str, Any]]:
        """Validate an order without submitting it.

        Returns a dict with all params needed for batch submission if valid,
        or None if the order should be skipped/blocked.  Sets skip metadata
        on *bot* the same way _create_order_checked does.
        """
        # Reuse all the pre-flight checks from _create_order_checked
        if bot and not reduce_only:
            exchange_truth_blocker = self._get_exchange_truth_opening_blocker(bot)
            if exchange_truth_blocker is not None:
                bot["last_skip_reason"] = exchange_truth_blocker["reason"]
                return None
            if bot.get("_block_opening_orders") or bot.get("_nlp_block_opening_orders"):
                return None
            if bot.get("_micro_bias_skip_buy") and side == "Buy":
                return None
            if bot.get("_micro_bias_skip_sell") and side == "Sell":
                return None

        if bot is not None and position_idx is None:
            position_idx = self._resolve_position_idx(bot, symbol, side, reduce_only)
            if bot.get("_position_mode") is None:
                return None

        normalized_qty = self._normalize_order_qty(
            bot, symbol, side, qty, price, reduce_only,
            diagnostic_context=diagnostic_context,
        )
        if not normalized_qty:
            return None

        instrument = self._get_instrument_info(symbol)
        if instrument:
            qty_step = instrument.get("qty_step")
            if qty_step:
                normalized_qty = self._round_to_step(normalized_qty, qty_step, round_down=True)
            min_order_qty = instrument.get("min_order_qty")
            if not normalized_qty or (min_order_qty and normalized_qty < min_order_qty):
                return None

        if not reduce_only and price is not None and instrument:
            min_notional_value = instrument.get("min_notional_value")
            if min_notional_value and (float(price) * normalized_qty) < float(min_notional_value):
                return None

        if bot and not reduce_only:
            budget_guard = self._enforce_auto_pilot_opening_loss_budget(
                bot=bot, symbol=symbol, side=side, qty=qty,
                price=price, normalized_qty=normalized_qty,
            )
            if budget_guard is not None:
                return None

        if order_link_id is None:
            bid = (bot.get("id") if bot else "unknown") or "unknown"
            ts = int(time.time() * 1000) % 1000000
            intent = "close" if reduce_only else "open"
            s = "B" if side.lower() == "buy" else "S"
            order_link_id = f"gen_{bid[:8]}_{ts}{s}{intent[0]}"

        ownership_snapshot = self._build_persistent_ownership_snapshot(
            bot, order_link_id=order_link_id, reduce_only=reduce_only,
            diagnostic_context=diagnostic_context,
        )

        return {
            "side": side,
            "qty": normalized_qty,
            "order_type": order_type,
            "price": price,
            "reduce_only": reduce_only,
            "time_in_force": time_in_force,
            "order_link_id": order_link_id,
            "position_idx": position_idx,
            "ownership_snapshot": ownership_snapshot,
            "diagnostic_context": diagnostic_context,
        }

    def _submit_batch_orders(
        self,
        bot: Dict[str, Any],
        symbol: str,
        pending_orders: List[Dict[str, Any]],
    ) -> List[Dict[str, Any]]:
        """Submit a list of validated orders via the batch API.

        Falls back to serial submission if the client doesn't support batch.
        Returns per-order result dicts.
        """
        if not pending_orders:
            return []

        batch_fn = getattr(self.client, "create_batch_orders", None)
        if not batch_fn:
            # H3: Fallback serial submission — validate each result
            results = []
            for entry in pending_orders:
                r = self.client.create_order(
                    symbol=symbol,
                    side=entry["side"],
                    qty=entry["qty"],
                    order_type=entry.get("order_type", "Limit"),
                    price=entry.get("price"),
                    reduce_only=entry.get("reduce_only", False),
                    time_in_force=entry.get("time_in_force", "GTC"),
                    order_link_id=entry.get("order_link_id"),
                    position_idx=entry.get("position_idx"),
                    qty_is_normalized=True,
                    ownership_snapshot=entry.get("ownership_snapshot"),
                )
                if not r.get("success"):
                    logger.warning(
                        "[%s] Serial order failed: side=%s error=%s",
                        symbol,
                        entry.get("side"),
                        r.get("error", "unknown"),
                    )
                results.append(r)
            return results

        # H4: Check batch-level success before returning results
        batch_result = batch_fn(symbol, pending_orders)
        if not batch_result.get("success") and not batch_result.get("partial"):
            logger.warning(
                "[%s] Batch order failed entirely: %s",
                symbol,
                batch_result.get("error", "unknown"),
            )
            return []
        return batch_result.get("results", [])

    def _create_order_checked(
        self,
        bot: Optional[Dict[str, Any]],
        symbol: str,
        side: str,
        qty: Optional[float],
        order_type: str = "Market",
        price: Optional[float] = None,
        reduce_only: bool = False,
        time_in_force: str = "GTC",
        order_link_id: Optional[str] = None,
        full_close_qty: Optional[float] = None,
        position_idx: Optional[int] = None,
        diagnostic_context: Optional[Dict[str, Any]] = None,
        _batch_pending: Optional[List[Dict[str, Any]]] = None,
    ) -> Dict[str, Any]:
        decision_started_at = now_ts()
        # PRE-FLIGHT STATUS CHECK: Ensure bot is still running OR this is a reduce-only order
        # (Always allow reduce-only to close positions, but block new entry orders if stopped)
        if bot and not reduce_only:
            exchange_truth_blocker = self._get_exchange_truth_opening_blocker(bot)
            if exchange_truth_blocker is not None:
                bot["last_skip_reason"] = exchange_truth_blocker["reason"]
                logger.warning(
                    "[%s] Order placement blocked by exchange truth enforcement: %s",
                    symbol,
                    exchange_truth_blocker["reason"],
                )
                return {
                    "success": False,
                    "error": exchange_truth_blocker["reason"],
                    "retCode": -1,
                    "skipped": True,
                    "skip_reason": exchange_truth_blocker["reason"],
                    "diagnostic_reason": exchange_truth_blocker["reason"],
                    "diagnostic_detail": exchange_truth_blocker["detail"],
                }
            # Check if opening orders are explicitly blocked due to previous failures
            if bot.get("_block_opening_orders") or bot.get("_nlp_block_opening_orders"):
                logger.warning(
                    f"[{symbol}] Order placement blocked: _block_opening_orders=True"
                )
                return {
                    "success": False,
                    "error": "opening_orders_blocked",
                    "retCode": -1,
                }

            # MICRO-BIAS per-side skip (ENTRY orders only for neutral mode)
            # Skip counter-bias orders to reduce inventory accumulation against micro-trend
            if bot.get("_micro_bias_skip_buy") and side == "Buy":
                logger.debug(
                    "[%s] MICRO_BIAS skip Buy ENTRY order (score=%.3f direction=%s)",
                    symbol,
                    bot.get("_micro_bias_score", 0.0),
                    bot.get("_micro_bias_direction", "NEUTRAL"),
                )
                return {
                    "success": False,
                    "error": "micro_bias_skip",
                    "retCode": -1,
                    "skipped": True,
                }
            if bot.get("_micro_bias_skip_sell") and side == "Sell":
                logger.debug(
                    "[%s] MICRO_BIAS skip Sell ENTRY order (score=%.3f direction=%s)",
                    symbol,
                    bot.get("_micro_bias_score", 0.0),
                    bot.get("_micro_bias_direction", "NEUTRAL"),
                )
                return {
                    "success": False,
                    "error": "micro_bias_skip",
                    "retCode": -1,
                    "skipped": True,
                }

            bot_id = bot.get("id")
            if bot_id:
                fresh_bot = self.bot_storage.get_bot(bot_id)
                if fresh_bot and fresh_bot.get("status") not in (
                    "running",
                    "paused",
                    "recovering",
                ):
                    logger.warning(
                        f"[{symbol}] Order placement aborted: bot status is '{fresh_bot.get('status')}' (Emergency Stop check)"
                    )
                    return {
                        "success": False,
                        "error": "bot_not_running_abort",
                        "retCode": -1,
                    }

        if bot is not None and position_idx is None:
            position_idx = self._resolve_position_idx(bot, symbol, side, reduce_only)
            if bot.get("_position_mode") is None:
                return {
                    "success": False,
                    "error": "position_mode_unknown",
                    "retCode": -1,
                }

        normalized_qty = self._normalize_order_qty(
            bot,
            symbol,
            side,
            qty,
            price,
            reduce_only,
            full_close_qty=full_close_qty,
            diagnostic_context=diagnostic_context,
        )
        if not normalized_qty:
            return {
                "success": False,
                "error": "qty_below_min",
                "retCode": -1,
                "skipped": True,
            }

        # Hard guard against minQty/step issues (including reduce_only)
        instrument = self._get_instrument_info(symbol)
        if instrument:
            min_order_qty = instrument.get("min_order_qty")
            qty_step = instrument.get("qty_step")
            if qty_step:
                normalized_qty = self._round_to_step(
                    normalized_qty, qty_step, round_down=True
                )
            if not normalized_qty or (min_order_qty and normalized_qty < min_order_qty):
                self._log_skip_order(
                    bot,
                    symbol,
                    side,
                    qty,
                    normalized_qty,
                    min_order_qty,
                    qty_step,
                    price,
                    reason="qty_below_min",
                    diagnostic_context=diagnostic_context,
                )
                return {
                    "success": False,
                    "error": "qty_below_min",
                    "retCode": -1,
                    "skipped": True,
                }

        # Prevent min-notional failures on opening orders (best-effort, price required)
        if not reduce_only and price is not None:
            min_notional_value = None
            min_order_qty = None
            qty_step = None
            if instrument:
                min_notional_value = instrument.get("min_notional_value")
                min_order_qty = instrument.get("min_order_qty")
                qty_step = instrument.get("qty_step")
            if min_notional_value:
                notional = float(price) * normalized_qty
                if notional < float(min_notional_value):
                    self._log_skip_order(
                        bot,
                        symbol,
                        side,
                        qty,
                        normalized_qty,
                        min_order_qty,
                        qty_step,
                        price,
                        min_notional_value=min_notional_value,
                        reason="notional_below_min",
                    )
                    return {
                        "success": False,
                        "error": "notional_below_min",
                        "retCode": -1,
                        "skipped": True,
                    }

        if bot and not reduce_only:
            budget_guard_result = self._enforce_auto_pilot_opening_loss_budget(
                bot=bot,
                symbol=symbol,
                side=side,
                qty=qty,
                price=price,
                normalized_qty=normalized_qty,
            )
            if budget_guard_result is not None:
                return budget_guard_result

        if order_link_id is None:
            bid = (bot.get("id") if bot else "unknown") or "unknown"
            ts = int(time.time() * 1000) % 1000000
            intent = "close" if reduce_only else "open"
            s = "B" if side.lower() == "buy" else "S"
            order_link_id = f"gen_{bid[:8]}_{ts}{s}{intent[0]}"

        ownership_snapshot = self._build_persistent_ownership_snapshot(
            bot,
            order_link_id=order_link_id,
            reduce_only=reduce_only,
            diagnostic_context=diagnostic_context,
        )
        submitted_opening_sizing = self._augment_directional_opening_sizing_fields(
            (diagnostic_context or {}).get("opening_sizing"),
            submitted_qty=normalized_qty,
            submitted_price=price,
        )
        if ownership_snapshot is not None and submitted_opening_sizing:
            ownership_snapshot["opening_sizing"] = submitted_opening_sizing

        # A1: When _batch_pending is provided, defer submission and collect
        # the validated order for batch API call later.
        if _batch_pending is not None and order_type == "Limit":
            _batch_pending.append({
                "side": side,
                "qty": normalized_qty,
                "order_type": order_type,
                "price": price,
                "reduce_only": reduce_only,
                "time_in_force": time_in_force,
                "order_link_id": order_link_id,
                "position_idx": position_idx,
                "ownership_snapshot": ownership_snapshot,
                "_opening_sizing": submitted_opening_sizing,
                "_decision_started_at": decision_started_at,
            })
            # Return optimistic success so the caller's accounting works.
            # Actual exchange result is applied when the batch is flushed.
            return {
                "success": True,
                "batched": True,
                "normalized_qty": normalized_qty,
                "opening_sizing": submitted_opening_sizing,
            }

        order_result = self.client.create_order(
            symbol=symbol,
            side=side,
            qty=normalized_qty,
            order_type=order_type,
            price=price,
            reduce_only=reduce_only,
            time_in_force=time_in_force,
            order_link_id=order_link_id,
            position_idx=position_idx,
            qty_is_normalized=True,
            ownership_snapshot=ownership_snapshot,
        )
        order_result = merge_result_timing(
            order_result,
            decision_started_at=iso_from_ts(decision_started_at),
            decision_completed_at=iso_from_ts(),
            decision_to_submit_ack_ms=elapsed_ms(decision_started_at, now_ts()),
        )
        order_result["normalized_qty"] = normalized_qty
        if submitted_opening_sizing:
            order_result["opening_sizing"] = submitted_opening_sizing
        if isinstance(ownership_snapshot, dict) and ownership_snapshot.get("entry_story"):
            order_result["entry_story"] = dict(ownership_snapshot.get("entry_story") or {})
        if isinstance(ownership_snapshot, dict):
            order_result["experiment_attribution_state"] = ownership_snapshot.get(
                "experiment_attribution_state"
            ) or "none"
            if ownership_snapshot.get("profit_protection_advisory"):
                order_result["profit_protection_advisory"] = dict(
                    ownership_snapshot.get("profit_protection_advisory") or {}
                )
            if ownership_snapshot.get("profit_protection_shadow"):
                order_result["profit_protection_shadow"] = dict(
                    ownership_snapshot.get("profit_protection_shadow") or {}
                )
        if self._is_ambiguous_order_result(order_result):
            self._mark_ambiguous_execution_follow_up(
                bot,
                action="create_order",
                symbol=symbol,
                result=order_result,
                side=side,
                reduce_only=reduce_only,
                order_link_id=order_link_id,
            )
        # --- Phase 1: Order starvation tracking ---
        if bot and not self._is_ambiguous_order_result(order_result):
            if order_result.get("success"):
                bot["_consecutive_order_failures"] = 0
                bot.pop("_last_order_failure_reason", None)
                bot.pop("_last_order_failure_at", None)
                bot.pop("_order_starvation_block", None)
            elif not order_result.get("batched"):
                prev = int(bot.get("_consecutive_order_failures") or 0)
                bot["_consecutive_order_failures"] = prev + 1
                bot["_last_order_failure_reason"] = str(
                    order_result.get("error") or order_result.get("retMsg") or "unknown"
                )[:120]
                bot["_last_order_failure_at"] = time.time()
                count = bot["_consecutive_order_failures"]
                if count >= strategy_cfg.ORDER_STARVATION_BLOCK_THRESHOLD:
                    bot["_order_starvation_block"] = True
                    bot["_block_opening_orders"] = True
                    self._emit_order_starvation_watchdog(
                        bot, symbol, count, "CRITICAL"
                    )
                elif count >= strategy_cfg.ORDER_STARVATION_ERROR_THRESHOLD:
                    self._emit_order_starvation_watchdog(
                        bot, symbol, count, "ERROR"
                    )
                elif count >= strategy_cfg.ORDER_STARVATION_WARN_THRESHOLD:
                    self._emit_order_starvation_watchdog(
                        bot, symbol, count, "WARN"
                    )
        # --- Phase 5: Fill slippage tracking for market orders ---
        if (
            order_result.get("success")
            and bot
            and order_type == "Market"
            and price
            and strategy_cfg.FILL_SLIPPAGE_WATCHDOG_ENABLED
        ):
            try:
                expected_price = float(price)
                fill_data = order_result.get("data") or {}
                fill_price = self._safe_float(fill_data.get("avgPrice"), 0.0)
                if fill_price <= 0:
                    fill_price = expected_price
                if expected_price > 0 and fill_price > 0:
                    slippage_bps = abs(fill_price - expected_price) / expected_price * 10000
                    history = list(bot.get("_fill_slippage_history") or [])
                    history.append({"ts": time.time(), "bps": round(slippage_bps, 2)})
                    max_hist = int(strategy_cfg.FILL_SLIPPAGE_HISTORY_SIZE)
                    bot["_fill_slippage_history"] = history[-max_hist:]
                    bot["_last_fill_slippage_bps"] = round(slippage_bps, 2)
                    warn_bps = float(strategy_cfg.FILL_SLIPPAGE_WARN_BPS)
                    cluster_thresh = int(strategy_cfg.FILL_SLIPPAGE_CLUSTER_THRESHOLD)
                    recent = bot["_fill_slippage_history"][-5:]
                    high_count = sum(1 for h in recent if h.get("bps", 0) > warn_bps)
                    if high_count >= cluster_thresh:
                        self._emit_fill_slippage_watchdog(
                            bot, symbol, slippage_bps, "ERROR", is_cluster=True
                        )
                    elif slippage_bps > warn_bps:
                        self._emit_fill_slippage_watchdog(
                            bot, symbol, slippage_bps, "WARN"
                        )
            except Exception:
                pass
        if order_result.get("success") and bot and not reduce_only:
            self._promote_trade_forensic_context(
                bot,
                side=side,
            )
            self._remember_forensic_active_entry_state(bot, ownership_snapshot)
        self._record_control_timing(
            bot,
            "last_order_submit",
            symbol=symbol,
            side=side,
            reduce_only=bool(reduce_only),
            order_link_id=order_link_id,
            timing=dict((order_result or {}).get("timing") or {}),
        )
        self._record_first_start_order(
            bot,
            order_result,
            symbol=symbol,
            side=side,
            reduce_only=reduce_only,
            order_link_id=order_link_id,
        )
        return order_result

    def _is_insufficient_margin_result(self, result: Optional[Dict[str, Any]]) -> bool:
        if not result:
            return False
        ret_code = str(result.get("retCode", "") or "").strip()
        if ret_code in {"110007", "110045"}:
            return True
        error_text = str(result.get("error", "") or "").lower()
        return "not enough" in error_text or "insufficient" in error_text

    def _maybe_trigger_auto_stop_loss(
        self,
        bot: Dict[str, Any],
        symbol: str,
        now_iso: str,
        unrealized_pnl: Optional[float] = None,
        position_size: Optional[float] = None,
    ) -> Optional[Dict[str, Any]]:
        auto_stop_usdt = self._safe_float(bot.get("auto_stop"), 0.0)
        if auto_stop_usdt <= 0:
            return None

        if unrealized_pnl is None or position_size is None:
            unrealized_pnl = 0.0
            position_size = 0.0
            try:
                pos_resp = self.client.get_positions()
                if pos_resp.get("success"):
                    for pos in pos_resp.get("data", {}).get("list", []) or []:
                        if pos.get("symbol") != symbol:
                            continue
                        pos_size = self._safe_float(pos.get("size"), 0.0)
                        if pos_size > 0:
                            position_size = pos_size
                            unrealized_pnl = self._safe_float(
                                pos.get("unrealisedPnl"), 0.0
                            )
                        break
            except Exception as e:
                logger.debug(f"[{symbol}] Auto-stop position fetch failed: {e}")
                return None

        if position_size <= 0:
            return None

        if unrealized_pnl < 0 and abs(unrealized_pnl) >= auto_stop_usdt:
            bot_id = bot.get("id")
            logger.warning(
                "Auto Stop triggered for bot %s (symbol=%s): unrealized_pnl=%.4f, auto_stop_limit=%.4f",
                bot_id,
                symbol,
                unrealized_pnl,
                auto_stop_usdt,
            )
            close_success = self._close_bot_symbol(
                bot,
                hard_fail=True,
                fail_reason="Auto-stop loss close failed",
            )
            if close_success:
                bot["status"] = "stopped"
                bot["started_at"] = None
                self._reset_auto_pilot_on_stop(bot)
                bot["last_error"] = (
                    f"Auto-stop: loss ${abs(unrealized_pnl):.2f} >= ${auto_stop_usdt:.2f}"
                )
            else:
                bot["status"] = "error"
                bot["last_error"] = (
                    "AUTO_STOP_CLOSE_FAILED: Position still open - requires manual close"
                )
                bot["_block_opening_orders"] = True
            bot["last_run_at"] = now_iso
            self.bot_storage.save_bot(bot)
            return bot

        return None

    def _prune_far_orders_for_margin(
        self,
        symbol: str,
        far_orders: List[Tuple[float, str, str]],
        start_idx: int,
        last_price: float,
        target_level: float,
        max_cancel: int = 2,
    ) -> Tuple[int, int]:
        pruned = 0
        idx = start_idx
        target_distance = abs(target_level - last_price)

        while idx < len(far_orders) and pruned < max_cancel:
            far_price, far_order_id, far_side = far_orders[idx]
            idx += 1

            if abs(far_price - last_price) <= target_distance:
                continue

            cancel_result = self.client.cancel_order(symbol, far_order_id)
            if cancel_result.get("success"):
                logger.info(
                    f"[{symbol}] Cancelled far {far_side} order at {far_price:.6f} after insufficient margin "
                    f"while targeting {target_level:.6f}"
                )
                pruned += 1

        return pruned, idx


    def _get_symbol_unrealized_pnl_total(
        self,
        symbol: Optional[str],
        positions_resp: Optional[Dict[str, Any]] = None,
    ) -> float:
        normalized_symbol = str(symbol or "").strip().upper()
        if not normalized_symbol or self._is_auto_pilot_placeholder_symbol(
            normalized_symbol
        ):
            return 0.0

        if positions_resp is None:
            try:
                positions_resp = self.client.get_positions(skip_cache=True)
            except Exception as exc:
                logger.debug(
                    "[%s] Auto-Pilot loss budget position lookup failed: %s",
                    normalized_symbol,
                    exc,
                )
                return 0.0

        if not positions_resp or not positions_resp.get("success"):
            return 0.0

        total = 0.0
        for pos in (positions_resp.get("data", {}) or {}).get("list", []) or []:
            if str(pos.get("symbol") or "").strip().upper() != normalized_symbol:
                continue
            total += self._safe_float(pos.get("unrealisedPnl"), 0.0)
        return total




    def _refresh_auto_pilot_loss_budget_state(
        self,
        bot: Dict[str, Any],
        symbol: Optional[str],
        *,
        investment: Optional[float] = None,
        leverage: Optional[float] = None,
        available_equity: Optional[float] = None,
        symbol_unrealized_pnl: Optional[float] = None,
        positions_resp: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        state = self._compute_auto_pilot_loss_budget_state(
            bot,
            symbol,
            investment=investment,
            leverage=leverage,
            available_equity=available_equity,
            symbol_unrealized_pnl=symbol_unrealized_pnl,
            positions_resp=positions_resp,
        )
        return self._apply_auto_pilot_loss_budget_runtime_state(bot, state)


    def _enforce_auto_pilot_opening_loss_budget(
        self,
        bot: Dict[str, Any],
        symbol: str,
        side: str,
        qty: Optional[float],
        price: Optional[float],
        normalized_qty: Optional[float] = None,
    ) -> Optional[Dict[str, Any]]:
        if not bot or not bot.get("auto_pilot"):
            return None

        status = str(bot.get("auto_pilot_loss_budget_state") or "")
        if status:
            budget_state = {
                "status": status,
                "remaining_pct": self._safe_float(
                    bot.get("auto_pilot_remaining_loss_budget_pct"),
                    0.0,
                ),
                "remaining_usdt": self._safe_float(
                    bot.get("auto_pilot_remaining_loss_budget_usdt"),
                    0.0,
                ),
                "loss_budget_usdt": self._safe_float(
                    bot.get("auto_pilot_loss_budget_usdt"),
                    0.0,
                ),
            }
        else:
            budget_state = self._refresh_auto_pilot_loss_budget_state(bot, symbol)
            status = str(budget_state.get("status") or "")

        if status == "blocked":
            bot["last_skip_reason"] = "auto_pilot_loss_budget_blocked"
            if self._get_auto_pilot_loss_budget_guard_settings(bot)["logging_enabled"]:
                logger.warning(
                    "[%s] Auto-Pilot opening blocked: remaining loss budget %.2f%% ($%.2f / $%.2f)",
                    symbol,
                    self._safe_float(budget_state.get("remaining_pct"), 0.0) * 100.0,
                    self._safe_float(budget_state.get("remaining_usdt"), 0.0),
                    self._safe_float(budget_state.get("loss_budget_usdt"), 0.0),
                )
            return {
                "success": False,
                "error": "auto_pilot_loss_budget_blocked",
                "retCode": -1,
                "skipped": True,
                "skip_reason": "auto_pilot_loss_budget_blocked",
            }

        max_opening_notional_usdt = self._safe_float(
            bot.get("auto_pilot_low_budget_max_opening_notional_usdt"),
            0.0,
        )
        if status != "low" or max_opening_notional_usdt <= 0:
            return None

        order_price = self._get_auto_pilot_opening_order_price(bot, symbol, price)
        order_qty = self._safe_float(
            normalized_qty if normalized_qty is not None else qty,
            0.0,
        )
        order_notional = (
            order_price * order_qty if order_price and order_qty > 0 else 0.0
        )
        # Cumulative per-cycle cap: track total opening notional across all orders this cycle
        cycle_used = self._safe_float(bot.get("_cycle_opening_notional_used"), 0.0)
        remaining_cap = max_opening_notional_usdt - cycle_used
        if order_notional <= 0 or order_notional <= remaining_cap:
            if order_notional > 0:
                bot["_cycle_opening_notional_used"] = cycle_used + order_notional
            return None

        bot["last_skip_reason"] = "auto_pilot_low_budget_notional_cap"
        if self._get_auto_pilot_loss_budget_guard_settings(bot)["logging_enabled"]:
            logger.info(
                "[%s] Auto-Pilot low-budget opening skipped: %s %.6f notional $%.2f > remaining cap $%.2f "
                "(remaining loss budget %.2f%%, $%.2f left)",
                symbol,
                side,
                order_qty,
                order_notional,
                remaining_cap,
                self._safe_float(budget_state.get("remaining_pct"), 0.0) * 100.0,
                self._safe_float(budget_state.get("remaining_usdt"), 0.0),
            )
        return {
            "success": False,
            "error": "auto_pilot_low_budget_notional_cap",
            "retCode": -1,
            "skipped": True,
            "skip_reason": "auto_pilot_low_budget_notional_cap",
        }

    def _get_exchange_truth_opening_blocker(
        self,
        bot: Optional[Dict[str, Any]],
    ) -> Optional[Dict[str, str]]:
        if not isinstance(bot, dict):
            return None
        reconcile = dict(bot.get("exchange_reconciliation") or {})
        reconcile_status = str(reconcile.get("status") or "").strip().lower()
        mismatches = [
            str(item or "").strip().lower()
            for item in list(reconcile.get("mismatches") or [])
            if str(item or "").strip()
        ]
        # Auto-clear stale reconciliation divergence after 60s.
        # Prevents permanent order blocks when exchange data lags.
        if reconcile_status in {"diverged", "error_with_exchange_persist_divergence"}:
            updated_at = str(reconcile.get("updated_at") or "").strip()
            reconcile_age = 0.0
            if updated_at:
                try:
                    from datetime import datetime as _dt
                    _ts = _dt.fromisoformat(updated_at.replace("Z", "+00:00")).timestamp()
                    reconcile_age = time.time() - _ts
                except Exception:
                    pass
            if reconcile_age > 30.0:
                # C2 audit: recheck exchange state instead of blindly auto-clearing
                _sym = bot.get("symbol") or "?"
                logger.info(
                    "[%s] Divergence guard stale (%.0fs) — rechecking exchange state",
                    _sym, reconcile_age,
                )
                try:
                    _cleanup = self._confirm_symbol_cleanup_state(str(_sym))
                    if _cleanup.get("flat") and _cleanup.get("orders_cleared"):
                        logger.info(
                            "[%s] Exchange recheck confirms clean — resolving divergence",
                            _sym,
                        )
                        reconcile["status"] = "auto_resolved_recheck"
                        reconcile["mismatches"] = []
                        bot["exchange_reconciliation"] = reconcile
                        reconcile_status = "auto_resolved_recheck"
                        mismatches = []
                    else:
                        logger.warning(
                            "[%s] Exchange recheck still diverged — keeping blocker active "
                            "(flat=%s orders_cleared=%s)",
                            _sym, _cleanup.get("flat"), _cleanup.get("orders_cleared"),
                        )
                        reconcile["updated_at"] = datetime.now(timezone.utc).isoformat()
                        bot["exchange_reconciliation"] = reconcile
                except Exception as _exc:
                    logger.warning(
                        "[%s] Exchange recheck failed — keeping divergence blocker: %s",
                        _sym, _exc,
                    )

        if reconcile_status in {
            "diverged",
            "error_with_exchange_persist_divergence",
        } or mismatches:
            mismatch_label = ", ".join(mismatches[:3]) if mismatches else None
            detail = (
                "Exchange reconciliation diverged from local bot assumptions, so new "
                "opening orders stay blocked until truth is rechecked."
            )
            if mismatch_label:
                detail = f"{detail} Mismatch: {mismatch_label}."
            return {
                "reason": "reconciliation_diverged",
                "reason_text": "Reconciliation diverged",
                "detail": detail,
            }
        stale_parts = []
        if bool(bot.get("position_assumption_stale")):
            stale_parts.append("position assumptions")
        if bool(bot.get("order_assumption_stale")):
            stale_parts.append("open-order assumptions")
        if stale_parts:
            return {
                "reason": "exchange_truth_stale",
                "reason_text": "Exchange truth stale",
                "detail": (
                    "Local exchange assumptions are stale, so new opening orders stay "
                    f"blocked until truth is rechecked. Stale assumptions: {', '.join(stale_parts)}."
                ),
            }
        marker = dict(bot.get("ambiguous_execution_follow_up") or {})
        # Only block while the marker is actively pending (awaiting exchange truth check).
        # Resolved markers (pending=False) — including expired ones (truth_check_expired)
        # — must not block indefinitely. A non-pending marker means we've given up
        # waiting or confirmed the outcome; the bot should resume normal operation.
        if bool(marker.get("pending")):
            marker_status = str(marker.get("status") or "").strip().lower()
            detail = (
                "A previous exchange action still has an unresolved truth check, so "
                "new opening orders stay blocked until the exchange outcome is clear."
            )
            action = str(marker.get("action") or "").strip().lower()
            reason = str(
                marker.get("exchange_effect_reason")
                or marker.get("reason")
                or marker.get("diagnostic_reason")
                or ""
            ).strip().lower()
            context = ", ".join(
                item for item in (action, reason or marker_status or None) if item
            )
            if context:
                detail = f"{detail} Pending context: {context}."
            return {
                "reason": "exchange_state_untrusted",
                "reason_text": "Exchange state untrusted",
                "detail": detail,
            }
        return None

    def _ai_block_opening_orders(self, bot: Dict[str, Any]) -> bool:
        """Check if opening orders should be blocked."""
        if self._get_exchange_truth_opening_blocker(bot) or bot.get(
            "_block_opening_orders"
        ) or bot.get(
            "_small_capital_block_opening_orders"
        ) or bot.get(
            "_session_timer_block_opening_orders"
        ) or bot.get(
            "_capital_starved_block_opening_orders"
        ) or bot.get("_auto_pilot_loss_budget_block_openings") or bot.get(
            "_stall_overlay_block_opening_orders"
        ) or bot.get(
            "_breakout_invalidation_block_opening_orders"
        ):
            return True
        return False

