    _EXPERIMENT_OUTCOME_PREFIXES = {
        "trigger_ready": "exp_trigger_ready_after_",
        "executed": "exp_executed_after_",
        "blocked": "exp_blocked_after_",
        "profit": "exp_profit_after_",
        "loss": "exp_loss_after_",
        "neutral": "exp_neutral_after_",
    }
    _EXPERIMENT_TAG_BASES = {
        "exp_strong_continuation_promotion_used": "strong_continuation_promotion",
        "exp_directional_structure_relax_used": "directional_structure_relax",
        "exp_directional_position_cap_headroom_used": (
            "directional_position_cap_headroom"
        ),
        "exp_profitable_add_cap_headroom_used": "profitable_add_cap_headroom",
        "exp_long_near_price_continuation_add_used": (
            "long_near_price_continuation_add"
        ),
    }

    @classmethod
    def _normalize_experiment_tags(cls, *values: Any) -> List[str]:
        tags: List[str] = []
        for value in values:
            if isinstance(value, (list, tuple, set)):
                items = value
            else:
                items = [value]
            for item in items:
                tag = str(item or "").strip().lower()
                if tag and tag not in tags:
                    tags.append(tag)
        return sorted(tags)

    @classmethod
    def _merge_experiment_details(cls, *values: Any) -> Dict[str, Any]:
        merged: Dict[str, Any] = {}
        for value in values:
            if not isinstance(value, dict):
                continue
            for key, detail in value.items():
                tag = str(key or "").strip().lower()
                if not tag:
                    continue
                if isinstance(detail, dict):
                    existing = merged.get(tag)
                    if isinstance(existing, dict):
                        combined = dict(existing)
                        combined.update(detail)
                        merged[tag] = combined
                    else:
                        merged[tag] = dict(detail)
                elif detail is not None:
                    merged[tag] = detail
        return merged

    @classmethod
    def _derive_experiment_outcome_tags(
        cls,
        experiment_tags: Optional[List[str]],
        outcome_kind: Optional[str],
    ) -> List[str]:
        prefix = cls._EXPERIMENT_OUTCOME_PREFIXES.get(
            str(outcome_kind or "").strip().lower()
        )
        if not prefix:
            return []
        derived: List[str] = []
        for tag in cls._normalize_experiment_tags(experiment_tags):
            base = cls._EXPERIMENT_TAG_BASES.get(tag)
            if not base:
                base = str(tag).strip().lower()
                if base.startswith("exp_"):
                    base = base[4:]
                for suffix in ("_used", "_created"):
                    if base.endswith(suffix):
                        base = base[: -len(suffix)]
                        break
            if not base:
                continue
            outcome_tag = f"{prefix}{base}"
            if outcome_tag not in derived:
                derived.append(outcome_tag)
        return derived

    @classmethod
    def _remember_runtime_experiment_usage(
        cls,
        bot: Optional[Dict[str, Any]],
        tags: Optional[List[str]] = None,
        *,
        details: Optional[Dict[str, Any]] = None,
    ) -> None:
        if not isinstance(bot, dict):
            return
        merged_tags = cls._normalize_experiment_tags(
            bot.get("runtime_experiment_tags"),
            tags,
        )
        if merged_tags:
            bot["runtime_experiment_tags"] = merged_tags
            bot["runtime_experiment_count"] = len(merged_tags)
        else:
            bot["runtime_experiment_tags"] = []
            bot["runtime_experiment_count"] = 0
        merged_details = cls._merge_experiment_details(
            bot.get("runtime_experiment_details"),
            details,
        )
        if merged_details:
            bot["runtime_experiment_details"] = merged_details
        else:
            bot.pop("runtime_experiment_details", None)
        if merged_tags:
            bot["runtime_experiment_last_seen_at"] = datetime.now(
                timezone.utc
            ).isoformat()

    @classmethod
    def _clear_runtime_experiment_state(cls, bot: Optional[Dict[str, Any]]) -> None:
        if not isinstance(bot, dict):
            return
        bot["runtime_experiment_tags"] = []
        bot["runtime_experiment_count"] = 0
        bot.pop("runtime_experiment_details", None)
        bot.pop("runtime_experiment_last_seen_at", None)
        bot.pop("entry_signal_experiment_tags", None)
        bot.pop("entry_signal_experiment_details", None)
        bot.pop("_entry_gate_experiment_tags", None)
        bot.pop("_entry_gate_experiment_details", None)

    @classmethod
    def _apply_directional_entry_signal_runtime_state(
        cls,
        bot: Dict[str, Any],
        signal: Optional[Dict[str, Any]],
    ) -> None:
        if not bot:
            return
        payload = dict(signal or {})
        bot["entry_signal_code"] = payload.get("code")
        bot["entry_signal_label"] = payload.get("label")
        bot["entry_signal_phase"] = payload.get("phase")
        bot["entry_signal_detail"] = payload.get("detail")
        bot["entry_signal_preferred"] = bool(payload.get("preferred", False))
        bot["entry_signal_late"] = bool(payload.get("late", False))
        bot["entry_signal_executable"] = bool(payload.get("executable", False))
        bot["entry_signal_aligned"] = bool(payload.get("aligned", False))
        bot["entry_signal_extension_ratio"] = payload.get("extension_ratio")
        experiment_tags = cls._normalize_experiment_tags(payload.get("experiment_tags"))
        experiment_details = cls._merge_experiment_details(
            payload.get("experiment_details")
        )
        if experiment_tags:
            bot["entry_signal_experiment_tags"] = experiment_tags
            if experiment_details:
                bot["entry_signal_experiment_details"] = experiment_details
            cls._remember_runtime_experiment_usage(
                bot,
                experiment_tags,
                details=experiment_details or None,
            )
        else:
            bot.pop("entry_signal_experiment_tags", None)
            bot.pop("entry_signal_experiment_details", None)

