    def _remember_forensic_active_entry_state(
        self,
        bot: Optional[Dict[str, Any]],
        ownership_snapshot: Optional[Dict[str, Any]],
    ) -> None:
        if not isinstance(bot, dict) or not isinstance(ownership_snapshot, dict):
            return
        entry_story = ownership_snapshot.get("entry_story")
        if isinstance(entry_story, dict) and entry_story:
            bot["forensic_active_entry_story"] = dict(entry_story)
        opening_sizing = self._compact_directional_opening_sizing_fields(
            ownership_snapshot.get("opening_sizing")
        )
        if opening_sizing:
            bot["forensic_active_opening_sizing"] = opening_sizing
        experiment_tags = self._normalize_experiment_tags(
            ownership_snapshot.get("experiment_tags")
        )
        experiment_details = self._merge_experiment_details(
            ownership_snapshot.get("experiment_details")
        )
        if experiment_tags:
            bot["forensic_active_experiment_tags"] = experiment_tags
        else:
            bot.pop("forensic_active_experiment_tags", None)
        if experiment_details:
            bot["forensic_active_experiment_details"] = experiment_details
        else:
            bot.pop("forensic_active_experiment_details", None)

    def _emit_audit_event(
        self,
        bot: Optional[Dict[str, Any]],
        *,
        event_type: str,
        severity: str,
        symbol: str,
        mode: Optional[str],
        throttle_key: Optional[str] = None,
        throttle_sec: Optional[float] = None,
        **fields: Any,
    ) -> bool:
        diagnostics_service = getattr(self, "audit_diagnostics_service", None)
        if diagnostics_service is None or not diagnostics_service.enabled():
            return False
        experiment_tags = self._normalize_experiment_tags(
            ((bot or {}).get("runtime_experiment_tags") if isinstance(bot, dict) else None),
            fields.pop("experiment_tags", None),
        )
        experiment_details = self._merge_experiment_details(
            ((bot or {}).get("runtime_experiment_details") if isinstance(bot, dict) else None),
            fields.pop("experiment_details", None),
        )
        experiment_outcome_kind = (
            str(fields.pop("experiment_outcome_kind", "") or "").strip().lower() or None
        )
        payload = {
            "event_type": event_type,
            "severity": severity,
            "symbol": symbol,
            "bot_id": (bot or {}).get("id"),
            "mode": mode,
            "experiment_attribution_state": "present" if experiment_tags else "none",
        }
        if experiment_tags:
            payload["experiment_tags"] = experiment_tags
        if experiment_details:
            payload["experiment_details"] = experiment_details
        if experiment_tags and experiment_outcome_kind:
            outcome_tags = self._derive_experiment_outcome_tags(
                experiment_tags,
                experiment_outcome_kind,
            )
            payload["experiment_outcome_kind"] = experiment_outcome_kind
            if outcome_tags:
                payload["experiment_outcome_tags"] = outcome_tags
            if isinstance(bot, dict):
                bot["runtime_experiment_last_outcome_kind"] = experiment_outcome_kind
                bot["runtime_experiment_last_outcome_tags"] = outcome_tags
                bot["runtime_experiment_last_outcome_at"] = datetime.now(
                    timezone.utc
                ).isoformat()
        for key, value in fields.items():
            if value is not None:
                payload[key] = value
        return diagnostics_service.record_event(
            payload,
            throttle_key=throttle_key,
            throttle_sec=throttle_sec,
        )

