    def _emit_order_starvation_watchdog(
        self,
        bot: Dict[str, Any],
        symbol: str,
        count: int,
        severity: str,
    ) -> None:
        self._emit_audit_event(
            bot,
            event_type="order_starvation",
            severity=severity,
            symbol=symbol,
            mode=bot.get("mode"),
            throttle_key=f"order_starvation:{bot.get('id')}",
            throttle_sec=float(strategy_cfg.ORDER_STARVATION_WATCHDOG_COOLDOWN_SEC),
            consecutive_failures=count,
            last_failure_reason=bot.get("_last_order_failure_reason"),
        )
        wd = getattr(self, "watchdog_diagnostics_service", None)
        if wd and wd.enabled("order_starvation"):
            wd.emit(
                watchdog_type="order_starvation",
                severity=severity,
                reason=f"{count} consecutive order failures",
                bot_id=bot.get("id"),
                symbol=symbol,
                mode=bot.get("mode"),
                metrics={"consecutive_failures": count},
            )

