    def check_upnl_stoploss_fast(self, bot: Dict[str, Any]) -> Dict[str, Any]:
        """
        Fast UPnL check for risk tick loop (runs every 1s).

        This is called from runner.py's fast risk check loop.

        Args:
            bot: Bot configuration dictionary

        Returns:
            Dict with:
                - action_taken: bool
                - action: str ("hard_close", "soft_block", or None)
                - reason: str (if action taken)
        """
        if not (ENABLE_UPNL_STOPLOSS and bot.get("upnl_stoploss_enabled")):
            return {"action_taken": False, "action": None, "reason": None}

        trading_env = (bot.get("trading_env") or "mainnet").strip().lower()
        if trading_env != "mainnet" or bot.get("paper_trading"):
            return {
                "action_taken": False,
                "action": None,
                "reason": "Testnet/paper trading disabled",
            }

        symbol = bot.get("symbol")
        if not symbol:
            return {"action_taken": False, "action": None, "reason": "No symbol"}

        # Get current position
        try:
            positions_resp = self.client.get_positions()
            if not positions_resp.get("success"):
                return {
                    "action_taken": False,
                    "action": None,
                    "reason": "Failed to get position",
                }

            positions = positions_resp.get("data", {}).get("list", []) or []
            position = None
            for pos in positions:
                if pos.get("symbol") == symbol:
                    position = pos
                    break

            if not position or float(position.get("size", 0)) == 0:
                # No position - clear any soft block
                if bot.get("_block_opening_orders") and not bot.get(
                    "auto_pilot_rotation_pending"
                ):
                    bot["_block_opening_orders"] = False
                    bot["_upnl_stoploss_reason"] = None
                    self.bot_storage.save_bot(bot)
                return {"action_taken": False, "action": None, "reason": "No position"}

        except Exception as e:
            logger.error(f"[{symbol}] Fast UPnL check exception: {e}")
            return {"action_taken": False, "action": None, "reason": str(e)}

        pre_state = bot.get("auto_margin_state") or {}
        pre_total_added = float(pre_state.get("total_added_usdt", 0) or 0)
        margin_added = False
        try:
            self._auto_margin_guard(bot, symbol, positions_resp=positions_resp)
            post_state = bot.get("auto_margin_state") or {}
            post_total_added = float(post_state.get("total_added_usdt", 0) or 0)
            margin_added = post_total_added > pre_total_added
        except Exception as e:
            logger.debug(f"[{symbol}] Fast auto-margin exception (non-fatal): {e}")

        # Check UPnL thresholds
        result = self._check_upnl_stoploss(
            bot,
            symbol,
            position,
            atr_15m_pct=bot.get("atr_15m_pct"),
        )

        if result.get("in_cooldown"):
            return {
                "action_taken": False,
                "action": None,
                "reason": result.get("reason"),
            }

        if result.get("hard_triggered"):
            if result.get("hard_liq_triggered") and margin_added:
                bot["_block_opening_orders"] = True
                bot["_upnl_stoploss_reason"] = (
                    "AutoMargin added; waiting for liq distance update"
                )
                self.bot_storage.save_bot(bot)
                return {
                    "action_taken": False,
                    "action": None,
                    "reason": "auto_margin_added_wait",
                }
            self._handle_upnl_hard_stoploss(bot, symbol, result)
            return {
                "action_taken": True,
                "action": "hard_close",
                "reason": result.get("reason"),
            }

        if result.get("soft_triggered"):
            self._handle_upnl_soft_stoploss(bot, symbol, result)
            return {
                "action_taken": True,
                "action": "soft_block",
                "reason": result.get("reason"),
            }

        # Clear soft block if UPnL recovered above soft threshold
        if bot.get("_block_opening_orders") and not bot.get(
            "auto_pilot_rotation_pending"
        ):
            bot["_block_opening_orders"] = False
            bot["_upnl_stoploss_reason"] = None
            self.bot_storage.save_bot(bot)
            logger.info(
                f"[{symbol}] UPnL recovered to {result.get('upnl_pct'):.2f}%, clearing soft block"
            )

        return {"action_taken": False, "action": None, "reason": None}

    def _emergency_cancel_far_orders(
        self,
        symbol: str,
        last_price: float,
        min_orders_to_cancel: int = 1,
        max_orders_to_cancel: int = 5,
        force: bool = False,
    ) -> int:
        """
        Cancel far OPENING orders to free up margin in emergency liquidation situations.

        IMPORTANT: Only cancels orders that reserve margin (opening orders).
        reduceOnly/closing orders do NOT free margin and are skipped.

        Args:
            symbol: Trading symbol
            last_price: Current market price
            min_orders_to_cancel: Minimum orders to try to cancel
            max_orders_to_cancel: Maximum orders to cancel

        Returns:
            Number of orders successfully cancelled
        """
        from config.strategy_config import EMERGENCY_CANCEL_FAR_ORDERS_ENABLED

        if not force and not EMERGENCY_CANCEL_FAR_ORDERS_ENABLED:
            return 0
        try:
            # Get open orders
            orders_resp = self.client.get_open_orders(symbol)
            if not orders_resp.get("success"):
                return 0

            order_list = orders_resp.get("data", {}).get("list", []) or []
            if not order_list:
                return 0

            # Build list of OPENING orders with distance from current price
            # Skip reduceOnly orders as they don't free margin when cancelled
            opening_orders = []
            reduce_only_count = 0

            for order in order_list:
                price = float(order.get("price", 0) or 0)
                order_id = order.get("orderId")
                order_side = order.get("side", "")
                order_link_id = order.get("orderLinkId", "")

                if price <= 0 or not order_id:
                    continue

                # Check if this is a reduceOnly/closing order
                is_reduce_only = self._is_reduce_only_order(order, order_link_id)

                if is_reduce_only:
                    reduce_only_count += 1
                    continue  # Skip - cancelling this won't free margin

                distance = abs(price - last_price)
                opening_orders.append((distance, price, order_id, order_side))

            # Log eligibility stats
            total_orders = len(order_list)
            eligible_count = len(opening_orders)
            logger.info(
                f"[{symbol}] 🚨 Margin freeing: {total_orders} total orders, "
                f"{eligible_count} eligible (opening), {reduce_only_count} skipped (reduceOnly)"
            )

            if not opening_orders:
                logger.warning(
                    f"[{symbol}] 🚨 No opening orders to cancel for margin freeing "
                    f"({reduce_only_count} reduceOnly orders preserved)"
                )
                return 0

            # Sort by distance (farthest first)
            opening_orders.sort(reverse=True)

            # Cancel farthest OPENING orders
            cancelled = 0
            for distance, price, order_id, side in opening_orders:
                if cancelled >= max_orders_to_cancel:
                    break

                cancel_result = self.client.cancel_order(symbol, order_id)
                if cancel_result.get("success"):
                    logger.warning(
                        f"[{symbol}] 🚨 EMERGENCY: Cancelled {side} OPENING order at {price:.6f} "
                        f"(distance {distance:.6f}) to free margin [reason=free_margin_far_open_order]"
                    )
                    cancelled += 1
                else:
                    logger.debug(
                        f"[{symbol}] Failed to cancel {order_id}: {cancel_result.get('error')}"
                    )

            if cancelled > 0:
                logger.warning(
                    f"[{symbol}] 🚨 Cancelled {cancelled} far OPENING orders to protect against liquidation "
                    f"({reduce_only_count} reduceOnly orders preserved)"
                )

            return cancelled

        except Exception as e:
            logger.error(f"[{symbol}] Error in emergency cancel: {e}")
            return 0

    def _emergency_partial_close(
        self,
        bot: Dict[str, Any],
        symbol: str,
        position_size: float,
        position_side: str,
        pct_to_liq: float,
        position_idx: Optional[int] = None,
        is_tier2: bool = False,
    ) -> bool:
        """
        Emergency partial close: reduce position size to free margin when near liquidation.

        This is a last-resort safety mechanism when:
        - Tier 1: Liquidation is dangerously close (< 20%) AND no margin/orders
        - Tier 2: Liquidation is extremely close (< 5%) - Absolute Floor
        """
        bot_id = bot.get("id")
        try:
            from config.strategy_config import (
                EMERGENCY_PARTIAL_CLOSE_ENABLED,
                EMERGENCY_PARTIAL_CLOSE_PCT,
                EMERGENCY_PARTIAL_CLOSE_TIER2_PCT,
                EMERGENCY_PARTIAL_CLOSE_COOLDOWN,
                EMERGENCY_PARTIAL_CLOSE_MAX_COUNT,
            )

            import time

            if not EMERGENCY_PARTIAL_CLOSE_ENABLED:
                return False

            # Check cooldown
            now = time.time()
            last_partial_close = bot.get("_last_emergency_partial_close", 0)
            if (now - last_partial_close) < EMERGENCY_PARTIAL_CLOSE_COOLDOWN:
                return False

            # Death spiral protection: If too many emergency closes, close entire position and stop
            current_count = bot.get("_emergency_partial_close_count", 0)
            if current_count >= EMERGENCY_PARTIAL_CLOSE_MAX_COUNT:
                logger.error(
                    f"[{symbol}:{bot_id[:8]}] 🛑 DEATH SPIRAL PROTECTION: {current_count} emergency closes reached "
                    f"(max: {EMERGENCY_PARTIAL_CLOSE_MAX_COUNT})! Closing entire position and stopping bot."
                )
                bot["error_code"] = "DEATH_SPIRAL"
                bot = self._transition_to_stop_cleanup_state(
                    bot,
                    symbol,
                    target_status="risk_stopped",
                    cleanup_reason="death_spiral_protection",
                    final_last_error=(
                        f"Death spiral protection: {current_count} emergency closes"
                    ),
                )
                return True

            close_pct = (
                EMERGENCY_PARTIAL_CLOSE_TIER2_PCT
                if is_tier2
                else EMERGENCY_PARTIAL_CLOSE_PCT
            )
            tier_label = (
                "TIER 2 (ABSOLUTE FLOOR)" if is_tier2 else "TIER 1 (MARGIN EXHAUSTED)"
            )

            # Calculate quantity to close
            close_qty = abs(position_size) * (close_pct / 100.0)

            # Ensure close_qty meets minimum order requirements
            instrument = self._get_instrument_info(symbol)
            if instrument:
                min_order_qty = instrument.get("min_order_qty", 0)
                qty_step = instrument.get("qty_step", 0)

                # Round to qty_step first
                if qty_step > 0:
                    close_qty = self._round_to_step(close_qty, qty_step, round_down=True)

                # Adjust if below minimum
                if close_qty < min_order_qty:
                    original_qty = close_qty
                    if min_order_qty <= abs(position_size):
                        # Close minimum allowed quantity
                        close_qty = min_order_qty
                        logger.warning(
                            f"[{symbol}:{bot_id[:8]}] Emergency close qty adjusted: "
                            f"{original_qty:.6f} -> {close_qty:.6f} (min_order_qty)"
                        )
                    else:
                        # Position smaller than minimum - close entire position
                        close_qty = abs(position_size)
                        if qty_step > 0:
                            close_qty = self._round_to_step(close_qty, qty_step, round_down=True)
                        logger.warning(
                            f"[{symbol}:{bot_id[:8]}] Emergency close: position ({abs(position_size):.6f}) "
                            f"< min_order_qty ({min_order_qty:.6f}), closing entire position"
                        )

            logger.warning(
                f"[{symbol}] 🚨 EMERGENCY PARTIAL CLOSE TRIGGERED: {tier_label} "
                f"at {pct_to_liq:.2f}% to liq. Closing {close_pct}% ({close_qty:.4f})"
            )

            close_side = "Sell" if position_side.lower() == "buy" else "Buy"

            order_result = self._create_order_checked(
                bot=bot,
                symbol=symbol,
                side=close_side,
                qty=close_qty,
                order_type="Market",
                reduce_only=True,
                order_link_id=self._build_close_order_link_id(bot_id, "EMRG"),
                position_idx=position_idx,
            )

            if self._is_position_empty_close_result(order_result):
                logger.info(
                    "[%s] Emergency partial close skipped: position already flat",
                    symbol,
                )
                return True
            if order_result.get("success"):
                bot["_last_emergency_partial_close"] = now
                bot["_emergency_partial_close_count"] = (
                    bot.get("_emergency_partial_close_count", 0) + 1
                )
                return True
            else:
                self._hard_fail_close(
                    bot, symbol, "emergency_partial_close", order_result.get("error")
                )
                return False

        except Exception as e:
            self._hard_fail_close(bot, symbol, "emergency_partial_close_exception", e)
            return False

    @staticmethod
    def _clear_pause_runtime_state(bot: Dict[str, Any]) -> None:
        """Clear transient pause/recovery markers before resuming a bot."""
        for key in (
            "pause_reason",
            "pause_reason_type",
            "paused_at",
            "pause_unrealized_pnl",
            "recovery_entry_pnl",
            "_last_pause_recovery_check",
            "_last_recovery_check",
            "_neutral_trend_exit",
        ):
            bot.pop(key, None)

    @staticmethod
    def _trend_exit_guard_is_active(bot: Dict[str, Any]) -> bool:
        return (
            bot.get("regime_effective") in ("UP", "DOWN")
            and bot.get("regime_confidence") in ("high", "locked")
        )

    def _refresh_multi_tf_regime_snapshot(
        self, bot: Dict[str, Any], symbol: str, force: bool = False
    ) -> bool:
        """
        Refresh the cached multi-timeframe regime snapshot when needed.
        """
        try:
            now_ts = self.client._get_now_ts()
            last_regime_eval = self._safe_float(bot.get("_regime_last_eval_ts"), 0.0)
            if not force and now_ts - last_regime_eval < INDICATOR_CACHE_TTL_5M15M:
                return False

            primary_indicators = self.indicator_service.compute_indicators(
                symbol,
                interval=REGIME_TF_PRIMARY,
                limit=200,
            )
            secondary_indicators = self.indicator_service.compute_indicators(
                symbol,
                interval=REGIME_TF_SECONDARY,
                limit=200,
            )
            if primary_indicators.get("close") and secondary_indicators.get("close"):
                self._update_multi_tf_regime(
                    bot=bot,
                    symbol=symbol,
                    primary_indicators=primary_indicators,
                    secondary_indicators=secondary_indicators,
                )
            bot["_regime_last_eval_ts"] = now_ts
            return True
        except Exception as e:
            logger.debug(f"[{symbol}] Regime snapshot failed: {e}")
            return False

    def _check_trend_exit_pause(self, bot: Dict[str, Any]) -> Dict[str, Any]:
        """
        Keep a trend-exit-paused neutral bot progressing while it waits to close
        a green position or for the market regime to normalize.
        """
        trend_exit_state = bot.get("_neutral_trend_exit") or {}
        if not trend_exit_state:
            return bot

        symbol = bot.get("symbol")
        if not symbol:
            return bot

        now_ts = self.client._get_now_ts()
        last_exit_ts = self._safe_float(trend_exit_state.get("last_exit_ts"), 0.0)
        waiting_for_green = bool(trend_exit_state.get("waiting_for_green"))
        check_interval = 30 if waiting_for_green else 60
        if now_ts - last_exit_ts < check_interval:
            return bot

        try:
            positions_resp = self.client.get_positions()
        except Exception as exc:
            logger.debug("[%s] Trend-exit pause check failed: %s", symbol, exc)
            return bot

        if not positions_resp.get("success"):
            return bot

        position = None
        for candidate in positions_resp.get("data", {}).get("list", []) or []:
            if candidate.get("symbol") != symbol:
                continue
            if self._safe_float(candidate.get("size"), 0.0) <= 0:
                continue
            position = candidate
            break

        if position:
            unrealized = self._safe_float(position.get("unrealisedPnl"), 0.0)
            if unrealized <= 0:
                if not waiting_for_green:
                    trend_exit_state["waiting_for_green"] = True
                    trend_exit_state["last_exit_ts"] = now_ts
                    bot["_neutral_trend_exit"] = trend_exit_state
                    bot["pause_reason"] = (
                        "Trend exit guard: paused; waiting for green to close position"
                    )
                    bot["pause_reason_type"] = "trend_exit_guard"
                    bot["last_error"] = bot["pause_reason"]
                    return self.bot_storage.save_bot(bot)
                return bot

            close_side = "Sell" if position.get("side") == "Buy" else "Buy"
            position_idx = int(position.get("positionIdx", 0) or 0)
            close_result = self._create_order_checked(
                bot=bot,
                symbol=symbol,
                side=close_side,
                qty=self._safe_float(position.get("size"), 0.0),
                order_type="Market",
                price=None,
                reduce_only=True,
                time_in_force="GTC",
                order_link_id=self._build_close_order_link_id(bot.get("id"), "TRND"),
                position_idx=position_idx,
            )
            if self._is_position_empty_close_result(close_result):
                logger.info(
                    "[%s] Trend-exit pause close skipped: position already flat",
                    symbol,
                )
            elif not close_result.get("success"):
                logger.warning(
                    "[%s] Trend-exit pause close retry failed: %s",
                    symbol,
                    close_result.get("error"),
                )
                return bot

            trend_exit_state["waiting_for_green"] = False
            trend_exit_state["last_exit_ts"] = now_ts
            bot["_neutral_trend_exit"] = trend_exit_state
            bot["pause_reason"] = (
                "Trend exit guard: closed position; waiting for regime to normalize"
            )
            bot["pause_reason_type"] = "trend_exit_guard"
            bot["last_error"] = bot["pause_reason"]
            return self.bot_storage.save_bot(bot)

        trend_exit_state["waiting_for_green"] = False
        trend_exit_state["last_exit_ts"] = now_ts
        bot["_neutral_trend_exit"] = trend_exit_state
        self._refresh_multi_tf_regime_snapshot(bot, symbol, force=True)
        return self._check_resume_conditions(bot)

    def _smart_pause_bot(
        self,
        bot: Dict[str, Any],
        symbol: str,
        reason: str,
        reason_type: str,
    ) -> Dict[str, Any]:
        """
        Smart pause: Instead of just pausing, track the reason and wait for position recovery.

        Args:
            bot: Bot dict
            symbol: Trading symbol
            reason: Human-readable reason for pause
            reason_type: Machine-readable type (danger_zone, regime_blocked, regime_illiquid, out_of_range)

        Returns:
            Updated bot dict
        """
        try:
            from config.strategy_config import (
                SMART_PAUSE_RECOVERY_ENABLED,
                SMART_PAUSE_WAIT_FOR_PROFIT,
            )

            # Check if position exists and is in loss
            positions_resp = self.client.get_positions()
            position = None
            unrealized_pnl = 0

            if positions_resp.get("success"):
                positions = positions_resp.get("data", {}).get("list", []) or []
                position = next(
                    (
                        p
                        for p in positions
                        if p.get("symbol") == symbol and float(p.get("size", 0)) > 0
                    ),
                    None,
                )
                if position:
                    unrealized_pnl = float(position.get("unrealisedPnl", 0))

            # Save pause state
            bot["pause_reason"] = reason
            bot["pause_reason_type"] = reason_type
            bot["paused_at"] = self.client._get_now_ts()
            bot["pause_unrealized_pnl"] = unrealized_pnl

            # If smart recovery enabled and position is in loss, use "recovering" status
            if (
                SMART_PAUSE_RECOVERY_ENABLED
                and SMART_PAUSE_WAIT_FOR_PROFIT
                and position
                and unrealized_pnl < 0
            ):
                bot["status"] = "recovering"
                bot["recovery_entry_pnl"] = unrealized_pnl
                logger.warning(
                    f"[{symbol}] 🔄 RECOVERING: Paused due to '{reason}' with position in loss "
                    f"(PnL: ${unrealized_pnl:.2f}). Waiting for profit before closing."
                )
            else:
                bot["status"] = "paused"
                logger.warning(f"[{symbol}] ⏸️ PAUSED: {reason}")

            bot["last_error"] = reason
            return self.bot_storage.save_bot(bot)

        except Exception as e:
            logger.error(f"[{symbol}] Error in smart pause: {e}")
            bot["status"] = "paused"
            bot["last_error"] = reason
            return self.bot_storage.save_bot(bot)

    def _check_recovery_status(self, bot: Dict[str, Any]) -> Dict[str, Any]:
        """
        Check if a recovering bot should close position or resume.

        Returns:
            Updated bot dict, or None if no action needed
        """
        try:
            from config.strategy_config import (
                SMART_PAUSE_RECOVERY_ENABLED,
                SMART_PAUSE_MIN_PROFIT_PCT,
                SMART_PAUSE_MAX_WAIT_HOURS,
                SMART_PAUSE_AUTO_RESUME,
                SMART_PAUSE_CHECK_INTERVAL,
            )

            if not SMART_PAUSE_RECOVERY_ENABLED:
                return bot

            if bot.get("status") != "recovering":
                return bot

            symbol = bot.get("symbol")

            # Check interval
            last_check = bot.get("_last_recovery_check", 0)
            now = self.client._get_now_ts()
            if now - last_check < SMART_PAUSE_CHECK_INTERVAL:
                return bot

            bot["_last_recovery_check"] = now

            # Check max wait time
            paused_at = bot.get("paused_at", now)
            hours_waiting = (now - paused_at) / 3600
            if hours_waiting > SMART_PAUSE_MAX_WAIT_HOURS:
                logger.warning(
                    f"[{symbol}] ⏰ Recovery timeout ({hours_waiting:.1f}h > {SMART_PAUSE_MAX_WAIT_HOURS}h). "
                    f"Closing position at current price."
                )
                self._close_position_and_pause(bot, symbol, "Recovery timeout")
                return bot

            # Get current position
            positions_resp = self.client.get_positions()
            if not positions_resp.get("success"):
                return bot

            positions = positions_resp.get("data", {}).get("list", []) or []
            position = next((p for p in positions if p.get("symbol") == symbol), None)

            if not position or float(position.get("size", 0)) <= 0:
                # Position already closed - check if we can resume
                if SMART_PAUSE_AUTO_RESUME:
                    return self._check_resume_conditions(bot)
                else:
                    bot["status"] = "paused"
                    return self.bot_storage.save_bot(bot)

            # Check PnL
            unrealized_pnl = float(position.get("unrealisedPnl", 0))
            entry_price = float(position.get("avgPrice", 0))
            position_value = float(position.get("positionValue", 0))

            if position_value > 0:
                pnl_pct = (unrealized_pnl / position_value) * 100
            else:
                pnl_pct = 0

            # Check if profitable enough to close
            if pnl_pct >= SMART_PAUSE_MIN_PROFIT_PCT:
                logger.info(
                    f"[{symbol}] ✅ Recovery SUCCESS! Position now profitable "
                    f"(PnL: ${unrealized_pnl:.2f}, {pnl_pct:.2f}%). Closing position."
                )
                self._close_position_and_pause(
                    bot, symbol, "Recovery successful - position closed at profit"
                )

                # Check if we can resume
                if SMART_PAUSE_AUTO_RESUME:
                    return self._check_resume_conditions(bot)

            else:
                # Still waiting for recovery
                entry_pnl = bot.get("recovery_entry_pnl", unrealized_pnl)
                improvement = unrealized_pnl - entry_pnl
                logger.debug(
                    f"[{symbol}] 🔄 Still recovering... PnL: ${unrealized_pnl:.2f} ({pnl_pct:.2f}%), "
                    f"improvement: ${improvement:.2f}, waiting {hours_waiting:.1f}h"
                )

            return bot
        except Exception as e:
            logger.error(f"Recovery status check error: {e}")
            return bot

    def _check_smart_pause_recovery(self, bot: Dict[str, Any]) -> Dict[str, Any]:
        """
        Smart Pause Recovery (#28): Check if a paused bot should auto-resume.
        """
        try:
            from config.strategy_config import SMART_PAUSE_CHECK_INTERVAL

            # Rate limit recovery checks
            last_check = bot.get("_last_pause_recovery_check", 0)
            now = time.time()
            if now - last_check < SMART_PAUSE_CHECK_INTERVAL:
                return bot

            bot["_last_pause_recovery_check"] = now
            return self._check_resume_conditions(bot)
        except Exception as e:
            logger.error(f"Smart pause recovery check error: {e}")
            return bot

            return bot

        except Exception as e:
            logger.error(f"[{bot.get('symbol')}] Error checking recovery: {e}")
            return bot

    def _check_resume_conditions(self, bot: Dict[str, Any]) -> Dict[str, Any]:
        """
        Check if the original pause reason has resolved and bot can resume.

        Returns:
            Updated bot dict
        """
        try:
            symbol = bot.get("symbol")
            reason_type = bot.get("pause_reason_type", "")

            can_resume = False
            resume_reason = ""

            if reason_type == "danger_zone":
                # Check if danger zone has cleared
                if hasattr(self, "danger_zone_service") and self.danger_zone_service:
                    danger_result = self.danger_zone_service.check_danger_zone(symbol)
                    if not danger_result.get("is_dangerous", True):
                        can_resume = True
                        resume_reason = "Danger zone cleared"

            elif reason_type == "regime_blocked":
                # Check if regime is no longer blocked
                if hasattr(self, "entry_filter") and self.entry_filter:
                    regime_result = self.entry_filter.classify_regime(
                        symbol, include_btc_filter=bot.get("btc_correlation_filter_enabled", True)
                    )
                    regime = regime_result.get("regime", "blocked")
                    if regime not in ("blocked", "illiquid"):
                        can_resume = True
                        resume_reason = f"Regime normalized: {regime}"

            elif reason_type == "regime_illiquid":
                # Check if liquidity is back
                if hasattr(self, "entry_filter") and self.entry_filter:
                    regime_result = self.entry_filter.classify_regime(
                        symbol, include_btc_filter=bot.get("btc_correlation_filter_enabled", True)
                    )
                    regime = regime_result.get("regime", "illiquid")
                    if regime != "illiquid":
                        can_resume = True
                        resume_reason = f"Liquidity restored: {regime}"

            elif reason_type == "trend_exit_guard":
                self._refresh_multi_tf_regime_snapshot(bot, symbol, force=True)
                if not self._trend_exit_guard_is_active(bot):
                    can_resume = True
                    resume_reason = "Trend regime normalized"

            elif reason_type == "out_of_range":
                # Out of range bots should stay paused until user restarts
                can_resume = False

            if can_resume:
                logger.info(f"[{symbol}] ▶️ AUTO-RESUMING: {resume_reason}")
                bot["status"] = "running"
                bot["last_error"] = None
                self._clear_pause_runtime_state(bot)
                return self.bot_storage.save_bot(bot)
            else:
                # Stay paused
                bot["status"] = "paused"
                return self.bot_storage.save_bot(bot)

        except Exception as e:
            logger.error(f"[{bot.get('symbol')}] Error checking resume conditions: {e}")
            bot["status"] = "paused"
            return self.bot_storage.save_bot(bot)

    def _close_position_and_pause(
        self, bot: Dict[str, Any], symbol: str, reason: str
    ) -> bool:
        """
        Close position with market order and set bot to paused.

        Returns:
            True if position was closed
        """
        bot_id = bot.get("id")
        try:
            positions_resp = self.client.get_positions(skip_cache=True)
            if not positions_resp.get("success"):
                return False

            positions = positions_resp.get("data", {}).get("list", []) or []
            closed_any = False

            for position in positions:
                if position.get("symbol") != symbol:
                    continue
                if float(position.get("size", 0)) <= 0:
                    continue

                size = float(position.get("size", 0))
                side = position.get("side", "Buy")
                close_side = "Sell" if side == "Buy" else "Buy"
                position_idx = int(position.get("positionIdx", 0) or 0)

                # Place market order to close
                price = self._safe_float(
                    position.get("markPrice"), None
                ) or self._safe_float(position.get("avgPrice"), None)
                order_result = self._create_order_checked(
                    bot=bot,
                    symbol=symbol,
                    side=close_side,
                    qty=size,
                    order_type="Market",
                    price=price,
                    reduce_only=True,
                    time_in_force="GTC",
                    order_link_id=self._build_close_order_link_id(bot_id, "PAUS"),
                    position_idx=position_idx,
                )

                if self._is_position_empty_close_result(order_result):
                    logger.info(
                        "[%s] Position already flat while pausing: %s",
                        symbol,
                        reason,
                    )
                elif order_result.get("success"):
                    logger.info(f"[{symbol}] ✅ Position closed: {reason}")
                    closed_any = True
                else:
                    error_code = (
                        order_result.get("error") or "close_position_and_pause_failed"
                    )
                    self._hard_fail_close(
                        bot, symbol, "close_position_and_pause", error_code
                    )

            if closed_any:
                bot["status"] = "paused"
                bot["last_error"] = reason
                self.bot_storage.save_bot(bot)
                return True
            return True  # Already closed

        except Exception as e:
            self._hard_fail_close(bot, symbol, "close_position_and_pause_exception", e)
            return False



    def run_bot_cycle(
        self, bot: Dict[str, Any], fast_refill_tick: bool = False
    ) -> Dict[str, Any]:
        """Execute one logical cycle for a single bot."""
        bot_id = bot.get("id")
        acquired, lock = self._try_acquire_bot_run_lock(bot_id)
        if not acquired:
            deferred_bot = dict(bot or {})
            deferred_bot["_cycle_lock_busy"] = True
            deferred_bot["_cycle_lock_busy_reason"] = "bot_cycle_lock_busy"
            return deferred_bot
        try:
            incoming_bot = dict(bot or {})
            if bot_id:
                # Always read from disk to avoid stale-cache races with app.py.
                fresh_bot = None
                try:
                    fresh_bot = self.bot_storage.get_bot_fresh(bot_id)
                except (AttributeError, TypeError):
                    fresh_bot = self.bot_storage.get_bot(bot_id)
                if not isinstance(fresh_bot, dict):
                    fresh_bot = self.bot_storage.get_bot(bot_id)
                if fresh_bot:
                    bot = self._merge_cycle_runtime_context(
                        fresh_bot,
                        incoming_bot=incoming_bot,
                    )

            if bot.get("status") == "stop_cleanup_pending" or bool(
                bot.get("stop_cleanup_pending")
            ):
                return self._monitor_stop_cleanup_pending(bot)

            # Handle recovering bots - check if position is profitable or resume conditions met
            if bot.get("status") == "recovering":
                return self._check_recovery_status(bot)

            # =========================================================
            # Paused bots may still need maintenance checks even though they no
            # longer place fresh opening orders.
            # =========================================================
            if bot.get("status") == "paused":
                if bot.get("_neutral_trend_exit"):
                    return self._check_trend_exit_pause(bot)

                pause_reason_type = str(bot.get("pause_reason_type") or "").strip()
                if (
                    SMART_PAUSE_RECOVERY_ENABLED
                    and pause_reason_type in AUTO_RESUMABLE_PAUSE_REASON_TYPES
                ):
                    bot = self._check_smart_pause_recovery(bot)
                    if bot.get("status") == "running":
                        logger.warning(
                            f"[{bot.get('symbol')}] Smart Pause Recovery triggered - resuming bot"
                        )

            if bot.get("status") != "running":
                return bot

            trading_env = (bot.get("trading_env") or "mainnet").strip().lower()
            # Allow backtest mode to pass through
            if trading_env != "mainnet" and trading_env != "backtest":
                stop_time_iso = datetime.now(timezone.utc).isoformat()
                bot["status"] = "stopped"
                bot["started_at"] = None
                bot["last_run_at"] = stop_time_iso
                bot["last_error"] = "Testnet disabled. Mainnet only."
                self._reset_auto_pilot_on_stop(bot)
                self.bot_storage.save_bot(bot)
                return bot

            if bot.get("paper_trading"):
                stop_time_iso = datetime.now(timezone.utc).isoformat()
                bot["status"] = "stopped"
                bot["started_at"] = None
                bot["last_run_at"] = stop_time_iso
                bot["last_error"] = "paper_trading disabled. Mainnet only."
                self._reset_auto_pilot_on_stop(bot)
                self.bot_storage.save_bot(bot)
                return bot

            self._mark_runner_pickup(bot, fast_refill_tick=fast_refill_tick)

            # C1: Record control_version at cycle start so mid-cycle checks can
            # detect if the UI changed the bot's control state.
            bot["_cycle_start_control_version"] = int(
                bot.get("control_version") or 0
            )

            # Get the appropriate client for this bot's environment
            # Temporarily swap self.client for this bot's environment-specific client
            # This allows all helper methods to use the correct environment automatically
            original_client = self.client
            self.client = self._get_client_for_bot(bot)

            try:
                return self._run_bot_cycle_impl(bot, fast_refill_tick=fast_refill_tick)
            finally:
                # Always restore original client
                self.client = original_client
        finally:
            self._release_bot_run_lock(lock)










    def _is_auto_pilot_innovation_symbol(
        self,
        instrument: Optional[Dict[str, Any]],
    ) -> bool:
        if not isinstance(instrument, dict) or not instrument:
            return False

        for field in ("innovation", "innovationFlag", "isInnovation"):
            raw = str(instrument.get(field) or "").strip().lower()
            if raw in {"1", "true", "yes", "y"}:
                return True

        for field in ("symbolType", "displayName", "contractType"):
            raw = str(instrument.get(field) or "").strip().lower()
            if "innovation" in raw or "experimental" in raw or "novel" in raw:
                return True

        return False





    def _log_auto_pilot_universe_summary(
        self,
        settings: Dict[str, Any],
        stats: Dict[str, Any],
    ) -> None:
        excluded = stats.get("excluded", {}) if isinstance(stats, dict) else {}
        logger.info(
            "[Auto-Pilot] Universe mode=%s strong_filters=%s innovation=%s new_listings=%s "
            "pattern_blacklist=%s symbol_blacklist=%d vol_caps=%s scan_cap=%s active_usdt=%d pre_eligible=%d scan_universe=%d scanned=%d "
            "blacklist=%d innovation=%d new_listing=%d quality=%d volatility=%d "
            "final_eligible=%d",
            settings.get("universe_mode") or AUTO_PILOT_UNIVERSE_MODE_DEFAULT_SAFE,
            "on" if settings.get("strong_filters_enabled") else "off",
            "excluded" if settings.get("exclude_innovation") else "allowed",
            (
                f"<{int(round(self._safe_float(settings.get('new_listing_min_days'), 0.0)))}d excluded"
                if settings.get("exclude_new_listings")
                else "allowed"
            ),
            "on" if settings.get("symbol_name_blacklist_patterns") else "off",
            len(settings.get("symbol_blacklist") or []),
            "on" if settings.get("volatility_cap_enabled") else "off",
            (
                int(settings.get("max_scan_symbols", 0) or 0)
                if int(settings.get("max_scan_symbols", 0) or 0) > 0
                else "off"
            ),
            int(stats.get("active_usdt", 0) or 0),
            int(stats.get("eligible_pre_scan", 0) or 0),
            int(stats.get("scan_universe", 0) or 0),
            int(stats.get("scanned", 0) or 0),
            int(excluded.get("blacklist", 0) or 0),
            int(excluded.get("innovation", 0) or 0),
            int(excluded.get("new_listing", 0) or 0),
            int(excluded.get("quality", 0) or 0),
            int(excluded.get("volatility", 0) or 0),
            int(stats.get("eligible_final", 0) or 0),
        )

        sample_parts: List[str] = []
        samples = stats.get("samples", {}) if isinstance(stats, dict) else {}
        for bucket in ("blacklist", "innovation", "new_listing", "quality", "volatility"):
            bucket_samples = samples.get(bucket) or []
            if bucket_samples:
                sample_parts.append(f"{bucket}={','.join(bucket_samples[:2])}")
        if sample_parts:
            logger.info("[Auto-Pilot] Universe samples: %s", " | ".join(sample_parts))



    @staticmethod
    def _to_float(value: Any, default: float = 0.0) -> float:
        try:
            return float(value)
        except (TypeError, ValueError):
            return default

    def _get_cycle_now_ts(self) -> float:
        client = getattr(self, "client", None)
        client_now = getattr(client, "_get_now_ts", None)
        if callable(client_now):
            try:
                return float(client_now())
            except Exception:
                pass
        return time.time()

    def _track_position_timing(
        self,
        bot: Dict[str, Any],
        symbol: str,
        position: Dict[str, Any],
    ) -> Dict[str, float]:
        now_ts = self._get_cycle_now_ts()
        safe_symbol = str(symbol or position.get("symbol") or "").strip().upper()
        pos_side = str(position.get("side") or "").strip()
        pos_idx = int(self._safe_float(position.get("positionIdx"), 0.0))
        timing_key = f"{safe_symbol}:{pos_side}:{pos_idx}"
        stale_after = float(
            max(
                120,
                QUICK_PROFIT_FAST_PROFIT_WINDOW_SECONDS,
                PROFIT_LOCK_FAST_ARM_WINDOW_SECONDS,
            )
        )

        timing_state = bot.get("_position_timing_state")
        if not isinstance(timing_state, dict):
            timing_state = {}

        state = timing_state.get(timing_key)
        if not isinstance(state, dict):
            state = {}

        opened_at_ts = self._safe_float(state.get("opened_at_ts"), 0.0)
        last_seen_ts = self._safe_float(state.get("last_seen_ts"), 0.0)
        if opened_at_ts <= 0 or (last_seen_ts > 0 and now_ts - last_seen_ts > stale_after):
            opened_at_ts = now_ts

        state["opened_at_ts"] = opened_at_ts
        state["last_seen_ts"] = now_ts
        state["entry_price"] = self._safe_float(position.get("avgPrice"), 0.0)
        state["size"] = max(self._safe_float(position.get("size"), 0.0), 0.0)
        state["position_side"] = pos_side
        state["position_idx"] = pos_idx
        timing_state[timing_key] = state

        for existing_key in list(timing_state.keys()):
            if not existing_key.startswith(f"{safe_symbol}:") or existing_key == timing_key:
                continue
            existing_state = timing_state.get(existing_key) or {}
            existing_last_seen = self._safe_float(existing_state.get("last_seen_ts"), 0.0)
            if existing_last_seen <= 0 or now_ts - existing_last_seen > stale_after:
                timing_state.pop(existing_key, None)

        bot["_position_timing_state"] = timing_state
        return {
            "opened_at_ts": opened_at_ts,
            "age_sec": max(0.0, now_ts - opened_at_ts),
        }



    def _scan_auto_pilot_candidates_live(
        self,
        bot: Dict[str, Any],
    ) -> Tuple[List[Dict[str, Any]], int]:
        top_symbols = self._get_auto_pilot_top_symbols(bot)
        scan_universe = len(top_symbols or [])
        scan_results = (
            self.neutral_scanner.scan(top_symbols)
            if hasattr(self, "neutral_scanner") and top_symbols
            else []
        )
        if not scan_results:
            return [], scan_universe

        eligible_results = self._filter_auto_pilot_scan_results(bot, scan_results)
        if not eligible_results:
            return [], scan_universe

        return self._rank_auto_pilot_candidates(bot, eligible_results), scan_universe

    def _prepare_auto_pilot_candidate_cache(
        self,
        bot: Dict[str, Any],
        *,
        reason: str,
        force: bool = False,
    ) -> Optional[Dict[str, Any]]:
        settings = self._get_auto_pilot_candidate_cache_settings(bot)
        if not settings["enabled"]:
            return None

        cache_service = self._get_auto_pilot_candidate_cache_service(bot)
        if cache_service is None:
            return None

        now_ts = self._get_cycle_now_ts()
        existing = cache_service.get_snapshot()
        prepared_ts = self._safe_float(existing.get("prepared_ts"), 0.0)
        if (
            not force
            and prepared_ts > 0
            and (now_ts - prepared_ts) < settings["refresh_seconds"]
        ):
            return existing

        ranked_results, scan_universe = self._scan_auto_pilot_candidates_live(bot)
        if not ranked_results:
            return None

        prepared_at = datetime.now(timezone.utc).isoformat()
        cached_candidates: List[Dict[str, Any]] = []
        for raw_candidate in ranked_results[: settings["max_items"]]:
            candidate = dict(raw_candidate)
            candidate["_auto_pilot_cached_at"] = prepared_at
            cached_candidates.append(candidate)

        snapshot = cache_service.store(
            candidates=cached_candidates,
            source=reason,
            scan_universe=scan_universe,
            now_ts=now_ts,
            prepared_at=prepared_at,
        )
        top_candidate = cached_candidates[0] if cached_candidates else {}
        top_symbol = str(top_candidate.get("symbol") or "").strip().upper() or "n/a"
        top_score = self._to_float(
            top_candidate.get("_auto_pilot_score"),
            self._to_float(top_candidate.get("neutral_score")),
        )
        logger.info(
            "[Auto-Pilot] Candidate cache refreshed mode=%s: %d candidates, top=%s:%.1f",
            self._get_auto_pilot_universe_mode(bot),
            len(cached_candidates),
            top_symbol,
            top_score,
        )
        return snapshot

    def _maybe_prepare_auto_pilot_candidate_cache(
        self,
        bot: Dict[str, Any],
        *,
        reason: str = "background",
    ) -> None:
        try:
            self._prepare_auto_pilot_candidate_cache(
                bot,
                reason=reason,
                force=False,
            )
        except Exception as exc:
            logger.debug("[Auto-Pilot] Candidate cache refresh skipped: %s", exc)

    def _get_ranked_auto_pilot_candidates(
        self,
        bot: Dict[str, Any],
        *,
        reason: str,
    ) -> List[Dict[str, Any]]:
        bot["_auto_pilot_candidate_source_hint"] = None
        settings = self._get_auto_pilot_candidate_cache_settings(bot)
        if settings["enabled"]:
            cache_service = self._get_auto_pilot_candidate_cache_service(bot)
            if cache_service is not None:
                fresh_snapshot = cache_service.get_fresh(
                    settings["max_age_seconds"],
                    now_ts=self._get_cycle_now_ts(),
                )
                if fresh_snapshot and fresh_snapshot.get("candidates"):
                    logger.info(
                        "[Auto-Pilot] Using fresh Auto Pilot candidate cache mode=%s (age=%ss)",
                        self._get_auto_pilot_universe_mode(bot),
                        int(round(self._safe_float(fresh_snapshot.get("age_seconds"), 0.0))),
                    )
                    bot["_auto_pilot_candidate_source_hint"] = "cache"
                    return [
                        dict(candidate)
                        for candidate in (fresh_snapshot.get("candidates") or [])
                    ]

            refreshed_snapshot = self._prepare_auto_pilot_candidate_cache(
                bot,
                reason=reason,
                force=True,
            )
            if refreshed_snapshot and refreshed_snapshot.get("candidates"):
                bot["_auto_pilot_candidate_source_hint"] = "live"
                return [
                    dict(candidate)
                    for candidate in (refreshed_snapshot.get("candidates") or [])
                ]

        live_results, _scan_universe = self._scan_auto_pilot_candidates_live(bot)
        if live_results:
            bot["_auto_pilot_candidate_source_hint"] = "live"
        return live_results



