    def _refresh_persisted_bot_snapshot(
        self, bot: Dict[str, Any]
    ) -> Dict[str, Any]:
        bot_id = str((bot or {}).get("id") or "").strip()
        if not bot_id:
            return bot

        get_bot = getattr(self.bot_storage, "get_bot", None)
        if not callable(get_bot):
            return bot

        try:
            fresh_bot = get_bot(bot_id)
        except Exception as exc:
            logger.debug(
                "[Auto-Pilot:%s] Persisted bot refresh failed before save: %s",
                bot_id[:8] or "n/a",
                exc,
            )
            return bot

        if isinstance(fresh_bot, dict) and fresh_bot:
            return fresh_bot
        return bot

    @staticmethod
    def _normalize_auto_pilot_candidate_source(source: Any) -> Optional[str]:
        normalized = str(source or "").strip().lower()
        return normalized if normalized in {"cache", "live"} else None

    def _set_auto_pilot_pick_runtime_state(
        self,
        bot: Optional[Dict[str, Any]],
        *,
        search_status: Optional[str],
        pick_status: Optional[str],
        block_reason: Optional[str] = None,
        top_candidate: Optional[Dict[str, Any]] = None,
        candidate_source: Optional[str] = None,
    ) -> None:
        if not bot:
            return

        candidate = top_candidate or {}
        raw_score = candidate.get("_auto_pilot_score")
        if raw_score is None:
            raw_score = candidate.get("neutral_score")
        top_score = round(self._to_float(raw_score), 2) if raw_score is not None else None
        top_symbol = str(candidate.get("symbol") or "").strip().upper() or None
        top_mode = str(candidate.get("recommended_mode") or "").strip().lower() or None
        top_eligibility = (
            str(candidate.get("_auto_pilot_eligibility_status") or "").strip() or None
        )

        bot["auto_pilot_search_status"] = search_status
        bot["auto_pilot_pick_status"] = pick_status
        bot["auto_pilot_block_reason"] = block_reason
        bot["auto_pilot_top_candidate_symbol"] = top_symbol
        bot["auto_pilot_top_candidate_score"] = top_score
        bot["auto_pilot_top_candidate_mode"] = top_mode
        bot["auto_pilot_top_candidate_eligibility"] = top_eligibility
        bot["auto_pilot_candidate_source"] = self._normalize_auto_pilot_candidate_source(
            candidate_source
        )




    def _log_auto_pilot_pick_blocked_by_loss_budget(
        self,
        bot: Dict[str, Any],
        budget_state: Dict[str, Any],
        *,
        top_candidate: Optional[Dict[str, Any]] = None,
        candidate_source: Optional[str] = None,
    ) -> None:
        if not self._get_auto_pilot_loss_budget_guard_settings(bot)["logging_enabled"]:
            return

        candidate = top_candidate or {}
        top_symbol = str(candidate.get("symbol") or "").strip().upper() or "n/a"
        raw_score = candidate.get("_auto_pilot_score")
        if raw_score is None:
            raw_score = candidate.get("neutral_score")
        top_score = self._to_float(raw_score) if raw_score is not None else None
        top_score_text = f"{top_score:.1f}" if top_score is not None else "n/a"
        top_mode = str(candidate.get("recommended_mode") or "").strip().lower() or "n/a"
        top_eligibility = (
            str(candidate.get("_auto_pilot_eligibility_status") or "").strip() or "n/a"
        )
        source = self._normalize_auto_pilot_candidate_source(candidate_source) or "n/a"
        remaining_pct = round(
            self._safe_float(budget_state.get("remaining_pct"), 0.0) * 100.0,
            2,
        )
        remaining_usdt = round(
            self._safe_float(budget_state.get("remaining_usdt"), 0.0),
            2,
        )
        loss_budget_usdt = round(
            self._safe_float(budget_state.get("loss_budget_usdt"), 0.0),
            2,
        )

        signature = (
            f"{top_symbol}|{top_score_text}|{top_mode}|{top_eligibility}|{source}|"
            f"{remaining_pct:.2f}|{remaining_usdt:.2f}|{loss_budget_usdt:.2f}"
        )
        now_ts = self._get_cycle_now_ts()
        cache = self._get_auto_pilot_pick_block_log_cache()
        log_key = self._get_auto_pilot_pick_block_log_key(bot)
        previous = cache.get(log_key) or {}
        last_signature = str(previous.get("signature") or "")
        last_logged_ts = self._safe_float(previous.get("last_logged_ts"), 0.0)
        should_log = (
            signature != last_signature
            or (now_ts - last_logged_ts) >= AUTO_PILOT_PICK_BLOCK_LOG_THROTTLE_SECONDS
        )
        if not should_log:
            return

        cache[log_key] = {
            "signature": signature,
            "last_logged_ts": now_ts,
        }
        logger.info(
            "[Auto-Pilot] Search ok; top candidate=%s score=%s mode=%s eligibility=%s source=%s",
            top_symbol,
            top_score_text,
            top_mode,
            top_eligibility,
            source,
        )
        logger.warning(
            "[Auto-Pilot] Pick blocked by loss budget: remaining %.2f%% ($%.2f / $%.2f)",
            remaining_pct,
            remaining_usdt,
            loss_budget_usdt,
        )



    def _run_bot_cycle_impl(
        self, bot: Dict[str, Any], fast_refill_tick: bool = False
    ) -> Dict[str, Any]:
        """Internal implementation of bot cycle (with environment-specific client already set)."""
        bot_id = bot.get("id")

        # C1: Final stale-control-version check right before executing the
        # cycle body.  If the UI changed the bot (stop/pause/reduce-only)
        # between the fresh read and here, abort immediately to prevent
        # placing orders on a bot the user already stopped.
        if self._is_control_version_stale(bot):
            bot["_cycle_aborted_stale_control"] = True
            return bot

        # Clear sticky block flags at start of EVERY cycle so they get
        # re-evaluated fresh.  Prevents permanent order stoppage mid-trend.
        bot.pop("_capital_starved_block_opening_orders", None)
        bot.pop("_small_capital_block_opening_orders", None)
        bot.pop("_profit_lock_closed_this_cycle", None)
        bot.pop("_cycle_opening_notional_used", None)
        # Clear stale assumption flags — they're set by startup reconciliation
        # and never cleared, causing permanent "exchange truth stale" blocks.
        bot["position_assumption_stale"] = False
        bot["order_assumption_stale"] = False
        # Clear UPnL soft-SL block if it was set in a previous cycle.
        # The UPnL check runs again this cycle and will re-set if still needed.
        if bot.get("_block_opening_orders") and bot.get("_upnl_stoploss_reason"):
            bot["_block_opening_orders"] = False
            bot["_upnl_stoploss_reason"] = None

        # Clear expired auto-pilot entry hold at cycle start (prevents re-set loop)
        if bot.get("_auto_pilot_entry_hold"):
            _hold_until = float(bot.get("_auto_pilot_entry_hold_until") or 0)
            if _hold_until <= 0 or time.time() >= _hold_until:
                bot["_auto_pilot_entry_hold"] = False
                bot.pop("_auto_pilot_entry_hold_until", None)
                bot.pop("_auto_pilot_picked_mode", None)
                logger.info("[%s] Auto-Pilot entry hold cleared at cycle start (expired)", bot.get("symbol"))

        now_iso = datetime.now(timezone.utc).isoformat()
        now_ts = time.time()
        reevaluation_context_applied = self._apply_reevaluation_runtime_context(
            bot,
            now_ts=now_ts,
        )
        symbol = bot.get("symbol")
        if not symbol:
            return self._set_error(bot, "Missing symbol configuration")
        self._ensure_stream_symbol(symbol)
        self._normalize_mode_range_state(bot)

        # ===== AUTO-PILOT: Must run FIRST before any exchange API calls =====
        # When symbol is "Auto-Pilot", pick a coin via scanner and return immediately.
        # The NEXT cycle will use the real symbol for position mode, auto-stop, etc.
        auto_pilot = bool(bot.get("auto_pilot", False))
        if auto_pilot and (not symbol or symbol == "Auto-Pilot"):
            return self._auto_pilot_pick_symbol(bot)

        if auto_pilot and symbol and symbol != "Auto-Pilot":
            self._maybe_prepare_auto_pilot_candidate_cache(
                bot,
                reason="background",
            )

        # ===== AUTO-PILOT ROTATION: Periodically check for better coins =====
        force_repick = (
            auto_pilot
            and symbol
            and symbol != "Auto-Pilot"
            and self._auto_pilot_should_force_repick(bot, symbol)
        )
        pending_rotation_ready = (
            auto_pilot
            and symbol
            and symbol != "Auto-Pilot"
            and self._auto_pilot_pending_rotation_ready(bot, symbol)
        )
        if auto_pilot and symbol and symbol != "Auto-Pilot" and (
            ENABLE_SMART_ROTATION or force_repick or pending_rotation_ready
        ):
            rotation_result = self._auto_pilot_check_rotation(bot, symbol)
            if rotation_result is not None:
                return rotation_result  # Switched to new coin, skip rest of cycle

        # Detect position mode early (hedge vs one-way). Fail-safe: halt if unknown.
        position_mode = self._get_position_mode(bot, symbol)
        if position_mode is None:
            return bot

        # =============================================================================
        # LEVERAGE ENFORCEMENT: Ensure exchange leverage matches bot config
        # =============================================================================
        try:
            leverage_to_set = int(bot.get("leverage", DEFAULT_LEVERAGE))
            self.client.set_leverage(symbol, leverage_to_set)
        except Exception as e:
            logger.debug(f"[{symbol}] Leverage enforcement: {e}")

        # =============================================================================
        # AUTO-STOP ON BALANCE TARGET CHECK (Smart Feature #19)
        # =============================================================================
        configured_auto_stop_target = float(bot.get("auto_stop_target_usdt", 0) or 0)
        effective_auto_stop_target = float(
            bot.get("auto_stop_target_effective_usdt", 0) or 0
        )
        auto_stop_target = (
            effective_auto_stop_target
            if effective_auto_stop_target > 0
            else configured_auto_stop_target
        )
        if (
            auto_stop_target > 0
            and not bot.get("auto_stop_triggered")
            and bot.get("auto_stop_armed", True)
        ):
            try:
                account_equity = self._get_usdt_wallet_balance()
                self._record_control_timing(
                    bot,
                    "balance_target",
                    balance_target_checked_at=now_iso,
                    balance_target_metric="account_equity",
                    balance_target_value=account_equity,
                    balance_target_threshold_usdt=auto_stop_target,
                    balance_target_triggered=False,
                    balance_target_action_taken="monitor_only",
                )
                if account_equity >= auto_stop_target:
                    logger.warning(
                        f"[{symbol}] 🎯 AUTO-STOP TARGET REACHED! "
                        f"Equity ${account_equity:.2f} >= Target ${auto_stop_target:.2f}"
                    )
                    # Close position if configured
                    from config.strategy_config import (
                        AUTO_STOP_CLOSE_POSITION,
                        AUTO_STOP_CANCEL_ORDERS,
                    )

                    if AUTO_STOP_CLOSE_POSITION:
                        close_success = self._close_position_market(symbol, bot=bot)
                        if not close_success:
                            self._hard_fail_close(
                                bot,
                                symbol,
                                "auto_stop_target",
                                "close_position_market_failed",
                            )
                    if AUTO_STOP_CANCEL_ORDERS:
                        # Use forceful cancel with verification
                        self._force_cancel_all_orders(symbol, max_retries=3, bot=bot)
                    # H2 audit: verify flat before finalizing stopped
                    _auto_cleanup = self._confirm_symbol_cleanup_state(symbol)
                    if not (_auto_cleanup.get("flat") and _auto_cleanup.get("orders_cleared")):
                        logger.warning(
                            "[%s] Auto-stop: not flat yet — entering stop_cleanup_pending",
                            symbol,
                        )
                        bot["status"] = "stop_cleanup_pending"
                        bot["stop_cleanup_reason"] = "auto_stop_balance_target"
                        self.bot_storage.save_bot(bot)
                        return bot
                    # Mark bot as fully stopped
                    bot["status"] = "stopped"
                    bot["started_at"] = None
                    bot["last_run_at"] = now_iso
                    self._reset_auto_pilot_on_stop(bot)
                    bot["auto_stop_triggered"] = True
                    bot["auto_stop_armed"] = False
                    bot["auto_stop_hit_at"] = now_iso
                    bot["auto_stop_hit_balance"] = account_equity
                    if configured_auto_stop_target > 0:
                        bot["auto_stop_target_rearm_on_start"] = True
                        bot["auto_stop_target_session_base_usdt"] = account_equity
                        bot["auto_stop_target_effective_usdt"] = (
                            account_equity + configured_auto_stop_target
                        )
                    self._record_control_timing(
                        bot,
                        "balance_target",
                        balance_target_triggered=True,
                        balance_target_action_taken="stop_bot_and_flatten",
                        balance_target_triggered_at=now_iso,
                    )
                    self.bot_storage.save_bot(bot)
                    logger.warning(
                        f"[{symbol}] ✅ Bot stopped - target reached. "
                        f"Final equity: ${account_equity:.2f}"
                    )
                    return bot
            except Exception as e:
                bot["_block_opening_orders"] = True
                bot["last_skip_reason"] = "auto_stop_target_error"
                bot["last_error"] = f"AUTO_STOP_TARGET_CHECK_FAILED: {e}"
                bot["last_run_at"] = now_iso
                self._record_control_timing(
                    bot,
                    "balance_target",
                    balance_target_checked_at=now_iso,
                    balance_target_metric="account_equity",
                    balance_target_triggered=False,
                    balance_target_action_taken="check_failed",
                    balance_target_error=str(e),
                )
                self.bot_storage.save_bot(bot)
                logger.error(
                    "[%s] Auto-stop target check failed; opening orders blocked until resolved: %s",
                    symbol,
                    e,
                )
                return bot

        # Extract profile and auto_direction
        profile = bot.get("profile", "normal")

        auto_direction = bool(bot.get("auto_direction", False))
        current_mode = (
            str(bot.get("effective_runtime_mode") or bot.get("mode") or "neutral").lower()
            if runtime_auto_switch_allowed(bot)
            else (bot.get("mode") or "neutral").lower()
        )
        mode = current_mode
        range_mode = (
            str(
                bot.get("effective_runtime_range_mode")
                or bot.get("range_mode")
                or "fixed"
            ).lower()
            if runtime_auto_switch_allowed(bot)
            else str(bot.get("range_mode") or "fixed").lower()
        )
        if runtime_auto_switch_allowed(bot):
            bot["mode"] = mode
            bot["range_mode"] = range_mode
        ai_mode_override_active = False  # May be set later by AI override logic

        # =============================================================================
        # CRITICAL: Run Auto-Margin Guard FIRST - before any skips/cooldowns
        # This ensures liquidation protection runs every cycle regardless
        # =============================================================================
        try:
            self._auto_margin_guard(bot, symbol)
        except Exception as e:
            logger.error(f"AutoMargin error for {bot_id} ({symbol}): {str(e)}")
            if bot.get("status") != "running":
                return bot

        # If critical liq protection cancelled orders, usually skip the cycle to
        # preserve margin. For scalp_pnl, still allow the reduce-only TP section
        # to run because closing profitable positions frees margin rather than
        # consuming it.
        if bot.get("_skip_new_orders_for_margin"):
            bot.pop("_skip_new_orders_for_margin", None)  # Clear flag
            bot["_skip_opening_orders_for_margin"] = True
            bot["last_warning"] = "Preserving margin for auto-margin"
            logger.info(
                f"[{symbol}] Auto-margin maintenance active - "
                f"reduce-only exits allowed, new entries blocked"
            )

        # =============================================================================
        # Indicators (5m + 15m) for adaptive tuning and risk checks
        # =============================================================================
        atr_pct = None
        bbw_pct = None
        atr_5m_pct = None
        atr_15m_pct = None
        fast_indicators = {}
        indicator_interval = "5" if mode == "scalp_pnl" else "15"


        try:
            fast_indicators = self.indicator_service.compute_indicators(
                symbol, interval=indicator_interval, limit=200
            )
            atr_pct = fast_indicators.get("atr_pct")
            bbw_pct = fast_indicators.get("bbw_pct")

            if indicator_interval == "5":
                atr_5m_pct = atr_pct
            else:
                atr_15m_pct = atr_pct

            if atr_5m_pct is None:
                indicators_5m = self.indicator_service.compute_indicators(
                    symbol, interval="5", limit=200
                )
                atr_5m_pct = indicators_5m.get("atr_pct")

            if atr_15m_pct is None:
                indicators_15m = self.indicator_service.compute_indicators(
                    symbol, interval="15", limit=200
                )
                atr_15m_pct = indicators_15m.get("atr_pct")

            # Fetch 1h ADX for extreme trend detection (grid freeze)
            try:
                htf_ind_1h = self.indicator_service.compute_indicators(
                    symbol, interval="60", limit=50
                )
                bot["_htf_adx_1h"] = htf_ind_1h.get("adx")
            except Exception:
                pass  # Use cached value from previous cycle
        except Exception as e:
            logger.warning(f"[{symbol}] Failed to fetch indicators: {e}")

        if atr_5m_pct is not None:
            bot["atr_5m_pct"] = atr_5m_pct
        if atr_15m_pct is not None:
            bot["atr_15m_pct"] = atr_15m_pct

        requested_open_cap_total = int(
            bot.get("runtime_open_order_cap_total")
            or (
                PROXIMITY_SCALP_OPEN_ORDER_CAP_TOTAL
                if mode in ("scalp_pnl", "scalp_market")
                else PROXIMITY_DEFAULT_OPEN_ORDER_CAP_TOTAL
            )
        )
        volatility_derisk_profile = self._get_volatility_derisk_profile(
            atr_pct=atr_pct,
            mode=mode,
            requested_open_cap_total=requested_open_cap_total,
        )
        bot["volatility_derisk_tier"] = volatility_derisk_profile.get("tier")
        bot["volatility_derisk_step_mult"] = volatility_derisk_profile.get("step_mult")
        bot["volatility_derisk_size_mult"] = volatility_derisk_profile.get("size_mult")
        bot["volatility_derisk_open_cap_total"] = volatility_derisk_profile.get(
            "open_cap_total"
        )
        bot["_volatility_block_opening_orders"] = bool(
            volatility_derisk_profile.get("block_opening_orders")
        )
        if bot["_volatility_block_opening_orders"]:
            bot["last_warning"] = (
                f"Volatility de-risk active: ATR {self._safe_float(atr_pct, 0.0) * 100:.2f}% "
                f">= {VOLATILITY_DERISK_BLOCK_NEW_ORDERS_ATR_PCT * 100:.2f}%"
            )

        # =============================================================================
        # Multi-Timeframe Regime Snapshot (15m primary, 5m secondary)
        # =============================================================================
        self._refresh_multi_tf_regime_snapshot(bot, symbol)

        # =============================================================================
        # Auto Neutral Mode Selection (Classic vs Dynamic)
        # =============================================================================
        try:
            if (bot.get("mode") or "").lower() in ("neutral", "neutral_classic_bybit"):
                bot, switched = self._maybe_auto_select_neutral_mode(
                    bot=bot,
                    symbol=symbol,
                    fast_indicators=fast_indicators,
                    atr_15m_pct=atr_15m_pct,
                )
                if switched:
                    return bot
        except Exception as e:
            logger.debug(f"[{symbol}] Auto neutral mode switch failed: {e}")

        # =============================================================================
        # CLEAR STALE BLOCK FLAGS (when no position exists)
        # =============================================================================
        # This must run BEFORE any other checks to prevent the bot from getting stuck
        # when _block_opening_orders persists from a previous stoploss event
        if bot.get("_block_opening_orders") or bot.get("upnl_stoploss_cooldown_until"):
            try:
                positions_resp = self.client.get_positions()
                if positions_resp.get("success"):
                    positions = positions_resp.get("data", {}).get("list", []) or []
                    has_position = False
                    for pos in positions:
                        if (
                            pos.get("symbol") == symbol
                            and float(pos.get("size", 0) or 0) > 0
                        ):
                            has_position = True
                            break

                    if not has_position:
                        cleared = False
                        self._clear_stall_overlay_state(bot)
                        # No position - clear all stale block flags
                        if bot.get("_block_opening_orders") and not bot.get(
                            "auto_pilot_rotation_pending"
                        ):
                            logger.info(
                                f"[{symbol}] Clearing stale _block_opening_orders (no position)"
                            )
                            bot.pop("_block_opening_orders", None)
                            cleared = True
                        if bot.get("upnl_stoploss_cooldown_until"):
                            logger.info(
                                f"[{symbol}] Clearing stale upnl_stoploss_cooldown (no position)"
                            )
                            bot.pop("upnl_stoploss_cooldown_until", None)
                            cleared = True
                        if cleared:
                            self.bot_storage.save_bot(bot)
            except Exception as e:
                logger.debug(f"[{symbol}] Stale flag check error: {e}")

        # =============================================================================
        # UPNL STOP-LOSS CHECK (NEW - Part 7)
        # =============================================================================
        # This check takes PRECEDENCE over legacy MAX_BOT_LOSS_PCT
        # 1) HARD trigger: immediate close + cooldown + risk_stopped
        # 2) SOFT trigger: block opening orders + cancel pending opens
        # Fast risk loop also runs this every 1s, but we check here too for safety
        if ENABLE_UPNL_STOPLOSS and bot.get("upnl_stoploss_enabled"):
            try:
                # Get position for UPnL check
                positions_resp = self.client.get_positions()
                if positions_resp.get("success"):
                    positions = positions_resp.get("data", {}).get("list", []) or []
                    position = None
                    for pos in positions:
                        if pos.get("symbol") == symbol:
                            position = pos
                            break

                    if position and float(position.get("size", 0)) > 0:
                        upnl_result = self._check_upnl_stoploss(
                            bot,
                            symbol,
                            position,
                            atr_15m_pct=atr_15m_pct,
                        )

                        # Store computed UPnL for dashboard visibility
                        bot["_computed_upnl_pct"] = upnl_result.get("upnl_pct")
                        bot["effective_upnl_soft"] = upnl_result.get("soft_pct")
                        bot["effective_upnl_hard"] = upnl_result.get("hard_pct")
                        bot["effective_liq_pct"] = upnl_result.get("liq_pct")
                        bot["last_liq_distance_pct"] = upnl_result.get(
                            "liq_distance_pct"
                        )

                        if upnl_result.get("hard_triggered"):
                            # HARD SL takes immediate action
                            return self._handle_upnl_hard_stoploss(
                                bot, symbol, upnl_result
                            )

                        if upnl_result.get("soft_triggered"):
                            # SOFT SL: block opening orders, but continue cycle for TP/reduce orders
                            self._handle_upnl_soft_stoploss(bot, symbol, upnl_result)
                            # Note: bot["_block_opening_orders"] is now True

                        if upnl_result.get("in_cooldown"):
                            # In cooldown - don't place opening orders but allow reduce orders
                            bot["_block_opening_orders"] = True
                    else:
                        # NO POSITION: Clear stale block flags and cooldown
                        # This prevents the bot from getting stuck when position was closed
                        # but the block flag persisted from a previous UPnL stoploss event
                        if bot.get("_block_opening_orders"):
                            logger.info(
                                f"[{symbol}] Clearing stale _block_opening_orders (no position)"
                            )
                            bot.pop("_block_opening_orders", None)
                        if bot.get("upnl_stoploss_cooldown_until"):
                            logger.info(
                                f"[{symbol}] Clearing stale upnl_stoploss_cooldown (no position)"
                            )
                            bot.pop("upnl_stoploss_cooldown_until", None)

            except Exception as e:
                logger.error(f"[{symbol}] UPnL SL check error: {e}")

        session_timer_result = self._apply_session_timer_control(
            bot,
            symbol,
            now_dt=datetime.now(timezone.utc),
        )
        if session_timer_result is not None:
            return session_timer_result

        if auto_pilot:
            self._refresh_auto_pilot_loss_budget_state(bot, symbol)

        if mode == "neutral_classic_bybit":
            return self._run_neutral_classic_bybit(bot, symbol)

        self._clear_capital_starved_opening_block(bot)

        ai_block_opening_orders = self._ai_block_opening_orders(bot)
        if bot.pop("_skip_opening_orders_for_margin", False):
            ai_block_opening_orders = True
            logger.info(
                "[%s] Opening orders blocked for auto-margin preservation", symbol
            )
        if ai_block_opening_orders:
            logger.info(
                "[%s] Opening guard active - blocking new opening orders", symbol
            )

        last_price = self._get_last_price(symbol)
        if last_price is None:
            return self._set_error(bot, f"Failed to fetch price for {symbol}")
        self._persist_early_current_price_runtime(
            bot,
            symbol=symbol,
            price=last_price,
            write_reason="trusted_price_ready",
            write_path=(
                "directional_pre_gate"
                if mode in ("long", "short")
                else "neutral_pre_guard"
            ),
            persisted_before_guard=bool(
                mode == "neutral" or ai_block_opening_orders or not fast_refill_tick
            ),
            force_persist=reevaluation_context_applied,
        )

        directional_gate_result = self._evaluate_directional_cycle_state(
            bot=bot, symbol=symbol, mode=mode,
            last_price=last_price, fast_indicators=fast_indicators,
        )

        # =============================================================================
        # PULLBACK RE-ENTRY WATCH — track pullback progress or trigger re-entry
        # =============================================================================
        pullback_result = self._evaluate_pullback_watch(
            bot=bot, symbol=symbol, mode=mode,
            last_price=last_price, fast_indicators=fast_indicators,
        )

        # =============================================================================
        # TIER 2: Auto-Pilot entry hold — wait for flow confirmation before placing
        # orders on a freshly picked coin.  Prevents entering at bad timing.
        # =============================================================================
        if bot.get("_auto_pilot_entry_hold") and bot.get("auto_pilot"):
            hold_until = bot.get("_auto_pilot_entry_hold_until") or 0
            now_hold = time.time()
            flow_score_val = float(bot.get("flow_score") or 0)
            picked_mode = str(bot.get("_auto_pilot_picked_mode") or mode).lower()

            # Check if flow confirms the direction
            flow_confirms = False
            if picked_mode == "long" and flow_score_val >= 20:
                flow_confirms = True
            elif picked_mode == "short" and flow_score_val <= -20:
                flow_confirms = True
            elif picked_mode in ("neutral", "neutral_classic_bybit") and abs(flow_score_val) < 60:
                flow_confirms = True  # Neutral wants calm flow (relaxed from 40 to reduce entry delay)

            if flow_confirms or now_hold >= hold_until:
                # Flow confirmed or hold expired — proceed with entry
                bot["_auto_pilot_entry_hold"] = False
                bot.pop("_auto_pilot_entry_hold_until", None)
                bot.pop("_auto_pilot_picked_mode", None)
                if flow_confirms:
                    logger.info(
                        "[%s] Auto-Pilot entry hold released: flow confirms %s (score=%.0f)",
                        symbol, picked_mode, flow_score_val,
                    )
                else:
                    logger.info(
                        "[%s] Auto-Pilot entry hold expired after 60s — proceeding without flow confirmation",
                        symbol,
                    )
            else:
                # Still waiting — skip order placement this cycle
                logger.debug(
                    "[%s] Auto-Pilot entry hold: waiting for flow confirmation (flow=%.0f, need %s)",
                    symbol, flow_score_val,
                    "≥+20" if picked_mode == "long" else "≤-20" if picked_mode == "short" else "calm",
                )
                bot["last_run_at"] = datetime.now(timezone.utc).isoformat()
                self._save_runtime_bot(bot)
                return bot

        neutral_guard_result = self._run_neutral_phase_guards(
            bot=bot, symbol=symbol, mode=mode,
            last_price=last_price, fast_refill_tick=fast_refill_tick,
            fast_indicators=fast_indicators, now_iso=now_iso,
        )
        if neutral_guard_result is not None:
            return neutral_guard_result

        # =============================================================================
        # Fast Execution Layer (1m indicators) - Partial TP / Profit Lock
        # =============================================================================
        exec_indicators = {}
        try:
            exec_indicators = self.indicator_service.compute_indicators(
                symbol,
                interval=EXECUTION_TF,
                limit=200,
            )
            if not exec_indicators.get("close"):
                exec_indicators = {}
        except Exception as e:
            logger.debug(f"[{symbol}] Fast execution indicators unavailable: {e}")

        if exec_indicators:
            try:
                self._run_fast_execution_layer(
                    bot=bot,
                    symbol=symbol,
                    last_price=last_price,
                    exec_indicators=exec_indicators,
                )
            except Exception as e:
                if isinstance(e, RuntimeError):
                    raise
                logger.warning(f"[{symbol}] Fast execution layer failed: {e}")

        # =============================================================================
        # Fetch Funding Rate for Dashboard Display (all bots)
        # =============================================================================
        try:
            if self.funding_rate_service:
                from config.strategy_config import ENABLE_FUNDING_RATE_SIGNAL

                if ENABLE_FUNDING_RATE_SIGNAL:
                    funding_result = self.funding_rate_service.get_funding_signal(
                        symbol
                    )
                    bot["funding_rate_pct"] = funding_result.get("funding_rate_pct", 0)
                    bot["funding_signal"] = funding_result.get("signal", "NEUTRAL")
                    bot["funding_score"] = funding_result.get("score", 0)
        except Exception as e:
            logger.debug(f"[{symbol}] Funding rate fetch failed: {e}")

        # =============================================================================
        # CHOPPY MARKET DETECTION for Neutral Mode - DISABLED
        # Cooldown (45s) is sufficient to prevent rapid order churn
        # =============================================================================
        # Choppy detection disabled - was too aggressive and pausing trending markets

        # =============================================================================
        # Feature #9: Danger Zone Detection
        # =============================================================================
        # Detect extreme market conditions and pause trading if score >= threshold
        if self.danger_zone_service and bot.get("danger_zone_enabled", True):
            try:
                from config.strategy_config import (
                    ENABLE_DANGER_ZONE_DETECTION,
                    DANGER_PAUSE_THRESHOLD_SCORE,
                )

                if ENABLE_DANGER_ZONE_DETECTION:
                    # Get existing bounds for range extreme check
                    existing_lower = bot.get("lower_price", 0)
                    existing_upper = bot.get("upper_price", 0)

                    danger_result = self.danger_zone_service.detect_danger_zones(
                        symbol=symbol,
                        indicators=fast_indicators,
                        grid_lower=existing_lower if existing_lower > 0 else None,
                        grid_upper=existing_upper if existing_upper > 0 else None,
                        current_price=last_price,
                    )

                    # Store danger info in bot state for UI/monitoring
                    bot["danger_score"] = danger_result.get("danger_score", 0)
                    bot["danger_level"] = danger_result.get("danger_level", "none")
                    bot["danger_in_zone"] = danger_result.get("in_danger_zone", False)
                    bot["danger_warnings"] = danger_result.get("warnings", [])

                    # Log warnings
                    if danger_result.get("in_danger_zone"):
                        warnings_str = "; ".join(danger_result.get("warnings", []))
                        logger.warning(
                            f"[{symbol}] ⚠️ DANGER DETECTED - Level={danger_result.get('danger_level')}, "
                            f"Score={danger_result.get('danger_score')}/100 - {warnings_str}"
                        )

                    # Check if should pause trading
                    pause_check = self.danger_zone_service.should_pause_trading(
                        danger_result=danger_result,
                        pause_threshold_score=DANGER_PAUSE_THRESHOLD_SCORE,
                    )

                    if pause_check.get("should_pause"):
                        # Use smart pause for recovery tracking
                        bot = self._smart_pause_bot(
                            bot=bot,
                            symbol=symbol,
                            reason=f"Danger zone: {pause_check.get('reason')}",
                            reason_type="danger_zone",
                        )
                        return bot

            except Exception as e:
                logger.warning(f"[{symbol}] Danger zone detection failed: {e}")
                # Continue without danger detection on error
        else:
            # Clear stale danger flags when disabled
            bot["danger_score"] = 0
            bot["danger_level"] = "none"
            bot["danger_in_zone"] = False
            bot["danger_warnings"] = []

        # =============================================================================
        # REGIME FILTER CHECK (NEW - with BTC Correlation)
        # =============================================================================
        # Check if entry filter is available and classify regime
        if self.entry_filter and mode in ("neutral", "long", "short"):
            _btc_filter_on = bot.get("btc_correlation_filter_enabled", True)
            try:
                regime_result = self.entry_filter.classify_regime(
                    symbol=symbol, indicators=fast_indicators,
                    include_btc_filter=_btc_filter_on,
                )
                regime = regime_result.get("regime")
                regime_reason = regime_result.get("reason")
                bot["entry_filter_regime"] = regime
                bot["entry_filter_regime_reason"] = regime_reason

                # Log regime classification with multi-TF ADX
                logger.info(
                    f"[{symbol}] Regime={regime}, "
                    f"ADX_15m={regime_result.get('adx_main')}, ADX_1h={regime_result.get('adx_higher')}, "
                    f"BTC_corr={regime_result.get('btc_correlation')}, BTC_ADX={regime_result.get('btc_adx')}"
                )

                # BLOCK if regime is "blocked" (high BTC correlation + BTC trend)
                # Block opening orders but continue cycle for position management
                # (TPs, grid sells, profit lock). Never pause — positions need exits.
                if regime == "blocked":
                    bot["_block_opening_orders"] = True
                    bot["last_error"] = f"Entry blocked: {regime_reason}"
                    logger.warning(
                        f"[{symbol}] 🚫 Regime blocked - "
                        f"new entries blocked, position management continues"
                    )

                # BLOCK if regime is "illiquid" — same treatment
                if regime == "illiquid":
                    bot["_block_opening_orders"] = True
                    bot["last_error"] = f"Low liquidity: {regime_reason}"
                    logger.warning(
                        f"[{symbol}] 🚫 Illiquid regime - "
                        f"new entries blocked, position management continues"
                    )

                # WARN if regime is "too_strong" (but continue - may still place orders)
                if regime == "too_strong":
                    logger.warning(
                        f"[{symbol}] ⚠️ Strong trend detected - {regime_reason}"
                    )

            except Exception as e:
                bot["entry_filter_regime"] = None
                bot["entry_filter_regime_reason"] = None
                logger.warning(f"[{symbol}] Regime filter check failed: {e}")
                # Continue without regime filter on error

        # =============================================================================
        # Direction-Change Auto-Stop (server-side dashboard toggle)
        # =============================================================================
        direction_change_result = self._maybe_apply_direction_change_auto_stop(
            bot=bot,
            symbol=symbol,
            indicators=fast_indicators,
            now_iso=now_iso,
        )
        if direction_change_result is not None:
            return direction_change_result

        # =============================================================================
        # Smart Auto Direction Logic (Multi-Timeframe) with Hysteresis
        # =============================================================================
        if (
            auto_direction
            and mode in ("neutral", "long", "short")
            and not ai_mode_override_active
        ):
            current_effective_mode = str(
                bot.get("effective_runtime_mode") or current_mode
            ).strip().lower() or current_mode
            previous_runtime_mode = str(
                bot.get("effective_runtime_mode") or ""
            ).strip().lower()
            previous_runtime_source = str(
                bot.get("runtime_mode_source") or ""
            ).strip().lower()
            new_mode = self._compute_smart_auto_direction(
                symbol=symbol,
                current_mode=current_effective_mode,
                fast_indicators=fast_indicators,
                bot_id=bot_id,
                bot=bot,  # Pass bot for mode_entered_at check
                current_price=last_price,
            )
            applied_runtime_mode = new_mode or current_effective_mode
            defer_neutral_switch, _ = self._should_defer_auto_direction_neutral_switch(
                bot,
                symbol=symbol,
                current_mode=current_effective_mode,
                target_mode=applied_runtime_mode,
            )
            if defer_neutral_switch:
                applied_runtime_mode = current_effective_mode
                logger.info(
                    "[%s] Auto-direction neutral switch deferred due to live exposure "
                    "(target=%s, applied=%s)",
                    symbol,
                    new_mode,
                    current_effective_mode,
                )
            elif new_mode:
                self._clear_auto_direction_deferred_state(bot)
            if new_mode:
                self._set_runtime_mode_metadata(
                    bot,
                    effective_mode=applied_runtime_mode,
                    effective_range_mode=range_mode,
                    source="auto_direction",
                    non_persistent=runtime_auto_switch_allowed(bot),
                )
            metadata_changed = (
                previous_runtime_mode != applied_runtime_mode
                or previous_runtime_source != "auto_direction"
            )

            # MEME guard: prevent auto-direction from switching to a mode
            # that the small-capital MEME guard will block.  Only trailing_long
            # is allowed for small accounts on meme coins.
            meme_guard_blocks_switch = False
            if (
                new_mode
                and new_mode != current_effective_mode
                and bot.get("small_capital_mode_active")
                and str(bot.get("small_capital_profile") or "").upper() == "MEME"
            ):
                is_target_trailing_long = (
                    new_mode == "long"
                    and str(bot.get("range_mode") or "").lower() == "trailing"
                )
                if not is_target_trailing_long:
                    meme_guard_blocks_switch = True
                    logger.info(
                        "[%s] Auto-direction blocked: MEME guard prevents switch to %s (only trailing_long allowed)",
                        symbol,
                        new_mode,
                    )

            if (
                new_mode != current_effective_mode
                and runtime_auto_switch_allowed(bot)
                and not defer_neutral_switch
                and not meme_guard_blocks_switch
            ):
                bot["mode"] = new_mode
                self._clear_directional_entry_runtime_state(bot)
                self._clear_directional_audit_runtime_state(bot)
                self._normalize_mode_range_state(bot)
                # Track when mode was entered for hysteresis hold time
                bot["mode_entered_at"] = datetime.now(timezone.utc).isoformat()
                # Track mode change count for monitoring
                bot["mode_change_count"] = bot.get("mode_change_count", 0) + 1
                mode = new_mode
                directional_gate_result = (
                    self._evaluate_directional_entry_gate(
                        bot=bot,
                        symbol=symbol,
                        mode=mode,
                        last_price=last_price,
                        fast_indicators=fast_indicators,
                    )
                    if mode in ("long", "short")
                    else None
                )
                logger.info(
                    f"[{symbol}] Smart auto-direction changed mode from '{current_effective_mode}' to '{new_mode}'"
                )
                self.bot_storage.save_bot(bot)
            elif new_mode == current_effective_mode and runtime_auto_switch_allowed(bot):
                bot["mode"] = new_mode
                mode = new_mode
            elif metadata_changed or defer_neutral_switch:
                self.bot_storage.save_runtime_bot(bot)

            # =============================================================================
            # Auto Range Mode (Smart Feature #29)
            # =============================================================================
            # Automatically switch range_mode based on market regime
            new_range_mode = self._compute_auto_range_mode(
                bot=bot,
                symbol=symbol,
                current_mode=mode,
                current_range_mode=range_mode,
                indicators=fast_indicators,
            )
            if new_range_mode and new_range_mode != range_mode:
                old_range_mode = range_mode
                bot["range_mode"] = new_range_mode
                bot["_last_range_mode_change"] = self.client._get_now_ts()
                bot["range_mode_change_count"] = (
                    bot.get("range_mode_change_count", 0) + 1
                )
                range_mode = new_range_mode
                logger.info(
                    f"[{symbol}] Auto range mode changed from '{old_range_mode}' to '{new_range_mode}'"
                )

        # =============================================================================
        # TREND REVERSAL PROTECTION (Smart Feature #17)
        # Detect when trend reverses against position and auto-close + switch mode
        # =============================================================================
        logger.info(
            f"[{symbol}] Trend reversal check eligibility - mode={mode}, range_mode={range_mode}"
        )
        if mode in ("long", "short") and range_mode == "trailing":
            logger.info(f"[{symbol}] Calling _check_trend_reversal_protection...")
            try:
                reversal_result = self._check_trend_reversal_protection(
                    bot=bot,
                    symbol=symbol,
                    mode=mode,
                    indicators=fast_indicators,
                    last_price=last_price,
                )
                if reversal_result.get("action_taken") in (
                    "closed",
                    "closed_and_switched",
                    "switched",
                ):
                    # Mode may have changed - update local variable
                    mode = reversal_result.get("new_mode", mode)
                    bot["trend_reversal_action"] = reversal_result.get("action_taken")
                    bot["trend_reversal_reason"] = reversal_result.get("reason")
                    # Save bot state immediately after reversal action
                    self.bot_storage.save_bot(bot)
                elif reversal_result.get("reversal_detected"):
                    # Reversal detected but waiting for confirmation
                    bot["trend_reversal_pending"] = True
                    bot["trend_reversal_reason"] = reversal_result.get("reason")
                else:
                    # No reversal - clear pending state
                    bot["trend_reversal_pending"] = False
                    bot["trend_reversal_reason"] = None
            except Exception as e:
                logger.warning(f"[{symbol}] Trend reversal check failed: {e}")

        # =============================================================================
        # Close Opposite Positions (prevent holding against trend)
        # For dynamic mode: also cancel opposite side orders aggressively
        # =============================================================================
        self._close_opposite_positions(bot, symbol, mode)

        # =============================================================================
        # Global unrealized PnL TP (all modes, before mode-specific cycles)
        # =============================================================================
        if GLOBAL_UNREALIZED_TP_USD > 0:
            try:
                pos_resp = self.client.get_positions()
                if pos_resp.get("success"):
                    for pos in pos_resp.get("data", {}).get("list", []) or []:
                        if pos.get("symbol") != symbol:
                            continue
                        pos_size = self._safe_float(pos.get("size"), 0.0)
                        if pos_size > 0:
                            unrealized_pnl = self._safe_float(
                                pos.get("unrealisedPnl"), 0.0
                            )
                            if unrealized_pnl >= GLOBAL_UNREALIZED_TP_USD:
                                self._handle_global_unrealized_tp(
                                    bot=bot,
                                    symbol=symbol,
                                    unrealized_pnl=unrealized_pnl,
                                    now_iso=now_iso,
                                )
                        break
            except Exception as e:
                logger.debug(f"[{symbol}] Global unrealized TP check failed: {e}")

        symbol_daily_stop = self._maybe_trigger_symbol_daily_kill_switch(
            bot=bot,
            symbol=symbol,
            now_iso=now_iso,
            investment=self._safe_float(bot.get("investment"), DEFAULT_INVESTMENT_USDT),
        )
        if symbol_daily_stop is not None:
            return symbol_daily_stop

        failure_breaker_skip_opening_orders, failure_breaker_reason = (
            self._failure_breaker_skip_opening_orders(bot, now_ts)
        )
        if failure_breaker_skip_opening_orders:
            bot["last_warning"] = failure_breaker_reason

        # Dynamic mode: Cancel opposite side orders immediately when strong trend detected
        if range_mode == "dynamic" and auto_direction and mode in ("neutral", "long", "short"):
            rsi_fast = fast_indicators.get("rsi")

            if rsi_fast and rsi_fast > 58:
                cancelled = self._cancel_bot_opening_orders_by_side(
                    bot=bot,
                    symbol=symbol,
                    side="Sell",
                )
                if cancelled > 0:
                    logger.info(
                        "[%s] Dynamic mode - cancelled %d bot-owned SELL opening order(s) (uptrend detected)",
                        symbol,
                        cancelled,
                    )

            elif rsi_fast and rsi_fast < 42:
                cancelled = self._cancel_bot_opening_orders_by_side(
                    bot=bot,
                    symbol=symbol,
                    side="Buy",
                )
                if cancelled > 0:
                    logger.info(
                        "[%s] Dynamic mode - cancelled %d bot-owned BUY opening order(s) (downtrend detected)",
                        symbol,
                        cancelled,
                    )

        # =============================================================================
        # SCALP PNL MODE: Intelligent unrealized profit scalping (Limit Orders)
        # =============================================================================
        if mode == "scalp_pnl":
            auto_stop_result = self._maybe_trigger_auto_stop_loss(
                bot=bot,
                symbol=symbol,
                now_iso=now_iso,
            )
            if auto_stop_result is not None:
                return auto_stop_result
            scalp_result = self._run_scalp_pnl_cycle(
                bot=bot,
                symbol=symbol,
                last_price=last_price,
                fast_indicators=fast_indicators,
                now_iso=now_iso,
                fast_refill_tick=fast_refill_tick,
            )
            if scalp_result is not None:
                # Scalp mode handled the cycle, return the result
                return scalp_result

        # =============================================================================
        # SCALP MARKET MODE: Fast market order scalping
        # =============================================================================
        if mode == "scalp_market":
            auto_stop_result = self._maybe_trigger_auto_stop_loss(
                bot=bot,
                symbol=symbol,
                now_iso=now_iso,
            )
            if auto_stop_result is not None:
                return auto_stop_result
            scalp_market_result = self._run_scalp_market_cycle(
                bot=bot,
                symbol=symbol,
                last_price=last_price,
                fast_indicators=fast_indicators,
                now_iso=now_iso,
            )
            if scalp_market_result is not None:
                return scalp_market_result

        # =============================================================================
        # INITIAL ENTRY: Place market order at current price when bot starts
        # Allows entering position immediately instead of waiting for grid level
        # =============================================================================
        initial_entry = bool(bot.get("initial_entry", False))
        initial_entry_done = bool(bot.get("initial_entry_done", False))

        # Auto-enable initial entry on strong trend
        if not initial_entry and not initial_entry_done and bool(bot.get("initial_entry_auto_trend", False)):
            gate_scores = (directional_gate_result or {}).get("scores", {})
            setup_quality = (gate_scores.get("setup_quality") or {}).get("score", 0)
            signal_code = (gate_scores.get("entry_signal") or {}).get("code", "")
            if (
                setup_quality >= 72.0
                and signal_code in ("early_entry", "good_continuation", "confirmed_breakout")
            ):
                initial_entry = True
                logger.info(
                    "[%s] Auto-enabled initial entry: strong trend (score=%.1f, signal=%s)",
                    symbol, setup_quality, signal_code,
                )

        if initial_entry and not initial_entry_done and mode in ("long", "short"):
            funding_guard = self._evaluate_funding_protection(bot, symbol, mode)
            btc_guard = self._evaluate_btc_guard(bot, symbol)
            smart_entry_state = self._evaluate_smart_entry_timing(
                bot=bot,
                symbol=symbol,
                mode=mode,
                last_price=last_price,
                fast_indicators=fast_indicators,
            )
            exchange_truth_opening_blocker = self._get_exchange_truth_opening_blocker(
                bot
            )
            opening_order_guard_skip = (
                failure_breaker_skip_opening_orders
                or bool(bot.get("_volatility_block_opening_orders"))
                or bool(exchange_truth_opening_blocker)
            )
            initial_entry_blockers: List[Dict[str, Any]] = []
            if ai_block_opening_orders:
                opening_guard_reason = "Opening guard active"
                if exchange_truth_opening_blocker is not None:
                    opening_guard_reason = exchange_truth_opening_blocker["reason_text"]
                self._append_audit_blocker(
                    initial_entry_blockers,
                    code="opening_guard",
                    reason=opening_guard_reason,
                    phase="initial_entry",
                    side=mode,
                )
            if opening_order_guard_skip:
                opening_guard_cycle_reason = (
                    exchange_truth_opening_blocker["reason_text"]
                    if exchange_truth_opening_blocker is not None
                    else (
                        failure_breaker_reason
                        or f"Volatility de-risk ({bot.get('volatility_derisk_tier')})"
                    )
                )
                self._append_audit_blocker(
                    initial_entry_blockers,
                    code=(
                        "exchange_truth"
                        if exchange_truth_opening_blocker is not None
                        else "opening_guard_cycle"
                    ),
                    reason=opening_guard_cycle_reason,
                    phase="initial_entry",
                    side=mode,
                )
            if funding_guard.get("skip"):
                self._append_audit_blocker(
                    initial_entry_blockers,
                    code="funding_protection",
                    reason=funding_guard.get("reason") or "funding protection",
                    phase="initial_entry",
                    side=mode,
                )
            if btc_guard.get("skip"):
                self._append_audit_blocker(
                    initial_entry_blockers,
                    code="btc_guard",
                    reason=btc_guard.get("reason") or "BTC guard",
                    phase="initial_entry",
                    side=mode,
                )
            if mode == "long" and smart_entry_state.get("skip_buy"):
                self._append_audit_blocker(
                    initial_entry_blockers,
                    code="smart_entry",
                    reason=smart_entry_state.get("buy_reason")
                    or "waiting for pullback",
                    phase="initial_entry",
                    side="buy",
                )
            if mode == "short" and smart_entry_state.get("skip_sell"):
                self._append_audit_blocker(
                    initial_entry_blockers,
                    code="smart_entry",
                    reason=smart_entry_state.get("sell_reason")
                    or "waiting for bounce",
                    phase="initial_entry",
                    side="sell",
                )
            if bot.get("_entry_gate_blocked") and bot.get("entry_gate_enabled", True):
                self._append_audit_blocker(
                    initial_entry_blockers,
                    code="entry_gate",
                    reason=bot.get("_entry_gate_blocked_reason", "unsafe entry"),
                    phase="initial_entry",
                    side=mode,
                )
            if initial_entry_blockers:
                forensic_context = self._build_trade_forensic_decision_context(
                    bot=bot,
                    symbol=symbol,
                    mode=mode,
                    range_mode=range_mode,
                    last_price=last_price,
                    decision_type="initial_entry",
                    candidate_open_sides=["buy" if mode == "long" else "sell"],
                    candidate_counts={
                        "buy": 1 if mode == "long" else 0,
                        "sell": 1 if mode == "short" else 0,
                    },
                    fast_indicators=fast_indicators,
                    gate_result=directional_gate_result,
                    blockers=initial_entry_blockers,
                    position_snapshot=self._build_ai_advisor_position_snapshot(
                        side=None,
                        size=0.0,
                        unrealized_pnl=None,
                    ),
                )
                self._record_trade_forensic_decision(
                    bot=bot,
                    symbol=symbol,
                    mode=mode,
                    side=mode,
                    decision_type="initial_entry",
                    decision_context=forensic_context,
                    event_type="decision",
                    event_status="candidate",
                )
                self._record_trade_forensic_decision(
                    bot=bot,
                    symbol=symbol,
                    mode=mode,
                    side=mode,
                    decision_type="initial_entry",
                    decision_context=forensic_context,
                    event_type="skip_blocked",
                    event_status="blocked",
                    skip_reason=initial_entry_blockers[0].get("reason"),
                )
                self._record_audit_cycle(
                    bot,
                    symbol=symbol,
                    mode=mode,
                    last_price=last_price,
                    lower_price=bot.get("lower_price") or bot.get("grid_lower_price"),
                    upper_price=bot.get("upper_price") or bot.get("grid_upper_price"),
                    blocker_stack=initial_entry_blockers,
                    gate_result=directional_gate_result,
                    setup_quality=((directional_gate_result or {}).get("scores") or {}).get(
                        "setup_quality"
                    ),
                    skipped_reason=initial_entry_blockers[0].get("reason"),
                    event="initial_entry_skipped",
                )
                logger.info(
                    "[%s] Initial %s entry blocked: %s",
                    symbol,
                    mode,
                    initial_entry_blockers[0].get("reason"),
                )
                return bot
            initial_advisor_review = self._maybe_review_ai_advisor_candidate(
                bot=bot,
                symbol=symbol,
                mode=mode,
                range_mode=range_mode,
                last_price=last_price,
                decision_type="initial_entry",
                candidate_open_sides=["buy" if mode == "long" else "sell"],
                candidate_counts={
                    "buy": 1 if mode == "long" else 0,
                    "sell": 1 if mode == "short" else 0,
                },
                fast_indicators=fast_indicators,
                gate_result=directional_gate_result,
                blockers=[],
                position_snapshot=self._build_ai_advisor_position_snapshot(
                    side=None,
                    size=0.0,
                    unrealized_pnl=None,
                ),
            )
            forensic_context = self._build_trade_forensic_decision_context(
                bot=bot,
                symbol=symbol,
                mode=mode,
                range_mode=range_mode,
                last_price=last_price,
                decision_type="initial_entry",
                candidate_open_sides=["buy" if mode == "long" else "sell"],
                candidate_counts={
                    "buy": 1 if mode == "long" else 0,
                    "sell": 1 if mode == "short" else 0,
                },
                fast_indicators=fast_indicators,
                gate_result=directional_gate_result,
                blockers=[],
                position_snapshot=self._build_ai_advisor_position_snapshot(
                    side=None,
                    size=0.0,
                    unrealized_pnl=None,
                ),
                advisor_review=initial_advisor_review,
            )
            self._record_trade_forensic_decision(
                bot=bot,
                symbol=symbol,
                mode=mode,
                side=mode,
                decision_type="initial_entry",
                decision_context=forensic_context,
                event_type="decision",
                event_status="candidate",
            )
            entry_result = self._place_initial_entry(
                bot=bot,
                symbol=symbol,
                last_price=last_price,
                mode=mode,
                now_iso=now_iso,
            )
            if entry_result:
                # Mark initial entry as done so we don't repeat it
                bot["initial_entry_done"] = True
                self.bot_storage.save_bot(bot)
                logger.info(
                    f"[{symbol}] Initial {mode.upper()} entry placed at {last_price}"
                )

                # Run auto margin immediately after initial entry to protect new position
                try:
                    self._auto_margin_guard(bot, symbol)
                except Exception as e:
                    logger.debug(
                        f"[{symbol}] AutoMargin after initial entry error: {e}"
                    )

        # Extract range mode and current range
        range_mode = (bot.get("range_mode") or "fixed").lower()

        lower_price = self._safe_float(bot.get("lower_price"))
        upper_price = self._safe_float(bot.get("upper_price"))
        investment = self._get_effective_investment(
            bot, self._safe_float(bot.get("investment"), DEFAULT_INVESTMENT_USDT)
        )
        leverage = self._safe_float(bot.get("leverage"), DEFAULT_LEVERAGE)

        # =============================================================================
        # Global TP Check (based on total PnL = realized + unrealized)
        # =============================================================================
        tp_basis_investment = investment
        realized_pnl_total = self._safe_float(bot.get("realized_pnl"), 0.0)
        # Session-scoped baseline prevents immediate re-trigger after restart.
        if bot.get("tp_session_realized_baseline") is None:
            bot["tp_session_realized_baseline"] = realized_pnl_total
        tp_realized_baseline = self._safe_float(
            bot.get("tp_session_realized_baseline"), realized_pnl_total
        )
        if realized_pnl_total < tp_realized_baseline:
            tp_realized_baseline = realized_pnl_total
            bot["tp_session_realized_baseline"] = tp_realized_baseline
        realized_pnl = max(0.0, realized_pnl_total - tp_realized_baseline)
        tp_pct = self._safe_float(bot.get("tp_pct"), 0.0)

        # Fetch current unrealized PnL from position
        unrealized_pnl = 0.0
        position_size = 0.0
        try:
            pos_resp = self.client.get_positions()
            if pos_resp.get("success"):
                for pos in pos_resp.get("data", {}).get("list", []) or []:
                    if pos.get("symbol") == symbol:
                        pos_size = self._safe_float(pos.get("size"), 0)
                        if pos_size > 0:
                            position_size = pos_size
                            unrealized_pnl = self._safe_float(
                                pos.get("unrealisedPnl"), 0.0
                            )
                        break
        except Exception as e:
            logger.debug(f"[{symbol}] Failed to fetch position for TP check: {e}")

        # Global unrealized PnL take-profit (close position, keep bot running)
        if (
            GLOBAL_UNREALIZED_TP_USD > 0
            and position_size > 0
            and unrealized_pnl >= GLOBAL_UNREALIZED_TP_USD
        ):
            self._handle_global_unrealized_tp(
                bot=bot,
                symbol=symbol,
                unrealized_pnl=unrealized_pnl,
                now_iso=now_iso,
            )
            # Avoid stale in-cycle position data triggering TP% logic right after close.
            position_size = 0.0
            unrealized_pnl = 0.0

        total_pnl = realized_pnl + unrealized_pnl

        tp_hit = False
        # Only evaluate TP hit while position is open.
        if tp_pct > 0 and tp_basis_investment > 0 and position_size > 0:
            pnl_pct = total_pnl / tp_basis_investment
            if pnl_pct >= tp_pct:
                tp_hit = True

        if tp_hit:
            # Close the symbol completely and mark bot as TP hit
            logger.info(
                "Global TP hit for bot %s (symbol=%s): total_pnl=%.4f (session_realized=%.4f + unrealized=%.4f), realized_total=%.4f baseline=%.4f tp_pct=%.4f tp_basis_investment=%.2f",
                bot_id,
                symbol,
                total_pnl,
                realized_pnl,
                unrealized_pnl,
                realized_pnl_total,
                tp_realized_baseline,
                tp_pct,
                tp_basis_investment,
            )

            # CRITICAL: Check if position was actually closed
            close_success = self._close_bot_symbol(
                bot,
                hard_fail=False,  # Don't hard fail - we'll handle status ourselves
                fail_reason="tp_hit",
            )

            if close_success:
                bot["status"] = "tp_hit"
                bot["last_error"] = None
                # Re-arm TP baseline at hit point so a future restart starts cleanly.
                bot["tp_session_realized_baseline"] = realized_pnl_total
                logger.info(
                    "[%s] TP hit successfully closed position for bot %s",
                    symbol,
                    bot_id,
                )
            else:
                # Position close FAILED - set error status so user can intervene
                bot["status"] = "error"
                bot["last_error"] = "TP_HIT_CLOSE_FAILED: Position still open - requires manual close"
                bot["_block_opening_orders"] = True
                bot["tp_session_realized_baseline"] = realized_pnl_total
                logger.error(
                    "[%s] CRITICAL: TP hit but position close FAILED for bot %s - manual intervention required",
                    symbol,
                    bot_id,
                )

            bot["last_run_at"] = now_iso
            self.bot_storage.save_bot(bot)
            return bot


        # =============================================================================
        # Auto Stop USDT Check (user-defined loss limit in USDT)
        # =============================================================================
        auto_stop_result = self._maybe_trigger_auto_stop_loss(
            bot=bot,
            symbol=symbol,
            now_iso=now_iso,
            unrealized_pnl=unrealized_pnl,
            position_size=position_size,
        )
        if auto_stop_result is not None:
            return auto_stop_result

        # Compute current width if valid
        current_width_pct = None
        if lower_price > 0 and upper_price > lower_price:
            mid = (upper_price + lower_price) / 2.0
            current_width_pct = (upper_price - lower_price) / mid

        new_range = None
        range_settings = get_dynamic_range_settings(mode)
        range_width_floor_pct = float(
            range_settings.get("width_floor_pct", self.range_engine.default_width_pct)
        )
        grid_stability_threshold_pct = float(
            range_settings.get(
                "recalc_threshold_pct", self.GRID_STABILITY_THRESHOLD_PCT
            )
        )
        bot["effective_range_width_floor_pct"] = range_width_floor_pct
        bot["effective_range_recalc_threshold_pct"] = grid_stability_threshold_pct

        # =============================================================================
        # GRID STABILITY CHECK: Only recalculate if price moved significantly
        # This prevents constant grid churning as price fluctuates
        # =============================================================================
        grid_center_key = f"{bot_id}_{symbol}"
        last_grid_center = self._last_grid_center.get(grid_center_key, 0)

        # Calculate current range center
        current_center = (
            (lower_price + upper_price) / 2.0
            if lower_price > 0 and upper_price > lower_price
            else last_price
        )

        # Check if we should recalculate (first time or significant price move)
        should_recalculate_range = False
        if last_grid_center <= 0:
            should_recalculate_range = True  # First run
        else:
            price_move_pct = abs(last_price - last_grid_center) / last_grid_center
            if price_move_pct >= grid_stability_threshold_pct:
                should_recalculate_range = True
                logger.debug(
                    f"[{symbol}] Price moved {price_move_pct * 100:.2f}% from grid center, "
                    f"recalculating (threshold={grid_stability_threshold_pct * 100:.2f}%, mode={mode})"
                )

        # =============================================================================
        # Feature #6: Range Recentering & Profile-Based Adjustment
        # =============================================================================
        # Use enhanced range builder with profile support and automatic recentering
        from config.strategy_config import RANGE_RECENTER_THRESHOLD_PCT

        # Dynamic range mode: only recompute if significant price move
        if range_mode == "dynamic":
            if (
                should_recalculate_range
                or lower_price <= 0
                or upper_price <= lower_price
            ):
                dynamic_recenter_expectation = self._get_dynamic_recenter_expectation(
                    current_price=last_price,
                    lower_price=lower_price,
                    upper_price=upper_price,
                    recenter_threshold_pct=RANGE_RECENTER_THRESHOLD_PCT,
                )
                dynamic_threshold_values = {
                    "recenter_threshold_pct": RANGE_RECENTER_THRESHOLD_PCT,
                    "should_recalculate_range": bool(should_recalculate_range),
                }
                if dynamic_recenter_expectation.get("price_position_pct") is not None:
                    dynamic_threshold_values["price_position_pct"] = round(
                        self._safe_float(
                            dynamic_recenter_expectation.get("price_position_pct"), 0.0
                        ),
                        6,
                    )

                # Use profile-aware range builder with recentering support
                new_range = self.range_engine.build_neutral_range_with_profile(
                    last_price=last_price,
                    atr_pct=atr_pct,
                    bbw_pct=bbw_pct,
                    profile=profile,
                    existing_lower=lower_price if lower_price > 0 else None,
                    existing_upper=upper_price if upper_price > 0 else None,
                    recenter_threshold_pct=RANGE_RECENTER_THRESHOLD_PCT,
                    width_floor_pct=range_width_floor_pct,
                )
                # Log recentering events
                if new_range.get("recentered"):
                    logger.info(
                        f"[{symbol}] 🔄 Range RECENTERED - {new_range.get('recenter_reason')} "
                        f"(profile={profile}, multiplier={new_range.get('profile_multiplier', 1.0):.2f})"
                    )
                    self._record_recenter_happened_event(
                        bot,
                        symbol=symbol,
                        mode=mode,
                        range_mode=range_mode,
                        current_price=last_price,
                        previous_lower=lower_price,
                        previous_upper=upper_price,
                        new_range=new_range,
                    )
                logger.debug(
                    f"[{symbol}] Dynamic range computed: lower={new_range.get('lower')}, upper={new_range.get('upper')}, width={new_range.get('width_pct') * 100:.2f}%"
                )
                self._maybe_record_recenter_expected_skipped(
                    bot,
                    symbol=symbol,
                    mode=mode,
                    range_mode=range_mode,
                    current_price=last_price,
                    lower_price=lower_price,
                    upper_price=upper_price,
                    expected_recenter=bool(
                        dynamic_recenter_expectation.get("expected_recenter")
                    ),
                    actual_recenter=bool(new_range.get("recentered")),
                    skip_reason=(
                        None
                        if new_range.get("recentered")
                        else (
                            dynamic_recenter_expectation.get("reason")
                            or new_range.get("recenter_reason")
                            or "range_builder_not_recentered"
                        )
                    ),
                    threshold_values=dynamic_threshold_values,
                )
            else:
                logger.debug(f"[{symbol}] Dynamic range stable, keeping current range")

        # Trailing range mode: only shift when price approaches edges
        elif range_mode == "trailing":
            if lower_price <= 0 or upper_price <= lower_price:
                # Invalid range, treat as dynamic with profile support
                new_range = self.range_engine.build_neutral_range_with_profile(
                    last_price=last_price,
                    atr_pct=atr_pct,
                    bbw_pct=bbw_pct,
                    profile=profile,
                    existing_lower=None,
                    existing_upper=None,
                    recenter_threshold_pct=RANGE_RECENTER_THRESHOLD_PCT,
                    width_floor_pct=range_width_floor_pct,
                )
                logger.info(
                    f"[{symbol}] Trailing mode with invalid range, computing new range (profile={profile})"
                )
            else:
                recenter_check = self.range_engine.should_recenter_range(
                    current_price=last_price,
                    current_lower=lower_price,
                    current_upper=upper_price,
                    recenter_threshold_pct=RANGE_RECENTER_THRESHOLD_PCT,
                )
                if recenter_check.get("should_recenter") and should_recalculate_range:
                    new_range = self.range_engine.build_neutral_range_with_profile(
                        last_price=last_price,
                        atr_pct=atr_pct,
                        bbw_pct=bbw_pct,
                        profile=profile,
                        existing_lower=lower_price,
                        existing_upper=upper_price,
                        recenter_threshold_pct=RANGE_RECENTER_THRESHOLD_PCT,
                        width_floor_pct=range_width_floor_pct,
                    )
                    if new_range.get("recentered"):
                        logger.info(
                            f"[{symbol}] 🔄 Trailing range RECENTERED - {new_range.get('recenter_reason')} "
                            f"(profile={profile})"
                        )
                        self._record_recenter_happened_event(
                            bot,
                            symbol=symbol,
                            mode=mode,
                            range_mode=range_mode,
                            current_price=last_price,
                            previous_lower=lower_price,
                            previous_upper=upper_price,
                            new_range=new_range,
                        )
                    else:
                        logger.info(
                            f"[{symbol}] Trailing range shifted - {recenter_check.get('reason')}"
                        )
                self._maybe_record_recenter_expected_skipped(
                    bot,
                    symbol=symbol,
                    mode=mode,
                    range_mode=range_mode,
                    current_price=last_price,
                    lower_price=lower_price,
                    upper_price=upper_price,
                    expected_recenter=bool(recenter_check.get("should_recenter")),
                    actual_recenter=bool(new_range and new_range.get("recentered")),
                    skip_reason=(
                        None
                        if (new_range and new_range.get("recentered"))
                        else (
                            "recalc_gate_not_met"
                            if recenter_check.get("should_recenter")
                            and not should_recalculate_range
                            else recenter_check.get("reason")
                            or "trailing_recenter_skipped"
                        )
                    ),
                    threshold_values={
                        "recenter_threshold_pct": RANGE_RECENTER_THRESHOLD_PCT,
                        "should_recalculate_range": bool(should_recalculate_range),
                        "recenter_reason": recenter_check.get("reason"),
                    },
                )

        # Apply new range if computed
        if new_range is not None:
            lower_price = float(new_range["lower"])
            upper_price = float(new_range["upper"])
            bot["lower_price"] = lower_price
            bot["upper_price"] = upper_price
            bot["last_range_width_pct"] = float(new_range.get("width_pct") or 0.0)
            # Update grid center tracking
            self._last_grid_center[grid_center_key] = (lower_price + upper_price) / 2.0
        elif last_grid_center <= 0 and lower_price > 0 and upper_price > lower_price:
            # First time with valid existing range - track the center
            self._last_grid_center[grid_center_key] = (lower_price + upper_price) / 2.0

        # Validate price range
        if lower_price <= 0 or upper_price <= 0 or lower_price >= upper_price:
            return self._set_error(
                bot, f"Invalid price range: {lower_price} - {upper_price}"
            )

        instrument = self._get_instrument_info(symbol)
        if not instrument:
            return self._set_error(bot, f"Failed to fetch instrument info for {symbol}")

        # =============================================================================
        # Feature #10: Out-of-Range Behavior Options
        # =============================================================================
        # Configurable handling when price breaks out of grid range
        # Supports: recenter, pause, close, ignore
        from config.strategy_config import (
            OUT_OF_RANGE_ACTION,
            OUT_OF_RANGE_WAIT_SEC,
            OUT_OF_RANGE_CLOSE_POSITIONS,
        )

        # Out-of-range handling (for fixed mode, dynamic/trailing auto-adjust)
        if range_mode == "fixed" and (
            last_price < lower_price or last_price > upper_price
        ):
            # Track when price first went out of range
            out_of_range_key = f"out_of_range_since_{bot_id}"
            out_of_range_since = bot.get(out_of_range_key)

            if not out_of_range_since:
                # First detection - record timestamp
                bot[out_of_range_key] = now_iso
                logger.warning(
                    f"[{symbol}] ⚠️ Price ${last_price:.8f} BROKE OUT of range "
                    f"[${lower_price:.8f}, ${upper_price:.8f}] - waiting {OUT_OF_RANGE_WAIT_SEC}s before action"
                )
                bot["last_run_at"] = now_iso
                self._set_bot_current_price(bot, last_price, symbol=symbol)
                self.bot_storage.save_bot(bot)
                return bot

            # Calculate how long price has been out of range
            try:
                out_since_dt = datetime.fromisoformat(
                    out_of_range_since.replace("Z", "+00:00")
                )
                now_dt = datetime.now(timezone.utc)
                out_duration_sec = (now_dt - out_since_dt).total_seconds()
            except Exception as e:
                logger.warning(
                    f"[{symbol}] Failed to parse out-of-range timestamp: {e}"
                )
                out_duration_sec = OUT_OF_RANGE_WAIT_SEC + 1  # Force action

            # Wait period to avoid false breakouts
            if out_duration_sec < OUT_OF_RANGE_WAIT_SEC:
                logger.debug(
                    f"[{symbol}] Out-of-range wait period ({out_duration_sec:.0f}s/{OUT_OF_RANGE_WAIT_SEC}s)"
                )
                bot["status"] = "out_of_range"
                bot["last_run_at"] = now_iso
                self._set_bot_current_price(bot, last_price, symbol=symbol)
                self.bot_storage.save_bot(bot)
                return bot

            # Wait period passed - take configured action
            action = OUT_OF_RANGE_ACTION.lower()

            # 001-trading-bot-audit FR-009, US7: Override to pause if volatility extreme
            from config.strategy_config import (
                VOLATILITY_FREEZE_ATR_PCT,
                VOLATILITY_FREEZE_BBW_PCT,
            )

            try:
                oor_ind = self.indicator_service.compute_indicators(symbol, "15m")
                oor_atr_pct = oor_ind.get("atr_pct", 0) if oor_ind else 0
                oor_bbw_pct = oor_ind.get("bbw_pct", 0) if oor_ind else 0
                if (
                    oor_atr_pct > VOLATILITY_FREEZE_ATR_PCT
                    or oor_bbw_pct > VOLATILITY_FREEZE_BBW_PCT
                ):
                    action = "pause"  # Override to pause
                    logger.warning(
                        "[%s] ⚠️ Out-of-range action overridden to PAUSE due to extreme volatility "
                        "(ATR%%=%.2f%%, BBW%%=%.2f%%)",
                        symbol,
                        oor_atr_pct * 100,
                        oor_bbw_pct * 100,
                    )
            except Exception as oor_vol_err:
                logger.debug(
                    "[%s] Volatility check for OOR failed: %s", symbol, oor_vol_err
                )

            # Also check regime for "too_strong" (US7)
            regime = bot.get("regime_effective", "").lower()
            if regime in ("too_strong", "extreme_trend") and action == "recenter":
                action = "pause"
                logger.warning(
                    "[%s] ⚠️ Out-of-range action overridden to PAUSE due to regime: %s",
                    symbol,
                    regime,
                )

            logger.warning(
                f"[{symbol}] 🚨 Out-of-range for {out_duration_sec:.0f}s - taking action: {action}"
            )

            if action == "pause":
                # Pause bot and cancel opening orders
                bot["status"] = "paused"
                bot["last_error"] = (
                    f"Out-of-range: price ${last_price:.8f} outside [{lower_price:.8f}, {upper_price:.8f}]"
                )
                self._cancel_non_reducing_bot_orders(bot, symbol)
                logger.info(
                    f"[{symbol}] ⏸️ PAUSED due to out-of-range (action={action})"
                )

            elif action == "close":
                # Close positions and pause bot
                if OUT_OF_RANGE_CLOSE_POSITIONS:
                    close_resp = self._close_position_or_hard_fail(
                        bot, symbol, "out_of_range"
                    )
                    if close_resp.get("success"):
                        logger.info(
                            f"[{symbol}] ✅ Closed positions due to out-of-range"
                        )

                bot["status"] = "paused"
                bot["last_error"] = (
                    f"Out-of-range: closed positions, price ${last_price:.8f} outside [{lower_price:.8f}, {upper_price:.8f}]"
                )
                cancel_result = self._force_cancel_all_orders(
                    symbol,
                    max_retries=2,
                    bot=bot,
                )
                if not cancel_result.get("success"):
                    logger.warning(
                        "[%s] Out-of-range cancel skipped or failed (%s)",
                        symbol,
                        cancel_result,
                    )
                logger.info(
                    f"[{symbol}] 🛑 CLOSED & PAUSED due to out-of-range (action={action})"
                )

            elif action == "recenter":
                # Check for Smart Recovery first
                recovered = self._handle_smart_recovery(
                    bot, symbol, last_price, fast_indicators, now_iso
                )

                if recovered:
                    # Recovery handled it (either rolled range or scaled out)
                    # Implementation of _handle_smart_recovery already cleared out-of-range flags if rolled
                    pass
                else:
                    # Normal recenter or wait
                    logger.info(
                        f"[{symbol}] 🔄 RECENTERING grid due to out-of-range (action={action})"
                    )
                    # Clear grid center to force recalc
                    grid_center_key = f"{bot_id}_{symbol}"
                    if grid_center_key in self._last_grid_center:
                        del self._last_grid_center[grid_center_key]
                    # Clear out-of-range timestamp
                    bot.pop(out_of_range_key, None)
                    # Continue normal cycle (will recalculate range)

            elif action == "ignore":
                # Just log and continue
                logger.info(f"[{symbol}] ℹ️ Ignoring out-of-range (action={action})")
                # Clear out-of-range timestamp
                bot.pop(out_of_range_key, None)

            else:
                # Unknown action - default to pause
                logger.warning(
                    f"[{symbol}] Unknown out-of-range action '{action}', defaulting to pause"
                )
                bot["status"] = "paused"
                bot["last_error"] = f"Out-of-range with unknown action: {action}"

            bot["last_run_at"] = now_iso
            self._set_bot_current_price(bot, last_price, symbol=symbol)
            bot = self.bot_storage.save_bot(bot)

            # If paused or stopped, return early
            if bot.get("status") in ("paused", "stopped"):
                return bot

        else:
            # Price is within range - clear out-of-range timestamp if exists
            out_of_range_key = f"out_of_range_since_{bot_id}"
            if out_of_range_key in bot:
                bot.pop(out_of_range_key, None)

        # =============================================================================
        # Small Capital Adaptive Tuning (opt-in)
        # =============================================================================
        user_grid_count = int(
            bot.get("target_grid_count", 0) or bot.get("grid_count", 0)
        )
        runtime_grid_cap = int(bot.get("runtime_grid_count_cap") or 0)
        if runtime_grid_cap > 0:
            user_grid_count = min(user_grid_count, runtime_grid_cap)
        small_capital_active = (
            SMALL_CAPITAL_MODE_ENABLED
            and investment <= SMALL_CAPITAL_INVEST_USDT_THRESHOLD
        )
        bot["small_capital_mode_active"] = small_capital_active
        if not small_capital_active:
            bot.pop("small_capital_profile", None)
            bot.pop("_small_capital_block_opening_orders", None)
            bot.pop("per_order_notional_target", None)

        adaptive_config = None
        adaptive_levels = user_grid_count
        adaptive_step_override = None
        if small_capital_active:
            bot.pop("_small_capital_block_opening_orders", None)
            adaptive_config = self.adaptive_config_service.compute_effective_config(
                symbol=symbol,
                invest_usdt=investment,
                leverage=leverage,
                target_levels=user_grid_count,
                instrument=instrument,
                atr_5m_pct=atr_5m_pct,
                atr_15m_pct=atr_15m_pct,
                liq_distance_pct=bot.get("last_liq_distance_pct"),
            )
            adaptive_levels = adaptive_config.get("effective_levels") or user_grid_count
            adaptive_step_override = adaptive_config.get("effective_step_pct")

            bot["small_capital_profile"] = adaptive_config.get("profile")
            bot["per_order_notional_target"] = adaptive_config.get(
                "per_order_notional_target"
            )
            bot["per_order_notional"] = adaptive_config.get("per_order_notional")
            bot["effective_range_pct"] = adaptive_config.get("effective_range_pct")

            if adaptive_config.get("budget_too_small"):
                bot["_small_capital_block_opening_orders"] = True
                bot["last_skip_reason"] = "budget_below_min_notional"
                logger.warning(
                    f"[{symbol}] Small-cap budget too small for min notional (investment=${investment:.2f})"
                )

            allowed_modes = adaptive_config.get("allowed_modes")
            if allowed_modes:
                is_trailing_long = mode == "long" and range_mode == "trailing"
                if not is_trailing_long:
                    bot["_small_capital_block_opening_orders"] = True
                    bot["last_skip_reason"] = "meme_mode_guard"
                    self._cancel_opening_orders_only(bot, symbol)
                    logger.info(
                        f"[{symbol}] Small-cap MEME guard active - only TRAILING_LONG or PAUSE allowed"
                    )

        runtime_target_grid_levels = int(
            (adaptive_levels if small_capital_active else user_grid_count) or 0
        )
        setup_quality = None
        entry_gate_service = None
        if mode in ("long", "short", "neutral", "scalp_pnl", "scalp_market"):
            gate_like_shaping_active = self._is_entry_gate_contract_active(bot, mode)
            try:
                if gate_like_shaping_active:
                    entry_gate_service = self._build_entry_gate_service()
                    if mode in ("long", "short") and directional_gate_result:
                        setup_quality = (
                            ((directional_gate_result or {}).get("scores") or {}).get(
                                "setup_quality"
                            )
                            or None
                        )
                    if setup_quality is None:
                        setup_quality = entry_gate_service.get_setup_quality(
                            symbol=symbol,
                            mode=mode,
                            current_price=last_price,
                            indicators=fast_indicators,
                        )
                    self._apply_setup_quality_runtime_state(bot, setup_quality)
                else:
                    self._clear_setup_quality_runtime_state(bot)
            except Exception as setup_quality_err:
                self._clear_setup_quality_runtime_state(bot)
                logger.debug(
                    "[%s] Setup-quality analysis skipped: %s",
                    symbol,
                    setup_quality_err,
                )
        else:
            self._clear_setup_quality_runtime_state(bot)

        if setup_quality and setup_quality.get("enabled"):
            grid_level_mult = self._safe_float(
                setup_quality.get("grid_level_mult"),
                1.0,
            )
            adjusted_levels = (
                max(2, int(math.floor(runtime_target_grid_levels * grid_level_mult)))
                if runtime_target_grid_levels >= 2
                else runtime_target_grid_levels
            )
            if runtime_target_grid_levels >= 2 and adjusted_levels < runtime_target_grid_levels:
                runtime_target_grid_levels = adjusted_levels
            bot["setup_quality_target_grid_levels"] = runtime_target_grid_levels
        else:
            bot["setup_quality_target_grid_levels"] = None

        if entry_gate_service and self._is_entry_gate_contract_active(bot, mode):
            sr_overlay = self._apply_sr_aware_grid_overlay(
                bot=bot,
                symbol=symbol,
                mode=mode,
                last_price=last_price,
                lower_price=lower_price,
                upper_price=upper_price,
                target_grid_levels=runtime_target_grid_levels,
                entry_gate=entry_gate_service,
                setup_quality=setup_quality,
            )
            lower_price = sr_overlay["lower_price"]
            upper_price = sr_overlay["upper_price"]
            sr_target_levels = int(sr_overlay["target_grid_levels"] or 0)
            if runtime_target_grid_levels >= 2 and sr_target_levels >= 2:
                runtime_target_grid_levels = min(
                    runtime_target_grid_levels,
                    sr_target_levels,
                )
            elif runtime_target_grid_levels <= 0 and sr_target_levels >= 2:
                runtime_target_grid_levels = sr_target_levels
        else:
            bot["sr_aware_grid_applied"] = False
            bot["sr_aware_grid_summary"] = None
            bot["sr_aware_grid_spacing_mult"] = None
            bot["sr_aware_grid_target_levels"] = None

        # Calculate grid step
        # Respect explicit user grid count before applying ATR-derived spacing.
        prefer_explicit_grid_count = user_grid_count >= 2
        # Smart Feature #27-B: Continuous Volatility Spacing
        dynamic_spacing_active = False
        if (
            not prefer_explicit_grid_count
            and VOLATILITY_DYNAMIC_SPACING_ENABLED
            and atr_pct
            and atr_pct > 0
        ):
            # Target spacing is 1.5x ATR, clamped between min/max
            target_spacing = atr_pct * VOLATILITY_SPACING_ATR_MULT
            effective_step_pct = max(
                VOLATILITY_SPACING_MIN_PCT,
                min(VOLATILITY_SPACING_MAX_PCT, target_spacing),
            )
            dynamic_spacing_active = True
            logger.debug(
                f"[{symbol}] Using dynamic volatility spacing: {effective_step_pct:.6f} (ATR%={atr_pct:.4f})"
            )

        # Fallback to fixed grid count spacing if dynamic spacing is off or failed
        if not dynamic_spacing_active:
            grid_count_for_step = runtime_target_grid_levels

            if (
                grid_count_for_step >= 2
                and lower_price > 0
                and upper_price > lower_price
            ):
                ratio = upper_price / lower_price
                effective_step_pct = (
                    math.pow(ratio, 1.0 / (grid_count_for_step - 1)) - 1
                )
                logger.debug(
                    f"[{symbol}] Using grid_count={grid_count_for_step}, calculated step={effective_step_pct:.6f}"
                )
            else:
                effective_step_pct = GRID_STEP_PCT
                # Legacy discrete buckets
                if atr_pct is not None and atr_pct > 0:
                    if atr_pct <= LOW_ATR_PCT:
                        effective_step_pct = GRID_STEP_PCT * TIGHT_GRID_MULTIPLIER
                    elif atr_pct >= HIGH_ATR_PCT:
                        effective_step_pct = GRID_STEP_PCT * WIDE_GRID_MULTIPLIER

        # Apply session volatility adjustment (if enabled)
        if SESSION_USE_VOLATILITY_ADJUST:
            try:
                session_adj = self.session_service.get_volatility_adjustment()
                spacing_mult = session_adj.get("grid_spacing_mult", 1.0)
                if spacing_mult and spacing_mult != 1.0:
                    effective_step_pct *= spacing_mult
                    logger.debug(
                        "[%s] Session spacing mult applied: %.2f (step=%.6f, vol=%s, weekend=%s)",
                        symbol,
                        spacing_mult,
                        effective_step_pct,
                        session_adj.get("volatility_level"),
                        session_adj.get("is_weekend"),
                    )
            except Exception as e:
                logger.debug("[%s] Session spacing adjustment skipped: %s", symbol, e)

        # Apply coin-category multiplier for ALL modes (tighter grids for majors)
        is_major = symbol in TRAILING_MAJOR_SYMBOLS
        category_mult = GRID_STEP_MAJOR_MULT if is_major else GRID_STEP_MEME_MULT

        if is_major or (range_mode == "trailing" and mode in ("long", "short")):
            effective_step_pct = effective_step_pct * category_mult
            logger.debug(
                f"[{symbol}] Applied coin-category multiplier: {category_mult} (is_major={is_major}, mode={mode}, step={effective_step_pct:.6f})"
            )

        if adaptive_step_override is not None and adaptive_step_override > 0:
            effective_step_pct = adaptive_step_override

        fee_aware_min_step_pct = self._get_fee_aware_min_step_pct(bot)
        if fee_aware_min_step_pct > 0 and effective_step_pct < fee_aware_min_step_pct:
            logger.info(
                "[%s] Fee-aware step floor applied: %.6f -> %.6f",
                symbol,
                effective_step_pct,
                fee_aware_min_step_pct,
            )
            effective_step_pct = fee_aware_min_step_pct

        # Leverage-aware step scaling — wider spacing at higher leverage
        # to ensure each fill captures enough price movement to cover fees
        _bot_leverage = max(1.0, float(bot.get("leverage") or leverage or 3.0))
        if _bot_leverage > 5.0:
            leverage_step_mult = _bot_leverage / 5.0
            effective_step_pct *= leverage_step_mult

        derisk_step_mult = self._safe_float(
            volatility_derisk_profile.get("step_mult"), 1.0
        )
        if derisk_step_mult > 1.0:
            effective_step_pct *= derisk_step_mult

        # Ensure sane bounds
        if effective_step_pct <= 0:
            effective_step_pct = GRID_STEP_PCT
        bot["effective_step_pct"] = effective_step_pct
        bot["fee_aware_min_step_pct"] = fee_aware_min_step_pct
        trained_runtime_open_order_cap_total = None

        if self.symbol_training_service:
            try:
                base_open_cap_total = int(
                    bot.get("runtime_open_order_cap_total")
                    or (
                        PROXIMITY_SCALP_OPEN_ORDER_CAP_TOTAL
                        if mode in ("scalp_pnl", "scalp_market")
                        else PROXIMITY_DEFAULT_OPEN_ORDER_CAP_TOTAL
                    )
                )
                training_result = self.symbol_training_service.get_adapted_parameters(
                    symbol=symbol,
                    base_config={
                        "effective_step_pct": effective_step_pct,
                        "runtime_open_order_cap_total": base_open_cap_total,
                        "mode": mode,
                        "range_mode": range_mode,
                        "profile": profile,
                        "atr_pct": atr_pct,
                    },
                    context={
                        "small_capital_active": small_capital_active,
                        "_small_capital_block_opening_orders": bot.get(
                            "_small_capital_block_opening_orders"
                        ),
                        "_volatility_block_opening_orders": bot.get(
                            "_volatility_block_opening_orders"
                        ),
                        "fee_aware_min_step_pct": fee_aware_min_step_pct,
                    },
                )
                bot["training_status"] = training_result.get("training_status")
                bot["training_confidence"] = training_result.get("confidence", 0.0)
                bot["training_adaptations"] = training_result.get(
                    "adaptations_applied", []
                )
                bot["training_applied_step_pct"] = effective_step_pct
                bot["training_applied_open_cap_total"] = base_open_cap_total

                trained_step_pct = self._safe_float(
                    training_result.get("effective_step_pct"), 0.0
                )
                if trained_step_pct > 0:
                    effective_step_pct = trained_step_pct
                    if fee_aware_min_step_pct > 0:
                        effective_step_pct = max(
                            effective_step_pct, fee_aware_min_step_pct
                        )
                    bot["effective_step_pct"] = effective_step_pct
                    bot["training_applied_step_pct"] = effective_step_pct

                trained_open_cap_total = int(
                    training_result.get("runtime_open_order_cap_total") or 0
                )
                if trained_open_cap_total > 0:
                    trained_runtime_open_order_cap_total = trained_open_cap_total
                    bot["training_applied_open_cap_total"] = trained_open_cap_total

                if training_result.get("adaptations_applied"):
                    logger.info(
                        "[%s] Training adaptations applied: %s",
                        symbol,
                        training_result.get("adaptations_applied"),
                    )
            except Exception as e:
                logger.debug("[%s] Training adaptation skipped: %s", symbol, e)

        quality_spacing_mult = 1.0
        if setup_quality and setup_quality.get("enabled"):
            quality_spacing_mult = max(
                quality_spacing_mult,
                self._safe_float(setup_quality.get("grid_spacing_mult"), 1.0),
            )
        quality_spacing_mult = max(
            quality_spacing_mult,
            self._safe_float(bot.get("sr_aware_grid_spacing_mult"), 1.0),
        )
        if quality_spacing_mult > 1.0:
            effective_step_pct *= quality_spacing_mult

        if runtime_target_grid_levels >= 2 and lower_price > 0 and upper_price > lower_price:
            target_ratio = upper_price / lower_price
            target_step_pct = (
                math.pow(target_ratio, 1.0 / (runtime_target_grid_levels - 1)) - 1
            )
            effective_step_pct = max(effective_step_pct, target_step_pct)
            bot["setup_quality_target_grid_levels"] = runtime_target_grid_levels
        else:
            bot["setup_quality_target_grid_levels"] = None

        bot["effective_step_pct"] = effective_step_pct

        # =============================================================================
        # Feature #7: Grid Distribution Modes
        # =============================================================================
        # Build grid levels with optional distribution patterns (buy_heavy, sell_heavy, clustered)
        from config.strategy_config import (
            DEFAULT_GRID_DISTRIBUTION,
            GRID_BUY_SELL_RATIO,
            GRID_CLUSTER_CONCENTRATION,
        )

        # Get distribution mode from bot config (fallback to default)
        grid_distribution = bot.get("grid_distribution", DEFAULT_GRID_DISTRIBUTION)

        # Smart Grid Spacing: ATR-adaptive concentration
        # High ATR (volatile) = spread grids wider (lower concentration)
        # Low ATR (calm) = pack grids tighter near price (higher concentration)
        smart_concentration = GRID_CLUSTER_CONCENTRATION
        if grid_distribution == "clustered" and atr_pct is not None and atr_pct > 0:
            # ATR < 0.5% => very calm, pack tight (0.85 concentration)
            # ATR ~ 1% => normal (0.70 concentration)
            # ATR > 2% => volatile, spread out (0.55 concentration)
            if atr_pct < 0.005:
                smart_concentration = 0.85  # Very tight near price
            elif atr_pct < 0.01:
                smart_concentration = 0.75  # Moderate concentration
            elif atr_pct < 0.02:
                smart_concentration = 0.65  # Slightly spread
            else:
                smart_concentration = 0.55  # Volatile - spread grids wider
            
            if smart_concentration != GRID_CLUSTER_CONCENTRATION:
                logger.info(
                    f"[{symbol}] Smart grid: ATR={atr_pct*100:.2f}% -> concentration={smart_concentration:.2f} "
                    f"(default={GRID_CLUSTER_CONCENTRATION:.2f})"
                )

        # =====================================================================
        # ATR-Adaptive Take-Profit (for ALL modes)
        # Scale TP thresholds based on actual market volatility
        # =====================================================================
        if atr_pct and atr_pct > 0:
            _atr_scale = max(0.3, min(3.0, atr_pct / 0.01))
            bot["_atr_adaptive_tp_levels"] = [
                (0.005 * _atr_scale, 0.30),
                (0.010 * _atr_scale, 0.40),
                (0.020 * _atr_scale, 0.30),
            ]
            bot["_atr_partial_tp_min_pct"] = max(0.001, 0.0035 * _atr_scale)
            bot["_atr_profit_lock_arm_pct"] = max(0.003, 0.008 * _atr_scale)
            if _atr_scale < 0.8 or _atr_scale > 1.2:
                logger.info(
                    f"[{symbol}] ATR-adaptive TP: scale={_atr_scale:.2f}x, "
                    f"levels=[{0.5*_atr_scale:.1f}%, {1.0*_atr_scale:.1f}%, {2.0*_atr_scale:.1f}%]"
                )
        
        # ATR-Adaptive Scalp TP (for scalp_pnl mode)
        if mode == "scalp_pnl" and hasattr(self, 'scalp_pnl_service'):
            _s_atr = atr_pct if (atr_pct and atr_pct > 0) else 0.01
            _s_inv = float(bot.get("investment", 10) or 10)
            _s_price = last_price if last_price > 0 else float(bot.get("current_price", 1) or 1)
            targets = self.scalp_pnl_service.adapt_targets_to_atr(_s_atr, _s_inv, _s_price)
            # Store adapted targets in bot dict for dashboard display
            bot["_scalp_adapted_target"] = targets["target_profit"]
            bot["_scalp_adapted_quick"] = targets["quick_profit"]
            bot["_scalp_adapted_min"] = targets["min_profit"]
            bot["_scalp_adapted_max"] = targets["max_target"]

        # Build grid with distribution support
        grid_result = self.grid_engine.build_levels_with_distribution(
            lower=lower_price,
            upper=upper_price,
            current_price=last_price,
            distribution=grid_distribution,
            grid_step_pct=effective_step_pct,
            buy_sell_ratio=GRID_BUY_SELL_RATIO,
            cluster_concentration=smart_concentration,
        )

        levels = grid_result.get("levels", [])
        if not levels:
            return self._set_error(bot, "Failed to build grid levels")

        # Log distribution stats if not balanced
        if grid_distribution != "balanced":
            logger.info(
                f"[{symbol}] 📊 Grid distribution={grid_distribution}, "
                f"total={grid_result.get('total_count')}, "
                f"buy={grid_result.get('buy_count')}, "
                f"sell={grid_result.get('sell_count')}"
            )

        # Risk checks
        effective_capital = self._calculate_effective_capital(
            bot=bot,
            investment=investment,
            leverage=leverage,
            available_equity=self._get_usdt_available_balance(),
        )
        bot_realized_pnl = self._safe_float(bot.get("realized_pnl"), 0.0)
        risk_result = self.risk_manager.check_bot_limits(
            bot_id or "unknown",
            bot_realized_pnl,
            effective_capital,
        )
        if risk_result.get("risk_stopped"):
            current_bot = self.bot_storage.get_bot(bot_id)
            if current_bot and current_bot.get("status") not in (
                "running",
                "risk_stopped",
            ):
                return current_bot
            bot = self._transition_to_stop_cleanup_state(
                bot,
                symbol,
                target_status="risk_stopped",
                cleanup_reason="max_bot_loss_limit",
                final_last_error="Bot hit max loss limit",
                now_iso=now_iso,
            )
            logger.warning(f"[{symbol}] Risk stopped due to loss limit")
            return bot

        # Additional safeguard: include unrealized PnL in loss limit (prevents silent large drawdowns)
        # NOTE: This legacy check only runs if UPnL SL did not run
        # When UPnL SL is enabled, it takes precedence (checked earlier in cycle)
        new_upnl_ran = ENABLE_UPNL_STOPLOSS and bot.get("upnl_stoploss_enabled")
        if not new_upnl_ran:
            try:
                positions_resp = self.client.get_positions()
                symbol_unrealized = 0.0
                if positions_resp.get("success"):
                    pos_list = (positions_resp.get("data", {}) or {}).get(
                        "list", []
                    ) or []
                    for pos in pos_list:
                        if pos.get("symbol") == symbol:
                            try:
                                symbol_unrealized += float(
                                    pos.get("unrealisedPnl", 0) or 0
                                )
                            except (ValueError, TypeError):
                                continue
                total_pnl = bot_realized_pnl + symbol_unrealized
                pnl_pct_total = (
                    (total_pnl / effective_capital) if effective_capital > 0 else 0.0
                )
                if pnl_pct_total <= -float(
                    getattr(self.risk_manager, "max_bot_loss_pct", 0.05) or 0.05
                ):
                    current_bot = self.bot_storage.get_bot(bot_id)
                    if current_bot and current_bot.get("status") not in (
                        "running",
                        "risk_stopped",
                    ):
                        return current_bot
                    bot = self._transition_to_stop_cleanup_state(
                        bot,
                        symbol,
                        target_status="risk_stopped",
                        cleanup_reason="legacy_total_pnl_risk_stop",
                        final_last_error=(
                            f"Risk stop (total PnL {pnl_pct_total:.4%} ≤ -max loss)"
                        ),
                        now_iso=now_iso,
                    )
                    logger.warning(
                        f"[{symbol}] Risk-stopped by legacy unrealized check (pnl_pct={pnl_pct_total:.4%})"
                    )
                    return bot
            except Exception as _e:
                # Best-effort; continue if positions lookup fails
                logger.debug(f"[{symbol}] Unrealized PnL check failed: {_e}")

        # Orders handling
        min_order_qty = instrument.get("min_order_qty")
        qty_step = instrument.get("qty_step")
        tick_size = instrument.get("tick_size")
        min_notional_value = instrument.get("min_notional_value", 5.0)
        if not min_order_qty or not qty_step or not tick_size:
            return self._set_error(bot, f"Missing instrument sizing for {symbol}")

        # =============================================================================
        # FETCH OPEN ORDERS ONCE - Use single API call for all order checks
        # =============================================================================
        open_orders_response = self.client.get_open_orders(
            symbol=symbol,
            limit=200,
            skip_cache=True,
        )
        order_list = []
        if open_orders_response.get("success"):
            order_list = open_orders_response.get("data", {}).get("list", []) or []
        duplicate_cleanup = self._cancel_duplicate_bot_orders(
            bot=bot,
            symbol=symbol,
            order_list=order_list,
        )
        if duplicate_cleanup.get("cancelled_count", 0) > 0:
            order_list = duplicate_cleanup.get("order_list", order_list)
        order_snapshot = self._snapshot_open_orders(order_list, tick_size)
        existing_order_prices = order_snapshot["existing_order_prices"]
        existing_order_prices_list = order_snapshot["existing_order_prices_list"]
        existing_orders_with_ids = order_snapshot["existing_orders_with_ids"]
        current_order_count = order_snapshot["current_order_count"]
        existing_reduce_only_buy_qty = order_snapshot["existing_reduce_only_buy_qty"]
        existing_reduce_only_sell_qty = order_snapshot["existing_reduce_only_sell_qty"]

        # Cancel any open orders clearly outside the current range each cycle.
        # Use half-tick tolerance to avoid churn from boundary rounding drift
        # (e.g., lower=16.2074997 while valid tick price=16.207).
        if lower_price and upper_price and upper_price > lower_price and order_list:
            range_tolerance = max(float(tick_size) * 0.5, 1e-12)
            lower_bound = lower_price - range_tolerance
            upper_bound = upper_price + range_tolerance
            cancelled_outside = 0
            cancelled_ids = set()
            for order in order_list:
                price = float(order.get("price", 0) or 0)
                if price <= 0:
                    continue
                if price < lower_bound or price > upper_bound:
                    order_id = order.get("orderId")
                    if not order_id:
                        continue
                    try:
                        cancel_result = self.client.cancel_order(symbol, order_id)
                        if cancel_result.get("success"):
                            cancelled_outside += 1
                            cancelled_ids.add(order_id)
                    except Exception:
                        continue

            if cancelled_outside > 0:
                logger.info(
                    f"[{symbol}] Cancelled {cancelled_outside} orders outside range "
                    f"({lower_price:.6f}-{upper_price:.6f})"
                )

            if cancelled_ids:
                order_list = [
                    order
                    for order in order_list
                    if order.get("orderId") not in cancelled_ids
                ]
                order_snapshot = self._snapshot_open_orders(order_list, tick_size)
                existing_order_prices = order_snapshot["existing_order_prices"]
                existing_order_prices_list = order_snapshot["existing_order_prices_list"]
                existing_orders_with_ids = order_snapshot["existing_orders_with_ids"]
                current_order_count = order_snapshot["current_order_count"]
                existing_reduce_only_buy_qty = order_snapshot["existing_reduce_only_buy_qty"]
                existing_reduce_only_sell_qty = order_snapshot["existing_reduce_only_sell_qty"]

        logger.debug(
            f"[{symbol}] Found {current_order_count} existing orders for {symbol}"
        )

        active_open_order_cap_total = int(
            trained_runtime_open_order_cap_total
            or bot.get("runtime_open_order_cap_total")
            or (
                PROXIMITY_SCALP_OPEN_ORDER_CAP_TOTAL
                if mode in ("scalp_pnl", "scalp_market")
                else PROXIMITY_DEFAULT_OPEN_ORDER_CAP_TOTAL
            )
        )
        if volatility_derisk_profile.get("open_cap_total"):
            active_open_order_cap_total = min(
                active_open_order_cap_total,
                int(
                    volatility_derisk_profile.get("open_cap_total")
                    or active_open_order_cap_total
                ),
            )
        manual_open_cap_total = self._get_manual_runtime_open_order_cap_total(bot)
        if manual_open_cap_total > 0:
            active_open_order_cap_total = min(
                active_open_order_cap_total,
                manual_open_cap_total,
            )
        active_open_order_cap_total = max(2, active_open_order_cap_total)

        if setup_quality and setup_quality.get("enabled"):
            entry_aggressiveness_mult = self._safe_float(
                setup_quality.get("entry_aggressiveness_mult"),
                1.0,
            )
            adjusted_open_cap_total = max(
                2,
                int(math.ceil(active_open_order_cap_total * entry_aggressiveness_mult)),
            )
            if adjusted_open_cap_total < active_open_order_cap_total:
                logger.info(
                    "[%s] Setup-quality open-order cap: %s -> %s (score=%.1f, band=%s)",
                    symbol,
                    active_open_order_cap_total,
                    adjusted_open_cap_total,
                    self._safe_float(setup_quality.get("score"), 0.0),
                    setup_quality.get("band"),
                )
                active_open_order_cap_total = adjusted_open_cap_total
            bot["setup_quality_open_order_cap_total"] = active_open_order_cap_total
        bot["runtime_open_order_cap_total"] = active_open_order_cap_total
        launch_affordability = bot.get("launch_affordability")
        if isinstance(launch_affordability, dict):
            launch_affordability["max_active_open_orders"] = active_open_order_cap_total

        trimmed_opening_order_ids = self._trim_opening_orders_to_cap(
            symbol=symbol,
            last_price=last_price,
            existing_orders_with_ids=existing_orders_with_ids,
            max_open_orders=active_open_order_cap_total,
        )
        if trimmed_opening_order_ids:
            order_list = [
                order
                for order in order_list
                if order.get("orderId") not in trimmed_opening_order_ids
            ]
            order_snapshot = self._snapshot_open_orders(order_list, tick_size)
            existing_order_prices = order_snapshot["existing_order_prices"]
            existing_order_prices_list = order_snapshot["existing_order_prices_list"]
            existing_orders_with_ids = order_snapshot["existing_orders_with_ids"]
            current_order_count = order_snapshot["current_order_count"]
            existing_reduce_only_buy_qty = order_snapshot["existing_reduce_only_buy_qty"]
            existing_reduce_only_sell_qty = order_snapshot["existing_reduce_only_sell_qty"]

        # =============================================================================
        # GRID EXTENSION: Extend grid levels when orders are filled
        # - For directional modes (long/short): Extend in the direction of trading
        # - For neutral mode: Extend both sides to maintain symmetric grid
        # =============================================================================
        should_extend_grid = (
            range_mode in ("trailing", "dynamic")
            and existing_order_prices_list
            and mode in ("long", "short", "neutral")
        )

        if should_extend_grid:
            levels = self._extend_trailing_grid(
                levels=levels,
                last_price=last_price,
                existing_order_prices=existing_order_prices_list,
                mode=mode,
                step_pct=effective_step_pct,
                bot_id=bot_id,
                symbol=symbol,
                indicators=fast_indicators,
            )

        # =============================================================================
        # Build Biased Levels for Directional Trading
        # =============================================================================
        buy_levels, sell_levels = self._build_biased_levels(
            levels=levels,
            last_price=last_price,
            mode=mode,
            tick_size=tick_size,
            existing_order_prices=existing_order_prices,
            fast_indicators=fast_indicators,
            range_mode=range_mode,
        )

        # Enforce range bounds for new orders (dynamic/trailing ranges should not place outside)
        if lower_price and upper_price and upper_price > lower_price:
            buy_levels = [
                lvl for lvl in buy_levels
                if lower_price <= lvl <= upper_price
            ]
            sell_levels = [
                lvl for lvl in sell_levels
                if lower_price <= lvl <= upper_price
            ]

        runtime_open_order_cap_total = active_open_order_cap_total
        buy_levels, sell_levels = self._cap_levels_by_proximity(
            buy_levels=buy_levels,
            sell_levels=sell_levels,
            last_price=last_price,
            max_total=runtime_open_order_cap_total,
        )

        num_levels = len(buy_levels) + len(sell_levels)
        if num_levels > 0 and last_price > 0:
            # 1. Get available balance (best-effort)
            avail_equity = self._get_usdt_available_balance()

            # 2. Unified Reserve Check
            reserve_usd, usable_investment = self._calculate_auto_margin_reserve(
                bot, investment, avail_equity
            )

            size_mult = self._safe_float(
                volatility_derisk_profile.get("size_mult"), 1.0
            )
            total_notional = usable_investment * leverage * size_mult
            position_size_per_level = total_notional / (num_levels * last_price)
        else:
            position_size_per_level = 0.0

        # =============================================================================
        # DYNAMIC POSITION SIZING (Smart Feature #20)
        # Scale position size based on signal confidence
        # =============================================================================
        try:
            from config.strategy_config import (
                DYNAMIC_SIZING_ENABLED,
                DYNAMIC_SIZING_HIGH_CONFIDENCE,
                DYNAMIC_SIZING_MEDIUM_CONFIDENCE,
                DYNAMIC_SIZING_LOW_MULTIPLIER,
                DYNAMIC_SIZING_MEDIUM_MULTIPLIER,
                DYNAMIC_SIZING_HIGH_MULTIPLIER,
            )

            if DYNAMIC_SIZING_ENABLED and mode in ("long", "short"):
                direction_score = abs(
                    self._safe_float(
                        bot.get("direction_score"),
                        self._safe_float(bot.get("setup_quality_score"), 0.0),
                    )
                )

                if direction_score >= DYNAMIC_SIZING_HIGH_CONFIDENCE:
                    size_multiplier = DYNAMIC_SIZING_HIGH_MULTIPLIER
                elif direction_score >= DYNAMIC_SIZING_MEDIUM_CONFIDENCE:
                    size_multiplier = DYNAMIC_SIZING_MEDIUM_MULTIPLIER
                else:
                    size_multiplier = DYNAMIC_SIZING_LOW_MULTIPLIER

                # Performance memory adjustment — scale up for winners, down for losers
                memory = getattr(self, "auto_pilot_memory", None)
                if memory is not None:
                    mem_risk = memory.get_risk_multiplier(symbol)
                    if mem_risk != 1.0:
                        size_multiplier *= mem_risk
                        size_multiplier = max(0.3, min(1.5, size_multiplier))

                # Flow confidence boost — strong flow = more conviction = bigger size
                flow_score_val = abs(self._safe_float(bot.get("flow_score"), 0.0))
                flow_conf = self._safe_float(bot.get("flow_confidence"), 0.0)
                if flow_score_val >= 40 and flow_conf >= 0.45:
                    size_multiplier = min(1.5, size_multiplier * 1.2)  # +20% for strong flow

                # Apply multiplier
                original_size = position_size_per_level
                position_size_per_level *= size_multiplier

                # Store for dashboard display
                bot["position_size_multiplier"] = round(size_multiplier, 2)

                if size_multiplier != 1.0:
                    logger.debug(
                        f"[{symbol}] Dynamic sizing: score={direction_score:.0f} → "
                        f"multiplier={size_multiplier:.2f}x ({original_size:.6f}→{position_size_per_level:.6f})"
                    )
        except Exception as e:
            logger.debug(
                f"[{symbol}] Dynamic position sizing failed (non-critical): {e}"
            )

        position_size_per_level = self._round_to_step(
            position_size_per_level, qty_step, round_down=True
        )
        order_value = position_size_per_level * last_price
        bot["effective_levels"] = num_levels
        if num_levels > 0:
            bot["effective_range_pct"] = effective_step_pct * num_levels / 2.0
        bot["per_order_notional"] = order_value

        capital_starved_opening_reason = None

        # Check minimum order quantity
        if position_size_per_level < min_order_qty:
            capital_starved_opening_reason = "qty_below_min"
            if small_capital_active:
                bot["_small_capital_block_opening_orders"] = True
            logger.warning(
                f"[{symbol}] Opening qty below min (qty={position_size_per_level}, min={min_order_qty})"
            )

        # Check minimum order VALUE (notional) - use symbol-specific minimum from Bybit
        if order_value < min_notional_value:
            self._register_failure_breaker_event(
                bot, "notional_below_min", now_ts=now_ts
            )
            # =============================================================================
            # AUTO GRID ADJUSTMENT: Automatically reduce grid levels to meet minimum
            # =============================================================================
            try:
                from config.strategy_config import (
                    AUTO_GRID_ADJUSTMENT_ENABLED,
                    AUTO_GRID_ADJUSTMENT_MIN_LEVELS,
                    AUTO_GRID_ADJUSTMENT_BUFFER,
                )
            except ImportError:
                AUTO_GRID_ADJUSTMENT_ENABLED = True
                AUTO_GRID_ADJUSTMENT_MIN_LEVELS = 3
                AUTO_GRID_ADJUSTMENT_BUFFER = 1.1

            # Calculate max levels that would meet minimum notional (with buffer)
            target_notional = min_notional_value * AUTO_GRID_ADJUSTMENT_BUFFER
            total_notional_available = max(order_value * num_levels, 0.0)
            max_allowed_levels = int(total_notional_available / target_notional)

            if AUTO_GRID_ADJUSTMENT_ENABLED and max_allowed_levels >= AUTO_GRID_ADJUSTMENT_MIN_LEVELS:
                # Auto-adjust grid_count to meet minimum
                old_grid_count = bot.get("grid_count", num_levels)
                new_grid_count = max(AUTO_GRID_ADJUSTMENT_MIN_LEVELS, max_allowed_levels)

                # Preserve configured grid_count; store runtime reduction separately.
                bot["grid_levels_total_effective"] = new_grid_count
                bot["runtime_grid_count"] = new_grid_count

                # Recalculate with new levels
                num_levels = new_grid_count
                position_size_per_level = total_notional_available / (num_levels * last_price)
                position_size_per_level = self._round_to_step(
                    position_size_per_level, qty_step, round_down=True
                )
                order_value = position_size_per_level * last_price
                bot["effective_levels"] = num_levels
                bot["per_order_notional"] = order_value
                if (
                    position_size_per_level >= min_order_qty
                    and order_value >= min_notional_value
                ):
                    capital_starved_opening_reason = None

                # Truncate existing levels to new_grid_count (keep closest to current price)
                # Sort levels by distance from current price and keep closest ones
                all_levels = sorted(levels, key=lambda x: abs(x - last_price))
                levels = sorted(all_levels[:new_grid_count])  # Keep closest, then sort by price

                # Rebuild buy/sell levels from truncated levels using the active mode rules.
                buy_levels, sell_levels = self._build_biased_levels(
                    levels=levels,
                    last_price=last_price,
                    mode=mode,
                    tick_size=tick_size,
                    existing_order_prices=existing_order_prices,
                    fast_indicators=fast_indicators,
                    range_mode=range_mode,
                )

                if lower_price and upper_price and upper_price > lower_price:
                    buy_levels = [
                        lvl for lvl in buy_levels
                        if lower_price <= lvl <= upper_price
                    ]
                    sell_levels = [
                        lvl for lvl in sell_levels
                        if lower_price <= lvl <= upper_price
                    ]

                logger.warning(
                    f"[{symbol}] AUTO_GRID_ADJUST: Reduced grid_count {old_grid_count}→{new_grid_count} "
                    f"to meet ${min_notional_value:.2f} minimum (now ${order_value:.2f}/order)"
                )

                # Clear any previous error state since we fixed it
                if bot.get("status") == "error" and "below minimum" in (bot.get("last_error") or ""):
                    bot["status"] = "running"
                    bot["last_error"] = None
            else:
                # Cannot auto-adjust - either disabled or would go below min levels
                # Calculate minimum qty needed to meet min notional
                min_qty_for_value = min_notional_value / last_price
                min_qty_for_value = self._round_to_step(
                    min_qty_for_value, qty_step, round_down=False
                )
                # Round up to next step
                if min_qty_for_value * last_price < min_notional_value:
                    min_qty_for_value += qty_step

                min_investment_needed = (min_notional_value * num_levels) / leverage
                min_leverage_needed = None
                if investment > 0:
                    min_leverage_needed = (min_notional_value * num_levels) / investment
                    if min_leverage_needed < 1.0:
                        min_leverage_needed = 1.0
                    # round up to 2 decimals for display
                    min_leverage_needed = math.ceil(min_leverage_needed * 100) / 100.0

                capital_starved_opening_reason = "notional_below_min"
                if small_capital_active:
                    bot["_small_capital_block_opening_orders"] = True
                lev_hint = (
                    f" or leverage >= {min_leverage_needed:.2f}x"
                    if min_leverage_needed
                    else ""
                )
                logger.warning(
                    f"[{symbol}] Opening notional below min (order=${order_value:.2f}, min=${min_notional_value:.2f}, "
                    f"need qty {min_qty_for_value:.6f}, investment >= ${min_investment_needed:.0f} at {leverage}x{lev_hint})"
                )

        # =============================================================================
        # TOLERANCE-BASED ORDER CHECK: Don't place orders if one exists nearby
        # This prevents the add/cancel loop when price moves slightly
        # =============================================================================
        ORDER_TOLERANCE_PCT = 0.0005  # 0.05% tolerance (allow tighter grid placement)

        # Determine which buy/sell levels need orders (with tolerance check)
        buy_levels_needing_orders = []
        for level in buy_levels:
            # Check both exact match (rounded) and tolerance-based match
            rounded_level = self._round_to_step(level, tick_size, round_down=False)
            has_exact = rounded_level in existing_order_prices
            has_near = self._has_order_near_level(
                level, existing_order_prices_list, ORDER_TOLERANCE_PCT
            )
            if not has_exact and not has_near:
                buy_levels_needing_orders.append(level)

        sell_levels_needing_orders = []
        for level in sell_levels:
            rounded_level = self._round_to_step(level, tick_size, round_down=False)
            has_exact = rounded_level in existing_order_prices
            has_near = self._has_order_near_level(
                level, existing_order_prices_list, ORDER_TOLERANCE_PCT
            )
            if not has_exact and not has_near:
                sell_levels_needing_orders.append(level)

        total_biased_levels = len(buy_levels) + len(sell_levels)
        levels_needing_orders = buy_levels_needing_orders + sell_levels_needing_orders
        existing_count = total_biased_levels - len(levels_needing_orders)

        # NOTE: Removed aggressive full reset logic - it was causing grid explosion
        # as price movement changed biased levels and triggered constant resets.
        # Now we only place orders at levels that don't already have them.

        # Cap on how many orders already exist - if too many, don't add more
        reduce_only_order_count = sum(
            1 for _, _, _, is_reduce_only in existing_orders_with_ids if is_reduce_only
        )
        MAX_ORDERS_PER_SYMBOL = max(
            2,
            runtime_open_order_cap_total + reduce_only_order_count,
        )
        # current_order_count already fetched above from single API call

        # =============================================================================
        # GRID REPLACEMENT LOGIC: Replace filled orders to maintain grid density
        # - Always allow placement if there are levels needing orders (orders were filled)
        # - This ensures grids are maintained for ALL modes (neutral, long, short)
        # - Hard cap at MAX_ORDERS_PER_SYMBOL to prevent explosion
        # =============================================================================
        has_levels_needing_orders = len(levels_needing_orders) > 0

        if has_levels_needing_orders:
            # There are levels needing orders - allow replacement of filled orders
            logger.info(
                f"[{symbol}] {len(levels_needing_orders)} levels need orders "
                f"(current: {current_order_count}, buys: {len(buy_levels_needing_orders)}, sells: {len(sell_levels_needing_orders)})"
            )
        else:
            # Grid is complete - all levels have orders, nothing to do
            logger.debug(
                f"[{symbol}] Grid complete - all {current_order_count} levels have orders"
            )

        if current_order_count >= MAX_ORDERS_PER_SYMBOL:
            logger.debug(
                f"[{symbol}] Already {current_order_count} orders, at cap of {MAX_ORDERS_PER_SYMBOL}"
            )
            bot["last_run_at"] = now_iso
            bot["last_error"] = None
            self._set_bot_current_price(bot, last_price, symbol=symbol)
            bot["runtime_grid_count"] = current_order_count
            bot["orders_placed"] = current_order_count
            self.bot_storage.save_bot(bot)
            return bot

        # Limit how many new orders to place per cycle
        # Neutral mode: place all grids at once (like Bybit native bot)
        # Other modes: gradual placement for safety
        if mode == "neutral":
            MAX_NEW_ORDERS_PER_CYCLE = 100  # No practical limit for neutral
        else:
            MAX_NEW_ORDERS_PER_CYCLE = (
                12  # 6 buys + 6 sells for directional modes (faster refill)
            )
        available_slots = MAX_ORDERS_PER_SYMBOL - current_order_count
        max_new = min(MAX_NEW_ORDERS_PER_CYCLE, available_slots)
        exchange_truth_opening_blocker = self._get_exchange_truth_opening_blocker(bot)
        opening_order_guard_skip = (
            failure_breaker_skip_opening_orders
            or bool(bot.get("_volatility_block_opening_orders"))
            or bool(exchange_truth_opening_blocker)
        )
        opening_order_guard_reason = None
        if exchange_truth_opening_blocker is not None:
            opening_order_guard_reason = exchange_truth_opening_blocker["reason_text"]
        elif failure_breaker_skip_opening_orders:
            opening_order_guard_reason = failure_breaker_reason
        elif bot.get("_volatility_block_opening_orders"):
            opening_order_guard_reason = (
                f"Volatility de-risk ({bot.get('volatility_derisk_tier')})"
            )

        if not buy_levels_needing_orders and not sell_levels_needing_orders:
            logger.debug(
                f"[{symbol}] All {total_biased_levels} grid orders already in place (mode={mode})"
            )
            bot["last_run_at"] = now_iso
            bot["last_error"] = None
            self._set_bot_current_price(bot, last_price, symbol=symbol)
            bot["runtime_grid_count"] = total_biased_levels
            bot["orders_placed"] = existing_count

            current_bot = self.bot_storage.get_bot(bot_id)
            if current_bot and current_bot.get("status") != "running":
                return current_bot
            self.bot_storage.save_bot(bot)
            return bot

        # Sort: buys descending (closest to price first), sells ascending (closest to price first)
        buy_levels_needing_orders = sorted(buy_levels_needing_orders, reverse=True)
        sell_levels_needing_orders = sorted(sell_levels_needing_orders)

        # =============================================================================
        # TREND FILTER FOR TRAILING MODES
        # Long trailing: DCA buys placed regardless of trend (catch dips)
        # Short trailing: Only place SELL orders in downtrend (wait for confirmation)
        # =============================================================================
        trend_status = None
        if range_mode == "trailing" and mode in ("long", "short"):
            candle_color = (
                self._detect_candle_color(fast_indicators)
                if fast_indicators
                else "neutral"
            )

            if mode == "long":
                # DCA mode: place buy orders regardless of trend to catch dips
                trend_status = f"DCA mode - placing buy orders (trend: {candle_color})"
                bot["trend_status"] = trend_status
                logger.debug(f"[{symbol}] LONG trailing - {trend_status}")

            elif mode == "short":
                if candle_color != "red":
                    # Don't place sell orders in uptrend/neutral - wait for downtrend
                    skipped_sells = len(sell_levels_needing_orders)
                    sell_levels_needing_orders = []
                    trend_status = f"Waiting for downtrend (current: {candle_color}) - skipped {skipped_sells} sell orders"
                    logger.info(f"[{symbol}] SHORT trailing - {trend_status}")
                    bot["trend_status"] = trend_status
                else:
                    trend_status = "Downtrend confirmed - placing sell orders"
                    bot["trend_status"] = trend_status

        logger.info(
            f"[{symbol}] Placing orders (mode={mode}): "
            f"{len(buy_levels_needing_orders)} buys, {len(sell_levels_needing_orders)} sells, "
            f"qty_per_level={position_size_per_level}, step={effective_step_pct:.4f} (cap={max_new})"
        )

        orders_placed = 0
        skipped_reasons = {}
        orders_failed = 0
        buy_orders_failed_balance = 0
        sell_orders_failed_balance = 0
        buy_orders_placed = 0
        sell_orders_placed = 0
        initial_opening_orders_placed = 0
        add_follow_through_placed = 0
        opening_order_margin_exhausted = False
        opening_order_block_reason = None

        # Initialize sequence counter for orderLinkId
        # Use timestamp to ensure uniqueness across cycles
        import time as time_module

        cycle_ts = (
            int(time_module.time() * 1000) % 1000000000
        )  # Last 9 digits of ms timestamp
        seq = 0

        # =============================================================================
        # REDUCE_ONLY LOGIC - Critical for order acceptance
        # - neutral mode: BOTH sides can OPEN positions (reduce_only=False)
        # - long mode: buys open (False), sells close (True)
        # - short mode: sells open (False), buys close (True)
        # =============================================================================
        if mode == "neutral":
            buy_reduce_only = False
            sell_reduce_only = False
        elif mode == "long":
            buy_reduce_only = False
            sell_reduce_only = True  # Sells are take-profit
        elif mode == "short":
            buy_reduce_only = True  # Buys are cover orders
            sell_reduce_only = False
        else:
            # Default to neutral behavior
            buy_reduce_only = False
            sell_reduce_only = False

        # Bot-level reduce-only mode (e.g., auto-stop safety): block all new entries
        reduce_only_mode = bool(bot.get("reduce_only_mode"))
        if reduce_only_mode:
            buy_reduce_only = True
            sell_reduce_only = True
            bot["last_skip_reason"] = "reduce_only_mode_active"
            logger.info(
                f"[{symbol}] Reduce-only mode active - skipping new opening orders"
            )

        # =============================================================================
        # POSITION CHECK - Skip reduce_only orders if no position exists
        # Long mode: Skip sells if no long position (nothing to take profit on)
        # Short mode: Skip buys if no short position (nothing to cover)
        # =============================================================================
        current_position_size = 0.0
        current_position_side = None
        current_position_unrealized_pnl = 0.0
        avg_entry_price = 0.0
        try:
            pos_resp = self.client.get_positions(skip_cache=True)
            if pos_resp.get("success"):
                for pos in (pos_resp.get("data", {}) or {}).get("list", []) or []:
                    if pos.get("symbol") == symbol:
                        pos_size = float(pos.get("size", 0) or 0)
                        if pos_size > 0:
                            current_position_size = pos_size
                            current_position_side = pos.get(
                                "side", ""
                            ).lower()  # "buy" or "sell"
                            current_position_unrealized_pnl = self._safe_float(
                                pos.get("unrealisedPnl"),
                                0.0,
                            )
                            avg_entry_price = self._safe_float(
                                pos.get("avgPrice"), 0.0
                            )
                            break
        except Exception as e:
            logger.debug(f"[{symbol}] Position check failed: {e}")

        # --- Phase 2: Position divergence continuous audit ---
        prev_persisted = self._safe_float(bot.get("current_position_size"), 0.0)
        if current_position_size > 0 or prev_persisted > 0:
            tolerance = float(strategy_cfg.POSITION_DIVERGENCE_TOLERANCE_PCT)
            ref = max(current_position_size, prev_persisted, 1e-12)
            divergence_pct = abs(current_position_size - prev_persisted) / ref
            zero_mismatch = (current_position_size == 0) != (prev_persisted == 0)
            if zero_mismatch:
                self._emit_position_divergence_watchdog(
                    bot, symbol, prev_persisted, current_position_size, "ERROR"
                )
                logger.warning(
                    "[%s] POSITION DIVERGENCE: persisted=%.6f exchange=%.6f (zero mismatch, auto-corrected)",
                    symbol, prev_persisted, current_position_size,
                )
            elif divergence_pct > tolerance:
                self._emit_position_divergence_watchdog(
                    bot, symbol, prev_persisted, current_position_size, "WARN"
                )
                logger.warning(
                    "[%s] POSITION DIVERGENCE: persisted=%.6f exchange=%.6f (%.1f%% drift, auto-corrected)",
                    symbol, prev_persisted, current_position_size, divergence_pct * 100,
                )

        # Write position to bot dict so dashboard + profit protection see it
        bot["current_position_size"] = current_position_size
        bot["current_position_side"] = current_position_side
        bot["unrealized_pnl"] = current_position_unrealized_pnl
        # H4 audit: persist actual entry price for leverage-aware stop-loss
        if avg_entry_price > 0:
            bot["actual_entry_price"] = avg_entry_price

        # --- Directional reanchor: consume pending marker if exchange confirms flat ---
        if bot.get("directional_reanchor_pending") and mode in ("long", "short"):
            from config.strategy_config import (
                DIRECTIONAL_REANCHOR_MAX_PENDING_CYCLES,
                DIRECTIONAL_REANCHOR_MAX_PENDING_AGE_SEC,
            )
            reanchor_cycle = int(bot.get("_reanchor_pending_cycle", 0)) + 1
            bot["_reanchor_pending_cycle"] = reanchor_cycle

            # Check age bound
            _reanchor_age_expired = False
            _reanchor_requested = bot.get("directional_reanchor_requested_at", "")
            if _reanchor_requested:
                try:
                    _req_dt = datetime.fromisoformat(
                        str(_reanchor_requested).replace("Z", "+00:00")
                    )
                    _age_sec = (datetime.now(timezone.utc) - _req_dt).total_seconds()
                    _reanchor_age_expired = _age_sec > DIRECTIONAL_REANCHOR_MAX_PENDING_AGE_SEC
                except Exception:
                    pass

            if current_position_size > 0:
                # Not flat yet — check bounds
                if reanchor_cycle > DIRECTIONAL_REANCHOR_MAX_PENDING_CYCLES or _reanchor_age_expired:
                    bot["directional_reanchor_pending"] = False
                    bot["_reanchor_pending_cycle"] = 0
                    bot["directional_reanchor_last_expired_at"] = now_iso
                    bot["directional_reanchor_last_result"] = "expired_position_still_open"
                    logger.warning(
                        "[%s] Directional reanchor expired (cycle=%d age_expired=%s)",
                        symbol, reanchor_cycle, _reanchor_age_expired,
                    )
                else:
                    logger.info(
                        "[%s] Directional reanchor pending, waiting for flat (cycle %d/%d)",
                        symbol, reanchor_cycle, DIRECTIONAL_REANCHOR_MAX_PENDING_CYCLES,
                    )
            else:
                # Exchange confirms flat — execute reanchor
                _reanchor_cancelled = self._cancel_opening_orders_only(bot, symbol)

                # Reset range state to force fresh rebuild next cycle
                bot["lower_price"] = 0.0
                bot["upper_price"] = 0.0

                # Clear cached grid center
                _gc_key = f"{bot_id}_{symbol}"
                self._last_grid_center.pop(_gc_key, None)

                # Record completion
                bot["directional_reanchor_pending"] = False
                bot["_reanchor_pending_cycle"] = 0
                bot["directional_reanchor_last_completed_at"] = now_iso
                bot["directional_reanchor_last_cancelled_opening_orders"] = _reanchor_cancelled
                bot["directional_reanchor_last_result"] = "completed"

                logger.info(
                    "[%s] Directional reanchor: cleared range, cancelled %d opening orders",
                    symbol, _reanchor_cancelled,
                )

                # Return early — next cycle will rebuild range from current price
                bot["last_run_at"] = now_iso
                self._save_runtime_bot(bot)
                return bot

        # In Long mode, skip sell orders if no long position exists
        if mode == "long" and sell_reduce_only and current_position_size == 0:
            if sell_levels_needing_orders:
                logger.debug(
                    f"[{symbol}] Skipping {len(sell_levels_needing_orders)} sell orders - no position to take profit on"
                )
                sell_levels_needing_orders = []

        # In Short mode, skip buy orders if no short position exists
        logger.info(
            f"[{symbol}] SHORT skip check: mode={mode}, buy_reduce_only={buy_reduce_only}, pos_size={current_position_size}, buys_pending={len(buy_levels_needing_orders)}"
        )
        if mode == "short" and buy_reduce_only and current_position_size == 0:
            if buy_levels_needing_orders:
                logger.info(
                    f"[{symbol}] Skipping {len(buy_levels_needing_orders)} reduce-only buy orders - no short position to cover"
                )
                buy_levels_needing_orders = []

        # In Neutral mode, make opposite side reduce_only when position exists
        # This prevents the flip-flop oscillation (buy→sell→buy→sell)
        if mode == "neutral" and current_position_size > 0:
            if current_position_side == "buy":  # LONG position exists
                sell_reduce_only = True  # Sells only close the long (won't open SHORT)
                logger.debug(
                    f"[{symbol}] Neutral mode with LONG - sells are reduce_only"
                )
            elif current_position_side == "sell":  # SHORT position exists
                buy_reduce_only = True  # Buys only close the short (won't open LONG)
                logger.debug(
                    f"[{symbol}] Neutral mode with SHORT - buys are reduce_only"
                )
        elif reduce_only_mode and current_position_size == 0:
            # Reduce-only with no position: nothing to close; skip all opening orders
            buy_levels_needing_orders = []
            sell_levels_needing_orders = []
            logger.info(
                f"[{symbol}] Reduce-only mode with no position - skipping all order placement"
            )
        elif reduce_only_mode and current_position_size > 0:
            # Reduce-only with a position: allow only close-side orders
            if current_position_side == "buy":
                buy_levels_needing_orders = []  # prevent re-longing
            elif current_position_side == "sell":
                sell_levels_needing_orders = []  # prevent re-shorting

        if ai_block_opening_orders or bot.get("_nlp_lite_block_opening"):
            if not buy_reduce_only:
                buy_levels_needing_orders = []
            if not sell_reduce_only:
                sell_levels_needing_orders = []

        available_balance = self._get_usdt_available_balance()
        reserve_usd, _ = self._calculate_auto_margin_reserve(
            bot,
            investment,
            available_balance,
        )
        opening_position_size_per_level = position_size_per_level
        opening_qty_adjustment = None
        opening_sizing_context = None
        opening_submission_sizing = None
        if (
            mode in ("long", "short")
            and position_size_per_level > 0
            and (
                (buy_levels_needing_orders and not buy_reduce_only)
                or (sell_levels_needing_orders and not sell_reduce_only)
            )
        ):
            opening_qty_adjustment = self._cap_directional_opening_qty_to_affordability(
                mode=mode,
                planned_qty=position_size_per_level,
                price=last_price,
                leverage=leverage,
                qty_step=qty_step,
                min_qty=min_order_qty,
                min_notional_value=min_notional_value,
                available_balance=available_balance,
                reserve_usd=reserve_usd,
            )
            opening_sizing_context = self._build_directional_opening_sizing_fields(
                planned_qty=position_size_per_level,
                price=last_price,
                leverage=leverage,
                opening_qty_adjustment=opening_qty_adjustment,
            )
            if opening_qty_adjustment.get("adjusted"):
                opening_position_size_per_level = max(
                    0.0,
                    self._safe_float(opening_qty_adjustment.get("qty"), 0.0),
                )
                logger.info(
                    "[%s] Directional opening qty capped by affordability: %.8f -> %.8f "
                    "(notional %.2f -> %.2f, opening_margin %.2f)",
                    symbol,
                    position_size_per_level,
                    opening_position_size_per_level,
                    opening_qty_adjustment["planned_notional"],
                    opening_qty_adjustment["candidate_notional"],
                    opening_qty_adjustment["available_opening_margin"],
                )
                bot["per_order_notional_target"] = round(
                    self._safe_float(opening_qty_adjustment.get("planned_notional"), 0.0),
                    8,
                )
                bot["per_order_notional"] = round(
                    opening_position_size_per_level * last_price,
                    8,
                )
            elif opening_qty_adjustment.get("blocked_reason"):
                capital_starved_opening_reason = str(
                    opening_qty_adjustment.get("blocked_reason") or ""
                ).strip().lower() or None
                opening_position_size_per_level = max(
                    0.0,
                    self._safe_float(opening_qty_adjustment.get("candidate_qty"), 0.0),
                )

        long_continuation_level = self._get_long_near_price_continuation_level(
            bot=bot,
            levels=levels,
            last_price=last_price,
            mode=mode,
            range_mode=range_mode,
            current_position_side=current_position_side,
            current_position_size=current_position_size,
            current_position_unrealized_pnl=current_position_unrealized_pnl,
            planned_qty=opening_position_size_per_level,
            leverage=leverage,
            min_order_qty=min_order_qty,
            min_notional_value=min_notional_value,
            available_balance=available_balance,
            capital_starved_opening_reason=capital_starved_opening_reason,
        )
        if long_continuation_level is not None:
            rounded_long_continuation = self._round_to_step(
                long_continuation_level,
                tick_size,
                round_down=False,
            )
            has_exact = rounded_long_continuation in existing_order_prices
            has_near = self._has_order_near_level(
                long_continuation_level,
                existing_order_prices_list,
                ORDER_TOLERANCE_PCT,
            )
            if (
                not has_exact
                and not has_near
                and long_continuation_level not in buy_levels_needing_orders
            ):
                buy_levels_needing_orders.append(long_continuation_level)
                self._emit_audit_event(
                    bot,
                    event_type="continuation_add_candidate_created",
                    severity="INFO",
                    symbol=symbol,
                    mode=mode,
                    throttle_key=(
                        f"continuation_add_candidate:{bot.get('id')}:{round(self._safe_float(long_continuation_level, 0.0), 6)}"
                    ),
                    throttle_sec=0,
                    experiment_tags=["exp_continuation_add_candidate_created"],
                    candidate_price=round(
                        self._safe_float(long_continuation_level, 0.0),
                        8,
                    ),
                    last_price=round(self._safe_float(last_price, 0.0), 8),
                )
                logger.info(
                    "[%s] Added experimental long continuation buy candidate at %.8f",
                    symbol,
                    long_continuation_level,
                )

        buy_levels_needing_orders, sell_levels_needing_orders = (
            self._limit_levels_for_available_order_slots(
                buy_levels=buy_levels_needing_orders,
                sell_levels=sell_levels_needing_orders,
                max_new=max_new,
                buy_reduce_only=buy_reduce_only,
                sell_reduce_only=sell_reduce_only,
            )
        )
        continuation_add_candidate_active = False
        if str(mode or "").strip().lower() == "long":
            continuation_add_candidate_active = long_continuation_level is not None and any(
                abs(self._safe_float(level, 0.0) - self._safe_float(long_continuation_level, 0.0))
                <= 1e-9
                for level in buy_levels_needing_orders
            )
        elif str(mode or "").strip().lower() == "short":
            continuation_add_candidate_active = (
                str(capital_starved_opening_reason or "").strip().lower()
                not in {"qty_below_min", "notional_below_min"}
                and self._has_short_near_price_continuation_candidate(
                    sell_levels=sell_levels_needing_orders,
                    last_price=last_price,
                    range_mode=range_mode,
                )
            )

        pre_cap_opening_buy_candidates = len(
            [level for level in buy_levels_needing_orders if not buy_reduce_only]
        )
        pre_cap_opening_sell_candidates = len(
            [level for level in sell_levels_needing_orders if not sell_reduce_only]
        )
        position_cap_was_active = bool(bot.get("_watchdog_position_cap_active"))
        position_cap_suppressed_this_cycle = False

        # =============================================================================
        # ADX EXTREME TREND FREEZE — block accumulation entries when 1h ADX > threshold
        # Prevents building one-sided positions in extreme trends (TAOUSDT $4 loss fix)
        # =============================================================================
        from config.strategy_config import ADX_EXTREME_FREEZE_THRESHOLD
        _htf_adx_val = self._safe_float(bot.get("_htf_adx_1h"), 0)
        _pos_side_lc = str(current_position_side or "").strip().lower()
        adx_freeze_buys = (
            _htf_adx_val >= ADX_EXTREME_FREEZE_THRESHOLD
            and current_position_size > 0
            and _pos_side_lc == "buy"
        )
        adx_freeze_sells = (
            _htf_adx_val >= ADX_EXTREME_FREEZE_THRESHOLD
            and current_position_size > 0
            and _pos_side_lc == "sell"
        )
        # Momentum throttle: instead of blocking all accumulation, keep a fraction
        # based on ADX intensity — closest-to-price levels survive
        _adx_momentum_keep_ratio = 1.0
        if adx_freeze_buys or adx_freeze_sells:
            if _htf_adx_val >= 55:
                _adx_momentum_keep_ratio = 0.10
            elif _htf_adx_val >= 45:
                _adx_momentum_keep_ratio = 0.30
            else:
                _adx_momentum_keep_ratio = 0.60
            logger.info(
                "[%s] ADX MOMENTUM THROTTLE: 1h ADX=%.1f — keeping %.0f%% of %s accumulation levels",
                symbol, _htf_adx_val, _adx_momentum_keep_ratio * 100,
                "buy" if adx_freeze_buys else "sell",
            )

        _cap_result = self._enforce_position_cap(
            bot=bot, symbol=symbol, mode=mode,
            last_price=last_price, investment=investment, leverage=leverage,
            buy_levels_needing_orders=buy_levels_needing_orders,
            sell_levels_needing_orders=sell_levels_needing_orders,
            buy_reduce_only=buy_reduce_only,
            sell_reduce_only=sell_reduce_only,
            existing_orders_with_ids=existing_orders_with_ids,
            continuation_add_candidate_active=continuation_add_candidate_active,
            capital_starved_opening_reason=capital_starved_opening_reason,
            current_order_count=current_order_count,
        )
        buy_levels_needing_orders = _cap_result["buy_levels_needing_orders"]
        sell_levels_needing_orders = _cap_result["sell_levels_needing_orders"]
        position_cap_suppressed_this_cycle = _cap_result["position_cap_suppressed_this_cycle"]

        # =============================================================================
        # VOLATILE SYMBOL PROTECTION - One-sided OPENING based on momentum
        # For PIPPINUSDT etc: Only OPEN positions on momentum side, but always allow closing
        # =============================================================================
        if mode == "neutral" and symbol in VOLATILE_NEUTRAL_SYMBOLS:
            # Determine momentum from RSI (fetched earlier as fast_indicators)
            # RSI > 55 = bullish, RSI < 45 = bearish, 45-55 = neutral
            rsi = fast_indicators.get("rsi") if fast_indicators else None

            if rsi is not None:
                if rsi > 55:
                    momentum = "up"
                elif rsi < 45:
                    momentum = "down"
                else:
                    momentum = "neutral"
            else:
                momentum = "neutral"

            # When NO position: only place orders on momentum side
            # When HAS position: keep both sides (opposite side will close via reduce_only)
            if current_position_size == 0:
                if momentum == "up":
                    sell_levels_needing_orders = []  # Only buys to open long
                    logger.info(
                        f"[{symbol}] Volatile neutral - RSI={rsi:.1f} UP, no pos, buys only"
                    )
                elif momentum == "down":
                    buy_levels_needing_orders = []  # Only sells to open short
                    logger.info(
                        f"[{symbol}] Volatile neutral - RSI={rsi:.1f} DOWN, no pos, sells only"
                    )
                else:
                    rsi_str = f"{rsi:.1f}" if rsi is not None else "N/A"
                    logger.info(
                        f"[{symbol}] Volatile neutral - RSI={rsi_str} neutral, no pos, both sides"
                    )
            else:
                # Has position - both sides active (reduce_only already set above based on position)
                rsi_str = f"{rsi:.1f}" if rsi is not None else "N/A"
                logger.info(
                    f"[{symbol}] Volatile neutral - RSI={rsi_str}, has {current_position_side} pos, both sides"
                )

            # Save current price for price movement tracking
            bot["last_trade_price"] = last_price

        # =============================================================================
        # REDUCE_ONLY QTY CAPPING - Cap qty to remaining position for reduce_only orders
        # Prevents Bybit error 110017 "orderQty will be truncated to zero"
        # Must account for existing pending reduce_only orders
        # =============================================================================
        available_reduce_only_buy_qty = 0.0
        qty_for_reduce_only_buy = 0
        available_reduce_only_sell_qty = 0.0
        qty_for_reduce_only_sell = 0
        if current_position_size > 0:
            # For LONG position (closed by sell reduce_only):
            # Available = position - already pending sell reduce_only orders
            if sell_reduce_only:
                (
                    available_reduce_only_sell_qty,
                    qty_for_reduce_only_sell,
                ) = self._compute_reduce_only_budget(
                    current_position_size=current_position_size,
                    existing_reduce_only_qty=existing_reduce_only_sell_qty,
                    position_size_per_level=position_size_per_level,
                    qty_step=qty_step,
                    min_order_qty=min_order_qty,
                    min_notional_value=min_notional_value,
                    last_price=last_price,
                )
                if available_reduce_only_sell_qty <= 0:
                    logger.debug(
                        f"[{symbol}] Reduce-only sell qty exhausted "
                        f"(pending={existing_reduce_only_sell_qty}, pos={current_position_size})"
                    )

            # For SHORT position (closed by buy reduce_only):
            # Available = position - already pending buy reduce_only orders
            if buy_reduce_only:
                (
                    available_reduce_only_buy_qty,
                    qty_for_reduce_only_buy,
                ) = self._compute_reduce_only_budget(
                    current_position_size=current_position_size,
                    existing_reduce_only_qty=existing_reduce_only_buy_qty,
                    position_size_per_level=position_size_per_level,
                    qty_step=qty_step,
                    min_order_qty=min_order_qty,
                    min_notional_value=min_notional_value,
                    last_price=last_price,
                )
                if available_reduce_only_buy_qty <= 0:
                    logger.debug(
                        f"[{symbol}] Reduce-only buy qty exhausted "
                        f"(pending={existing_reduce_only_buy_qty}, pos={current_position_size})"
                    )

        # Backwards compat: keep single var for existing logic (use sell value by default)
        qty_for_reduce_only = (
            qty_for_reduce_only_sell if sell_reduce_only else qty_for_reduce_only_buy
        )

        # =============================================================================
        # MARGIN BUFFER CHECK - Ensure we maintain reserve for auto-margin
        # Only applies to non-reduce_only orders (which require new margin)
        # When buffer is exceeded, cancel far orders to free margin for closer ones
        # =============================================================================
        available_balance = self._get_usdt_available_balance()
        margin_used = 0.0

        # 1. Unified Reserve Check for Margin Buffer
        reserve_usd, _ = self._calculate_auto_margin_reserve(
            bot, investment, available_balance
        )

        margin_per_order = (
            opening_position_size_per_level * last_price
        ) / max(leverage, 1.0)
        from config.strategy_config import MARGIN_BUFFER_ENABLED

        margin_buffer_active = MARGIN_BUFFER_ENABLED and available_balance > 0
        orders_cancelled_for_margin = 0

        has_opening_candidates = (
            (bool(buy_levels_needing_orders) and not buy_reduce_only)
            or (bool(sell_levels_needing_orders) and not sell_reduce_only)
        )
        opening_kind = (
            "add"
            if current_position_size > 0 and current_position_side in ("buy", "sell")
            else "initial_opening"
        )
        preferred_open_side = (
            "Buy" if buy_levels_needing_orders and not buy_reduce_only else "Sell"
        )
        if has_opening_candidates:
            if capital_starved_opening_reason in (
                "qty_below_min",
                "notional_below_min",
                "opening_margin_reserve",
            ):
                self._activate_capital_starved_opening_block(
                    bot,
                    symbol=symbol,
                    reason=capital_starved_opening_reason,
                    side=preferred_open_side,
                    action="grid_order",
                    opening_kind=opening_kind,
                    attempted_qty=opening_position_size_per_level,
                    price=last_price,
                    min_qty=min_order_qty,
                    min_notional_value=min_notional_value,
                    leverage=leverage,
                    available_balance=available_balance,
                    reserve_usd=reserve_usd,
                    opening_order_cap=runtime_open_order_cap_total,
                    current_order_count=current_order_count,
                )
                opening_order_margin_exhausted = True
                opening_order_block_reason = capital_starved_opening_reason
            else:
                available_opening_margin = max(0.0, available_balance - reserve_usd)
                if (
                    opening_position_size_per_level > 0
                    and margin_per_order > 0
                    and available_opening_margin + 1e-9 < margin_per_order
                ):
                    margin_guard_reason = self._get_opening_margin_guard_reason(
                        available_balance=available_balance,
                        reserve_usd=reserve_usd,
                        required_margin=margin_per_order,
                    )
                    self._activate_capital_starved_opening_block(
                        bot,
                        symbol=symbol,
                        reason=margin_guard_reason,
                        side=preferred_open_side,
                        action="grid_order",
                        opening_kind=opening_kind,
                        attempted_qty=opening_position_size_per_level,
                        price=last_price,
                        min_qty=min_order_qty,
                        min_notional_value=min_notional_value,
                        leverage=leverage,
                        available_balance=available_balance,
                        reserve_usd=reserve_usd,
                        opening_order_cap=runtime_open_order_cap_total,
                        current_order_count=current_order_count,
                    )
                    opening_order_margin_exhausted = True
                    opening_order_block_reason = margin_guard_reason
                else:
                    self._clear_capital_starved_opening_block(bot)
        else:
            self._clear_capital_starved_opening_block(bot)

        # Sort existing OPENING orders by distance from current price (farthest first)
        # IMPORTANT: Only include non-reduceOnly orders - cancelling reduceOnly won't free margin
        # Tuple format: (price, order_id, side, is_reduce_only)
        far_orders = sorted(
            [
                (price, oid, side)
                for price, oid, side, is_ro in existing_orders_with_ids
                if not is_ro
            ],
            key=lambda x: abs(x[0] - last_price),
            reverse=True,
        )
        far_order_idx = 0  # Index of next far order to cancel

        # Log margin cancellation eligibility for debugging
        reduce_only_count = sum(
            1 for _, _, _, is_ro in existing_orders_with_ids if is_ro
        )
        if reduce_only_count > 0:
            logger.debug(
                f"[{symbol}] Margin buffer: {len(far_orders)} opening orders eligible for cancel, "
                f"{reduce_only_count} reduceOnly orders protected"
            )

        # =============================================================================
        # FUNDING PROTECTION - Skip new orders near funding time
        # =============================================================================
        funding_guard = self._evaluate_funding_protection(bot, symbol, mode)
        funding_skip = bool(funding_guard.get("skip"))

        # =============================================================================
        # BTC CORRELATION GUARD - Skip altcoin orders when BTC is dumping
        # =============================================================================
        btc_guard = self._evaluate_btc_guard(bot, symbol)
        btc_guard_skip = bool(btc_guard.get("skip"))

        # =============================================================================
        # ENTRY GATE SKIP - Check if entry gate is blocking orders
        # =============================================================================
        entry_gate_skip = (
            (
                bot.get("_entry_gate_blocked", False)
                and bot.get("entry_gate_enabled", True)
            )
            if bot
            else False
        )

        # =============================================================================
        # SMART ENTRY TIMING (Smart Feature #21)
        # Wait for optimal RSI/EMA conditions before entering
        # =============================================================================
        smart_entry_state = self._evaluate_smart_entry_timing(
            bot=bot,
            symbol=symbol,
            mode=mode,
            last_price=last_price,
            fast_indicators=fast_indicators,
        )
        smart_entry_skip_buys = bool(smart_entry_state.get("skip_buy"))
        smart_entry_skip_sells = bool(smart_entry_state.get("skip_sell"))

        if mode in ("long", "short"):
            structure_entry_blocks = {
                "skip_buy": False,
                "skip_sell": False,
                "buy_reason": "",
                "sell_reason": "",
            }
        else:
            structure_entry_blocks = self._evaluate_structure_entry_blocks(
                bot=bot,
                symbol=symbol,
                last_price=last_price,
                fast_indicators=fast_indicators,
                allow_buy=mode in ("neutral", "long"),
                allow_sell=mode in ("neutral", "short"),
            )
        structure_entry_skip_buys = structure_entry_blocks.get("skip_buy", False)
        structure_entry_skip_sells = structure_entry_blocks.get("skip_sell", False)
        structure_buy_reason = structure_entry_blocks.get("buy_reason", "")
        structure_sell_reason = structure_entry_blocks.get("sell_reason", "")

        cycle_blocker_stack: List[Dict[str, Any]] = []
        if opening_order_guard_skip:
            self._append_audit_blocker(
                cycle_blocker_stack,
                code=(
                    "exchange_truth"
                    if exchange_truth_opening_blocker is not None
                    else "opening_guard"
                ),
                reason=opening_order_guard_reason or "opening guard",
                phase="order_placement",
            )
        if funding_skip:
            self._append_audit_blocker(
                cycle_blocker_stack,
                code="funding_protection",
                reason=funding_guard.get("reason") or "funding protection",
                phase="pre_grid",
            )
        if btc_guard_skip:
            self._append_audit_blocker(
                cycle_blocker_stack,
                code="btc_guard",
                reason=btc_guard.get("reason") or "BTC guard",
                phase="pre_grid",
            )
        if mode == "long" and smart_entry_skip_buys:
            self._append_audit_blocker(
                cycle_blocker_stack,
                code="smart_entry",
                reason=smart_entry_state.get("buy_reason") or "waiting for pullback",
                phase="pre_grid",
                side="buy",
            )
        if mode == "short" and smart_entry_skip_sells:
            self._append_audit_blocker(
                cycle_blocker_stack,
                code="smart_entry",
                reason=smart_entry_state.get("sell_reason") or "waiting for bounce",
                phase="pre_grid",
                side="sell",
            )
        if entry_gate_skip:
            self._append_audit_blocker(
                cycle_blocker_stack,
                code="entry_gate",
                reason=bot.get("_entry_gate_blocked_reason") or "entry gate",
                phase="pre_grid",
                side=mode,
            )
        if mode not in ("long", "short") and structure_entry_skip_buys:
            self._append_audit_blocker(
                cycle_blocker_stack,
                code="structure_gate",
                reason=structure_buy_reason or "nearby resistance",
                phase="order_placement",
                side="buy",
            )
        if mode not in ("long", "short") and structure_entry_skip_sells:
            self._append_audit_blocker(
                cycle_blocker_stack,
                code="structure_gate",
                reason=structure_sell_reason or "nearby support",
                phase="order_placement",
                side="sell",
            )
        self._record_audit_cycle(
            bot,
            symbol=symbol,
            mode=mode,
            last_price=last_price,
            lower_price=lower_price,
            upper_price=upper_price,
            blocker_stack=cycle_blocker_stack,
            gate_result=directional_gate_result,
            setup_quality=setup_quality,
            skipped_reason=cycle_blocker_stack[0]["reason"] if cycle_blocker_stack else None,
            event="cycle",
        )
        grid_advisor_review = self._maybe_review_ai_advisor_candidate(
            bot=bot,
            symbol=symbol,
            mode=mode,
            range_mode=range_mode,
            last_price=last_price,
            decision_type="grid_opening",
            candidate_open_sides=[
                side
                for side, count in (
                    ("buy", pre_cap_opening_buy_candidates),
                    ("sell", pre_cap_opening_sell_candidates),
                )
                if count > 0
            ],
            candidate_counts={
                "buy": pre_cap_opening_buy_candidates,
                "sell": pre_cap_opening_sell_candidates,
            },
            fast_indicators=fast_indicators,
            gate_result=directional_gate_result,
            blockers=cycle_blocker_stack,
            position_snapshot=self._build_ai_advisor_position_snapshot(
                side=current_position_side,
                size=current_position_size,
                unrealized_pnl=None,
            ),
        )
        if pre_cap_opening_buy_candidates > 0 or pre_cap_opening_sell_candidates > 0:
            forensic_side = "buy" if pre_cap_opening_buy_candidates > 0 else "sell"
            forensic_context = self._build_trade_forensic_decision_context(
                bot=bot,
                symbol=symbol,
                mode=mode,
                range_mode=range_mode,
                last_price=last_price,
                decision_type="grid_opening",
                candidate_open_sides=[
                    side
                    for side, count in (
                        ("buy", pre_cap_opening_buy_candidates),
                        ("sell", pre_cap_opening_sell_candidates),
                    )
                    if count > 0
                ],
                candidate_counts={
                    "buy": pre_cap_opening_buy_candidates,
                    "sell": pre_cap_opening_sell_candidates,
                },
                fast_indicators=fast_indicators,
                gate_result=directional_gate_result,
                blockers=cycle_blocker_stack,
                position_snapshot=self._build_ai_advisor_position_snapshot(
                    side=current_position_side,
                    size=current_position_size,
                    unrealized_pnl=None,
                ),
                advisor_review=grid_advisor_review,
                opening_sizing=opening_sizing_context,
            )
            self._record_trade_forensic_decision(
                bot=bot,
                symbol=symbol,
                mode=mode,
                side=forensic_side,
                decision_type="grid_opening",
                decision_context=forensic_context,
                event_type="decision",
                event_status="candidate",
            )

        # Track skip reasons for summary logging
        skipped_reasons = {}

        # A1: Batch order accumulator — validated Limit orders are collected
        # here and submitted in a single Bybit batch API call after both
        # buy and sell loops finish.  This reduces 6×400ms serial HTTP calls
        # to 1×400ms batch call.
        _batch_pending: List[Dict[str, Any]] = []

        # Place BUY orders
        # Track remaining reduce_only qty to prevent placing more than position supports
        remaining_reduce_only_buy_qty = available_reduce_only_buy_qty
        _adx_buy_keep_count = max(1, int(len(buy_levels_needing_orders) * _adx_momentum_keep_ratio)) if adx_freeze_buys else len(buy_levels_needing_orders)
        for _buy_loop_idx, level in enumerate(buy_levels_needing_orders):
            if opening_order_margin_exhausted and not buy_reduce_only:
                skipped_reasons["insufficient_margin_guard"] = (
                    skipped_reasons.get("insufficient_margin_guard", 0) + 1
                )
                continue

            # ADX momentum throttle — keep closest-to-price levels, skip farthest
            # buy_levels sorted ascending (farthest first), so skip early indices
            if adx_freeze_buys and not buy_reduce_only:
                if _buy_loop_idx < len(buy_levels_needing_orders) - _adx_buy_keep_count:
                    skipped_reasons["adx_momentum_throttle"] = skipped_reasons.get("adx_momentum_throttle", 0) + 1
                    continue

            # Skip all new orders if funding, BTC guard, or entry gate is active (reduce_only are allowed)
            if (
                funding_skip
                or btc_guard_skip
                or smart_entry_skip_buys
                or structure_entry_skip_buys
                or entry_gate_skip
                or opening_order_guard_skip
            ) and not buy_reduce_only:
                if funding_skip:
                    skip_reason = "funding protection"
                elif btc_guard_skip:
                    skip_reason = "BTC guard"
                elif structure_entry_skip_buys:
                    skip_reason = structure_buy_reason or "nearby resistance"
                elif entry_gate_skip:
                    skip_reason = "entry gate"
                elif opening_order_guard_skip:
                    skip_reason = opening_order_guard_reason or "opening guard"
                else:
                    skip_reason = "smart entry timing"

                skipped_reasons[skip_reason] = skipped_reasons.get(skip_reason, 0) + 1
                continue

            # Skip reduce_only orders if no remaining qty available
            if buy_reduce_only and remaining_reduce_only_buy_qty <= 0:
                price = self._round_price_for_order(level, tick_size, side="buy")
                skipped_reasons["reduce_only_exhausted"] = (
                    skipped_reasons.get("reduce_only_exhausted", 0) + 1
                )
                continue

            # Average entry guard — skip reduce-only buys above avg entry (short mode)
            if buy_reduce_only and avg_entry_price > 0 and mode == "short":
                max_profitable_buy = avg_entry_price * (1.0 - fee_aware_min_step_pct)
                if level > max_profitable_buy:
                    skipped_reasons["above_avg_entry"] = skipped_reasons.get("above_avg_entry", 0) + 1
                    continue

            # Check margin buffer for non-reduce_only orders
            if not buy_reduce_only and margin_buffer_active:
                remaining_balance = available_balance - margin_used
                if remaining_balance - margin_per_order < reserve_usd:
                    # Try to cancel a far order to free up margin
                    freed_margin = False
                    while far_order_idx < len(far_orders) and not freed_margin:
                        far_price, far_order_id, far_side = far_orders[far_order_idx]
                        far_order_idx += 1
                        # Only cancel if it's farther from price than the new order
                        if abs(far_price - last_price) > abs(level - last_price):
                            cancel_result = self.client.cancel_order(
                                symbol, far_order_id
                            )
                            if cancel_result.get("success"):
                                logger.info(
                                    f"[{symbol}] Cancelled far {far_side} order at {far_price:.6f} "
                                    f"to place closer order at {level:.6f}"
                                )
                                orders_cancelled_for_margin += 1
                                freed_margin = True
                                # Margin is now freed, we can place this order
                            else:
                                logger.debug(
                                    f"[{symbol}] Failed to cancel order {far_order_id}: {cancel_result.get('error')}"
                                )

                    if not freed_margin:
                        skipped_reasons["margin_buffer"] = (
                            skipped_reasons.get("margin_buffer", 0) + 1
                        )
                        continue
                margin_used += margin_per_order

            seq += 1
            # Build orderLinkId v2 with full bot UUID and intent
            intent = "close" if buy_reduce_only else "open"
            order_link_id = self._build_order_link_id(
                bot_id=bot_id,
                symbol=symbol,
                cycle_ts=cycle_ts,
                seq=seq,
                side="Buy",
                intent=intent,
            )

            # Use capped qty for reduce_only orders (use remaining, not original)
            order_qty = (
                min(remaining_reduce_only_buy_qty, position_size_per_level)
                if buy_reduce_only
                else opening_position_size_per_level
            )

            price = self._round_price_for_order(level, tick_size, side="buy")

            # SPREAD CHECK: Prevent immediate fill/stacking
            if price >= last_price:
                adjusted_price = self._round_price_for_order(
                    last_price - tick_size, tick_size, side="buy"
                )
                if adjusted_price <= 0 or adjusted_price >= last_price:
                    logger.debug(
                        f"[{symbol}] General: Skipping Buy at {price} - would cross spread (last=${last_price})"
                    )
                    skipped_reasons["spread_check"] = (
                        skipped_reasons.get("spread_check", 0) + 1
                    )
                    continue
                logger.debug(
                    f"[{symbol}] General: Repriced Buy {price} -> {adjusted_price} (last=${last_price})"
                )
                price = adjusted_price

            result = self._create_order_checked(
                bot=bot,
                symbol=symbol,
                side="Buy",
                qty=order_qty,
                order_type="Limit",
                price=price,
                reduce_only=buy_reduce_only,
                time_in_force="GTC",
                order_link_id=order_link_id,
                _batch_pending=_batch_pending,
                diagnostic_context={
                    "action": "grid_order",
                    "opening_kind": (
                        None
                        if buy_reduce_only
                        else ("add" if current_position_side == "buy" and current_position_size > 0 else "initial_opening")
                    ),
                    "opening_sizing": (
                        opening_sizing_context if not buy_reduce_only else None
                    ),
                },
            )

            if result.get("success"):
                orders_placed += 1
                buy_orders_placed += 1
                if not buy_reduce_only:
                    if opening_submission_sizing is None:
                        opening_submission_sizing = result.get("opening_sizing")
                    if current_position_side == "buy" and current_position_size > 0:
                        add_follow_through_placed += 1
                    else:
                        initial_opening_orders_placed += 1
                    first_opening_fill = not bool(bot.get("_audit_actual_entry_ts"))
                    self._mark_audit_actual_entry(
                        bot,
                        opening_kind="initial_opening",
                        opening_sizing=result.get("opening_sizing"),
                    )
                    if first_opening_fill:
                        self._record_audit_cycle(
                            bot,
                            symbol=symbol,
                            mode=mode,
                            last_price=last_price,
                            lower_price=lower_price,
                            upper_price=upper_price,
                            blocker_stack=[],
                            gate_result=directional_gate_result,
                            setup_quality=setup_quality,
                            skipped_reason=None,
                            event="opening_order_placed",
                        )
                # Decrement remaining reduce_only qty after successful placement
                if buy_reduce_only:
                    remaining_reduce_only_buy_qty -= order_qty
                elif mode == "long":
                    self._mark_breakout_entry_context(
                        bot,
                        mode,
                        bot.get("_breakout_gate_context"),
                    )
                logger.debug(
                    f"[{symbol}] Placed Buy order at {price}, qty={order_qty}, intent={intent}"
                )
            elif result.get("skipped"):
                skip_reason = (
                    result.get("skip_reason")
                    or result.get("error")
                    or "skipped"
                )
                skipped_reasons[skip_reason] = skipped_reasons.get(skip_reason, 0) + 1
                if skip_reason == "notional_below_min":
                    self._register_failure_breaker_event(
                        bot, "notional_below_min", now_ts=now_ts
                    )
                continue
            else:
                orders_failed += 1
                error_msg = result.get("error", "unknown")
                ret_code = result.get("retCode", "N/A")
                if not buy_reduce_only and self._is_insufficient_margin_result(result):
                    self._record_insufficient_margin_event(
                        bot,
                        symbol=symbol,
                        side="Buy",
                        action="grid_order",
                        attempted_qty=order_qty,
                        price=price,
                        available_balance=available_balance,
                        reserve_usd=reserve_usd,
                        margin_per_order=margin_per_order,
                        current_order_count=current_order_count,
                        opening_order_count=buy_orders_placed + sell_orders_placed,
                        opening_order_cap=runtime_open_order_cap_total,
                    )
                    self._register_failure_breaker_event(
                        bot, "insufficient_margin", now_ts=now_ts
                    )
                    buy_orders_failed_balance += 1
                    pruned_count, far_order_idx = self._prune_far_orders_for_margin(
                        symbol=symbol,
                        far_orders=far_orders,
                        start_idx=far_order_idx,
                        last_price=last_price,
                        target_level=level,
                    )
                    if pruned_count > 0:
                        orders_cancelled_for_margin += pruned_count
                        refreshed_balance = self._get_usdt_available_balance()
                        if refreshed_balance > 0:
                            available_balance = refreshed_balance
                        skipped_reasons["insufficient_margin_pruned"] = (
                            skipped_reasons.get("insufficient_margin_pruned", 0) + 1
                        )
                        bot["last_skip_reason"] = "insufficient_margin_pruned"
                        continue

                    opening_order_margin_exhausted = True
                    opening_order_block_reason = "insufficient_margin"
                    bot["last_skip_reason"] = "insufficient_margin"
                    bot["last_error"] = "Insufficient available balance for new entry orders"
                    skipped_reasons["insufficient_margin"] = (
                        skipped_reasons.get("insufficient_margin", 0) + 1
                    )
                    logger.warning(
                        f"[{symbol}] Margin exhausted for new BUY entries - stopping further opening orders this cycle"
                    )
                logger.warning(
                    f"[{symbol}] FAILED Buy at {price}: {error_msg} (code={ret_code}, reduce_only={buy_reduce_only})"
                )

        if (
            mode == "neutral"
            and buy_orders_failed_balance > 0
            and buy_orders_placed == 0
            and not sell_reduce_only
        ):
            self._register_failure_breaker_event(
                bot, "one_sided_grid_prevented", now_ts=now_ts
            )
            opening_order_margin_exhausted = True
            logger.warning(
                f"[{symbol}] Skipping SELL entry orders - buy side could not be funded and a one-sided neutral grid is unsafe"
            )

        # Place SELL orders
        # Track remaining reduce_only qty to prevent placing more than position supports
        remaining_reduce_only_sell_qty = available_reduce_only_sell_qty
        _adx_sell_keep_count = max(1, int(len(sell_levels_needing_orders) * _adx_momentum_keep_ratio)) if adx_freeze_sells else len(sell_levels_needing_orders)
        for _sell_loop_idx, level in enumerate(sell_levels_needing_orders):
            if opening_order_margin_exhausted and not sell_reduce_only:
                skipped_reasons["insufficient_margin_guard"] = (
                    skipped_reasons.get("insufficient_margin_guard", 0) + 1
                )
                continue

            # ADX momentum throttle — keep closest-to-price levels, skip farthest
            # sell_levels sorted ascending (closest first), so skip later indices
            if adx_freeze_sells and not sell_reduce_only:
                if _sell_loop_idx >= _adx_sell_keep_count:
                    skipped_reasons["adx_momentum_throttle"] = skipped_reasons.get("adx_momentum_throttle", 0) + 1
                    continue

            # Skip all new orders if funding, BTC guard, smart entry, or entry gate is active (reduce_only are allowed)
            if (
                funding_skip
                or btc_guard_skip
                or smart_entry_skip_sells
                or structure_entry_skip_sells
                or entry_gate_skip
                or opening_order_guard_skip
            ) and not sell_reduce_only:
                if funding_skip:
                    skip_reason = "funding protection"
                elif btc_guard_skip:
                    skip_reason = "BTC guard"
                elif structure_entry_skip_sells:
                    skip_reason = structure_sell_reason or "nearby support"
                elif entry_gate_skip:
                    skip_reason = "entry gate"
                elif opening_order_guard_skip:
                    skip_reason = opening_order_guard_reason or "opening guard"
                else:
                    skip_reason = "smart entry timing"

                skipped_reasons[skip_reason] = skipped_reasons.get(skip_reason, 0) + 1
                continue

            # Skip reduce_only orders if no remaining qty available
            if sell_reduce_only and remaining_reduce_only_sell_qty <= 0:
                price = self._round_price_for_order(level, tick_size, side="sell")
                skipped_reasons["reduce_only_exhausted"] = (
                    skipped_reasons.get("reduce_only_exhausted", 0) + 1
                )
                continue

            # Average entry guard — skip reduce-only sells below avg entry (long mode)
            if sell_reduce_only and avg_entry_price > 0 and mode == "long":
                min_profitable_sell = avg_entry_price * (1.0 + fee_aware_min_step_pct)
                if level < min_profitable_sell:
                    skipped_reasons["below_avg_entry"] = skipped_reasons.get("below_avg_entry", 0) + 1
                    continue

            # Check margin buffer for non-reduce_only orders
            if not sell_reduce_only and margin_buffer_active:
                remaining_balance = available_balance - margin_used
                if remaining_balance - margin_per_order < reserve_usd:
                    # Try to cancel a far order to free up margin
                    freed_margin = False
                    while far_order_idx < len(far_orders) and not freed_margin:
                        far_price, far_order_id, far_side = far_orders[far_order_idx]
                        far_order_idx += 1
                        # Only cancel if it's farther from price than the new order
                        if abs(far_price - last_price) > abs(level - last_price):
                            cancel_result = self.client.cancel_order(
                                symbol, far_order_id
                            )
                            if cancel_result.get("success"):
                                logger.info(
                                    f"[{symbol}] Cancelled far {far_side} order at {far_price:.6f} "
                                    f"to place closer order at {level:.6f}"
                                )
                                orders_cancelled_for_margin += 1
                                freed_margin = True
                            else:
                                logger.debug(
                                    f"[{symbol}] Failed to cancel order {far_order_id}: {cancel_result.get('error')}"
                                )

                    if not freed_margin:
                        skipped_reasons["margin_buffer"] = (
                            skipped_reasons.get("margin_buffer", 0) + 1
                        )
                        continue
                margin_used += margin_per_order

            seq += 1
            # Build orderLinkId v2 with full bot UUID and intent
            intent = "close" if sell_reduce_only else "open"
            order_link_id = self._build_order_link_id(
                bot_id=bot_id,
                symbol=symbol,
                cycle_ts=cycle_ts,
                seq=seq,
                side="Sell",
                intent=intent,
            )

            # Use capped qty for reduce_only orders (use remaining, not original)
            order_qty = (
                min(remaining_reduce_only_sell_qty, position_size_per_level)
                if sell_reduce_only
                else opening_position_size_per_level
            )

            price = self._round_price_for_order(level, tick_size, side="sell")

            # SPREAD CHECK: Prevent immediate fill/stacking
            if price <= last_price:
                adjusted_price = self._round_price_for_order(
                    last_price + tick_size, tick_size, side="sell"
                )
                if adjusted_price <= last_price:
                    logger.debug(
                        f"[{symbol}] General: Skipping Sell at {price} - would cross spread (last=${last_price})"
                    )
                    skipped_reasons["spread_check"] = (
                        skipped_reasons.get("spread_check", 0) + 1
                    )
                    continue
                logger.debug(
                    f"[{symbol}] General: Repriced Sell {price} -> {adjusted_price} (last=${last_price})"
                )
                price = adjusted_price

            result = self._create_order_checked(
                bot=bot,
                symbol=symbol,
                side="Sell",
                qty=order_qty,
                order_type="Limit",
                price=price,
                reduce_only=sell_reduce_only,
                time_in_force="GTC",
                order_link_id=order_link_id,
                _batch_pending=_batch_pending,
                diagnostic_context={
                    "action": "grid_order",
                    "opening_kind": (
                        None
                        if sell_reduce_only
                        else ("add" if current_position_side == "sell" and current_position_size > 0 else "initial_opening")
                    ),
                    "opening_sizing": (
                        opening_sizing_context if not sell_reduce_only else None
                    ),
                },
            )

            if result.get("success"):
                orders_placed += 1
                sell_orders_placed += 1
                if not sell_reduce_only:
                    if opening_submission_sizing is None:
                        opening_submission_sizing = result.get("opening_sizing")
                    if current_position_side == "sell" and current_position_size > 0:
                        add_follow_through_placed += 1
                    else:
                        initial_opening_orders_placed += 1
                    first_opening_fill = not bool(bot.get("_audit_actual_entry_ts"))
                    self._mark_audit_actual_entry(
                        bot,
                        opening_kind="initial_opening",
                        opening_sizing=result.get("opening_sizing"),
                    )
                    if first_opening_fill:
                        self._record_audit_cycle(
                            bot,
                            symbol=symbol,
                            mode=mode,
                            last_price=last_price,
                            lower_price=lower_price,
                            upper_price=upper_price,
                            blocker_stack=[],
                            gate_result=directional_gate_result,
                            setup_quality=setup_quality,
                            skipped_reason=None,
                            event="opening_order_placed",
                        )
                # Decrement remaining reduce_only qty after successful placement
                if sell_reduce_only:
                    remaining_reduce_only_sell_qty -= order_qty
                elif mode == "short":
                    self._mark_breakout_entry_context(
                        bot,
                        mode,
                        bot.get("_breakout_gate_context"),
                    )
                logger.debug(
                    f"[{symbol}] Placed Sell order at {price}, qty={order_qty}, intent={intent}"
                )
            elif result.get("skipped"):
                skip_reason = (
                    result.get("skip_reason")
                    or result.get("error")
                    or "skipped"
                )
                skipped_reasons[skip_reason] = skipped_reasons.get(skip_reason, 0) + 1
                if skip_reason == "notional_below_min":
                    self._register_failure_breaker_event(
                        bot, "notional_below_min", now_ts=now_ts
                    )
                continue
            else:
                orders_failed += 1
                error_msg = result.get("error", "unknown")
                ret_code = result.get("retCode", "N/A")
                if not sell_reduce_only and self._is_insufficient_margin_result(result):
                    self._record_insufficient_margin_event(
                        bot,
                        symbol=symbol,
                        side="Sell",
                        action="grid_order",
                        attempted_qty=order_qty,
                        price=price,
                        available_balance=available_balance,
                        reserve_usd=reserve_usd,
                        margin_per_order=margin_per_order,
                        current_order_count=current_order_count,
                        opening_order_count=buy_orders_placed + sell_orders_placed,
                        opening_order_cap=runtime_open_order_cap_total,
                    )
                    self._register_failure_breaker_event(
                        bot, "insufficient_margin", now_ts=now_ts
                    )
                    sell_orders_failed_balance += 1
                    pruned_count, far_order_idx = self._prune_far_orders_for_margin(
                        symbol=symbol,
                        far_orders=far_orders,
                        start_idx=far_order_idx,
                        last_price=last_price,
                        target_level=level,
                    )
                    if pruned_count > 0:
                        orders_cancelled_for_margin += pruned_count
                        refreshed_balance = self._get_usdt_available_balance()
                        if refreshed_balance > 0:
                            available_balance = refreshed_balance
                        skipped_reasons["insufficient_margin_pruned"] = (
                            skipped_reasons.get("insufficient_margin_pruned", 0) + 1
                        )
                        bot["last_skip_reason"] = "insufficient_margin_pruned"
                        continue

                    opening_order_margin_exhausted = True
                    opening_order_block_reason = "insufficient_margin"
                    bot["last_skip_reason"] = "insufficient_margin"
                    bot["last_error"] = "Insufficient available balance for new entry orders"
                    skipped_reasons["insufficient_margin"] = (
                        skipped_reasons.get("insufficient_margin", 0) + 1
                    )
                    logger.warning(
                        f"[{symbol}] Margin exhausted for new SELL entries - stopping further opening orders this cycle"
                    )
                logger.warning(
                    f"[{symbol}] FAILED Sell at {price}: {error_msg} (code={ret_code}, reduce_only={sell_reduce_only})"
                )

        # Log skip summary if any skips occurred
        if skipped_reasons:
            reasons_str = ", ".join([f"{k}:{v}" for k, v in skipped_reasons.items()])
            logger.info(f"[{symbol}] ⏭️ Skips: [{reasons_str}]")

        opening_orders_placed_count = initial_opening_orders_placed + add_follow_through_placed
        if (
            opening_orders_placed_count > 0
            and bot.get("auto_pilot")
            and not bot.get("auto_pilot_first_orders_at")
        ):
            bot["auto_pilot_first_orders_at"] = time.time()
        if opening_orders_placed_count > 0:
            self._maybe_record_opening_follow_through_restored(
                bot,
                symbol=symbol,
                mode=mode,
                restored_to="opening_orders_placed",
                buy_orders_placed=buy_orders_placed,
                sell_orders_placed=sell_orders_placed,
            )
            self._record_opening_follow_through_event(
                bot,
                event_type="opening_orders_placed",
                symbol=symbol,
                mode=mode,
                buy_candidates=pre_cap_opening_buy_candidates,
                sell_candidates=pre_cap_opening_sell_candidates,
                buy_orders_placed=buy_orders_placed,
                sell_orders_placed=sell_orders_placed,
                initial_opening_orders_placed=initial_opening_orders_placed,
                add_follow_through_placed=add_follow_through_placed,
                skipped_reasons=skipped_reasons,
                opening_order_cap=runtime_open_order_cap_total,
                current_order_count=current_order_count,
                opening_sizing=opening_submission_sizing or opening_sizing_context,
            )
        if add_follow_through_placed > 0:
            self._maybe_record_opening_follow_through_restored(
                bot,
                symbol=symbol,
                mode=mode,
                restored_to="add_follow_through_happened",
                buy_orders_placed=buy_orders_placed,
                sell_orders_placed=sell_orders_placed,
            )
            self._record_opening_follow_through_event(
                bot,
                event_type="add_follow_through_happened",
                symbol=symbol,
                mode=mode,
                buy_candidates=pre_cap_opening_buy_candidates,
                sell_candidates=pre_cap_opening_sell_candidates,
                buy_orders_placed=buy_orders_placed,
                sell_orders_placed=sell_orders_placed,
                initial_opening_orders_placed=initial_opening_orders_placed,
                add_follow_through_placed=add_follow_through_placed,
                skipped_reasons=skipped_reasons,
                opening_order_cap=runtime_open_order_cap_total,
                current_order_count=current_order_count,
                opening_sizing=opening_submission_sizing or opening_sizing_context,
            )
        if (
            opening_orders_placed_count <= 0
            and (pre_cap_opening_buy_candidates > 0 or pre_cap_opening_sell_candidates > 0)
        ):
            primary_reason = None
            if position_cap_suppressed_this_cycle:
                primary_reason = "position_cap_hit"
            elif opening_order_margin_exhausted:
                primary_reason = opening_order_block_reason or "insufficient_margin"
            elif skipped_reasons:
                primary_reason = next(iter(sorted(skipped_reasons.keys())))
            elif opening_order_guard_skip:
                primary_reason = opening_order_guard_reason or "opening_guard"
            if primary_reason:
                continuation_add_reason = None
                if opening_kind == "add" and continuation_add_candidate_active:
                    continuation_add_reason = self._get_continuation_add_block_reason(
                        primary_reason
                    )
                forensic_side = "buy" if pre_cap_opening_buy_candidates > 0 else "sell"
                blocked_opening_sizing = self._augment_directional_opening_sizing_fields(
                    opening_sizing_context,
                    final_blocker_reason=primary_reason,
                )
                forensic_context = self._build_trade_forensic_decision_context(
                    bot=bot,
                    symbol=symbol,
                    mode=mode,
                    range_mode=range_mode,
                    last_price=last_price,
                    decision_type="grid_opening",
                    candidate_open_sides=[
                        side
                        for side, count in (
                            ("buy", pre_cap_opening_buy_candidates),
                            ("sell", pre_cap_opening_sell_candidates),
                        )
                        if count > 0
                    ],
                    candidate_counts={
                        "buy": pre_cap_opening_buy_candidates,
                        "sell": pre_cap_opening_sell_candidates,
                    },
                    fast_indicators=fast_indicators,
                    gate_result=directional_gate_result,
                    blockers=cycle_blocker_stack,
                    position_snapshot=self._build_ai_advisor_position_snapshot(
                        side=current_position_side,
                        size=current_position_size,
                        unrealized_pnl=None,
                    ),
                    advisor_review=grid_advisor_review,
                    opening_sizing=blocked_opening_sizing,
                )
                self._record_trade_forensic_decision(
                    bot=bot,
                    symbol=symbol,
                    mode=mode,
                    side=forensic_side,
                    decision_type="grid_opening",
                    decision_context=forensic_context,
                    event_type="skip_blocked",
                    event_status="suppressed",
                    skip_reason=primary_reason,
                )
                self._record_opening_follow_through_event(
                    bot,
                    event_type="opening_orders_suppressed",
                    symbol=symbol,
                    mode=mode,
                    buy_candidates=pre_cap_opening_buy_candidates,
                    sell_candidates=pre_cap_opening_sell_candidates,
                    buy_orders_placed=buy_orders_placed,
                    sell_orders_placed=sell_orders_placed,
                    initial_opening_orders_placed=initial_opening_orders_placed,
                    add_follow_through_placed=add_follow_through_placed,
                    skipped_reasons=skipped_reasons,
                    primary_reason=primary_reason,
                    continuation_add_reason=continuation_add_reason,
                    opening_order_cap=runtime_open_order_cap_total,
                    current_order_count=current_order_count,
                    opening_sizing=blocked_opening_sizing,
                )
                if opening_kind == "add":
                    self._record_opening_follow_through_event(
                        bot,
                        event_type="add_follow_through_blocked",
                        symbol=symbol,
                        mode=mode,
                        buy_candidates=pre_cap_opening_buy_candidates,
                        sell_candidates=pre_cap_opening_sell_candidates,
                        buy_orders_placed=buy_orders_placed,
                        sell_orders_placed=sell_orders_placed,
                        initial_opening_orders_placed=initial_opening_orders_placed,
                        add_follow_through_placed=add_follow_through_placed,
                        skipped_reasons=skipped_reasons,
                        primary_reason=primary_reason,
                        continuation_add_reason=continuation_add_reason,
                        opening_order_cap=runtime_open_order_cap_total,
                        current_order_count=current_order_count,
                        opening_sizing=blocked_opening_sizing,
                    )

        # A1: Flush batch orders — submit all collected Limit orders in one
        # Bybit API call instead of N serial calls.
        if _batch_pending:
            batch_results = self._submit_batch_orders(bot, symbol, _batch_pending)
            batch_ok = sum(1 for r in batch_results if r.get("success"))
            batch_fail = sum(1 for r in batch_results if not r.get("success"))
            if batch_fail > 0:
                # Adjust counters: the loops counted optimistic successes,
                # subtract the actual failures.
                orders_placed = max(0, orders_placed - batch_fail)
                orders_failed += batch_fail
            logger.info(
                "[%s] Batch submitted: %d/%d succeeded in one API call",
                symbol,
                batch_ok,
                len(_batch_pending),
            )
            _batch_pending.clear()

        cancelled_info = (
            f", {orders_cancelled_for_margin} far orders cancelled"
            if orders_cancelled_for_margin > 0
            else ""
        )
        logger.info(
            f"[{symbol}] Placed {orders_placed} new orders, {orders_failed} failed{cancelled_info}"
        )

        # =============================================================================
        # SYNC ORDER COUNTS FROM EXCHANGE — ensures dashboard display matches
        # exchange truth.  Always runs (not just after placement) so that
        # orders placed by previous cycles or manually are reflected.
        # =============================================================================
        try:
            verify_response = self.client.get_open_orders(symbol, skip_cache=True)
            if verify_response.get("success"):
                all_orders = verify_response.get("data", {}).get("list", []) or []
                bot_id_prefix = str(bot.get("id") or "")[:8].replace("-", "")
                # Count bot-owned orders
                owned_orders = [
                    o for o in all_orders
                    if bot_id_prefix and bot_id_prefix in str(o.get("orderLinkId") or "")
                ]
                entry_count = sum(
                    1 for o in owned_orders if not o.get("reduceOnly", False)
                )
                exit_count = sum(
                    1 for o in owned_orders if o.get("reduceOnly", False)
                )
                total_count = len(owned_orders)
                bot["open_order_count"] = total_count
                bot["entry_orders_open"] = entry_count
                bot["exit_orders_open"] = exit_count
        except Exception as verify_exc:
            logger.debug("[%s] Order count sync failed: %s", symbol, verify_exc)

        try:
            self.pnl_service.sync_closed_pnl(symbol)
        except Exception as e:
            logger.warning(f"[{symbol}] PnL sync failed: {e}")

        self._maybe_run_dynamic_quick_profit(
            bot=bot,
            symbol=symbol,
            last_price=last_price,
            fast_indicators=fast_indicators,
        )

        if orders_placed > 0:
            self._clear_failure_breaker(bot)

        current_bot = self.bot_storage.get_bot(bot_id)
        if current_bot and current_bot.get("status") != "running":
            logger.info(
                f"[{symbol}] Status changed to '{current_bot.get('status')}' during cycle, skipping save"
            )
            return current_bot

        bot["last_run_at"] = now_iso
        bot["last_error"] = None
        self._set_bot_current_price(bot, last_price, symbol=symbol)
        bot["runtime_grid_count"] = total_biased_levels
        bot["orders_placed"] = orders_placed
        bot["orders_failed"] = orders_failed

        self.bot_storage.save_bot(bot)
        return bot

    def _run_neutral_classic_bybit(
        self, bot: Dict[str, Any], symbol: str
    ) -> Dict[str, Any]:
        mode = (bot.get("mode") or "").lower()
        bot = self.neutral_grid_service.ensure_hedge_mode(bot, symbol, self.client)
        if bot.get("status") == "error":
            return bot
        if bot.get("auto_pilot"):
            self._refresh_auto_pilot_loss_budget_state(bot, symbol)

        # =====================================================================
        # BTC CORRELATION / REGIME FILTER (neutral_classic_bybit)
        # =====================================================================
        # Same check as main cycle path — block opening orders when BTC
        # correlation is high or regime is illiquid/blocked.
        if self.entry_filter:
            _btc_filter_on = bot.get("btc_correlation_filter_enabled", True)
            try:
                _regime_indicators = self.indicator_service.compute_indicators(
                    symbol, interval="15", limit=200
                )
                _regime_result = self.entry_filter.classify_regime(
                    symbol=symbol,
                    indicators=_regime_indicators,
                    include_btc_filter=_btc_filter_on,
                )
                _regime = _regime_result.get("regime")
                bot["entry_filter_regime"] = _regime
                bot["entry_filter_regime_reason"] = _regime_result.get("reason")
                if _regime in ("blocked", "illiquid"):
                    bot["_block_opening_orders"] = True
                    bot["last_error"] = (
                        f"Entry blocked: {_regime_result.get('reason')}"
                    )
                    logger.warning(
                        f"[{symbol}] 🚫 Regime {_regime} (neutral_classic) - "
                        f"new entries blocked, position management continues"
                    )
            except Exception as _regime_err:
                logger.debug(
                    f"[{symbol}] Regime check error: {_regime_err}"
                )

        # =====================================================================
        # NEUTRAL SUITABILITY GATE CHECK
        # =====================================================================
        # Check if market conditions are suitable for neutral mode.
        # Blocks new orders (but allows position closes) when market is trending.
        from config.strategy_config import (
            NEUTRAL_GATE_ENABLED,
            NEUTRAL_GATE_RECHECK_SECONDS,
        )
        import time as _time

        if NEUTRAL_GATE_ENABLED:
            now = _time.time()
            blocked_until = self._get_blocked_until_ts(bot, "_gate_blocked_until")

            # Recheck if cooldown expired
            if now >= blocked_until:
                try:
                    from services.neutral_suitability_service import (
                        NeutralSuitabilityService,
                    )

                    gate_service = NeutralSuitabilityService(self.indicator_service)
                    gate_result = gate_service.check_suitability(
                        symbol=symbol,
                        preset=bot.get("neutral_preset"),
                    )

                    if not gate_result["suitable"]:
                        # Block new orders, allow closes
                        # BYPASS check: If user disabled entry gate, ignore suitability
                        if bot.get("entry_gate_enabled", True):
                            bot["_nlp_block_opening_orders"] = True
                            bot["_gate_blocked_until"] = (
                                now + NEUTRAL_GATE_RECHECK_SECONDS
                            )
                            bot["_gate_blocked_reason"] = gate_result["reason"]
                            logger.info(
                                "[%s] NEUTRAL_GATE blocked: %s",
                                symbol,
                                gate_result["reason"],
                            )
                        else:
                            bot["_nlp_block_opening_orders"] = False
                            bot["_gate_blocked_reason"] = (
                                f"BYPASSED: {gate_result['reason']}"
                            )
                            logger.info(
                                "[%s] NEUTRAL_GATE bypassed by user setting", symbol
                            )
                    else:
                        # Conditions improved - clear the block
                        if bot.get("_gate_blocked_reason"):
                            logger.info(
                                "[%s] NEUTRAL_GATE cleared - conditions now suitable",
                                symbol,
                            )
                        bot["_nlp_block_opening_orders"] = False
                        bot.pop("_gate_blocked_until", None)
                        bot.pop("_gate_blocked_reason", None)
                except Exception as gate_err:
                    logger.warning(
                        "[%s] Gate check error (continuing): %s", symbol, gate_err
                    )

        # =====================================================================
        # NEUTRAL LOSS PREVENTION CHECKS (priority order)
        # =====================================================================
        # Run all loss-prevention checks before grid operations.
        # Checks: Max Loss -> Breakout -> Inventory Cap -> Momentum -> Recenter
        last_price = self._get_last_price(symbol)
        if last_price:
            try:
                # Fetch 1m indicators for momentum filter
                indicators_1m = self.indicator_service.compute_indicators(
                    symbol, interval="1", limit=50
                )
                candles_1m = None
                try:
                    candles_1m = self.indicator_service.get_ohlcv(
                        symbol, interval="1", limit=5
                    )
                except Exception:
                    pass

                # Run all loss-prevention checks
                nlp_result = self.neutral_loss_prevention.run_all_checks(
                    bot=bot,
                    symbol=symbol,
                    mark_price=last_price,
                    indicators=indicators_1m,
                    candles_1m=candles_1m,
                )

                action = nlp_result.get("action")

                # Handle Max Loss Stop (stops bot entirely)
                if action == "max_loss_stop":
                    bot = nlp_result.get("bot", bot)
                    self.bot_storage.save_bot(bot)
                    return bot

                # Handle Breakout Flatten (flatten and enter cooldown)
                if action == "breakout_flatten":
                    bot = nlp_result.get("bot", bot)
                    self.bot_storage.save_bot(bot)
                    return bot

                # Handle Breakout Cooldown (still waiting)
                if action == "breakout_cooldown":
                    return bot

                # Handle Breakout Rebuild (cooldown expired, rebuild grid)
                if action == "breakout_rebuild":
                    bot = nlp_result.get("bot", bot)
                    # Clear grid state to trigger reconcile below
                    bot["neutral_grid"] = {}
                    bot["neutral_grid_initialized"] = False
                    # Fall through to normal reconcile

                # Handle Emergency Inventory Reduce
                if action == "inventory_reduce":
                    bot = nlp_result.get("bot", bot)
                    self.bot_storage.save_bot(bot)
                    # Continue with rest of cycle after reducing

                # Handle Grid Blocking (momentum/inventory cap exceeded)
                if action in ("block_grid", "pause_grid"):
                    is_momentum = nlp_result.get("details", {}).get("momentum_blocked")
                    is_inventory = nlp_result.get("details", {}).get(
                        "inventory_exceeded"
                    )

                    if is_inventory:
                        bot["_nlp_block_opening_orders"] = True
                    elif is_momentum and bot.get("entry_gate_enabled", True):
                        bot["_nlp_block_opening_orders"] = True
                    else:
                        # Momentum block bypassed or no block
                        bot["_nlp_block_opening_orders"] = False
                else:
                    bot["_nlp_block_opening_orders"] = False

                # Handle Recenter
                if action == "recenter":
                    bot = nlp_result.get("bot", bot)
                    # Grid state already cleared by recenter, will reconcile below

            except Exception as e:
                logger.warning("[%s] Loss prevention check error: %s", symbol, e)

        # =====================================================================
        # MICRO-BIAS AWARENESS
        # =====================================================================
        # Detect slight directional drift and set per-side skip flags.
        # Skip some ENTRY orders against the micro-trend to reduce inventory accumulation.
        from config.strategy_config import (
            NEUTRAL_MICRO_BIAS_ENABLED,
            NEUTRAL_MICRO_BIAS_THRESHOLD,
            NEUTRAL_MICRO_BIAS_STRONG,
            MICRO_BIAS_SKIP_PCT_MODERATE,
            MICRO_BIAS_SKIP_PCT_STRONG,
            MICRO_BIAS_HYSTERESIS_CHECKS,
            MICRO_BIAS_CACHE_SECONDS,
        )

        # Clear previous cycle's skip flags
        bot["_micro_bias_skip_buy"] = False
        bot["_micro_bias_skip_sell"] = False
        bot["_micro_bias_score"] = 0.0

        if NEUTRAL_MICRO_BIAS_ENABLED and self.micro_bias_service is not None:
            try:
                import random

                micro_bias = self.micro_bias_service.calculate_bias(
                    bot=bot,
                    symbol=symbol,
                    threshold=NEUTRAL_MICRO_BIAS_THRESHOLD,
                    strong_threshold=NEUTRAL_MICRO_BIAS_STRONG,
                    skip_pct_moderate=MICRO_BIAS_SKIP_PCT_MODERATE,
                    skip_pct_strong=MICRO_BIAS_SKIP_PCT_STRONG,
                    hysteresis_checks=MICRO_BIAS_HYSTERESIS_CHECKS,
                    cache_seconds=MICRO_BIAS_CACHE_SECONDS,
                )

                bot["_micro_bias_score"] = micro_bias.get("score", 0.0)
                bot["_micro_bias_direction"] = micro_bias.get("direction", "NEUTRAL")

                if micro_bias.get("direction") == "BULLISH":
                    # Bullish drift - probabilistically skip Sell ENTRY orders
                    bot["_micro_bias_skip_sell"] = (
                        random.random() < micro_bias.get("skip_probability", 0.0)
                    )
                    bot["_micro_bias_skip_buy"] = False
                elif micro_bias.get("direction") == "BEARISH":
                    # Bearish drift - probabilistically skip Buy ENTRY orders
                    bot["_micro_bias_skip_buy"] = (
                        random.random() < micro_bias.get("skip_probability", 0.0)
                    )
                    bot["_micro_bias_skip_sell"] = False

                if bot.get("_micro_bias_skip_buy") or bot.get("_micro_bias_skip_sell"):
                    logger.debug(
                        "[%s] MICRO_BIAS skip this cycle: skip_buy=%s skip_sell=%s "
                        "(direction=%s score=%.3f)",
                        symbol,
                        bot.get("_micro_bias_skip_buy"),
                        bot.get("_micro_bias_skip_sell"),
                        micro_bias.get("direction"),
                        micro_bias.get("score", 0.0),
                    )
            except Exception as mb_err:
                logger.debug("[%s] Micro-bias calculation error: %s", symbol, mb_err)

        self._evaluate_structure_entry_blocks(
            bot=bot,
            symbol=symbol,
            last_price=last_price or 0.0,
            fast_indicators=indicators_1m if last_price else None,
            allow_buy=True,
            allow_sell=True,
        )

        # =====================================================================
        # Early trend exit guard: prevent (re)seeding grids while market is trending
        from config.strategy_config import TREND_EXIT_GUARD_ENABLED

        regime_effective = bot.get("regime_effective")
        regime_conf = bot.get("regime_confidence")
        trend_exit_state = bot.get("_neutral_trend_exit") or {}
        last_exit_ts = self._safe_float(trend_exit_state.get("last_exit_ts"), 0.0)
        waiting_for_green = bool(trend_exit_state.get("waiting_for_green"))
        now_ts = self.client._get_now_ts()
        trend_exit_cooldown = 300  # 5 minutes to avoid flapping
        waiting_retry_cooldown = 30  # retry checks sooner when waiting for green
        min_trend_age = 120  # require 2 minutes of stable trend before exiting
        regime_last_change_ts = self._safe_float(bot.get("regime_last_change_ts"), 0.0)
        trend_age = now_ts - regime_last_change_ts if regime_last_change_ts else 0

        if TREND_EXIT_GUARD_ENABLED and waiting_for_green and now_ts - last_exit_ts < waiting_retry_cooldown:
            return bot

        if TREND_EXIT_GUARD_ENABLED and (
            bot.get("trading_env") != "backtest"
            and regime_effective in ("UP", "DOWN")
            and regime_conf == "high"
        ):
            if trend_age < min_trend_age:
                logger.debug(
                    "[%s] Trend exit guard skipped (trend_age=%.0fs < %ss, regime=%s)",
                    symbol,
                    trend_age,
                    min_trend_age,
                    regime_effective,
                )
                return bot
            if now_ts - last_exit_ts >= trend_exit_cooldown:
                try:
                    cancel_result = self._force_cancel_all_orders(
                        symbol,
                        max_retries=2,
                        bot=bot,
                    )
                    if not cancel_result.get("success"):
                        logger.warning(
                            "[%s] Trend exit: failed to cancel all orders (%s)",
                            symbol,
                            cancel_result,
                        )
                except Exception as e:
                    logger.warning("[%s] Trend exit: order cancel error: %s", symbol, e)

                try:
                    positions = self.client.get_positions(skip_cache=True)
                    closed_any = False
                    skipped_for_loss = False
                    if positions.get("success"):
                        for pos in positions.get("data", {}).get("list", []) or []:
                            if pos.get("symbol") != symbol:
                                continue
                            size = self._safe_float(pos.get("size"), 0.0)
                            if size <= 0:
                                continue
                            unrealized = self._safe_float(pos.get("unrealisedPnl"), 0.0)
                            if unrealized <= 0:
                                skipped_for_loss = True
                                logger.info(
                                    "[%s] Trend exit guard: keeping position open (uPnL=%.4f) until green",
                                    symbol,
                                    unrealized,
                                )
                                continue
                            side = pos.get("side")
                            close_side = "Sell" if side == "Buy" else "Buy"
                            position_idx = int(pos.get("positionIdx", 0) or 0)
                            close_result = self._create_order_checked(
                                bot=bot,
                                symbol=symbol,
                                side=close_side,
                                qty=size,
                                order_type="Market",
                                price=None,
                                reduce_only=True,
                                time_in_force="GTC",
                                order_link_id=f"close_{bot.get('id')}_{int(time.time() * 1000)}",
                                position_idx=position_idx,
                            )
                            if close_result.get("success") or self._is_position_empty_close_result(close_result):
                                closed_any = True
                            else:
                                logger.warning(
                                    "[%s] Trend exit guard: close order failed: %s",
                                    symbol,
                                    close_result.get("error"),
                                )

                    if skipped_for_loss and not closed_any:
                        bot["status"] = "paused"
                        bot["pause_reason"] = (
                            "Trend exit guard: paused; waiting for green to close position"
                        )
                        bot["pause_reason_type"] = "trend_exit_guard"
                        bot["paused_at"] = now_ts
                        bot["last_error"] = bot["pause_reason"]
                        bot["_neutral_trend_exit"] = {
                            "last_exit_ts": now_ts,
                            "reason": regime_effective,
                            "waiting_for_green": True,
                        }
                        self.bot_storage.save_bot(bot)
                        logger.info(
                            "[%s] Trend exit guard paused (regime=%s, conf=%s) - waiting for green to close",
                            symbol,
                            regime_effective,
                            regime_conf,
                        )
                        return bot

                    bot["status"] = "paused"
                    bot["pause_reason"] = "Trend exit guard: paused due to trending regime"
                    bot["pause_reason_type"] = "trend_exit_guard"
                    bot["paused_at"] = now_ts
                    bot["last_error"] = bot["pause_reason"]
                    bot["_neutral_trend_exit"] = {
                        "last_exit_ts": now_ts,
                        "reason": regime_effective,
                        "waiting_for_green": False,
                    }
                    self.bot_storage.save_bot(bot)
                    logger.info(
                        "[%s] Trend exit guard activated (regime=%s, conf=%s) -> paused",
                        symbol,
                        regime_effective,
                        regime_conf,
                    )
                    return bot
                except Exception as e:
                    logger.warning("[%s] Trend exit: close error: %s", symbol, e)

        if not bot.get("neutral_grid_initialized"):
            bot = self.neutral_grid_service.reconcile_on_start(bot, symbol, self.client)
            if bot.get("status") == "error":
                return bot
        else:
            # Process fills FIRST (before count check) to avoid race condition
            # where fill removes order before replacement appears
            bot = self.neutral_grid_service.process_execution_events(
                bot,
                symbol,
                self.client,
                execution_events=self._stream_execution_events_or_none(),
            )
            if bot.get("status") == "error":
                return bot

            # THEN check counts (after fills processed and replacements placed)
            neutral_state = bot.get("neutral_grid") or {}
            slots = neutral_state.get("slots") or {}
            expected = len(slots)
            if expected == 0:
                bot = self.neutral_grid_service.reconcile_on_start(
                    bot, symbol, self.client
                )
                if bot.get("status") == "error":
                    return bot
            else:
                open_count = self.neutral_grid_service.count_bot_open_orders(
                    bot, symbol, self.client, skip_cache=True
                )
                if open_count != expected:
                    logger.warning(
                        "[%s] Neutral grid reconcile: %s/%s orders open",
                        symbol,
                        open_count,
                        expected,
                    )
                    bot = self.neutral_grid_service.reconcile_on_start(
                        bot, symbol, self.client
                    )
                    if bot.get("status") == "error":
                        return bot

        neutral_state = bot.get("neutral_grid") or {}
        if neutral_state.get("needs_reconcile"):
            neutral_state["needs_reconcile"] = False
            bot["neutral_grid"] = neutral_state
            bot = self.neutral_grid_service.reconcile_on_start(bot, symbol, self.client)
            if bot.get("status") == "error":
                return bot

        # 001-trading-bot-audit: Volatility freeze check before recenter (FR-009)
        from config.strategy_config import (
            VOLATILITY_FREEZE_ATR_PCT,
            VOLATILITY_FREEZE_BBW_PCT,
        )

        volatility_frozen = False
        try:
            ind = self.indicator_service.compute_indicators(symbol, "15m")
            atr_pct = ind.get("atr_pct", 0) if ind else 0
            bbw_pct = ind.get("bbw_pct", 0) if ind else 0
            if (
                atr_pct > VOLATILITY_FREEZE_ATR_PCT
                or bbw_pct > VOLATILITY_FREEZE_BBW_PCT
            ):
                volatility_frozen = True
                logger.info(
                    "[%s] ❄️ VOLATILITY FREEZE: Recenter blocked (ATR%%=%.2f%%, BBW%%=%.2f%%)",
                    symbol,
                    atr_pct * 100,
                    bbw_pct * 100,
                )
        except Exception as e:
            logger.debug("[%s] Volatility check failed: %s", symbol, e)

        if not volatility_frozen:
            bot = self.neutral_grid_service.recenter_if_needed(bot, symbol, self.client)
        if bot.get("status") == "error":
            return bot

        # print(f"DEBUG: Processing neutral classic logic for {symbol}, mode={mode}")
        # Recenter neutral classic grid when flat (no positions/orders) on cooldown
        if mode == "neutral_classic_bybit" and not volatility_frozen:
            bot = self.neutral_grid_service.recenter_if_flat_and_stale(
                bot=bot,
                symbol=symbol,
                client=self.client,
                cooldown_seconds=300,  # 5 minutes
            )
            if bot.get("status") == "error":
                return bot

            # Trailing range recenter (moves grid when price hits outer 25%)
            last_price = self._get_last_price(symbol, skip_cache=True)
            if last_price:
                bot = self.neutral_grid_service.recenter_if_trailing(
                    bot=bot,
                    symbol=symbol,
                    client=self.client,
                    last_price=last_price,
                )
                if bot.get("status") == "error":
                    return bot

        last_price = self._get_last_price(symbol)
        if last_price:
            self._set_bot_current_price(bot, last_price, symbol=symbol)

        bot["last_error"] = None
        bot["last_run_at"] = datetime.now(timezone.utc).isoformat()
        return self._save_runtime_bot(bot)

    # =========================================================================
    # EXTRACTED HELPERS — mode-specific logic from _run_bot_cycle_impl
    # =========================================================================

    def _evaluate_directional_cycle_state(
        self,
        bot: Dict[str, Any],
        symbol: str,
        mode: str,
        last_price: float,
        fast_indicators: Optional[Dict[str, Any]],
    ) -> Optional[Dict[str, Any]]:
        """Evaluate directional entry gate, order flow, confidence scoring,
        smart exit, loss cutting, and Auto-Pilot flow reversal.

        Returns the directional_gate_result (or None for non-directional modes).
        Side-effects: sets bot flow/confidence fields, may execute market exits.
        """
        # =============================================================================
        # DIRECTIONAL ENTRY GATE (canonical per-cycle evaluation)
        # =============================================================================
        directional_gate_result = None
        if mode in ("long", "short"):
            directional_gate_result = self._evaluate_directional_entry_gate(
                bot=bot,
                symbol=symbol,
                mode=mode,
                last_price=last_price,
                fast_indicators=fast_indicators,
            )
        else:
            self._clear_runtime_experiment_state(bot)
            self._clear_directional_entry_runtime_state(bot)
            self._clear_directional_audit_runtime_state(bot)

        # =============================================================================
        # ORDER FLOW ANALYSIS — tick-level signal from real-time trade stream
        # Computes buy/sell pressure, volume spikes, orderbook imbalance
        # =============================================================================
        flow_state = None
        order_flow = getattr(self, "order_flow_service", None)
        if order_flow is not None and symbol:
            try:
                flow_state = order_flow.compute_flow_score(symbol)
                bot["flow_score"] = flow_state.get("flow_score", 0)
                bot["flow_signal"] = flow_state.get("signal", "neutral")
                bot["flow_confidence"] = flow_state.get("confidence", 0.0)
                bot["flow_volume_spike"] = flow_state.get("volume_spike", False)
                bot["flow_large_trade"] = flow_state.get("large_trade_detected", False)
                bot["flow_momentum_fading"] = flow_state.get("momentum_fading", False)
                bot["flow_momentum_exhausted"] = flow_state.get("momentum_exhausted", False)
                bot["flow_peak_recent"] = flow_state.get("peak_recent_score", 0)
                bot["flow_fade_amount"] = flow_state.get("fade_amount", 0)
            except Exception as flow_exc:
                logger.debug("[%s] Order flow analysis error: %s", symbol, flow_exc)

        # =============================================================================
        # MULTI-SIGNAL CONFIDENCE SCORE
        # Combines all available signals into one composite score (0-100).
        # Used for: entry confirmation, exit timing, position sizing.
        # Each signal contributes points. 3+ aligned signals = high confidence.
        # =============================================================================
        if mode in ("long", "short"):
            confidence_points = 0.0
            confidence_signals = 0
            confidence_reasons = []

            # Signal 1: Flow direction (0-25 points)
            flow_val = float(bot.get("flow_score") or 0)
            if mode == "long" and flow_val >= 20:
                pts = min(25.0, flow_val * 0.4)
                confidence_points += pts
                confidence_signals += 1
                confidence_reasons.append(f"flow+{pts:.0f}")
            elif mode == "short" and flow_val <= -20:
                pts = min(25.0, abs(flow_val) * 0.4)
                confidence_points += pts
                confidence_signals += 1
                confidence_reasons.append(f"flow+{pts:.0f}")
            elif (mode == "long" and flow_val <= -20) or (mode == "short" and flow_val >= 20):
                confidence_points -= 15.0
                confidence_reasons.append("flow_opposing")

            # Signal 2: Setup quality (0-20 points)
            quality = float(bot.get("setup_quality_score") or 0)
            if quality >= 55:
                confidence_points += 20.0
                confidence_signals += 1
                confidence_reasons.append("quality_good")
            elif quality >= 42:
                confidence_points += 10.0
                confidence_signals += 1
                confidence_reasons.append("quality_ok")
            elif quality > 0:
                confidence_reasons.append("quality_low")

            # Signal 3: Regime alignment (0-20 points)
            regime = str(bot.get("regime_effective") or "").upper()
            regime_conf = str(bot.get("regime_confidence") or "").lower()
            if (mode == "long" and regime == "UP") or (mode == "short" and regime == "DOWN"):
                pts = 20.0 if regime_conf in ("high", "locked") else 12.0
                confidence_points += pts
                confidence_signals += 1
                confidence_reasons.append(f"regime+{pts:.0f}")
            elif regime == "SIDEWAYS":
                confidence_points -= 5.0
                confidence_reasons.append("regime_sideways")
            elif (mode == "long" and regime == "DOWN") or (mode == "short" and regime == "UP"):
                confidence_points -= 15.0
                confidence_reasons.append("regime_opposing")

            # Signal 4: Price action alignment (0-15 points)
            pa_dir = str(bot.get("price_action_direction") or "").lower()
            pa_score = float(bot.get("price_action_score") or 0)
            if pa_dir == mode and pa_score >= 2.0:
                pts = min(15.0, pa_score * 2.0)
                confidence_points += pts
                confidence_signals += 1
                confidence_reasons.append(f"pa+{pts:.0f}")
            elif pa_score <= -2.0:
                confidence_points -= 10.0
                confidence_reasons.append("pa_opposing")

            # Signal 5: Orderbook imbalance (0-10 points)
            book_imb = float((flow_state or {}).get("book_imbalance", 0) if flow_state else 0)
            if mode == "long" and book_imb >= 0.15:
                confidence_points += 10.0
                confidence_signals += 1
                confidence_reasons.append("book_bullish")
            elif mode == "short" and book_imb <= -0.15:
                confidence_points += 10.0
                confidence_signals += 1
                confidence_reasons.append("book_bearish")

            # Signal 6: Momentum not exhausted (0-10 points, penalty if exhausted)
            if bot.get("flow_momentum_exhausted"):
                confidence_points -= 20.0
                confidence_reasons.append("momentum_exhausted")
            elif not bot.get("flow_momentum_fading"):
                confidence_points += 10.0
                confidence_signals += 1
                confidence_reasons.append("momentum_fresh")

            # Signal 7: Market sentiment — OI + L/S ratio + funding (0-20 points)
            sentiment_svc = getattr(self, "market_sentiment_service", None)
            if sentiment_svc is not None:
                try:
                    sentiment = sentiment_svc.get_sentiment(symbol)
                    sent_score = float(sentiment.get("sentiment_score") or 0)
                    bot["sentiment_score"] = sent_score
                    bot["sentiment_signal"] = sentiment.get("signal", "neutral")
                    bot["oi_conviction"] = sentiment.get("oi_conviction", "unknown")
                    bot["long_short_ratio"] = sentiment.get("long_short_ratio", 1.0)

                    if mode == "long" and sent_score >= 15:
                        pts = min(20.0, sent_score * 0.4)
                        confidence_points += pts
                        confidence_signals += 1
                        confidence_reasons.append(f"sentiment+{pts:.0f}")
                    elif mode == "short" and sent_score <= -15:
                        pts = min(20.0, abs(sent_score) * 0.4)
                        confidence_points += pts
                        confidence_signals += 1
                        confidence_reasons.append(f"sentiment+{pts:.0f}")
                    elif sentiment.get("signal") == "reversal_risk":
                        confidence_points -= 15.0
                        confidence_reasons.append("reversal_risk")
                    elif (mode == "long" and sent_score <= -15) or (mode == "short" and sent_score >= 15):
                        confidence_points -= 10.0
                        confidence_reasons.append("sentiment_opposing")
                except Exception:
                    pass

            composite_confidence = max(0.0, min(100.0, confidence_points))
            bot["composite_confidence"] = round(composite_confidence, 1)
            bot["composite_signals_aligned"] = confidence_signals
            bot["composite_confidence_reasons"] = ", ".join(confidence_reasons[:8])

            # CORRELATED EXIT: If holding a position and confidence drops critically
            _pos_size_check = float(bot.get("current_position_size") or 0)
            _pos_side_check = str(bot.get("current_position_side") or "").lower()
            _upnl_check = float(bot.get("unrealized_pnl") or 0)
            if _pos_size_check > 0 and composite_confidence <= 20 and confidence_signals <= 1:
                if _upnl_check >= 0:  # In profit or breakeven — exit to protect
                    logger.warning(
                        "[%s] CORRELATED EXIT: confidence=%.0f signals=%d "
                        "reasons=[%s] — closing to protect profit $%.2f",
                        symbol, composite_confidence, confidence_signals,
                        bot.get("composite_confidence_reasons", ""), _upnl_check,
                    )
                    close_side = "Sell" if _pos_side_check == "buy" else "Buy"
                    _corr_result = self._create_order_checked(
                        bot=bot, symbol=symbol, side=close_side, qty=_pos_size_check,
                        order_type="Market", reduce_only=True, time_in_force="IOC",
                        diagnostic_context={
                            "ownership_action": "correlated_exit",
                            "close_reason": f"confidence_drop_{composite_confidence:.0f}",
                        },
                    )
                    if _corr_result and _corr_result.get("success"):
                        self._maybe_activate_pullback_watch(
                            bot, exit_reason="correlated_exit", exit_price=last_price,
                        )

        # =============================================================================
        # SMART EXIT: Momentum exhaustion early exit
        # When flow was strong in our direction but is rapidly fading,
        # close position BEFORE price catches up to the momentum loss.
        # =============================================================================
        pos_size = float(bot.get("current_position_size") or 0)
        pos_side = str(bot.get("current_position_side") or "").lower()
        upnl = float(bot.get("unrealized_pnl") or 0)

        # Minimum profit buffer to account for slippage on thin orderbooks.
        # Prevents Smart Exit from closing at "profit" that evaporates on fill.
        _atr_pct = self._safe_float(bot.get("atr_15m_pct") or (fast_indicators or {}).get("atr_pct"), 0.005)
        _notional = pos_size * last_price if pos_size > 0 and last_price > 0 else 0
        _slippage_buffer = max(0.01, _notional * _atr_pct * 0.003)  # ~0.3% of ATR move as buffer

        if (
            pos_size > 0
            and upnl > _slippage_buffer  # Must exceed slippage buffer, not just > 0
            and bool(bot.get("flow_momentum_exhausted"))
            and float(bot.get("flow_confidence") or 0) >= 0.35
        ):
            # Check that exhaustion is AGAINST our position direction
            flow_score_val = float(bot.get("flow_score") or 0)
            peak = float(bot.get("flow_peak_recent") or 0)
            exit_signal = False

            if pos_side == "buy" and peak >= 30 and flow_score_val <= 10:
                exit_signal = True  # Was bullish, now fading
            elif pos_side == "sell" and peak <= -30 and flow_score_val >= -10:
                exit_signal = True  # Was bearish, now fading

            if exit_signal:
                logger.warning(
                    "[%s] SMART EXIT: Momentum exhausted! peak=%.0f now=%.0f fade=%.0f "
                    "upnl=$%.2f — closing to lock profit before reversal",
                    symbol, peak, flow_score_val,
                    float(bot.get("flow_fade_amount") or 0), upnl,
                )
                close_side = "Sell" if pos_side == "buy" else "Buy"
                close_result = self._create_order_checked(
                    bot=bot,
                    symbol=symbol,
                    side=close_side,
                    qty=pos_size,
                    order_type="Market",
                    reduce_only=True,
                    time_in_force="IOC",
                    diagnostic_context={
                        "ownership_action": "momentum_exhaustion_exit",
                        "close_reason": "momentum_exhaustion_exit",
                    },
                )
                if close_result.get("success"):
                    bot["_momentum_exit_count"] = int(bot.get("_momentum_exit_count") or 0) + 1
                    bot["_last_momentum_exit_at"] = datetime.now(timezone.utc).isoformat()
                    logger.info(
                        "[%s] SMART EXIT executed: closed %.4f %s at market (exit #%d)",
                        symbol, pos_size, pos_side,
                        bot.get("_momentum_exit_count", 1),
                    )
                    self._maybe_activate_pullback_watch(
                        bot, exit_reason="momentum_exhaustion_exit", exit_price=last_price,
                    )

        # =============================================================================
        # LOSS CUTTING SPEED: Flow-based early loss cut
        # When position is LOSING and flow strongly opposes for sustained period,
        # cut the loss early instead of waiting for UPnL stop-loss or grid exits.
        # This prevents small losses from becoming big losses (-$25 BANANAS style).
        # =============================================================================
        if (
            pos_size > 0
            and upnl < 0  # Position is losing
            and float(bot.get("flow_confidence") or 0) >= 0.40
        ):
            flow_score_val = float(bot.get("flow_score") or 0)
            flow_strongly_opposing = False

            if pos_side == "buy" and flow_score_val <= -40:
                flow_strongly_opposing = True
            elif pos_side == "sell" and flow_score_val >= 40:
                flow_strongly_opposing = True

            if flow_strongly_opposing:
                # Track how long flow has been opposing — need sustained opposition (not a spike)
                bot["_flow_opposing_flicker"] = 0  # Reset flicker counter when opposing
                opposing_since = float(bot.get("_flow_opposing_since") or 0)
                now_cut = time.time()
                from config.strategy_config import FLOW_LOSS_CUT_SUSTAINED_SEC
                if opposing_since <= 0:
                    bot["_flow_opposing_since"] = now_cut
                elif now_cut - opposing_since >= float(FLOW_LOSS_CUT_SUSTAINED_SEC):
                    # Flow has opposed for 30+ seconds — cut the loss
                    loss_pct = abs(upnl) / max(pos_size * last_price, 1.0) * 100
                    logger.warning(
                        "[%s] LOSS CUT: Flow opposing for %.0fs (flow=%.0f vs %s) "
                        "upnl=$%.2f (%.2f%%) — cutting loss early",
                        symbol, now_cut - opposing_since, flow_score_val,
                        pos_side, upnl, loss_pct,
                    )
                    close_side = "Sell" if pos_side == "buy" else "Buy"
                    cut_result = self._create_order_checked(
                        bot=bot,
                        symbol=symbol,
                        side=close_side,
                        qty=pos_size,
                        order_type="Market",
                        reduce_only=True,
                        time_in_force="IOC",
                        diagnostic_context={
                            "ownership_action": "flow_loss_cut",
                            "close_reason": f"flow_loss_cut_{flow_score_val:.0f}",
                        },
                    )
                    if cut_result.get("success"):
                        bot["_loss_cut_count"] = int(bot.get("_loss_cut_count") or 0) + 1
                        bot["_last_loss_cut_at"] = datetime.now(timezone.utc).isoformat()
                        bot["_flow_opposing_since"] = 0
                        logger.info(
                            "[%s] LOSS CUT executed: closed %.4f %s at market (cut #%d, saved from deeper loss)",
                            symbol, pos_size, pos_side,
                            bot.get("_loss_cut_count", 1),
                        )
            else:
                # Flow not strongly opposing — but don't reset immediately on a single flicker.
                # Only reset after 3 consecutive non-opposing checks to handle noisy flow.
                flicker_count = int(bot.get("_flow_opposing_flicker") or 0) + 1
                bot["_flow_opposing_flicker"] = flicker_count
                if flicker_count >= 3:
                    if bot.get("_flow_opposing_since"):
                        logger.debug(
                            "[%s] Loss cut timer reset after %d non-opposing checks (was %.0fs)",
                            symbol, flicker_count,
                            time.time() - float(bot.get("_flow_opposing_since") or 0),
                        )
                    bot["_flow_opposing_since"] = 0
                    bot["_flow_opposing_flicker"] = 0

        # =============================================================================
        # TIER 2: Auto-Pilot flow reversal detection — if flow strongly opposes
        # the position direction, force an early rotation to a better coin.
        # =============================================================================
        if (
            bot.get("auto_pilot")
            and not bot.get("_auto_pilot_entry_hold")
            and float(bot.get("current_position_size") or 0) > 0
            and float(bot.get("flow_confidence") or 0) >= 0.45
        ):
            flow_val = float(bot.get("flow_score") or 0)
            pos_side = str(bot.get("current_position_side") or "").lower()
            flow_against = (
                (pos_side == "buy" and flow_val <= -50)
                or (pos_side == "sell" and flow_val >= 50)
            )
            if flow_against:
                logger.warning(
                    "[%s] TIER 2: Auto-Pilot flow reversal! flow=%.0f vs position=%s — forcing rotation",
                    symbol, flow_val, pos_side,
                )
                bot["auto_pilot_rotation_forced_reason"] = f"flow_reversal_{flow_val:.0f}"
                # Don't close position here — let the rotation system handle it
                # Just mark for immediate rotation on next check
                bot["_auto_pilot_force_rotation"] = True

        return directional_gate_result

    def _run_neutral_phase_guards(
        self,
        bot: Dict[str, Any],
        symbol: str,
        mode: str,
        last_price: float,
        fast_refill_tick: bool,
        fast_indicators: Optional[Dict[str, Any]],
        now_iso: str,
    ) -> Optional[Dict[str, Any]]:
        """Run neutral-mode phase guards: cooldown, NLP-lite, micro-bias.

        Returns bot dict if cycle should end early, None to continue.
        Only executes when mode == 'neutral'.
        """
        # =============================================================================
        # COOLDOWN CHECK for Neutral Mode (all range types)
        # Prevents rapid order churn that loses money to fees in choppy markets
        # =============================================================================
        if mode == "neutral" and not fast_refill_tick:
            # Use longer cooldown for volatile meme coins
            is_volatile_symbol = symbol in VOLATILE_NEUTRAL_SYMBOLS
            cooldown_sec = (
                VOLATILE_NEUTRAL_COOLDOWN_SEC
                if is_volatile_symbol
                else NEUTRAL_DYNAMIC_COOLDOWN_SEC
            )

            last_run = bot.get("last_run_at")
            # Cooldown is cleared when bot starts, so if last_run exists, apply cooldown
            if last_run:
                try:
                    last_run_dt = datetime.fromisoformat(
                        last_run.replace("Z", "+00:00")
                    )
                    elapsed = (datetime.now(timezone.utc) - last_run_dt).total_seconds()
                    if elapsed < cooldown_sec:
                        logger.info(
                            f"[{symbol}] COOLDOWN ACTIVE - {elapsed:.0f}s < {cooldown_sec}s, skipping"
                        )
                        return bot  # Skip this cycle, wait for cooldown
                except Exception as e:
                    logger.warning(f"[{symbol}] Cooldown check error: {e}")

            # For volatile symbols: require minimum price movement before trading
            # BUT: bypass this check if there are no open orders (need to place orders first)
            if is_volatile_symbol:
                # Quick check for open orders
                orders_resp = self.client.get_open_orders(symbol)
                has_orders = False
                if orders_resp.get("success"):
                    order_list = orders_resp.get("data", {}).get("list", []) or []
                    has_orders = len(order_list) > 0

                if has_orders:
                    last_trade_price = bot.get("last_trade_price")
                    if last_trade_price:
                        try:
                            if last_price is None:
                                last_price = self._get_last_price(symbol)
                            if last_price:
                                price_move_pct = (
                                    abs(last_price - last_trade_price)
                                    / last_trade_price
                                )
                                if price_move_pct < VOLATILE_NEUTRAL_MIN_MOVE_PCT:
                                    logger.info(
                                        f"[{symbol}] Price move {price_move_pct * 100:.2f}% < {VOLATILE_NEUTRAL_MIN_MOVE_PCT * 100:.1f}% required, skipping"
                                    )
                                    return bot
                        except Exception as e:
                            logger.debug(f"[{symbol}] Price move check error: {e}")

        # =============================================================================
        # NLP-LITE FOR NEUTRAL MODE
        # =============================================================================
        # Provides breakout and strong momentum protection for regular neutral bots
        bot["_nlp_lite_block_opening"] = False
        if mode == "neutral" and hasattr(self, "neutral_loss_prevention"):
            try:
                # 1) Get indicators for NLP
                nlp_indicators = self.indicator_service.compute_indicators(
                    symbol, interval="1", limit=50
                )
                nlp_candles = None
                try:
                    # 1m candles for momentum checks
                    nlp_candles = self.indicator_service.get_ohlcv(
                        symbol, interval="1", limit=5
                    )
                except Exception:
                    pass

                # 2) Run NLP checks
                nlp_result = self.neutral_loss_prevention.run_all_checks(
                    bot=bot,
                    symbol=symbol,
                    mark_price=last_price,
                    indicators=nlp_indicators,
                    candles_1m=nlp_candles,
                )
                nlp_action = nlp_result.get("action")

                if nlp_action in {"max_loss_stop", "max_loss_stop_failed"}:
                    bot = nlp_result.get("bot", bot)
                    bot = self._apply_nlp_max_loss_stop_state(
                        bot,
                        action=nlp_action,
                        last_price=last_price,
                        now_iso=now_iso,
                    )
                    if nlp_action == "max_loss_stop":
                        logger.warning(
                            "[%s] NLP Max Loss Stop cleanup confirmed; bot finalized as risk_stopped.",
                            symbol,
                        )
                    else:
                        logger.error(
                            "[%s] NLP Max Loss Stop cleanup is still pending; bot remains inactive until flat.",
                            symbol,
                        )
                    return bot

                if nlp_action == "inventory_reduce":
                    bot = nlp_result.get("bot", bot)
                    self.bot_storage.save_bot(bot)
                    # continue the cycle, NLP service may have placed market orders to reduce inventory

                if nlp_action in ("block_grid", "pause_grid", "breakout_flatten", "breakout_cooldown"):
                    bot["_nlp_lite_block_opening"] = True
                    logger.info(f"[{symbol}] NLP-lite active: {nlp_action} - blocking new neutral opening orders")
            except Exception as e:
                logger.warning("[%s] NLP-lite execution error: %s", symbol, e)

        # =============================================================================
        # MICRO-BIAS AWARENESS FOR NEUTRAL MODE
        # =============================================================================
        # Detect slight directional drift and set per-side skip flags.
        # Skip some ENTRY orders against the micro-trend to reduce inventory accumulation.
        if mode == "neutral":
            from config.strategy_config import (
                NEUTRAL_MICRO_BIAS_ENABLED,
                NEUTRAL_MICRO_BIAS_THRESHOLD,
                NEUTRAL_MICRO_BIAS_STRONG,
                MICRO_BIAS_SKIP_PCT_MODERATE,
                MICRO_BIAS_SKIP_PCT_STRONG,
                MICRO_BIAS_HYSTERESIS_CHECKS,
                MICRO_BIAS_CACHE_SECONDS,
            )

            # Clear previous cycle's skip flags
            bot["_micro_bias_skip_buy"] = False
            bot["_micro_bias_skip_sell"] = False
            bot["_micro_bias_score"] = 0.0

            if NEUTRAL_MICRO_BIAS_ENABLED and self.micro_bias_service is not None:
                try:
                    import random

                    micro_bias = self.micro_bias_service.calculate_bias(
                        bot=bot,
                        symbol=symbol,
                        threshold=NEUTRAL_MICRO_BIAS_THRESHOLD,
                        strong_threshold=NEUTRAL_MICRO_BIAS_STRONG,
                        skip_pct_moderate=MICRO_BIAS_SKIP_PCT_MODERATE,
                        skip_pct_strong=MICRO_BIAS_SKIP_PCT_STRONG,
                        hysteresis_checks=MICRO_BIAS_HYSTERESIS_CHECKS,
                        cache_seconds=MICRO_BIAS_CACHE_SECONDS,
                    )

                    bot["_micro_bias_score"] = micro_bias.get("score", 0.0)
                    bot["_micro_bias_direction"] = micro_bias.get("direction", "NEUTRAL")

                    if micro_bias.get("direction") == "BULLISH":
                        # Bullish drift - probabilistically skip Sell ENTRY orders
                        bot["_micro_bias_skip_sell"] = (
                            random.random() < micro_bias.get("skip_probability", 0.0)
                        )
                        bot["_micro_bias_skip_buy"] = False
                    elif micro_bias.get("direction") == "BEARISH":
                        # Bearish drift - probabilistically skip Buy ENTRY orders
                        bot["_micro_bias_skip_buy"] = (
                            random.random() < micro_bias.get("skip_probability", 0.0)
                        )
                        bot["_micro_bias_skip_sell"] = False

                    if bot.get("_micro_bias_skip_buy") or bot.get("_micro_bias_skip_sell"):
                        logger.debug(
                            "[%s] MICRO_BIAS (neutral) skip this cycle: skip_buy=%s skip_sell=%s "
                            "(direction=%s score=%.3f)",
                            symbol,
                            bot.get("_micro_bias_skip_buy"),
                            bot.get("_micro_bias_skip_sell"),
                            micro_bias.get("direction"),
                            micro_bias.get("score", 0.0),
                        )
                except Exception as mb_err:
                    logger.debug("[%s] Micro-bias calculation error: %s", symbol, mb_err)

        return None  # Continue cycle

    def _enforce_position_cap(
        self,
        bot: Dict[str, Any],
        symbol: str,
        mode: str,
        last_price: float,
        investment: float,
        leverage: float,
        buy_levels_needing_orders: List[float],
        sell_levels_needing_orders: List[float],
        buy_reduce_only: bool,
        sell_reduce_only: bool,
        existing_orders_with_ids: list,
        continuation_add_candidate_active: bool,
        capital_starved_opening_reason: Optional[str],
        current_order_count: int,
    ) -> Dict[str, Any]:
        """Enforce position size cap — skip/cancel opening orders when at max capacity.

        Returns dict with possibly-filtered level lists and cap state.
        """
        current_position_size = float(bot.get("current_position_size") or 0)
        current_position_side = bot.get("current_position_side")
        current_position_unrealized_pnl = float(bot.get("unrealized_pnl") or 0)
        position_cap_was_active = bool(bot.get("_watchdog_position_cap_active"))
        position_cap_suppressed_this_cycle = False

        bot["stall_overlay_position_cap_hit"] = False
        if MAX_POSITION_ENABLED and current_position_size > 0:
            max_position_pct = self._get_effective_max_position_cap_pct(
                bot,
                symbol=symbol,
                mode=mode,
                position_side=current_position_side,
                position_size=current_position_size,
                position_unrealized_pnl=current_position_unrealized_pnl,
                continuation_add_candidate_active=continuation_add_candidate_active,
                capital_starved_opening_reason=capital_starved_opening_reason,
            )
            max_notional = investment * leverage * max_position_pct
            current_notional = current_position_size * last_price

            if current_notional >= max_notional:
                bot["stall_overlay_position_cap_hit"] = True
                bot["_watchdog_position_cap_active"] = True
                position_cap_suppressed_this_cycle = True
                if not position_cap_was_active:
                    self._record_position_cap_transition_event(
                        bot,
                        event_type="position_cap_suppression_started",
                        symbol=symbol,
                        mode=mode,
                        current_notional=current_notional,
                        cap_notional=max_notional,
                        side=str(current_position_side or "").lower() or "unknown",
                    )
                self._record_position_cap_hit_event(
                    bot,
                    symbol=symbol,
                    mode=mode,
                    side=str(current_position_side or "").lower() or "unknown",
                    current_notional=current_notional,
                    cap_notional=max_notional,
                    current_position_size=current_position_size,
                    suppression_kind="add",
                    runtime_cap_info={
                        "current_order_count": current_order_count,
                        "opening_buy_candidates": len(
                            [b for b in buy_levels_needing_orders if not buy_reduce_only]
                        ),
                        "opening_sell_candidates": len(
                            [s for s in sell_levels_needing_orders if not sell_reduce_only]
                        ),
                    },
                )
                # Position already at or above cap - skip opening orders AND cancel existing ones
                if mode == "long" and current_position_side == "buy":
                    # Long mode with long position at cap - skip new buys
                    open_buys_count = len(
                        [b for b in buy_levels_needing_orders if not buy_reduce_only]
                    )
                    if open_buys_count > 0:
                        logger.warning(
                            f"[{symbol}] POSITION CAP: Current ${current_notional:.2f} >= max ${max_notional:.2f} "
                            f"({max_position_pct * 100:.0f}% of ${investment}x{leverage}). Skipping {open_buys_count} opening buys."
                        )
                        if not buy_reduce_only:
                            buy_levels_needing_orders = []

                    # Cancel existing buy orders that would increase position (non-reduce-only)
                    existing_opening_buys = [
                        (price, oid, side)
                        for price, oid, side, is_ro in existing_orders_with_ids
                        if side.lower() == "buy" and not is_ro
                    ]
                    if existing_opening_buys:
                        self._record_opening_orders_cancelled_by_cap_event(
                            bot,
                            symbol=symbol,
                            mode=mode,
                            side="buy",
                            cancelled_count=len(existing_opening_buys),
                            current_notional=current_notional,
                            cap_notional=max_notional,
                        )
                        logger.warning(
                            f"[{symbol}] POSITION CAP: Cancelling {len(existing_opening_buys)} existing buy orders to enforce cap"
                        )
                        for price, order_id, side in existing_opening_buys:
                            try:
                                cancel_result = self.client.cancel_order(
                                    symbol=symbol, order_id=order_id
                                )
                                if cancel_result.get("retCode") == 0:
                                    logger.info(
                                        f"[{symbol}] Cancelled buy order {order_id} at {price} (position cap)"
                                    )
                                else:
                                    logger.debug(
                                        f"[{symbol}] Cancel buy {order_id} response: {cancel_result.get('retMsg')}"
                                    )
                            except Exception as e:
                                logger.debug(
                                    f"[{symbol}] Failed to cancel buy {order_id}: {e}"
                                )

                elif mode == "short" and current_position_side == "sell":
                    # Short mode with short position at cap - skip new sells
                    open_sells_count = len(
                        [s for s in sell_levels_needing_orders if not sell_reduce_only]
                    )
                    if open_sells_count > 0:
                        logger.warning(
                            f"[{symbol}] POSITION CAP: Current ${current_notional:.2f} >= max ${max_notional:.2f} "
                            f"({max_position_pct * 100:.0f}% of ${investment}x{leverage}). Skipping {open_sells_count} opening sells."
                        )
                        if not sell_reduce_only:
                            sell_levels_needing_orders = []

                    # Cancel existing sell orders that would increase position (non-reduce-only)
                    existing_opening_sells = [
                        (price, oid, side)
                        for price, oid, side, is_ro in existing_orders_with_ids
                        if side.lower() == "sell" and not is_ro
                    ]
                    if existing_opening_sells:
                        self._record_opening_orders_cancelled_by_cap_event(
                            bot,
                            symbol=symbol,
                            mode=mode,
                            side="sell",
                            cancelled_count=len(existing_opening_sells),
                            current_notional=current_notional,
                            cap_notional=max_notional,
                        )
                        logger.warning(
                            f"[{symbol}] POSITION CAP: Cancelling {len(existing_opening_sells)} existing sell orders to enforce cap"
                        )
                        for price, order_id, side in existing_opening_sells:
                            try:
                                cancel_result = self.client.cancel_order(
                                    symbol=symbol, order_id=order_id
                                )
                                if cancel_result.get("retCode") == 0:
                                    logger.info(
                                        f"[{symbol}] Cancelled sell order {order_id} at {price} (position cap)"
                                    )
                                else:
                                    logger.debug(
                                        f"[{symbol}] Cancel sell {order_id} response: {cancel_result.get('retMsg')}"
                                    )
                            except Exception as e:
                                logger.debug(
                                    f"[{symbol}] Failed to cancel sell {order_id}: {e}"
                                )

                elif mode == "neutral":
                    # Neutral mode at cap - skip opening on the side that would increase position
                    if current_position_side == "buy" and not buy_reduce_only:
                        logger.warning(
                            f"[{symbol}] POSITION CAP (neutral): LONG ${current_notional:.2f} >= max ${max_notional:.2f}. "
                            f"Skipping opening buys, keeping reduce-only sells."
                        )
                        buy_levels_needing_orders = []

                        # Cancel existing buy orders
                        existing_opening_buys = [
                            (price, oid, side)
                            for price, oid, side, is_ro in existing_orders_with_ids
                            if side.lower() == "buy" and not is_ro
                        ]
                        if existing_opening_buys:
                            self._record_opening_orders_cancelled_by_cap_event(
                                bot,
                                symbol=symbol,
                                mode=mode,
                                side="buy",
                                cancelled_count=len(existing_opening_buys),
                                current_notional=current_notional,
                                cap_notional=max_notional,
                            )
                            logger.warning(
                                f"[{symbol}] POSITION CAP: Cancelling {len(existing_opening_buys)} existing buy orders"
                            )
                            for price, order_id, side in existing_opening_buys:
                                try:
                                    self.client.cancel_order(
                                        symbol=symbol, order_id=order_id
                                    )
                                except Exception:
                                    pass

                    elif current_position_side == "sell" and not sell_reduce_only:
                        logger.warning(
                            f"[{symbol}] POSITION CAP (neutral): SHORT ${current_notional:.2f} >= max ${max_notional:.2f}. "
                            f"Skipping opening sells, keeping reduce-only buys."
                        )
                        sell_levels_needing_orders = []

                        # Cancel existing sell orders
                        existing_opening_sells = [
                            (price, oid, side)
                            for price, oid, side, is_ro in existing_orders_with_ids
                            if side.lower() == "sell" and not is_ro
                        ]
                        if existing_opening_sells:
                            self._record_opening_orders_cancelled_by_cap_event(
                                bot,
                                symbol=symbol,
                                mode=mode,
                                side="sell",
                                cancelled_count=len(existing_opening_sells),
                                current_notional=current_notional,
                                cap_notional=max_notional,
                            )
                            logger.warning(
                                f"[{symbol}] POSITION CAP: Cancelling {len(existing_opening_sells)} existing sell orders"
                            )
                            for price, order_id, side in existing_opening_sells:
                                try:
                                    self.client.cancel_order(
                                        symbol=symbol, order_id=order_id
                                    )
                                except Exception:
                                    pass
            else:
                bot["_watchdog_position_cap_active"] = False
                if position_cap_was_active:
                    self._record_cap_pressure_cleared_event(
                        bot,
                        symbol=symbol,
                        mode=mode,
                        current_notional=current_notional,
                        cap_notional=max_notional,
                    )
                # Position below cap - log how much room remains
                room_left = max_notional - current_notional
                room_pct = (room_left / max_notional) * 100 if max_notional > 0 else 0
                if room_pct < 20:
                    logger.info(
                        f"[{symbol}] Position ${current_notional:.2f} / ${max_notional:.2f} "
                        f"({100 - room_pct:.1f}% used, ${room_left:.2f} room left)"
                    )

        return {
            "buy_levels_needing_orders": buy_levels_needing_orders,
            "sell_levels_needing_orders": sell_levels_needing_orders,
            "position_cap_suppressed_this_cycle": position_cap_suppressed_this_cycle,
        }

    def _close_opposite_positions(
        self, bot: Dict[str, Any], symbol: str, mode: str
    ) -> None:
        """
        Close positions that are opposite to the current trend/mode.
        - In long mode or uptrend: close any SHORT positions
        - In short mode or downtrend: close any LONG positions
        - In neutral mode: no action (allows both directions)

        This prevents holding positions against the detected trend.
        """
        bot_id = bot.get("id")
        range_mode = bot.get("range_mode", "fixed")

        # Neutral mode allows both directions
        if mode == "neutral":
            return

        # Skip closing opposite positions for long trailing bots
        # (allows holding through temporary reversals in DCA strategy)
        if mode == "long" and range_mode == "trailing":
            return

        try:
            positions_resp = self.client.get_positions(skip_cache=True)
            if not positions_resp.get("success"):
                return

            positions = positions_resp.get("data", {}).get("list", []) or []
            for pos in positions:
                if pos.get("symbol") != symbol:
                    continue

                pos_side = pos.get("side")  # "Buy" or "Sell"
                pos_size = self._safe_float(pos.get("size"), 0.0)

                if pos_size <= 0 or not pos_side:
                    continue

                should_close = False
                reason = ""

                # Check if position conflicts with mode
                if mode == "long" and pos_side == "Sell":
                    should_close = True
                    reason = f"Uptrend/Long mode detected but holding SHORT position ({pos_size} {symbol})"
                elif mode == "short" and pos_side == "Buy":
                    should_close = True
                    reason = f"Downtrend/Short mode detected but holding LONG position ({pos_size} {symbol})"

                if should_close:
                    # Close with market order
                    close_side = "Buy" if pos_side == "Sell" else "Sell"
                    logger.warning(f"[{symbol}] 🚨 {reason} - CLOSING IMMEDIATELY")

                    price = self._safe_float(
                        pos.get("markPrice"), None
                    ) or self._safe_float(pos.get("avgPrice"), None)
                    result = self._create_order_checked(
                        bot=bot,
                        symbol=symbol,
                        side=close_side,
                        qty=pos_size,
                        order_type="Market",
                        price=price,
                        reduce_only=True,
                        time_in_force="GTC",
                        order_link_id=self._build_close_order_link_id(bot_id, "TREV"),
                    )

                    if self._is_position_empty_close_result(result):
                        logger.info(
                            "[%s] Opposite position close skipped: %s leg already flat",
                            symbol,
                            pos_side,
                        )
                    elif result.get("success"):
                        logger.info(
                            f"[{symbol}] ✅ Successfully closed opposite position: {pos_side} {pos_size} {symbol}"
                        )
                    else:
                        self._hard_fail_close(
                            bot,
                            symbol,
                            "close_opposite_position",
                            result.get("error"),
                        )

        except Exception as exc:
            self._hard_fail_close(bot, symbol, "close_opposite_position_exception", exc)

    def _close_bot_symbol(
        self,
        bot: Dict[str, Any],
        hard_fail: bool = False,
        fail_reason: Optional[str] = None,
    ) -> bool:
        """
        Close all exposure (orders + position) for this bot's symbol as a global TP action.
        Best-effort by default; with hard_fail=True, disable trading if close fails.
        """
        bot_id = bot.get("id")
        symbol = bot.get("symbol")
        if not symbol:
            return False

        conflict = self._get_shared_symbol_conflict(
            bot,
            symbol,
            "symbol-wide close/cancel",
        )
        if conflict:
            if hard_fail:
                self._hard_fail_close(
                    bot,
                    symbol,
                    fail_reason or "shared_symbol_active_bots",
                    conflict,
                )
            return False

        # Cancel all open orders for this symbol with forceful verification
        try:
            cancel_result = self._force_cancel_all_orders(
                symbol,
                max_retries=3,
                bot=bot,
            )
            if cancel_result.get("success"):
                logger.info(f"TP close: Cancelled all orders for {symbol}")
            else:
                logger.warning(
                    f"TP close: Order cancellation incomplete for {symbol}: {cancel_result}"
                )
        except Exception as exc:
            logger.error("Failed to cancel orders for TP close on %s: %s", symbol, exc)

        # Try to close any open position via reduce-only market order
        try:
            positions_resp = self.client.get_positions(skip_cache=True)
            if not positions_resp.get("success"):
                error_msg = positions_resp.get("error", "positions_fetch_failed")
                reason = fail_reason or "close_bot_symbol"
                logger.error(
                    "Failed to fetch positions for TP close on %s (bot_id=%s, close_reason=%s): %s",
                    symbol,
                    bot.get("id"),
                    reason,
                    error_msg,
                )
                if hard_fail:
                    self._hard_fail_close(bot, symbol, reason, error_msg)
                return False

            positions = positions_resp.get("data", {}).get("list", []) or []
            success = True
            for pos in positions:
                if pos.get("symbol") != symbol:
                    continue
                side = pos.get("side")
                size = self._safe_float(pos.get("size"), 0.0)
                if not side or size <= 0:
                    continue

                # Opposite side for closing
                close_side = "Sell" if side.lower() == "buy" else "Buy"
                price = self._safe_float(
                    pos.get("markPrice"), None
                ) or self._safe_float(pos.get("avgPrice"), None)
                position_idx = int(pos.get("positionIdx", 0) or 0)
                close_order_link_id = self._get_full_close_attempt_order_link_id(
                    bot=bot,
                    symbol=symbol,
                    close_side=close_side,
                    position_idx=position_idx,
                    close_reason="TRND",
                )
                result = self._create_order_checked(
                    bot=bot,
                    symbol=symbol,
                    side=close_side,
                    qty=size,
                    order_type="Market",
                    price=price,
                    reduce_only=True,
                    time_in_force="GTC",
                    order_link_id=close_order_link_id,
                    position_idx=position_idx,
                )
                if self._is_position_empty_close_result(result):
                    logger.info(
                        "TP close: Position already flat for %s on %s",
                        side,
                        symbol,
                    )
                    self._clear_full_close_attempt_fence(
                        bot=bot,
                        symbol=symbol,
                        close_side=close_side,
                        position_idx=position_idx,
                    )
                elif result.get("success"):
                    logger.info(
                        f"TP close: Closed {side} position of {size} on {symbol}"
                    )
                elif self._is_ambiguous_order_result(result):
                    logger.warning(
                        "CLOSE_RETRY_NOT_SAFE symbol=%s bot_id=%s order_link_id=%s status=%s retry_safe=%s",
                        symbol,
                        bot.get("id"),
                        close_order_link_id,
                        result.get("status"),
                        result.get("retry_safe"),
                    )
                    success = False
                else:
                    error_msg = result.get("error", "close_failed")
                    reason = fail_reason or "close_bot_symbol"
                    logger.error(
                        "Failed to close position for TP on %s (bot_id=%s, close_reason=%s): %s",
                        symbol,
                        bot.get("id"),
                        reason,
                        error_msg,
                    )
                    success = False
                    if hard_fail:
                        self._hard_fail_close(bot, symbol, reason, error_msg)
            return success
        except Exception as exc:
            if isinstance(exc, RuntimeError):
                raise
            logger.error("Failed to close position for TP on %s: %s", symbol, exc)
            if hard_fail:
                reason = fail_reason or "close_bot_symbol"
                self._hard_fail_close(bot, symbol, reason, exc)
            return False

    def _get_effective_min_profit_pct(
        self, bot: Dict[str, Any], user_min_profit_pct: float
    ) -> float:
        fee_rate = bot.get("taker_fee_rate")
        if fee_rate is None:
            fee_rate = bot.get("fee_rate")
        fee_rate = self._safe_float(fee_rate, FAST_EXEC_TAKER_FEE_RATE)
        if fee_rate < 0:
            fee_rate = FAST_EXEC_TAKER_FEE_RATE

        slippage_buffer = self._safe_float(
            bot.get("fast_exec_slippage_buffer_pct"),
            FAST_EXEC_SLIPPAGE_BUFFER_PCT,
        )
        if slippage_buffer < 0:
            slippage_buffer = FAST_EXEC_SLIPPAGE_BUFFER_PCT

        return max(user_min_profit_pct, (2 * fee_rate) + slippage_buffer + FEE_AWARE_MIN_STEP_BUFFER_PCT)

    def _get_quick_profit_speed_adjustment(
        self,
        bot: Dict[str, Any],
        symbol: str,
        position: Dict[str, Any],
        fast_indicators: Dict[str, Any],
        min_profit: float,
        target_profit: float,
        close_pct: float,
    ) -> Dict[str, Any]:
        timing = self._track_position_timing(bot, symbol, position)
        age_sec = timing["age_sec"]
        unrealized_pnl = max(
            0.0,
            self._safe_float(position.get("unrealisedPnl"), 0.0),
        )
        atr_pct = max(0.0, self._safe_float((fast_indicators or {}).get("atr_pct"), 0.0))
        velocity_per_hour = abs(
            self._safe_float((fast_indicators or {}).get("price_velocity"), 0.0)
        )
        speed_per_min = (unrealized_pnl / max(age_sec, 1.0)) * 60.0 if age_sec > 0 else 0.0
        speed_ratio = 0.0
        if target_profit > 0:
            speed_ratio = (
                (unrealized_pnl / target_profit)
                * (
                    max(
                        1.0,
                        self._safe_float(
                            bot.get("quick_profit_fast_profit_window_seconds"),
                            QUICK_PROFIT_FAST_PROFIT_WINDOW_SECONDS,
                        ),
                    )
                    / max(age_sec, 1.0)
                )
            )

        bot["quick_profit_trade_age_sec"] = round(age_sec, 1)
        bot["quick_profit_profit_speed_per_min"] = round(speed_per_min, 4)
        bot["quick_profit_profit_speed_ratio"] = round(speed_ratio, 4)

        enabled = bool(
            bot.get(
                "quick_profit_profit_speed_enabled",
                QUICK_PROFIT_PROFIT_SPEED_ENABLED,
            )
        )
        if not enabled:
            bot["quick_profit_fast_profit_active"] = False
            return {
                "active": False,
                "adjusted_target_profit": target_profit,
                "adjusted_close_pct": close_pct,
                "age_sec": age_sec,
                "speed_ratio": speed_ratio,
                "speed_per_min": speed_per_min,
            }

        min_age = max(
            1.0,
            self._safe_float(
                bot.get("quick_profit_fast_profit_min_trade_age_seconds"),
                QUICK_PROFIT_FAST_PROFIT_MIN_TRADE_AGE_SECONDS,
            ),
        )
        window_seconds = max(
            min_age,
            self._safe_float(
                bot.get("quick_profit_fast_profit_window_seconds"),
                QUICK_PROFIT_FAST_PROFIT_WINDOW_SECONDS,
            ),
        )
        min_usdt = max(
            0.0,
            self._safe_float(
                bot.get("quick_profit_fast_profit_min_usdt"),
                QUICK_PROFIT_FAST_PROFIT_MIN_USDT,
            ),
        )
        threshold_multiplier = max(
            1.0,
            self._safe_float(
                bot.get("quick_profit_fast_profit_threshold_multiplier"),
                QUICK_PROFIT_FAST_PROFIT_THRESHOLD_MULTIPLIER,
            ),
        )
        volatility_threshold = max(
            0.0,
            self._safe_float(
                bot.get("quick_profit_fast_profit_volatility_atr_pct"),
                QUICK_PROFIT_FAST_PROFIT_VOLATILITY_ATR_PCT,
            ),
        )
        target_multiplier = min(
            1.0,
            max(
                0.5,
                self._safe_float(
                    bot.get("quick_profit_fast_profit_target_multiplier"),
                    QUICK_PROFIT_FAST_PROFIT_TARGET_MULTIPLIER,
                ),
            ),
        )
        close_pct_bonus = max(
            0.0,
            self._safe_float(
                bot.get("quick_profit_fast_profit_close_pct_bonus"),
                QUICK_PROFIT_FAST_PROFIT_CLOSE_PCT_BONUS,
            ),
        )
        volatility_active = (
            atr_pct >= volatility_threshold
            or velocity_per_hour >= (AUTO_PILOT_VELOCITY_REFERENCE_PER_HOUR * 0.5)
        )
        fast_profit_active = (
            age_sec >= min_age
            and age_sec <= window_seconds
            and unrealized_pnl >= max(min_profit, min_usdt)
            and volatility_active
            and speed_ratio >= threshold_multiplier
        )
        bot["quick_profit_fast_profit_active"] = fast_profit_active

        adjusted_target_profit = target_profit
        adjusted_close_pct = close_pct
        if fast_profit_active:
            adjusted_target_profit = max(min_profit, target_profit * target_multiplier)
            adjusted_close_pct = min(0.85, close_pct + close_pct_bonus)

        return {
            "active": fast_profit_active,
            "adjusted_target_profit": adjusted_target_profit,
            "adjusted_close_pct": adjusted_close_pct,
            "age_sec": age_sec,
            "speed_ratio": speed_ratio,
            "speed_per_min": speed_per_min,
        }

    def _get_profit_lock_fast_arm_context(
        self,
        bot: Dict[str, Any],
        symbol: str,
        position: Dict[str, Any],
        atr_pct: float,
        velocity_per_hour: float,
        peak_pct: float,
        arm_threshold: float,
        profit_pct: float,
    ) -> Dict[str, Any]:
        timing = self._track_position_timing(bot, symbol, position)
        age_sec = timing["age_sec"]
        velocity_per_hour = abs(self._safe_float(velocity_per_hour, 0.0))

        speed_ratio = 0.0
        if arm_threshold > 0:
            window_seconds = max(
                1.0,
                self._safe_float(
                    bot.get("profit_lock_fast_arm_window_seconds"),
                    PROFIT_LOCK_FAST_ARM_WINDOW_SECONDS,
                ),
            )
            speed_ratio = (peak_pct / arm_threshold) * (window_seconds / max(age_sec, 1.0))
        bot["profit_lock_trade_age_sec"] = round(age_sec, 1)
        bot["profit_lock_profit_speed_ratio"] = round(speed_ratio, 4)

        enabled = bool(
            bot.get("profit_lock_fast_arm_enabled", PROFIT_LOCK_FAST_ARM_ENABLED)
        )
        if not enabled:
            bot["profit_lock_fast_arm_active"] = False
            return {
                "active": False,
                "arm_threshold": arm_threshold,
                "age_sec": age_sec,
                "speed_ratio": speed_ratio,
            }

        min_age = max(
            1.0,
            self._safe_float(
                bot.get("profit_lock_fast_arm_min_trade_age_seconds"),
                PROFIT_LOCK_FAST_ARM_MIN_TRADE_AGE_SECONDS,
            ),
        )
        window_seconds = max(
            min_age,
            self._safe_float(
                bot.get("profit_lock_fast_arm_window_seconds"),
                PROFIT_LOCK_FAST_ARM_WINDOW_SECONDS,
            ),
        )
        min_profit_pct = max(
            0.0,
            self._safe_float(
                bot.get("profit_lock_fast_arm_min_profit_pct"),
                PROFIT_LOCK_FAST_ARM_MIN_PROFIT_PCT,
            ),
        )
        threshold_multiplier = max(
            1.0,
            self._safe_float(
                bot.get("profit_lock_fast_arm_threshold_multiplier"),
                PROFIT_LOCK_FAST_ARM_THRESHOLD_MULTIPLIER,
            ),
        )
        arm_multiplier = min(
            1.0,
            max(
                0.5,
                self._safe_float(
                    bot.get("profit_lock_fast_arm_arm_multiplier"),
                    PROFIT_LOCK_FAST_ARM_ARM_MULTIPLIER,
                ),
            ),
        )
        volatility_threshold = max(
            0.0,
            self._safe_float(
                bot.get("profit_lock_fast_arm_volatility_atr_pct"),
                PROFIT_LOCK_FAST_ARM_VOLATILITY_ATR_PCT,
            ),
        )
        volatility_active = (
            atr_pct >= volatility_threshold
            or velocity_per_hour >= (AUTO_PILOT_VELOCITY_REFERENCE_PER_HOUR * 0.5)
        )
        fast_arm_active = (
            age_sec >= min_age
            and age_sec <= window_seconds
            and profit_pct >= min_profit_pct
            and peak_pct >= min_profit_pct
            and volatility_active
            and speed_ratio >= threshold_multiplier
        )
        bot["profit_lock_fast_arm_active"] = fast_arm_active
        adjusted_arm_threshold = arm_threshold
        if fast_arm_active:
            adjusted_arm_threshold = max(min_profit_pct, arm_threshold * arm_multiplier)

        return {
            "active": fast_arm_active,
            "arm_threshold": adjusted_arm_threshold,
            "age_sec": age_sec,
            "speed_ratio": speed_ratio,
        }

    def _handle_global_unrealized_tp(
        self,
        bot: Dict[str, Any],
        symbol: str,
        unrealized_pnl: float,
        now_iso: str,
    ) -> None:
        """
        Close position when global unrealized TP is hit, but keep bot running.
        Uses full close (cancel orders + reduce-only market), then verifies.
        """
        logger.info(
            "[%s] Global unrealized TP hit: pnl=%.4f >= %.4f. Closing position, bot continues.",
            symbol,
            unrealized_pnl,
            GLOBAL_UNREALIZED_TP_USD,
        )

        close_success = self._close_bot_symbol(
            bot,
            hard_fail=False,
            fail_reason="global_unrealized_tp",
        )

        # Verify position is actually closed; retry once if needed.
        try:
            positions_resp = self.client.get_positions()
            if positions_resp.get("success"):
                positions = positions_resp.get("data", {}).get("list", []) or []
                still_open = False
                for pos in positions:
                    if pos.get("symbol") == symbol:
                        size = self._safe_float(pos.get("size"), 0.0)
                        if size > 0:
                            still_open = True
                            break
                if still_open:
                    logger.warning(
                        "[%s] Global unrealized TP close incomplete, retrying market close.",
                        symbol,
                    )
                    close_success = self._close_position_market(symbol, bot=bot)
        except Exception as e:
            logger.debug("[%s] Global unrealized TP verify failed: %s", symbol, e)

        if close_success:
            bot["last_unrealized_tp_at"] = now_iso
            bot["last_unrealized_tp_usdt"] = unrealized_pnl
            self.bot_storage.save_bot(bot)
        else:
            logger.error(
                "[%s] Global unrealized TP close failed. Position may still be open.",
                symbol,
            )

    def _log_fast_exec_skip(
        self,
        bot: Dict[str, Any],
        symbol: str,
        reason: str,
        details: str,
    ) -> None:
        now = self.client._get_now_ts()
        log_ts = bot.get("_fast_exec_log_ts") or {}
        if not isinstance(log_ts, dict):
            log_ts = {}
        last_ts = log_ts.get(reason, 0)
        if now - last_ts < FAST_EXEC_LOG_COOLDOWN_SEC:
            bot["_fast_exec_log_ts"] = log_ts
            return
        log_ts[reason] = now
        bot["_fast_exec_log_ts"] = log_ts
        logger.info("[%s] Fast execution skipped (%s): %s", symbol, reason, details)

    def _classify_regime_snapshot(self, indicators: Dict[str, Any]) -> str:
        ema_slope = indicators.get("ema_slope")
        adx = indicators.get("adx")
        rsi = indicators.get("rsi")
        bbw_pct = indicators.get("bbw_pct")

        if (
            ema_slope is not None
            and adx is not None
            and rsi is not None
            and adx >= ADX_TREND_MIN
        ):
            if ema_slope > 0 and rsi >= RSI_UP_FAST:
                return "UP"
            if ema_slope < 0 and rsi <= RSI_DOWN_FAST:
                return "DOWN"

        if (
            adx is not None
            and adx <= ADX_CHOP_MAX
            and bbw_pct is not None
            and bbw_pct <= REGIME_BBW_LOW
        ):
            return "SIDEWAYS"

        return "SIDEWAYS"

    def _update_multi_tf_regime(
        self,
        bot: Dict[str, Any],
        symbol: str,
        primary_indicators: Dict[str, Any],
        secondary_indicators: Dict[str, Any],
    ) -> None:
        primary = self._classify_regime_snapshot(primary_indicators)
        secondary = self._classify_regime_snapshot(secondary_indicators)

        if primary in ("UP", "DOWN") and secondary == primary:
            confidence = "high"
        elif primary in ("UP", "DOWN") and secondary == "SIDEWAYS":
            confidence = "medium"
        elif primary == "SIDEWAYS" and secondary in ("UP", "DOWN"):
            confidence = "low"
        else:
            confidence = "low"

        effective = primary
        now = self.client._get_now_ts()
        last_effective = bot.get("regime_effective")
        last_change = self._safe_float(bot.get("regime_last_change_ts"), 0.0)

        if last_effective and effective != last_effective:
            if now - last_change < REGIME_HYSTERESIS_SEC:
                effective = last_effective
                confidence = "locked"
            else:
                bot["regime_last_change_ts"] = now
        elif effective != last_effective:
            bot["regime_last_change_ts"] = now

        bot["regime_primary"] = primary
        bot["regime_secondary"] = secondary
        bot["regime_effective"] = effective
        bot["regime_confidence"] = confidence

    def _clear_profit_protection_runtime_state(
        self,
        bot: Optional[Dict[str, Any]],
        *,
        clear_history: bool = False,
    ) -> None:
        if not isinstance(bot, dict):
            return
        bot.pop("profit_protection_advisory", None)
        bot.pop("profit_protection_mode", None)
        bot.pop("profit_protection_decision", None)
        bot.pop("profit_protection_reason_family", None)
        bot.pop("profit_protection_wait_justified", None)
        bot.pop("profit_protection_actionable", None)
        bot.pop("profit_protection_armed", None)
        bot.pop("profit_protection_blocked", None)
        bot.pop("profit_protection_blocked_reason", None)
        bot.pop("profit_protection_blocked_detail", None)
        bot.pop("profit_protection_current_profit_pct", None)
        bot.pop("profit_protection_peak_profit_pct", None)
        bot.pop("profit_protection_giveback_pct", None)
        bot.pop("profit_protection_giveback_threshold_pct", None)
        bot.pop("profit_protection_shadow_status", None)
        bot.pop("_profit_protection_state", None)
        if clear_history:
            bot.pop("profit_protection_shadow", None)
            bot.pop("profit_protection_last_action", None)
            bot.pop("profit_protection_last_action_at", None)

    def _record_trade_forensic_profit_protection_event(
        self,
        *,
        bot: Optional[Dict[str, Any]],
        symbol: str,
        mode: str,
        position_side: str,
        event_type: str,
        event_status: str,
        payload: Optional[Dict[str, Any]] = None,
    ) -> None:
        service = getattr(self, "trade_forensics_service", None)
        if service is None or not isinstance(bot, dict):
            return
        compact_exit = self._compact_profit_protection_payload(payload) or dict(payload or {})
        compact_shadow = self._compact_profit_protection_shadow_payload(
            bot.get("profit_protection_shadow")
        )
        if compact_shadow:
            compact_exit["shadow"] = compact_shadow
        service.record_event(
            {
                "event_type": event_type,
                "event_status": event_status,
                "forensic_decision_id": bot.get("forensic_active_decision_id"),
                "trade_context_id": bot.get("forensic_active_trade_context_id"),
                "bot_id": bot.get("id"),
                "symbol": symbol,
                "mode": mode,
                "profile": bot.get("profile"),
                "side": position_side,
                "decision_type": bot.get("forensic_active_decision_type")
                or "position_management",
                "linkage_method": (
                    "direct_runtime"
                    if bot.get("forensic_active_trade_context_id")
                    or bot.get("forensic_active_decision_id")
                    else "bot_symbol_only"
                ),
                "attribution_status": (
                    "linked"
                    if bot.get("forensic_active_trade_context_id")
                    or bot.get("forensic_active_decision_id")
                    else "unresolved"
                ),
                "exit": compact_exit,
            },
            dedupe_key=(
                f"{event_type}:{bot.get('id')}:{event_status}:"
                f"{compact_exit.get('decision') or compact_exit.get('result') or compact_exit.get('reason_family')}"
            ),
            dedupe_ttl=30.0,
        )

    def _emit_profit_protection_watchdog(
        self,
        *,
        bot: Optional[Dict[str, Any]],
        symbol: str,
        mode: str,
        reason: str,
        severity: str,
        payload: Optional[Dict[str, Any]] = None,
    ) -> None:
        watchdog_service = self._get_watchdog_diagnostics_service()
        if watchdog_service is None:
            return
        metrics = self._compact_profit_protection_payload(payload) or {}
        decision = str(metrics.get("decision") or "").strip().lower()
        if decision:
            metrics["decision"] = decision
        watchdog_service.emit(
            watchdog_type="profit_protection",
            severity=severity,
            reason=reason,
            bot=bot,
            symbol=symbol,
            mode=mode,
            throttle_key=f"profit_protection:{(bot or {}).get('id')}:{reason}",
            compact_metrics=metrics,
            suggested_action=(
                "Review the exit advisory before enabling autonomous profit protection."
            ),
        )

    def _record_profit_protection_event(
        self,
        bot: Optional[Dict[str, Any]],
        *,
        symbol: str,
        mode: str,
        event_type: str,
        position_side: str,
        severity: str = "INFO",
        throttle_key: Optional[str] = None,
        payload: Optional[Dict[str, Any]] = None,
        emit_watchdog_reason: Optional[str] = None,
    ) -> None:
        compact_payload = self._compact_profit_protection_payload(payload) or {}
        shadow_payload = self._compact_profit_protection_shadow_payload(
            bot.get("profit_protection_shadow") if isinstance(bot, dict) else None
        )
        self._record_watchdog_operational_event(
            bot,
            event_type=event_type,
            severity=severity,
            symbol=symbol,
            mode=mode,
            throttle_key=throttle_key
            or f"{event_type}:{(bot or {}).get('id')}:{position_side}",
            throttle_sec=0 if severity == "INFO" else 30,
            position_side=position_side,
            profit_protection=compact_payload or None,
            profit_protection_shadow=shadow_payload or None,
        )
        self._record_trade_forensic_profit_protection_event(
            bot=bot,
            symbol=symbol,
            mode=mode,
            position_side=position_side,
            event_type="exit_advisory",
            event_status=event_type,
            payload=compact_payload,
        )
        if emit_watchdog_reason:
            self._emit_profit_protection_watchdog(
                bot=bot,
                symbol=symbol,
                mode=mode,
                reason=emit_watchdog_reason,
                severity=severity,
                payload=compact_payload,
            )

    @staticmethod
    def _classify_profit_protection_shadow_outcome(
        shadow: Dict[str, Any],
        *,
        saved_threshold_pct: float,
        trend_cut_pct: float,
        premature_pct: float,
    ) -> Dict[str, Any]:
        trigger_profit_pct = abs(
            float(shadow.get("trigger_profit_pct") or 0.0)
        )
        max_profit_pct = abs(
            float(shadow.get("max_profit_pct_after_trigger") or trigger_profit_pct)
        )
        min_profit_pct = abs(
            float(shadow.get("min_profit_pct_after_trigger") or trigger_profit_pct)
        )
        saved_giveback_pct = max(trigger_profit_pct - min_profit_pct, 0.0)
        trend_cut_realized = max(max_profit_pct - trigger_profit_pct, 0.0)
        if saved_giveback_pct >= max(saved_threshold_pct, 0.0):
            return {
                "outcome_kind": "saved_giveback",
                "event_type": "profit_lock_saved_giveback",
                "result": "saved_giveback",
                "saved_giveback_pct": round(saved_giveback_pct, 6),
                "trend_cut_pct": round(trend_cut_realized, 6),
                "premature_regret_pct": round(
                    max(trend_cut_realized - saved_giveback_pct, 0.0),
                    6,
                ),
            }
        if trend_cut_realized >= max(trend_cut_pct, 0.0):
            return {
                "outcome_kind": "trend_cut",
                "event_type": "profit_lock_trend_cut",
                "result": "trend_cut",
                "saved_giveback_pct": round(saved_giveback_pct, 6),
                "trend_cut_pct": round(trend_cut_realized, 6),
                "premature_regret_pct": round(trend_cut_realized, 6),
            }
        if trend_cut_realized >= max(premature_pct, 0.0):
            return {
                "outcome_kind": "premature",
                "event_type": "profit_lock_premature",
                "result": "premature",
                "saved_giveback_pct": round(saved_giveback_pct, 6),
                "trend_cut_pct": round(trend_cut_realized, 6),
                "premature_regret_pct": round(trend_cut_realized, 6),
            }
        return {
            "outcome_kind": "neutral",
            "event_type": None,
            "result": "neutral",
            "saved_giveback_pct": round(saved_giveback_pct, 6),
            "trend_cut_pct": round(trend_cut_realized, 6),
            "premature_regret_pct": round(
                max(trend_cut_realized - saved_giveback_pct, 0.0),
                6,
            ),
        }

    def _finalize_profit_protection_shadow_state(
        self,
        bot: Optional[Dict[str, Any]],
        *,
        symbol: str,
        mode: str,
        position_side: Optional[str] = None,
        resolution_reason: str,
    ) -> None:
        if not isinstance(bot, dict):
            return
        shadow = dict(bot.get("profit_protection_shadow") or {})
        if not shadow or not shadow.get("active"):
            return
        service = getattr(self, "adaptive_profit_protection_service", None) or AdaptiveProfitProtectionService()
        settings = service.resolve_settings(bot)
        outcome = self._classify_profit_protection_shadow_outcome(
            shadow,
            saved_threshold_pct=settings["shadow_saved_giveback_pct"],
            trend_cut_pct=settings["shadow_trend_cut_pct"],
            premature_pct=settings["shadow_premature_pct"],
        )
        shadow["active"] = False
        shadow["status"] = "resolved"
        shadow["resolved_at"] = datetime.now(timezone.utc).isoformat()
        shadow["resolution_reason"] = resolution_reason
        shadow["result"] = outcome["result"]
        shadow["outcome_kind"] = outcome["outcome_kind"]
        shadow["saved_giveback_pct"] = outcome["saved_giveback_pct"]
        shadow["trend_cut_pct"] = outcome["trend_cut_pct"]
        shadow["premature_regret_pct"] = outcome["premature_regret_pct"]
        bot["profit_protection_shadow"] = shadow
        bot["profit_protection_shadow_status"] = shadow["status"]
        if outcome.get("event_type"):
            payload = self._compact_profit_protection_payload(
                bot.get("profit_protection_advisory")
            ) or {}
            payload["shadow_status"] = shadow.get("status")
            payload["shadow_result"] = shadow.get("result")
            self._record_profit_protection_event(
                bot,
                symbol=symbol,
                mode=mode,
                event_type=outcome["event_type"],
                position_side=position_side or str(shadow.get("position_side") or ""),
                severity="INFO",
                throttle_key=f"{outcome['event_type']}:{bot.get('id')}:{shadow.get('triggered_at')}",
                payload=payload,
                emit_watchdog_reason=outcome["outcome_kind"],
            )

    def _update_profit_protection_shadow_state(
        self,
        bot: Optional[Dict[str, Any]],
        *,
        symbol: str,
        mode: str,
        position_side: str,
        advisory: Dict[str, Any],
        now_ts: float,
        action_executed: bool,
    ) -> None:
        if not isinstance(bot, dict):
            return
        if advisory.get("mode") != "shadow":
            shadow = dict(bot.get("profit_protection_shadow") or {})
            if shadow.get("active"):
                self._finalize_profit_protection_shadow_state(
                    bot,
                    symbol=symbol,
                    mode=mode,
                    position_side=position_side,
                    resolution_reason="shadow_mode_disabled",
                )
            return
        if not advisory.get("settings", {}).get("shadow_eval_enabled", True):
            return
        shadow = dict(bot.get("profit_protection_shadow") or {})
        if shadow.get("position_side") != position_side:
            shadow = {}
        current_profit_pct = self._safe_float(advisory.get("current_profit_pct"), 0.0) or 0.0
        if shadow.get("active"):
            shadow["max_profit_pct_after_trigger"] = round(
                max(
                    self._safe_float(shadow.get("max_profit_pct_after_trigger"), current_profit_pct)
                    or current_profit_pct,
                    current_profit_pct,
                ),
                6,
            )
            shadow["min_profit_pct_after_trigger"] = round(
                min(
                    self._safe_float(shadow.get("min_profit_pct_after_trigger"), current_profit_pct)
                    or current_profit_pct,
                    current_profit_pct,
                ),
                6,
            )
            bot["profit_protection_shadow"] = shadow
            outcome = self._classify_profit_protection_shadow_outcome(
                shadow,
                saved_threshold_pct=self._safe_float(
                    advisory.get("shadow_saved_giveback_pct"), 0.0
                )
                or 0.0,
                trend_cut_pct=self._safe_float(
                    advisory.get("shadow_trend_cut_pct"), 0.0
                )
                or 0.0,
                premature_pct=self._safe_float(
                    advisory.get("shadow_premature_pct"), 0.0
                )
                or 0.0,
            )
            if outcome["outcome_kind"] in {"saved_giveback", "trend_cut", "premature"}:
                self._finalize_profit_protection_shadow_state(
                    bot,
                    symbol=symbol,
                    mode=mode,
                    position_side=position_side,
                    resolution_reason=outcome["outcome_kind"],
                )
            return
        if action_executed or not advisory.get("actionable"):
            return
        shadow = {
            "active": True,
            "status": "triggered",
            "position_side": position_side,
            "decision": advisory.get("decision"),
            "reason_family": advisory.get("reason_family"),
            "triggered_at": datetime.now(timezone.utc).isoformat(),
            "trigger_profit_pct": round(current_profit_pct, 6),
            "trigger_peak_profit_pct": round(
                self._safe_float(advisory.get("peak_profit_pct"), current_profit_pct)
                or current_profit_pct,
                6,
            ),
            "trigger_profit_usdt": round(
                self._safe_float(advisory.get("current_profit_usdt"), 0.0) or 0.0,
                6,
            ),
            "giveback_threshold_pct": round(
                self._safe_float(advisory.get("giveback_threshold_pct"), 0.0) or 0.0,
                6,
            ),
            "max_profit_pct_after_trigger": round(current_profit_pct, 6),
            "min_profit_pct_after_trigger": round(current_profit_pct, 6),
            "last_trigger_ts": now_ts,
        }
        bot["profit_protection_shadow"] = shadow
        bot["profit_protection_shadow_status"] = "triggered"
        payload = dict(self._compact_profit_protection_payload(advisory) or {})
        payload["shadow_status"] = "triggered"
        self._record_profit_protection_event(
            bot,
            symbol=symbol,
            mode=mode,
            event_type="profit_lock_shadow_triggered",
            position_side=position_side,
            severity="INFO",
            throttle_key=f"profit_lock_shadow_triggered:{bot.get('id')}:{position_side}",
            payload=payload,
            emit_watchdog_reason="shadow_triggered",
        )

    def _run_adaptive_profit_protection_layer(
        self,
        *,
        bot: Dict[str, Any],
        symbol: str,
        mode: str,
        position: Dict[str, Any],
        last_price: float,
        exec_indicators: Optional[Dict[str, Any]],
        profit_pct: float,
        peak_profit_pct: float,
    ) -> Dict[str, Any]:
        advisory_service = getattr(self, "adaptive_profit_protection_service", None) or AdaptiveProfitProtectionService()
        position_side = str(position.get("side") or "").strip()
        current_profit_usdt = self._safe_float(position.get("unrealisedPnl"), None)
        if current_profit_usdt is None:
            position_notional = self._safe_float(
                position.get("positionValue"),
                abs(
                    self._safe_float(position.get("size"), 0.0)
                    * self._safe_float(last_price, 0.0)
                ),
            )
            current_profit_usdt = (position_notional or 0.0) * max(profit_pct, 0.0)
        prior_state = dict(bot.get("_profit_protection_state") or {})
        advisory = advisory_service.evaluate(
            bot=bot,
            position_side=position_side,
            current_profit_pct=profit_pct,
            current_profit_usdt=current_profit_usdt or 0.0,
            peak_profit_pct=peak_profit_pct,
            indicators=exec_indicators or {},
            regime_effective=bot.get("regime_effective"),
            regime_confidence=bot.get("regime_confidence"),
            previous_state=prior_state,
        )
        state = dict(prior_state)
        if state.get("position_side") != position_side:
            state = {}
        state["position_side"] = position_side
        state["last_seen_ts"] = self.client._get_now_ts()
        previous_decision = str(state.get("last_decision") or "").strip().lower()
        previous_reason = str(state.get("last_reason_family") or "").strip().lower()
        previous_armed = bool(state.get("armed"))

        blocker = None
        if bot.get("status") == "stop_cleanup_pending" or bool(bot.get("stop_cleanup_pending")):
            blocker = {
                "reason": "stop_cleanup_pending",
                "detail": "Stop cleanup is still pending, so profit protection stays inactive.",
            }
        else:
            blocker = self._get_exchange_truth_opening_blocker(bot)
        if blocker is not None:
            advisory["blocked"] = True
            advisory["blocked_reason"] = blocker.get("reason")
            advisory["blocked_detail"] = blocker.get("detail")
            advisory["actionable"] = False
        else:
            advisory["blocked"] = False

        now_iso = datetime.now(timezone.utc).isoformat()
        advisory["updated_at"] = now_iso
        if not advisory.get("enabled"):
            self._clear_profit_protection_runtime_state(bot)
            return {"advisory": advisory, "action_executed": False}

        bot["profit_protection_advisory"] = self._compact_profit_protection_payload(advisory)
        bot["profit_protection_mode"] = advisory.get("mode")
        bot["profit_protection_decision"] = advisory.get("decision")
        bot["profit_protection_reason_family"] = advisory.get("reason_family")
        bot["profit_protection_wait_justified"] = advisory.get("wait_justified")
        bot["profit_protection_actionable"] = bool(advisory.get("actionable"))
        bot["profit_protection_armed"] = bool(advisory.get("armed"))
        bot["profit_protection_blocked"] = bool(advisory.get("blocked"))
        bot["profit_protection_blocked_reason"] = advisory.get("blocked_reason")
        bot["profit_protection_blocked_detail"] = advisory.get("blocked_detail")
        bot["profit_protection_current_profit_pct"] = advisory.get("current_profit_pct")
        bot["profit_protection_peak_profit_pct"] = advisory.get("peak_profit_pct")
        bot["profit_protection_giveback_pct"] = advisory.get("giveback_pct")
        bot["profit_protection_giveback_threshold_pct"] = advisory.get("giveback_threshold_pct")

        if advisory.get("armed") and not previous_armed and not advisory.get("blocked"):
            self._record_profit_protection_event(
                bot,
                symbol=symbol,
                mode=mode,
                event_type="profit_protection_armed",
                position_side=position_side,
                payload=advisory,
            )
        elif previous_armed and (not advisory.get("armed") or advisory.get("blocked")):
            advisory["shadow_status"] = bot.get("profit_protection_shadow_status")
            self._record_profit_protection_event(
                bot,
                symbol=symbol,
                mode=mode,
                event_type="profit_protection_disarmed",
                position_side=position_side,
                payload=advisory,
            )
            state["last_disarmed_ts"] = self.client._get_now_ts()
            state["last_disarmed_profit_pct"] = advisory.get("current_profit_pct")

        decision_changed = (
            advisory.get("decision") != previous_decision
            or str(advisory.get("reason_family") or "").strip().lower() != previous_reason
        )
        if decision_changed and not advisory.get("blocked"):
            event_type = {
                "wait": "exit_advisory_wait",
                "watch_closely": "exit_advisory_watch",
                "take_partial": "exit_advisory_partial",
                "exit_now": "exit_advisory_exit",
            }.get(str(advisory.get("decision") or "").strip().lower())
            watchdog_reason = {
                "take_partial": "take_partial_advised",
                "exit_now": "exit_now_advised",
            }.get(str(advisory.get("decision") or "").strip().lower())
            if event_type:
                self._record_profit_protection_event(
                    bot,
                    symbol=symbol,
                    mode=mode,
                    event_type=event_type,
                    position_side=position_side,
                    severity="WARN"
                    if advisory.get("decision") == "exit_now"
                    else "INFO",
                    payload=advisory,
                    emit_watchdog_reason=watchdog_reason,
                )

        action_executed = False
        live_action = None
        now_ts = self.client._get_now_ts()
        cooldown_sec = self._safe_float(
            ((advisory.get("settings") or {}).get("cooldown_sec")),
            0.0,
        ) or 0.0
        last_action_ts = self._safe_float(state.get("last_action_ts"), 0.0) or 0.0
        live_mode = str(advisory.get("mode") or "").strip().lower()
        live_allowed = (
            live_mode in {"partial_live", "full_live"}
            and not advisory.get("blocked")
            and bool(advisory.get("actionable"))
            and now_ts - last_action_ts >= cooldown_sec
        )
        if live_allowed:
            pos_size = self._safe_float(position.get("size"), 0.0) or 0.0
            close_side = "Sell" if position_side == "Buy" else "Buy"
            raw_fraction = self._safe_float(advisory.get("partial_fraction"), 0.0) or 0.0
            should_full_close = live_mode == "full_live" and advisory.get("decision") == "exit_now"
            close_qty = pos_size if should_full_close else pos_size * raw_fraction
            close_reason = (
                "profit_protection_full"
                if should_full_close
                else "profit_protection_partial"
            )
            order_link_id = self._build_close_order_link_id(
                bot.get("id"),
                "PPEX" if should_full_close else "PPAR",
            )
            position_idx = self._resolve_position_idx(bot, symbol, close_side, True)
            result = self._create_order_checked(
                bot=bot,
                symbol=symbol,
                side=close_side,
                qty=close_qty,
                order_type="Market",
                price=last_price,
                reduce_only=True,
                time_in_force="GTC",
                order_link_id=order_link_id,
                position_idx=position_idx,
                diagnostic_context={
                    "ownership_action": close_reason,
                    "close_reason": close_reason,
                },
            )
            if self._is_position_empty_close_result(result):
                action_executed = True
                live_action = "position_empty"
            elif result.get("retCode") == 0 or result.get("success"):
                action_executed = True
                live_action = "full_close" if should_full_close else "partial_close"
                state["last_action_ts"] = now_ts
                bot["profit_protection_last_action"] = close_reason
                bot["profit_protection_last_action_at"] = now_iso
                advisory["last_action"] = close_reason
                advisory["last_action_at"] = now_iso
                # Clear capital-starved block after profit protection close
                # so the bot can re-enter with fresh orders on the next cycle.
                bot.pop("_capital_starved_block_opening_orders", None)
                bot.pop("_small_capital_block_opening_orders", None)
                # Activate pullback watch on exhaustion-driven full close
                if (
                    should_full_close
                    and str(advisory.get("reason_family") or "").lower() == "exhaustion_risk"
                ):
                    self._maybe_activate_pullback_watch(
                        bot, exit_reason="profit_protection_exit", exit_price=last_price,
                    )
                self._record_profit_protection_event(
                    bot,
                    symbol=symbol,
                    mode=mode,
                    event_type=(
                        "profit_lock_full_executed"
                        if should_full_close
                        else "profit_lock_partial_executed"
                    ),
                    position_side=position_side,
                    severity="WARN" if should_full_close else "INFO",
                    throttle_key=f"profit_lock_live:{bot.get('id')}:{now_iso}",
                    payload=advisory,
                    emit_watchdog_reason=(
                        "live_full_executed"
                        if should_full_close
                        else "live_partial_executed"
                    ),
                )

        state["armed"] = bool(advisory.get("armed"))
        state["last_decision"] = advisory.get("decision")
        state["last_reason_family"] = advisory.get("reason_family")
        state["last_updated_at"] = now_iso
        bot["_profit_protection_state"] = state
        if bot.get("profit_protection_shadow"):
            bot["profit_protection_shadow_status"] = (
                bot.get("profit_protection_shadow") or {}
            ).get("status")
        self._update_profit_protection_shadow_state(
            bot,
            symbol=symbol,
            mode=mode,
            position_side=position_side,
            advisory=advisory,
            now_ts=now_ts,
            action_executed=action_executed,
        )
        if isinstance(bot.get("profit_protection_shadow"), dict):
            advisory["shadow_status"] = (bot.get("profit_protection_shadow") or {}).get(
                "status"
            )
            advisory["shadow_result"] = (bot.get("profit_protection_shadow") or {}).get(
                "result"
            )
            bot["profit_protection_shadow_status"] = advisory["shadow_status"]
        bot["profit_protection_advisory"] = self._compact_profit_protection_payload(advisory)
        return {
            "advisory": advisory,
            "action_executed": action_executed,
            "live_action": live_action,
        }

    def _run_fast_execution_layer(
        self,
        bot: Dict[str, Any],
        symbol: str,
        last_price: float,
        exec_indicators: Dict[str, Any],
    ) -> None:
        bot_id = bot.get("id")
        mode = (bot.get("mode") or "").lower()
        if mode in ("scalp_pnl", "scalp_market"):
            return

        positions_resp = self.client.get_positions(skip_cache=True)
        if not positions_resp.get("success"):
            return

        positions = positions_resp.get("data", {}).get("list", []) or []
        position = next((p for p in positions if p.get("symbol") == symbol), None)
        if not position:
            self._finalize_profit_protection_shadow_state(
                bot,
                symbol=symbol,
                mode=mode,
                resolution_reason="position_closed",
            )
            self._clear_profit_protection_runtime_state(bot)
            bot.pop("fast_partial_tp_state", None)
            bot.pop("profit_lock_state", None)
            bot.pop("_position_timing_state", None)
            self._clear_stall_overlay_state(bot)
            self._clear_breakout_invalidation_runtime_state(
                bot,
                clear_entry_context=True,
            )
            bot["peak_unrealized_pnl_pct"] = 0
            return

        pos_side = position.get("side")
        pos_size = self._safe_float(position.get("size"), 0.0)
        if not pos_side or pos_size <= 0:
            self._finalize_profit_protection_shadow_state(
                bot,
                symbol=symbol,
                mode=mode,
                resolution_reason="position_flat",
            )
            self._clear_profit_protection_runtime_state(bot)
            bot.pop("fast_partial_tp_state", None)
            bot.pop("profit_lock_state", None)
            bot.pop("_position_timing_state", None)
            self._clear_stall_overlay_state(bot)
            self._clear_breakout_invalidation_runtime_state(
                bot,
                clear_entry_context=True,
            )
            bot["peak_unrealized_pnl_pct"] = 0
            return

        if mode in ("long", "short"):
            self._activate_breakout_entry_context_from_position(
                bot=bot,
                symbol=symbol,
                mode=mode,
                position=position,
            )
            breakout_invalidation = self._handle_breakout_invalidation_guard(
                bot=bot,
                symbol=symbol,
                position=position,
                mode=mode,
                last_price=last_price,
            )
            if breakout_invalidation.get("active") and breakout_invalidation.get(
                "action"
            ) in {"trimmed", "closed", "position_empty"}:
                return
        else:
            self._clear_breakout_invalidation_runtime_state(
                bot,
                clear_entry_context=True,
            )

        entry_price = self._safe_float(position.get("avgPrice"), 0.0)
        if entry_price <= 0 or last_price <= 0:
            self._clear_profit_protection_runtime_state(bot)
            return

        is_long = pos_side == "Buy"
        profit_pct = (
            (last_price - entry_price) / entry_price
            if is_long
            else (entry_price - last_price) / entry_price
        )

        # Track peak unrealized PnL % for profit-lock
        profit_lock_state = bot.get("profit_lock_state") or {}
        if profit_lock_state.get("position_side") != pos_side:
            profit_lock_state = {
                "position_side": pos_side,
                "peak_pct": 0.0,
                "last_close_ts": 0.0,
            }

        peak_pct = self._safe_float(profit_lock_state.get("peak_pct"), 0.0)
        if profit_pct > peak_pct:
            peak_pct = profit_pct
            profit_lock_state["peak_pct"] = peak_pct
        bot["peak_unrealized_pnl_pct"] = peak_pct

        atr_pct = self._safe_float(exec_indicators.get("atr_pct"), 0.0)
        velocity_per_hour = self._safe_float(
            exec_indicators.get("price_velocity"),
            0.0,
        )
        # Inject flow score into indicators for profit protection decision
        pp_indicators = dict(exec_indicators or {})
        pp_indicators["flow_score"] = bot.get("flow_score") or 0
        pp_indicators["flow_confidence"] = bot.get("flow_confidence") or 0
        pp_indicators["flow_signal"] = bot.get("flow_signal") or "neutral"
        profit_protection_result = self._run_adaptive_profit_protection_layer(
            bot=bot,
            symbol=symbol,
            mode=mode,
            position=position,
            last_price=last_price,
            exec_indicators=pp_indicators,
            profit_pct=profit_pct,
            peak_profit_pct=peak_pct,
        )
        if profit_protection_result.get("action_executed"):
            return

        if not exec_indicators:
            return

        partial_tp_triggered = False
        partial_tp_ready = False
        partial_tp_reason = "not_ready"
        partial_tp_next_fraction = None
        profit_lock_armed = False
        profit_lock_ready = False
        profit_lock_reason = "not_ready"
        heartbeat_action = "no_action"
        effective_min_profit_pct = None
        fast_exec_disabled = mode == "neutral_classic_bybit"
        if fast_exec_disabled:
            partial_tp_reason = "disabled_for_mode"
            profit_lock_reason = "disabled_for_mode"
        # =============================================================
        # Partial Take Profit (fast execution)
        # =============================================================
        partial_tp_enabled = bot.get("partial_tp_enabled", PARTIAL_TP_ENABLED)
        if (not fast_exec_disabled) and partial_tp_enabled and profit_pct > 0:
            partial_state = bot.get("fast_partial_tp_state") or {}
            if partial_state.get("position_side") != pos_side:
                partial_state = {
                    "position_side": pos_side,
                    "next_index": 0,
                    "last_close_ts": 0.0,
                    "ref_entry_price": entry_price,
                }
            else:
                # Reset if entry price drifted significantly (DCA / partial fill)
                ref_entry = self._safe_float(
                    partial_state.get("ref_entry_price"), 0.0
                )
                if ref_entry > 0 and entry_price > 0:
                    entry_drift_pct = abs(entry_price - ref_entry) / ref_entry
                    if entry_drift_pct >= 0.02:  # 2% threshold
                        prev_index = partial_state.get("next_index", 0)
                        partial_state = {
                            "position_side": pos_side,
                            "next_index": 0,
                            "last_close_ts": 0.0,
                            "ref_entry_price": entry_price,
                        }
                        logger.info(
                            "[%s] ATR partial TP state reset: entry drifted "
                            "%.2f%% (%.4f -> %.4f), next_index %d -> 0",
                            symbol,
                            entry_drift_pct * 100,
                            ref_entry,
                            entry_price,
                            prev_index,
                        )
                elif ref_entry <= 0:
                    # Backfill ref_entry_price for existing states
                    partial_state["ref_entry_price"] = entry_price

            cooldown_sec = self._safe_float(
                bot.get("partial_tp_cooldown_sec"),
                PARTIAL_TP_COOLDOWN_SEC,
            )
            last_close_ts = self._safe_float(partial_state.get("last_close_ts"), 0.0)
            now = self.client._get_now_ts()
            if now - last_close_ts >= cooldown_sec:
                fractions = bot.get("partial_tp_fractions") or PARTIAL_TP_FRACTIONS
                if not isinstance(fractions, list) or not fractions:
                    fractions = PARTIAL_TP_FRACTIONS

                next_index = int(partial_state.get("next_index", 0))
                if 0 <= next_index < len(fractions):
                    fraction = self._safe_float(fractions[next_index], 0.0)
                    partial_tp_next_fraction = fraction
                    min_profit_pct = self._safe_float(
                        bot.get("partial_tp_min_profit_pct"),
                        bot.get("_atr_partial_tp_min_pct", PARTIAL_TP_MIN_PROFIT_PCT),
                    )
                    trigger_mult = self._safe_float(
                        bot.get("partial_tp_trigger_atr_mult"),
                        PARTIAL_TP_TRIGGER_ATR_MULT,
                    )
                    atr_trigger = trigger_mult * atr_pct if atr_pct else 0.0
                    trigger_pct = max(min_profit_pct, atr_trigger)
                    effective_min_profit_pct = self._get_effective_min_profit_pct(
                        bot, min_profit_pct
                    )

                    if profit_pct >= trigger_pct:
                        partial_tp_ready = True
                        if profit_pct < effective_min_profit_pct:
                            self._log_fast_exec_skip(
                                bot,
                                symbol,
                                "fee_guard",
                                f"profit_pct={profit_pct:.4f} < min={effective_min_profit_pct:.4f}",
                            )
                            partial_tp_ready = False
                            partial_tp_reason = "fee_guard"
                            heartbeat_action = "skip_fee_guard"
                        else:
                            close_qty = pos_size * fraction
                            close_side = "Sell" if is_long else "Buy"

                            close_result = self._create_order_checked(
                                bot=bot,
                                symbol=symbol,
                                side=close_side,
                                qty=close_qty,
                                order_type="Market",
                                price=last_price,
                                reduce_only=True,
                                time_in_force="GTC",
                                order_link_id=self._build_close_order_link_id(bot_id, "PRTP"),
                                full_close_qty=pos_size,
                            )

                            if close_result.get("skipped"):
                                bot["partial_tp_skipped_small_qty_count"] = (
                                    bot.get(
                                        "partial_tp_skipped_small_qty_count",
                                        0,
                                    )
                                    + 1
                                )

                                investment = self._safe_float(
                                    bot.get("investment"),
                                    DEFAULT_INVESTMENT_USDT,
                                )
                                if (
                                    investment <= SMALL_CAPITAL_INVEST_USDT_THRESHOLD
                                    and bot.get("partial_tp_skipped_small_qty_count", 0)
                                    >= SMALL_CAPITAL_PARTIAL_TP_MAX_SKIPS
                                ):
                                    bot["partial_tp_enabled"] = False
                                    self._log_fast_exec_skip(
                                        bot,
                                        symbol,
                                        "partial_tp_auto_disabled",
                                        "small-cap skip threshold reached",
                                    )
                                heartbeat_action = "skip_qty_below_min"
                                partial_tp_reason = "qty_below_min"
                            elif self._is_position_empty_close_result(close_result):
                                partial_tp_triggered = True
                                partial_tp_reason = "position_empty"
                                heartbeat_action = "position_flat"
                                logger.info(
                                    "[%s] Partial TP skipped: position already flat",
                                    symbol,
                                )
                            elif close_result.get("retCode") == 0 or close_result.get(
                                "success"
                            ):
                                bot["partial_tp_executed_count"] = (
                                    bot.get("partial_tp_executed_count", 0) + 1
                                )
                                partial_state["next_index"] = next_index + 1
                                partial_state["last_close_ts"] = now
                                partial_tp_triggered = True
                                partial_tp_reason = "executed"
                                heartbeat_action = "partial_tp"
                            elif self._is_ambiguous_order_result(close_result):
                                logger.warning(
                                    "[%s] Partial TP close AMBIGUOUS bot_id=%s: %s",
                                    symbol,
                                    bot.get("id"),
                                    close_result.get("error")
                                    or close_result.get("status")
                                    or "unknown",
                                )
                                bot["_block_opening_orders"] = True
                                partial_tp_reason = "ambiguous_outcome"
                                heartbeat_action = "ambiguous_close"
                            else:
                                self._hard_fail_close(
                                    bot,
                                    symbol,
                                    "partial_tp_fast",
                                    close_result.get("error", close_result),
                                )
                                partial_tp_reason = "error"
                    else:
                        partial_tp_reason = "below_trigger"
                else:
                    partial_tp_reason = "no_fraction"
            else:
                partial_tp_reason = "cooldown"

            bot["fast_partial_tp_state"] = partial_state

        # =============================================================
        # Profit Lock (fast execution)
        # =============================================================
        profit_lock_enabled = bot.get("profit_lock_enabled", PROFIT_LOCK_ENABLED)
        if (
            (not fast_exec_disabled)
            and profit_lock_enabled
            and profit_pct > 0
            and not partial_tp_triggered
        ):
            profit_lock_mult = max(
                0.5,
                min(
                    1.0,
                    self._safe_float(
                        bot.get("_stall_overlay_profit_lock_mult"),
                        1.0,
                    ),
                ),
            )
            arm_pct = self._safe_float(
                bot.get("profit_lock_arm_pct"), PROFIT_LOCK_ARM_PCT
            )
            arm_pct *= profit_lock_mult
            giveback_pct = self._safe_float(
                bot.get("profit_lock_giveback_pct"),
                PROFIT_LOCK_GIVEBACK_PCT,
            )
            giveback_pct *= profit_lock_mult
            close_fraction = self._safe_float(
                bot.get("profit_lock_close_fraction"),
                PROFIT_LOCK_CLOSE_FRACTION,
            )
            cooldown_sec = self._safe_float(
                bot.get("profit_lock_cooldown_sec"),
                PROFIT_LOCK_COOLDOWN_SEC,
            )

            arm_threshold = max(arm_pct, atr_pct or 0.0)
            fast_arm_context = self._get_profit_lock_fast_arm_context(
                bot=bot,
                symbol=symbol,
                position=position,
                atr_pct=atr_pct,
                velocity_per_hour=velocity_per_hour,
                peak_pct=peak_pct,
                arm_threshold=arm_threshold,
                profit_pct=profit_pct,
            )
            arm_threshold = fast_arm_context["arm_threshold"]
            bot["profit_lock_fast_arm_threshold"] = round(arm_threshold, 6)
            if fast_arm_context["active"]:
                logger.info(
                    "[%s] Profit lock fast-arm active: age=%.0fs speed_ratio=%.2f arm %.4f",
                    symbol,
                    fast_arm_context["age_sec"],
                    fast_arm_context["speed_ratio"],
                    arm_threshold,
                )
            last_close_ts = self._safe_float(
                profit_lock_state.get("last_close_ts"), 0.0
            )
            now = self.client._get_now_ts()

            if peak_pct >= arm_threshold and profit_pct <= peak_pct - giveback_pct:
                profit_lock_armed = True
                if now - last_close_ts >= cooldown_sec:
                    min_profit_pct = self._safe_float(
                        bot.get("profit_lock_min_profit_pct"),
                        bot.get("_atr_partial_tp_min_pct", PARTIAL_TP_MIN_PROFIT_PCT),
                    )
                    effective_min_profit_pct = self._get_effective_min_profit_pct(
                        bot, min_profit_pct
                    )

                    if profit_pct < effective_min_profit_pct:
                        bot["profit_lock_skipped_fee_guard_count"] = (
                            bot.get(
                                "profit_lock_skipped_fee_guard_count",
                                0,
                            )
                            + 1
                        )
                        self._log_fast_exec_skip(
                            bot,
                            symbol,
                            "profit_lock_fee_guard",
                            f"profit_pct={profit_pct:.4f} < min={effective_min_profit_pct:.4f}",
                        )
                        profit_lock_reason = "fee_guard"
                        heartbeat_action = "skip_fee_guard"
                    else:
                        close_qty = pos_size * close_fraction
                        close_side = "Sell" if is_long else "Buy"

                        close_result = self._create_order_checked(
                            bot=bot,
                            symbol=symbol,
                            side=close_side,
                            qty=close_qty,
                            order_type="Market",
                            price=last_price,
                            reduce_only=True,
                            time_in_force="GTC",
                            order_link_id=self._build_close_order_link_id(bot_id, "PLCK"),
                            full_close_qty=pos_size,
                        )

                        if close_result.get("skipped"):
                            bot["partial_tp_skipped_small_qty_count"] = (
                                bot.get(
                                    "partial_tp_skipped_small_qty_count",
                                    0,
                                )
                                + 1
                            )
                            heartbeat_action = "skip_qty_below_min"
                            profit_lock_reason = "qty_below_min"
                        elif self._is_position_empty_close_result(close_result):
                            profit_lock_ready = True
                            profit_lock_reason = "position_empty"
                            heartbeat_action = "position_flat"
                            logger.info(
                                "[%s] Profit lock close skipped: position already flat",
                                symbol,
                            )
                        elif close_result.get("retCode") == 0 or close_result.get(
                            "success"
                        ):
                            bot["profit_lock_executed_count"] = (
                                bot.get("profit_lock_executed_count", 0) + 1
                            )
                            profit_lock_state["last_close_ts"] = now
                            profit_lock_state["peak_pct"] = profit_pct
                            profit_lock_ready = True
                            profit_lock_reason = "executed"
                            heartbeat_action = "profit_lock"
                            # Prevent quick profit from also closing this cycle
                            bot["_profit_lock_closed_this_cycle"] = True
                            # Clear capital-starved block after profit lock so the
                            # bot can place fresh entry orders on the next cycle
                            # using the full investment budget.
                            bot.pop("_capital_starved_block_opening_orders", None)
                            bot.pop("_small_capital_block_opening_orders", None)
                        elif self._is_ambiguous_order_result(close_result):
                            logger.warning(
                                "[%s] Profit lock close AMBIGUOUS bot_id=%s: %s",
                                symbol,
                                bot.get("id"),
                                close_result.get("error")
                                or close_result.get("status")
                                or "unknown",
                            )
                            bot["_block_opening_orders"] = True
                            profit_lock_reason = "ambiguous_outcome"
                            heartbeat_action = "ambiguous_close"
                        else:
                            self._hard_fail_close(
                                bot,
                                symbol,
                                "profit_lock_fast",
                                close_result.get("error", close_result),
                            )
                            profit_lock_reason = "error"
                else:
                    profit_lock_reason = "cooldown"
            else:
                profit_lock_reason = (
                    "no_giveback" if peak_pct >= arm_threshold else "not_armed"
                )

        bot["profit_lock_state"] = profit_lock_state
        self._handle_stall_overlay(
            bot=bot,
            symbol=symbol,
            position=position,
            mode=mode,
            last_price=last_price,
            profit_pct=profit_pct,
            partial_tp_ready=partial_tp_ready,
            profit_lock_ready=profit_lock_ready,
            heartbeat_action=heartbeat_action,
        )

        # =============================================================
        # Heartbeat log (rate-limited) for visibility even when no TP fires
        # =============================================================
        hb_now = self.client._get_now_ts()
        last_hb = self._safe_float(bot.get("_fast_exec_heartbeat_ts"), 0.0)
        if hb_now - last_hb >= 60:
            if effective_min_profit_pct is None:
                base_min = self._safe_float(
                    bot.get("partial_tp_min_profit_pct"), PARTIAL_TP_MIN_PROFIT_PCT
                )
                effective_min_profit_pct = self._get_effective_min_profit_pct(
                    bot, base_min
                )
            partial_next_str = (
                f"{partial_tp_next_fraction:.4f}"
                if partial_tp_next_fraction is not None
                else "-"
            )
            logger.info(
                "[%s] FAST_EXEC_HEARTBEAT bot_id=%s side=%s size=%.6f upnl_pct=%.4f peak_upnl_pct=%.4f "
                "min_profit_pct=%.4f partial_next=%s partial_ready=%s partial_reason=%s "
                "profit_lock_armed=%s profit_lock_ready=%s profit_lock_reason=%s action=%s",
                symbol,
                bot.get("id"),
                pos_side,
                pos_size,
                profit_pct,
                peak_pct,
                effective_min_profit_pct
                if effective_min_profit_pct is not None
                else 0.0,
                partial_next_str,
                partial_tp_ready,
                partial_tp_reason,
                profit_lock_armed,
                profit_lock_ready,
                profit_lock_reason,
                heartbeat_action,
            )
            bot["_fast_exec_heartbeat_ts"] = hb_now

    def _check_quick_profit(
        self,
        bot: Dict[str, Any],
        symbol: str,
        last_price: float,
        fast_indicators: Dict[str, Any],
        position: Dict[str, Any],
    ) -> Optional[Dict[str, Any]]:
        """
        Check if quick profit should be taken for dynamic/trailing modes.

        This feature allows partial position closes when small profits are available,
        locking in gains while maintaining position bias.

        Supported modes: long, short, neutral (with dynamic or trailing range)

        Args:
            bot: Bot configuration dict
            symbol: Trading symbol
            last_price: Current market price
            fast_indicators: Technical indicators dict
            position: Current position data from Bybit

        Returns:
            Dict with result info if profit was taken, None otherwise
        """
        bot_id = bot.get("id")

        # Check if quick profit is enabled for this bot
        quick_profit_enabled = bot.get("quick_profit_enabled")
        if quick_profit_enabled is None:
            quick_profit_enabled = LONG_QUICK_PROFIT_ENABLED
        if not quick_profit_enabled:
            return None

        # Only for long/short/neutral mode with dynamic or trailing range
        mode = (bot.get("mode") or "").lower()
        range_mode = (bot.get("range_mode") or "").lower()
        if mode not in ("long", "short", "neutral") or range_mode not in (
            "dynamic",
            "trailing",
        ):
            return None

        # Get position details
        pos_side = position.get("side", "")
        pos_size = self._safe_float(position.get("size"), 0)
        unrealized_pnl = self._safe_float(position.get("unrealisedPnl"), 0)

        # Validate position based on mode
        if pos_size <= 0:
            # Clear trailing TP state if position closed between cycles
            if bot.get("_trailing_tp_active"):
                bot["_trailing_tp_active"] = False
                bot.pop("_trailing_tp_peak_pnl", None)
                bot.pop("_trailing_tp_stop_pnl", None)
            return None

        # For long mode: only process Buy positions
        # For short mode: only process Sell positions
        # For neutral mode: process both Buy and Sell positions
        if mode == "long" and pos_side != "Buy":
            return None
        if mode == "short" and pos_side != "Sell":
            return None

        # Must be in profit
        if unrealized_pnl <= 0:
            return None

        # Check cooldown
        last_quick_tp = bot.get("last_quick_profit_at")
        cooldown_sec = max(
            0,
            int(
                self._safe_float(
                    bot.get("quick_profit_cooldown"),
                    LONG_QUICK_PROFIT_COOLDOWN_SEC,
                )
            ),
        )
        if last_quick_tp:
            try:
                last_tp_dt = datetime.fromisoformat(
                    last_quick_tp.replace("Z", "+00:00")
                )
                elapsed = (datetime.now(timezone.utc) - last_tp_dt).total_seconds()
                if elapsed < cooldown_sec:
                    logger.debug(
                        f"[{symbol}] Quick profit cooldown active ({elapsed:.0f}s < {cooldown_sec}s)"
                    )
                    return None
            except Exception as e:
                logger.debug(f"[{symbol}] Quick profit cooldown check error: {e}")

        # Get configurable thresholds (per-bot overrides or defaults)
        min_profit = self._safe_float(
            bot.get("quick_profit_min"),
            LONG_QUICK_PROFIT_MIN,
        )
        target_profit = self._safe_float(
            bot.get("quick_profit_target"),
            LONG_QUICK_PROFIT_TARGET,
        )
        close_pct = self._safe_float(
            bot.get("quick_profit_close_pct"),
            LONG_QUICK_PROFIT_CLOSE_PCT,
        )
        if close_pct <= 0 or close_pct >= 1:
            close_pct = LONG_QUICK_PROFIT_CLOSE_PCT

        stall_quick_mult = max(
            0.5,
            min(
                1.0,
                self._safe_float(
                    bot.get("_stall_overlay_quick_profit_mult"),
                    1.0,
                ),
            ),
        )
        if stall_quick_mult < 1.0:
            min_profit *= stall_quick_mult
            target_profit *= stall_quick_mult

        # ATR-scaled TP: use the coin's actual volatility to set exit targets.
        # This replaces fixed $0.15 with a level that adapts per coin.
        # Example: ATR(15m) = 1.5% → target = 0.9% of position notional.
        atr_pct = self._safe_float(
            (fast_indicators or {}).get("atr_pct")
            or bot.get("atr_15m_pct"),
            0.0,
        )
        if atr_pct > 0 and last_price > 0 and pos_size > 0:
            position_notional_est = pos_size * last_price
            # Target = 60% of one ATR move (capture most of the move, exit before reversal)
            from config.strategy_config import QUICK_PROFIT_ATR_SCALE_FACTOR
            atr_target_usdt = position_notional_est * (atr_pct / 100.0) * QUICK_PROFIT_ATR_SCALE_FACTOR
            if atr_target_usdt > min_profit:
                target_profit = max(min_profit, atr_target_usdt)
                bot["_quick_profit_atr_scaled"] = True
                bot["_quick_profit_atr_target"] = round(target_profit, 4)

        # Adjust threshold based on market conditions (adaptive)
        if self.scalp_pnl_service and fast_indicators:
            try:
                price_history = self.scalp_pnl_service.get_price_history(symbol)
                market_condition, market_analysis = (
                    self.scalp_pnl_service.analyze_market_condition(
                        symbol=symbol,
                        indicators=fast_indicators,
                        recent_prices=price_history,
                        base_targets={
                            "quick_profit": min_profit,
                            "target_profit": target_profit,
                            "max_target": target_profit * 1.5,
                        }
                    )
                )

                is_choppy = market_analysis.get("is_choppy", False)
                momentum_strength = market_analysis.get("momentum_strength", 0)

                if is_choppy:
                    # Lower threshold in choppy markets - take profits quickly
                    target_profit *= LONG_QUICK_PROFIT_CHOPPY_MULT
                    logger.debug(
                        f"[{symbol}] Choppy market - lowered quick profit target to ${target_profit:.2f}"
                    )
                elif momentum_strength > 0.5:
                    # Higher threshold when trending well - let profits run
                    target_profit *= LONG_QUICK_PROFIT_TREND_MULT
                    logger.debug(
                        f"[{symbol}] Strong momentum - raised quick profit target to ${target_profit:.2f}"
                    )

            except Exception as e:
                logger.debug(f"[{symbol}] Market analysis for quick profit failed: {e}")

        min_profit, target_profit, position_notional, position_scale = (
            self._get_scaled_quick_profit_targets(
                bot=bot,
                last_price=last_price,
                pos_size=pos_size,
                min_profit=min_profit,
                target_profit=target_profit,
            )
        )
        if position_scale > 1.0:
            logger.debug(
                "[%s] Quick profit scaled by live notional %.2f USDT (scale=%.2fx, min=%.2f, target=%.2f)",
                symbol,
                position_notional,
                position_scale,
                min_profit,
                target_profit,
            )

        fee_floor_profit = max(
            0.0,
            position_notional * self._get_effective_min_profit_pct(bot, 0.0),
        )
        if fee_floor_profit > 0.0:
            if min_profit < fee_floor_profit:
                logger.debug(
                    "[%s] Quick profit min raised by fee floor %.4f -> %.4f",
                    symbol,
                    min_profit,
                    fee_floor_profit,
                )
                min_profit = fee_floor_profit
            if target_profit < fee_floor_profit:
                logger.debug(
                    "[%s] Quick profit target raised by fee floor %.4f -> %.4f",
                    symbol,
                    target_profit,
                    fee_floor_profit,
                )
                target_profit = fee_floor_profit

        quick_profit_guard_cooldown = max(30.0, float(cooldown_sec))
        recent_fast_exit_ts = max(
            self._safe_float(
                ((bot.get("fast_partial_tp_state") or {}) or {}).get("last_close_ts"),
                0.0,
            )
            or 0.0,
            self._safe_float(
                ((bot.get("profit_lock_state") or {}) or {}).get("last_close_ts"),
                0.0,
            )
            or 0.0,
        )
        if recent_fast_exit_ts > 0:
            elapsed_since_fast_exit = self._get_cycle_now_ts() - recent_fast_exit_ts
            if elapsed_since_fast_exit < quick_profit_guard_cooldown:
                logger.debug(
                    "[%s] Quick profit skipped after recent fast exit (%.0fs < %.0fs)",
                    symbol,
                    elapsed_since_fast_exit,
                    quick_profit_guard_cooldown,
                )
                return None

        quick_profit_speed = self._get_quick_profit_speed_adjustment(
            bot=bot,
            symbol=symbol,
            position=position,
            fast_indicators=fast_indicators or {},
            min_profit=min_profit,
            target_profit=target_profit,
            close_pct=close_pct,
        )
        if quick_profit_speed["active"]:
            adjusted_target_profit = quick_profit_speed["adjusted_target_profit"]
            adjusted_close_pct = quick_profit_speed["adjusted_close_pct"]
            logger.info(
                "[%s] Quick profit fast-burst protection active: age=%.0fs speed_ratio=%.2f "
                "target %.2f -> %.2f close_pct %.2f -> %.2f",
                symbol,
                quick_profit_speed["age_sec"],
                quick_profit_speed["speed_ratio"],
                target_profit,
                adjusted_target_profit,
                close_pct,
                adjusted_close_pct,
            )
            target_profit = adjusted_target_profit
            close_pct = adjusted_close_pct

        # Check if profit meets minimum threshold
        if unrealized_pnl < min_profit:
            # Clear trailing state when profit disappears
            if bot.get("_trailing_tp_active"):
                bot["_trailing_tp_active"] = False
                bot.pop("_trailing_tp_peak_pnl", None)
                bot.pop("_trailing_tp_stop_pnl", None)
            return None

        # =================================================================
        # TRAILING TAKE-PROFIT: Let profits run when flow confirms direction.
        # Instead of closing at the fixed target, track peak profit and
        # only close when profit pulls back by ATR * 0.5 from peak.
        # =================================================================
        flow_val = float(bot.get("flow_score") or 0)
        flow_conf = float(bot.get("flow_confidence") or 0)
        trailing_atr = self._safe_float(
            (fast_indicators or {}).get("atr_pct") or bot.get("atr_15m_pct"),
            0.0,
        )
        trailing_distance = max(min_profit, position_notional * trailing_atr * 0.005) if trailing_atr > 0 else min_profit

        # Check if flow confirms position direction (should let profit run)
        flow_confirms_direction = False
        from config.strategy_config import TRAILING_TP_FLOW_THRESHOLD, TRAILING_TP_FLOW_CONFIDENCE
        if pos_side == "Buy" and flow_val >= TRAILING_TP_FLOW_THRESHOLD and flow_conf >= TRAILING_TP_FLOW_CONFIDENCE:
            flow_confirms_direction = True
        elif pos_side == "Sell" and flow_val <= -TRAILING_TP_FLOW_THRESHOLD and flow_conf >= TRAILING_TP_FLOW_CONFIDENCE:
            flow_confirms_direction = True

        if bot.get("_trailing_tp_active"):
            # Trailing is active — update peak and check stop
            prev_peak = float(bot.get("_trailing_tp_peak_pnl") or unrealized_pnl)
            new_peak = max(prev_peak, unrealized_pnl)
            bot["_trailing_tp_peak_pnl"] = round(new_peak, 4)
            stop_pnl = new_peak - trailing_distance
            bot["_trailing_tp_stop_pnl"] = round(stop_pnl, 4)

            if unrealized_pnl <= stop_pnl:
                # Profit pulled back from peak — close now
                logger.warning(
                    "[%s] TRAILING TP: closing at $%.2f (peak=$%.2f, stop=$%.2f, trail=$%.4f)",
                    symbol, unrealized_pnl, new_peak, stop_pnl, trailing_distance,
                )
                bot["_trailing_tp_active"] = False
                bot.pop("_trailing_tp_peak_pnl", None)
                bot.pop("_trailing_tp_stop_pnl", None)
                bot["_trailing_tp_exit_count"] = int(bot.get("_trailing_tp_exit_count") or 0) + 1
                # Fall through to the close logic below
            else:
                # Profit still above stop — let it run
                logger.debug(
                    "[%s] Trailing TP running: upnl=$%.2f peak=$%.2f stop=$%.2f",
                    symbol, unrealized_pnl, new_peak, stop_pnl,
                )
                return None  # SKIP the fixed close — let profit run

        elif unrealized_pnl >= target_profit and flow_confirms_direction and not bot.get("stall_overlay_position_cap_hit"):
            # Profit hit target AND flow confirms AND position not capped — activate trailing
            bot["_trailing_tp_active"] = True
            bot["_trailing_tp_peak_pnl"] = round(unrealized_pnl, 4)
            bot["_trailing_tp_stop_pnl"] = round(unrealized_pnl - trailing_distance, 4)
            logger.info(
                "[%s] TRAILING TP activated: upnl=$%.2f target=$%.2f trail=$%.4f — letting profit run",
                symbol, unrealized_pnl, target_profit, trailing_distance,
            )
            return None  # SKIP the fixed close — trailing takes over

        # Check if profit meets target threshold (original fixed TP)
        if unrealized_pnl < target_profit:
            logger.debug(
                f"[{symbol}] Unrealized ${unrealized_pnl:.2f} below quick profit target ${target_profit:.2f}"
            )
            return None

        # Calculate partial close quantity
        close_qty = pos_size * close_pct

        # Determine close side (opposite of position side)
        close_side = "Sell" if pos_side == "Buy" else "Buy"

        # Place partial close order (reduce_only=True to never open new position)
        logger.info(
            f"[{symbol}] 💰 QUICK PROFIT - Taking partial profit ${unrealized_pnl:.2f} "
            f"(closing {close_pct * 100:.0f}% of {pos_side} position: {close_qty} of {pos_size})"
        )

        # Build orderLinkId v2 with full bot UUID and intent=close
        order_link_id = self._build_order_link_id(
            bot_id=bot_id,
            symbol=symbol,
            cycle_ts=int(time.time()),
            seq=0,
            side=close_side,
            intent="close",
        )

        close_result = self._create_order_checked(
            bot=bot,
            symbol=symbol,
            side=close_side,
            qty=close_qty,
            order_type="Market",
            price=last_price,
            reduce_only=True,  # Critical: only close, never open opposite position
            time_in_force="GTC",
            order_link_id=order_link_id,
            full_close_qty=pos_size,
        )

        if self._is_position_empty_close_result(close_result):
            logger.info(
                "[%s] Quick profit close skipped: position already flat",
                symbol,
            )
            return {
                "success": True,
                "action": "quick_profit",
                "already_flat": True,
                "close_qty": 0.0,
                "unrealized_pnl": unrealized_pnl,
                "profit_taken": 0.0,
                "target_threshold": target_profit,
                "remaining_size": 0.0,
                "recenter_needed": False,
            }
        if close_result.get("retCode") == 0 or close_result.get("success"):
            # Cancel pre-existing exits ONLY after successful market close —
            # never before, to avoid leaving position naked on close failure.
            self._cancel_bot_reduce_only_orders(
                bot=bot, symbol=symbol, side=close_side,
            )

            normalized_qty = close_result.get("normalized_qty", close_qty)
            # Calculate approximate profit taken (proportional to close %)
            profit_taken = unrealized_pnl * close_pct

            # Update bot state
            bot["last_quick_profit_at"] = datetime.now(timezone.utc).isoformat()
            bot["quick_profit_count"] = (
                int(self._safe_float(bot.get("quick_profit_count"), 0.0)) + 1
            )
            bot["quick_profit_total"] = (
                self._safe_float(bot.get("quick_profit_total"), 0.0) + profit_taken
            )

            logger.info(
                f"[{symbol}] ✅ Quick profit taken - closed {normalized_qty} @ market "
                f"(approx profit ${profit_taken:.2f}, total quick profits ${bot['quick_profit_total']:.2f})"
            )
            self._record_exit_reason(
                bot,
                symbol=symbol,
                mode=bot.get("mode"),
                reason="quick_profit",
                unrealized_pnl=unrealized_pnl,
                profit_taken=profit_taken,
                close_qty=normalized_qty,
                target_threshold=target_profit,
            )

            return {
                "success": True,
                "action": "quick_profit",
                "close_qty": close_qty,
                "unrealized_pnl": unrealized_pnl,
                "profit_taken": profit_taken,
                "target_threshold": target_profit,
                "remaining_size": pos_size - close_qty,
                "recenter_needed": True,
            }
        elif close_result.get("skipped"):
            return {
                "success": False,
                "action": "quick_profit",
                "error": close_result.get("error"),
                "skipped": True,
            }
        elif self._is_ambiguous_order_result(close_result):
            logger.warning(
                "[%s] Quick profit close AMBIGUOUS bot_id=%s: %s",
                symbol,
                bot.get("id"),
                close_result.get("error")
                or close_result.get("status")
                or "unknown",
            )
            bot["_block_opening_orders"] = True
            return {
                "success": False,
                "action": "quick_profit",
                "ambiguous": True,
                "error": close_result.get("error") or "ambiguous_outcome",
            }
        else:
            self._hard_fail_close(
                bot,
                symbol,
                "quick_profit",
                close_result.get("retMsg", close_result),
            )
            return {
                "success": False,
                "action": "quick_profit",
                "error": close_result.get("error"),
            }

    def _get_scaled_quick_profit_targets(
        self,
        bot: Dict[str, Any],
        last_price: float,
        pos_size: float,
        min_profit: float,
        target_profit: float,
    ) -> Tuple[float, float, float, float]:
        """
        Scale shared quick-profit targets by live position notional.
        """
        safe_price = max(self._safe_float(last_price, 0.0), 0.0)
        safe_size = max(self._safe_float(pos_size, 0.0), 0.0)
        position_notional = safe_price * safe_size

        scale = 1.0
        if (
            LONG_QUICK_PROFIT_SCALE_BY_POSITION_NOTIONAL
            and LONG_QUICK_PROFIT_BASE_POSITION_NOTIONAL_USDT > 0
            and position_notional > 0
        ):
            scale = position_notional / LONG_QUICK_PROFIT_BASE_POSITION_NOTIONAL_USDT
            scale = max(1.0, min(scale, LONG_QUICK_PROFIT_POSITION_SCALE_MAX))
            min_profit = max(min_profit, min_profit * scale)
            target_profit = max(target_profit, target_profit * scale)

        bot["quick_profit_position_notional"] = round(position_notional, 4)
        bot["quick_profit_target_scale"] = round(scale, 4)
        bot["quick_profit_live_min_profit"] = round(min_profit, 4)
        bot["quick_profit_live_target"] = round(target_profit, 4)

        return min_profit, target_profit, position_notional, scale

    def _run_quick_profit_check(
        self,
        bot: Dict[str, Any],
        symbol: str,
        last_price: float,
        fast_indicators: Dict[str, Any],
    ) -> None:
        current_mode = (bot.get("mode") or "").lower()
        range_mode = (bot.get("range_mode") or "").lower()
        if current_mode not in ("long", "short", "neutral") or range_mode not in (
            "dynamic",
            "trailing",
        ):
            return

        positions_resp = self.client.get_positions(skip_cache=True)
        if not positions_resp.get("success"):
            return

        positions = (positions_resp.get("data", {}) or {}).get("list", []) or []
        candidate_positions = [
            p
            for p in positions
            if p.get("symbol") == symbol and self._safe_float(p.get("size"), 0) > 0
        ]
        if not candidate_positions:
            bot.pop("_position_timing_state", None)
            return
        if current_mode == "long":
            candidate_positions = [
                p
                for p in candidate_positions
                if str(p.get("side") or "").strip().lower() == "buy"
            ]
        elif current_mode == "short":
            candidate_positions = [
                p
                for p in candidate_positions
                if str(p.get("side") or "").strip().lower() == "sell"
            ]
        if not candidate_positions:
            bot.pop("_position_timing_state", None)
            return

        candidate_positions.sort(
            key=lambda p: self._safe_float(p.get("size"), 0),
            reverse=True,
        )

        for symbol_position in candidate_positions:
            quick_profit_result = self._check_quick_profit(
                bot=bot,
                symbol=symbol,
                last_price=last_price,
                fast_indicators=fast_indicators,
                position=symbol_position,
            )

            if not quick_profit_result or not quick_profit_result.get("success"):
                continue

            profit_taken = quick_profit_result.get("profit_taken", 0)
            current_realized = self._safe_float(bot.get("realized_pnl"), 0.0)
            bot["realized_pnl"] = current_realized + profit_taken

            if quick_profit_result.get("recenter_needed"):
                remaining_size = quick_profit_result.get("remaining_size", 0)
                if remaining_size > 0:
                    recenter_result = self._trigger_quick_profit_recenter(
                        bot=bot,
                        symbol=symbol,
                        last_price=last_price,
                        remaining_position_size=remaining_size,
                    )
                    if recenter_result.get("success"):
                        logger.info(
                            f"[{symbol}] Grid recentered after quick profit "
                            f"(remaining: {remaining_size})"
                        )
            break

    def _maybe_run_dynamic_quick_profit(
        self,
        bot: Dict[str, Any],
        symbol: str,
        last_price: float,
        fast_indicators: Dict[str, Any],
    ) -> None:
        # Guard: skip if profit lock already closed this cycle (prevent double-close)
        if bot.get("_profit_lock_closed_this_cycle"):
            return

        current_mode = (bot.get("mode") or "").lower()
        range_mode = (bot.get("range_mode") or "").lower()
        if current_mode not in ("long", "short", "neutral") or range_mode not in (
            "dynamic",
            "trailing",
        ):
            return

        try:
            self._run_quick_profit_check(
                bot=bot,
                symbol=symbol,
                last_price=last_price,
                fast_indicators=fast_indicators,
            )
        except Exception as e:
            logger.warning(f"[{symbol}] Quick profit check failed: {e}")

    def _trigger_quick_profit_recenter(
        self,
        bot: Dict[str, Any],
        symbol: str,
        last_price: float,
        remaining_position_size: float,
    ) -> Dict[str, Any]:
        """
        Trigger grid recenter after quick profit partial close.

        After quick profit closes part of a position, the grid may have stale
        orders far from current price. This method:
        1. Cancels all existing orders for the bot
        2. Clears the grid center cache to force recalculation
        3. Updates grid bounds to center around current price

        The next cycle will rebuild the grid with proper reduce-only orders
        for the remaining position.

        Args:
            bot: Bot configuration dict
            symbol: Trading symbol
            last_price: Current market price
            remaining_position_size: Size of remaining position after partial close

        Returns:
            Dict with recenter result info
        """
        from config.strategy_config import (
            QUICK_PROFIT_RECENTER_ENABLED,
            QUICK_PROFIT_RECENTER_CANCEL_ALL,
            QUICK_PROFIT_RECENTER_COOLDOWN_SEC,
        )

        bot_id = bot.get("id")

        # Check if recenter is enabled
        if not QUICK_PROFIT_RECENTER_ENABLED:
            logger.debug(f"[{symbol}] Quick profit recenter disabled")
            return {"success": False, "reason": "disabled"}

        # Check cooldown
        last_recenter = bot.get("last_quick_profit_recenter_at")
        if last_recenter:
            try:
                last_recenter_dt = datetime.fromisoformat(
                    last_recenter.replace("Z", "+00:00")
                )
                elapsed = (datetime.now(timezone.utc) - last_recenter_dt).total_seconds()
                if elapsed < QUICK_PROFIT_RECENTER_COOLDOWN_SEC:
                    logger.debug(
                        f"[{symbol}] Quick profit recenter cooldown active "
                        f"({elapsed:.0f}s < {QUICK_PROFIT_RECENTER_COOLDOWN_SEC}s)"
                    )
                    return {"success": False, "reason": "cooldown"}
            except Exception as e:
                logger.debug(f"[{symbol}] Quick profit recenter cooldown check error: {e}")

        logger.info(
            f"[{symbol}] QUICK_PROFIT_RECENTER - Rebuilding grid after partial close "
            f"(remaining position: {remaining_position_size})"
        )
        self._record_quick_profit_rebuild_transition_event(
            bot,
            event_type="quick_profit_rebuild_started",
            symbol=symbol,
            mode=bot.get("mode"),
            current_price=last_price,
        )

        # Step 1: Cancel all existing orders
        cancelled_count = 0
        if QUICK_PROFIT_RECENTER_CANCEL_ALL:
            cancel_result = self._force_cancel_all_orders(
                symbol,
                max_retries=2,
                bot=bot,
            )
            if cancel_result.get("success"):
                cancelled_count = cancel_result.get("cancelled", 0)
                logger.info(
                    f"[{symbol}] Quick profit recenter: cancelled {cancelled_count} orders"
                )
            else:
                logger.warning(
                    f"[{symbol}] Quick profit recenter: order cancel incomplete "
                    f"({cancel_result.get('remaining', 0)} remaining)"
                )

        # Step 2: Clear grid center cache to force recalculation
        grid_center_key = f"{bot_id}_{symbol}"
        if grid_center_key in self._last_grid_center:
            del self._last_grid_center[grid_center_key]
            logger.debug(f"[{symbol}] Cleared grid center cache for recenter")

        # Step 3: Update grid bounds to center around current price
        # Get current range settings from bot
        range_mode = (bot.get("range_mode") or "dynamic").lower()
        range_width_pct = self._safe_float(
            bot.get("range_width_pct") or bot.get("last_range_width_pct"), 0.03
        )
        rebuild_width_mult, rebuild_width_source = (
            self._resolve_quick_profit_recenter_width_policy(bot)
        )
        effective_range_width_pct = range_width_pct
        if rebuild_width_mult < 1.0:
            effective_range_width_pct = range_width_pct * rebuild_width_mult

        if range_mode in ("dynamic", "trailing"):
            # Shift bounds to center around current price
            half_range = last_price * effective_range_width_pct / 2
            new_lower = last_price - half_range
            new_upper = last_price + half_range

            bot["lower_price"] = new_lower
            bot["upper_price"] = new_upper
            bot["grid_lower_price"] = None
            bot["grid_upper_price"] = None
            bot["quick_profit_recenter_width_mult_applied"] = round(
                rebuild_width_mult,
                4,
            )
            bot["quick_profit_recenter_width_source"] = rebuild_width_source
            bot["quick_profit_recenter_width_pct_applied"] = round(
                effective_range_width_pct,
                6,
            )

            logger.info(
                f"[{symbol}] Quick profit recenter: new grid range "
                f"[${new_lower:.4f} - ${new_upper:.4f}] centered at ${last_price:.4f} "
                f"(width={effective_range_width_pct*100:.2f}%, mult={rebuild_width_mult:.2f}x)"
            )

        # Update recenter timestamp
        bot["last_quick_profit_recenter_at"] = datetime.now(timezone.utc).isoformat()
        self._record_quick_profit_rebuild_event(
            bot,
            symbol=symbol,
            mode=bot.get("mode"),
            current_price=last_price,
            new_lower=bot.get("lower_price"),
            new_upper=bot.get("upper_price"),
            cancelled_orders=cancelled_count,
            remaining_position_size=remaining_position_size,
            rebuild_width_mult=rebuild_width_mult,
            rebuild_width_source=rebuild_width_source,
            rebuild_width_pct=effective_range_width_pct,
        )
        self._record_quick_profit_rebuild_transition_event(
            bot,
            event_type="quick_profit_rebuild_completed",
            symbol=symbol,
            mode=bot.get("mode"),
            current_price=last_price,
            cancelled_orders=cancelled_count,
            new_lower=bot.get("lower_price"),
            new_upper=bot.get("upper_price"),
            rebuild_width_source=rebuild_width_source,
            rebuild_width_pct=effective_range_width_pct,
        )

        return {
            "success": True,
            "cancelled_orders": cancelled_count,
            "new_center": last_price,
            "remaining_position": remaining_position_size,
        }

    def _run_scalp_pnl_cycle(
        self,
        bot: Dict[str, Any],
        symbol: str,
        last_price: float,
        fast_indicators: Dict[str, Any],
        now_iso: str,
        fast_refill_tick: bool = False,
    ) -> Optional[Dict[str, Any]]:
        """
        Run a scalp PnL cycle - intelligent unrealized profit scalping.

        This mode:
        1. Checks unrealized PnL on open positions
        2. Closes positions when profit target is reached (dynamic based on conditions)
        3. Places new orders close to current price to follow momentum
        4. Adapts between quick scalps (choppy) and trend-following (trending)

        Args:
            bot: Bot configuration dict
            symbol: Trading symbol
            last_price: Current market price
            fast_indicators: 15m indicators dict
            now_iso: Current timestamp ISO string

        Returns:
            Updated bot dict, or None if regular cycle should continue
        """
        bot_id = bot.get("id")
        investment = self._get_effective_investment(
            bot, self._safe_float(bot.get("investment"), DEFAULT_INVESTMENT_USDT)
        )
        leverage = self._safe_float(bot.get("leverage"), DEFAULT_LEVERAGE)
        planned_notional = investment * leverage
        ai_block_opening_orders = self._ai_block_opening_orders(bot)
        current_mode = (bot.get("mode") or "neutral").lower()
        range_mode = bot.get("range_mode", "fixed")
        current_spread_pct = 0.0
        now_ts = time.time()
        failure_breaker_skip_opening_orders, failure_breaker_reason = (
            self._failure_breaker_skip_opening_orders(bot, now_ts)
        )

        # =============================================================================
        # MICRO-BIAS AWARENESS FOR SCALP_PNL MODE
        # =============================================================================
        # Detect slight directional drift and set per-side skip flags.
        # Skip some ENTRY orders against the micro-trend to reduce inventory accumulation.
        from config.strategy_config import (
            NEUTRAL_MICRO_BIAS_ENABLED,
            NEUTRAL_MICRO_BIAS_THRESHOLD,
            NEUTRAL_MICRO_BIAS_STRONG,
            MICRO_BIAS_SKIP_PCT_MODERATE,
            MICRO_BIAS_SKIP_PCT_STRONG,
            MICRO_BIAS_HYSTERESIS_CHECKS,
            MICRO_BIAS_CACHE_SECONDS,
        )

        # Clear previous cycle's skip flags
        bot["_micro_bias_skip_buy"] = False
        bot["_micro_bias_skip_sell"] = False
        bot["_micro_bias_score"] = 0.0

        if NEUTRAL_MICRO_BIAS_ENABLED and self.micro_bias_service is not None:
            try:
                import random

                micro_bias = self.micro_bias_service.calculate_bias(
                    bot=bot,
                    symbol=symbol,
                    threshold=NEUTRAL_MICRO_BIAS_THRESHOLD,
                    strong_threshold=NEUTRAL_MICRO_BIAS_STRONG,
                    skip_pct_moderate=MICRO_BIAS_SKIP_PCT_MODERATE,
                    skip_pct_strong=MICRO_BIAS_SKIP_PCT_STRONG,
                    hysteresis_checks=MICRO_BIAS_HYSTERESIS_CHECKS,
                    cache_seconds=MICRO_BIAS_CACHE_SECONDS,
                )

                bot["_micro_bias_score"] = micro_bias.get("score", 0.0)
                bot["_micro_bias_direction"] = micro_bias.get("direction", "NEUTRAL")

                if micro_bias.get("direction") == "BULLISH":
                    # Bullish drift - probabilistically skip Sell ENTRY orders
                    bot["_micro_bias_skip_sell"] = (
                        random.random() < micro_bias.get("skip_probability", 0.0)
                    )
                    bot["_micro_bias_skip_buy"] = False
                elif micro_bias.get("direction") == "BEARISH":
                    # Bearish drift - probabilistically skip Buy ENTRY orders
                    bot["_micro_bias_skip_buy"] = (
                        random.random() < micro_bias.get("skip_probability", 0.0)
                    )
                    bot["_micro_bias_skip_sell"] = False

                if bot.get("_micro_bias_skip_buy") or bot.get("_micro_bias_skip_sell"):
                    logger.debug(
                        "[%s] MICRO_BIAS (scalp_pnl) skip this cycle: skip_buy=%s skip_sell=%s "
                        "(direction=%s score=%.3f)",
                        symbol,
                        bot.get("_micro_bias_skip_buy"),
                        bot.get("_micro_bias_skip_sell"),
                        micro_bias.get("direction"),
                        micro_bias.get("score", 0.0),
                    )
            except Exception as mb_err:
                logger.debug("[%s] Micro-bias calculation error: %s", symbol, mb_err)

        # Get instrument info for tick/qty sizing
        instrument = self._get_instrument_info(symbol)
        if not instrument:
            return self._set_error(bot, f"Failed to fetch instrument info for {symbol}")

        tick_size = instrument.get("tick_size")
        qty_step = instrument.get("qty_step")
        min_order_qty = instrument.get("min_order_qty")
        if not tick_size or not qty_step or not min_order_qty:
            return self._set_error(bot, f"Missing instrument sizing for {symbol}")

        # Update price history for swing detection
        self.scalp_pnl_service.update_price_history(symbol, last_price)
        price_history = self.scalp_pnl_service.get_price_history(symbol)

        # =============================================================================
        # Volatility Guard: Check Orderbook Spread (New Feature)
        # =============================================================================
        try:
            from config.strategy_config import (
                SCALPING_VOLATILITY_PAUSE_ENABLED,
                SCALPING_ENABLED_THRESHOLD_MULTIPLIER,
                SCALP_PNL_NEAR_GRID_PCT,
            )

            if SCALPING_VOLATILITY_PAUSE_ENABLED:
                imbalance_data = self.orderbook_service.calculate_imbalance(
                    symbol, depth_levels=10
                )

                if imbalance_data.get("success"):
                    current_spread_pct = (
                        imbalance_data.get("spread_pct", 0) / 100.0
                    )  # Convert to decimal

                    # Calculate max allowed spread based on grid spacing
                    max_spread = (
                        SCALP_PNL_NEAR_GRID_PCT * SCALPING_ENABLED_THRESHOLD_MULTIPLIER
                    )

                    if current_spread_pct > max_spread:
                        logger.warning(
                            f"[{symbol}] Scalp cycle skipped: Extreme volatility "
                            f"(Spread {current_spread_pct * 100:.4f}% > Limit {max_spread * 100:.4f}%)"
                        )
                        bot["last_run_at"] = now_iso
                        # Optional: store warning in bot state for UI
                        bot["last_warning"] = (
                            f"Volatility Pause: Spread {current_spread_pct * 100:.2f}%"
                        )
                        self.bot_storage.save_bot(bot)
                        return bot
        except Exception as e:
            logger.warning(f"[{symbol}] Volatility guard check failed: {e}")

        # Analyze market conditions
        base_targets = {
            "target_profit": self._safe_float(bot.get("_scalp_adapted_target"), 0.60),
            "quick_profit": self._safe_float(bot.get("_scalp_adapted_quick"), 0.30),
            "max_target": self._safe_float(bot.get("_scalp_adapted_max"), 1.00),
        }
        
        market_condition, market_analysis = (
            self.scalp_pnl_service.analyze_market_condition(
                symbol=symbol,
                indicators=fast_indicators,
                recent_prices=price_history,
                base_targets=base_targets,
            )
        )

        logger.debug(
            f"[{symbol}] Scalp PnL analysis - condition={market_condition.value}, "
            f"momentum={market_analysis.get('momentum_direction')}, "
            f"target=${market_analysis.get('recommended_profit_target', 0):.2f}"
        )

        market_analysis = dict(market_analysis or {})
        recommended_grid_distance = self._safe_float(
            market_analysis.get("recommended_grid_distance"), 0.0012
        )
        fee_aware_min_step_pct = self._get_fee_aware_min_step_pct(bot)
        recommended_grid_distance = max(recommended_grid_distance, fee_aware_min_step_pct)
        recommended_grid_distance *= self._safe_float(
            bot.get("volatility_derisk_step_mult"), 1.0
        )
        market_analysis["recommended_grid_distance"] = recommended_grid_distance
        bot["effective_step_pct"] = recommended_grid_distance
        bot["fee_aware_min_step_pct"] = fee_aware_min_step_pct

        # Store analysis in bot for UI display
        bot["scalp_analysis"] = {
            "condition": market_condition.value,
            "momentum": market_analysis.get("momentum_direction"),
            "volatility": market_analysis.get("volatility_level"),
            "is_choppy": market_analysis.get("is_choppy"),
            "profit_target": market_analysis.get("recommended_profit_target"),
        }
        bot["scalp_live_target"] = None
        bot["scalp_live_quick_profit"] = None
        bot["scalp_live_min_profit"] = None
        bot["scalp_live_position_notional"] = None

        # Fee-aware adaptive minimum profit baseline (display only).
        # The actual exit gate should use each live position's notional, not the
        # bot's full planned notional, otherwise small filled positions can never
        # hit the displayed scalp target.
        adaptive_min_profit = self.scalp_pnl_service.calculate_adaptive_min_profit(
            notional=planned_notional,
            spread_pct=current_spread_pct,
        )
        bot["scalp_adaptive_min_profit"] = round(adaptive_min_profit, 4)

        # Opening-order gating (cooldown + no-trade conditions)
        skip_opening_orders = False
        skip_open_reason = None
        if bot.pop("_skip_opening_orders_for_margin", False):
            skip_opening_orders = True
            skip_open_reason = "Preserving margin for auto-margin"
        if bot.get("_volatility_block_opening_orders"):
            skip_opening_orders = True
            skip_open_reason = (
                f"Volatility de-risk ({bot.get('volatility_derisk_tier')})"
            )
        if failure_breaker_skip_opening_orders:
            skip_opening_orders = True
            skip_open_reason = failure_breaker_reason
        if not fast_refill_tick:
            try:
                in_cooldown, remaining = self.scalp_pnl_service.is_in_cooldown(symbol)
                if in_cooldown:
                    skip_opening_orders = True
                    skip_open_reason = f"Cooldown {int(remaining)}s remaining"
            except Exception as e:
                logger.debug("[%s] Scalp cooldown check failed: %s", symbol, e)

            try:
                skip_trade, reason = self.scalp_pnl_service.should_skip_trade(
                    symbol=symbol,
                    spread_pct=current_spread_pct,
                    volume_24h=0,
                    regime=market_condition.value if market_condition else "neutral",
                )
                if skip_trade:
                    skip_opening_orders = True
                    skip_open_reason = reason
            except Exception as e:
                logger.debug("[%s] Scalp skip-trade check failed: %s", symbol, e)

        # =============================================================================
        # 1. CHECK POSITIONS AND TAKE PROFIT
        # =============================================================================
        positions_closed = 0
        positions_resp = self.client.get_positions()
        positions_snapshot_ok = positions_resp.get("success")

        # Track total positions for grid replacement logic
        total_long = 0.0
        total_short = 0.0

        # Initialize position entry tracking if not exists
        if not isinstance(bot.get("position_entries"), dict):
            bot["position_entries"] = {}
        known_position_keys = set(bot["position_entries"].keys())
        active_position_keys = set()

        if positions_snapshot_ok:
            positions = positions_resp.get("data", {}).get("list", []) or []

            for pos in positions:
                if pos.get("symbol") != symbol:
                    continue

                side = pos.get("side")
                size = self._safe_float(pos.get("size"), 0.0)
                unrealized_pnl = self._safe_float(pos.get("unrealisedPnl"), 0.0)
                position_notional = self._safe_float(pos.get("positionValue"), 0.0)
                if position_notional <= 0:
                    mark_price = self._safe_float(pos.get("markPrice"), 0.0)
                    ref_price = mark_price if mark_price > 0 else last_price
                    position_notional = abs(size) * max(ref_price, 0.0)

                if not side or size <= 0:
                    continue

                base_targets = {
                    "min_profit": bot.get("_scalp_adapted_min", 0.20),
                    "quick_profit": bot.get("_scalp_adapted_quick", 0.30),
                    "target_profit": bot.get("_scalp_adapted_target", 0.60),
                    "max_target": bot.get("_scalp_adapted_max", bot.get("_scalp_adapted_target", 0.60) * 1.5),
                }

                position_adaptive_min_profit = (
                    self.scalp_pnl_service.calculate_adaptive_min_profit(
                        notional=position_notional or planned_notional,
                        spread_pct=current_spread_pct,
                        base_min_profit=base_targets["min_profit"]
                    )
                )
                position_scaled_targets = (
                    self.scalp_pnl_service.calculate_position_scaled_targets(
                        position_notional=position_notional or planned_notional,
                        market_analysis=market_analysis,
                        base_targets=base_targets,
                    )
                )
                bot["scalp_adaptive_min_profit_live"] = round(
                    position_adaptive_min_profit, 4
                )
                current_display_notional = self._safe_float(
                    bot.get("scalp_live_position_notional"), 0.0
                )
                if (position_notional or planned_notional) >= current_display_notional:
                    bot["scalp_live_position_notional"] = round(
                        position_notional or planned_notional, 4
                    )
                    bot["scalp_live_target"] = round(
                        position_scaled_targets.get("recommended_target", 0.0), 4
                    )
                    bot["scalp_live_quick_profit"] = round(
                        position_scaled_targets.get("quick_profit", 0.0), 4
                    )
                    bot["scalp_live_min_profit"] = round(
                        max(
                            position_adaptive_min_profit,
                            position_scaled_targets.get("min_profit", 0.0),
                        ),
                        4,
                    )

                if (
                    position_adaptive_min_profit > 0
                    and unrealized_pnl < position_adaptive_min_profit
                ):
                    continue

                # Accumulate totals for grid replacement
                if side == "Buy":
                    total_long += size
                elif side == "Sell":
                    total_short += size

                # Track position entry time
                position_key = f"{symbol}_{side}"
                current_time = self.client._get_now_ts()
                if position_key not in bot["position_entries"]:
                    bot["position_entries"][position_key] = current_time
                    self._mark_scalp_fill_event(bot)
                    logger.info(f"[{symbol}] Started tracking {side} position age")
                active_position_keys.add(position_key)

                position_age = current_time - bot["position_entries"][position_key]

                # Check if we should take profit
                should_exit, reason = self.scalp_pnl_service.should_take_profit(
                    unrealized_pnl=unrealized_pnl,
                    market_analysis=market_analysis,
                    position_side=side,
                    position_age_seconds=position_age,
                    position_notional=position_notional,
                    base_targets=base_targets,
                )

                if should_exit:
                    logger.info(f"[{symbol}] SCALP TP - {reason}")

                    # Close the position with market order
                    close_side = "Sell" if side == "Buy" else "Buy"

                    # Resolve position_idx for hedge mode safety
                    pidx = self._resolve_position_idx(
                        bot, symbol, close_side, reduce_only=True
                    )

                    close_result = self._create_order_checked(
                        bot=bot,
                        symbol=symbol,
                        side=close_side,
                        qty=size,
                        order_type="Market",
                        price=last_price,
                        reduce_only=True,
                        time_in_force="GTC",
                        order_link_id=self._build_close_order_link_id(bot_id, "SCTP"),
                        position_idx=pidx,
                    )

                    if close_result.get("success"):
                        positions_closed += 1
                        self._mark_scalp_fill_event(bot)
                        self.scalp_pnl_service.record_close(symbol)
                        # Update totals after market close
                        if side == "Buy":
                            total_long -= size
                        elif side == "Sell":
                            total_short -= size

                        # Update realized PnL tracking (approximate until
                        # update_bots_realized_pnl corrects with exchange closedPnl;
                        # deduct estimated taker fee to stay conservative)
                        estimated_fee = abs(position_notional) * 0.00055
                        current_realized = self._safe_float(
                            bot.get("realized_pnl"), 0.0
                        )
                        bot["realized_pnl"] = current_realized + unrealized_pnl - estimated_fee
                        # Clear position entry time
                        if position_key in bot["position_entries"]:
                            del bot["position_entries"][position_key]
                        logger.info(
                            f"[{symbol}] Scalp closed {side} position after {position_age:.1f}s, "
                            f"PnL=${unrealized_pnl:.2f} (est fee=${estimated_fee:.4f}), total realized=${bot['realized_pnl']:.2f}"
                        )
                    elif self._is_position_empty_close_result(close_result):
                        positions_closed += 1
                        self._mark_scalp_fill_event(bot)
                        self.scalp_pnl_service.record_close(symbol)
                        if side == "Buy":
                            total_long -= size
                        elif side == "Sell":
                            total_short -= size
                        if position_key in bot["position_entries"]:
                            del bot["position_entries"][position_key]
                        logger.info(
                            "[%s] Scalp TP close skipped: position already flat",
                            symbol,
                        )
                    elif self._is_ambiguous_order_result(close_result):
                        logger.warning(
                            "[%s] Scalp TP close AMBIGUOUS bot_id=%s: %s",
                            symbol,
                            bot.get("id"),
                            close_result.get("error")
                            or close_result.get("status")
                            or "unknown",
                        )
                        bot["_block_opening_orders"] = True
                    else:
                        self._hard_fail_close(
                            bot,
                            symbol,
                            "scalp_tp",
                            close_result.get("error"),
                        )

        missing_position_keys = known_position_keys - active_position_keys
        if positions_snapshot_ok and missing_position_keys:
            for position_key in missing_position_keys:
                bot["position_entries"].pop(position_key, None)
            self._mark_scalp_fill_event(bot, count=len(missing_position_keys))
            logger.debug(
                "[%s] Scalp fill detected via closed position(s): %s",
                symbol,
                ",".join(sorted(missing_position_keys)),
            )

        # =============================================================================
        # 2. PLACE NEW SCALP GRID ORDERS
        # =============================================================================
        if ai_block_opening_orders or skip_opening_orders:
            duplicate_cleanup = self._cancel_duplicate_bot_orders(bot, symbol)
            if duplicate_cleanup.get("cancelled_count"):
                logger.info(
                    "[%s] Removed %d duplicate scalp order(s) while opening was paused",
                    symbol,
                    duplicate_cleanup.get("cancelled_count", 0),
                )
            if ai_block_opening_orders:
                reason = "Opening guard active"
            else:
                reason = f"Scalp skip opening: {skip_open_reason}"
            logger.info(
                f"[{symbol}] {reason} - skipping scalp opening orders"
            )
            bot["last_run_at"] = now_iso
            bot["last_warning"] = reason
            bot["last_error"] = None
            self._set_bot_current_price(bot, last_price, symbol=symbol)
            self.bot_storage.save_bot(bot)
            return bot
        # Scalp mode: use bot's grid_count setting like other modes
        grid_count = int(bot.get("grid_count", 0))
        runtime_grid_cap = int(bot.get("runtime_grid_count_cap") or 0)
        if runtime_grid_cap > 0:
            grid_count = min(grid_count, runtime_grid_cap)
        MAX_SCALP_ORDERS = max(
            2,
            grid_count if grid_count > 0 else 20,
        )
        opening_order_cap = self._get_scalp_effective_opening_order_cap(
            bot, MAX_SCALP_ORDERS
        )

        open_orders_response = self.client.get_open_orders(
            symbol,
            limit=200,
            skip_cache=True,
        )
        order_list = []
        if open_orders_response.get("success"):
            order_list = open_orders_response.get("data", {}).get("list", []) or []
        duplicate_cleanup = self._cancel_duplicate_bot_orders(
            bot,
            symbol,
            order_list=order_list,
        )
        if duplicate_cleanup.get("cancelled_count"):
            order_list = duplicate_cleanup.get("order_list", []) or []
        order_snapshot = self._snapshot_open_orders(order_list, tick_size)
        existing_order_prices = order_snapshot["existing_order_prices"]
        existing_order_prices_list = order_snapshot["existing_order_prices_list"]
        existing_orders_with_ids = order_snapshot["existing_orders_with_ids"]
        current_order_count = order_snapshot["current_order_count"]
        current_opening_order_count = order_snapshot["current_opening_order_count"]
        current_opening_buy_count = order_snapshot["current_opening_buy_count"]
        current_opening_sell_count = order_snapshot["current_opening_sell_count"]
        if (
            current_opening_order_count > 0
            and not self._safe_float(bot.get("scalp_learned_opening_order_cap"), 0)
        ):
            failure_state = bot.get("_failure_breaker") or {}
            counts = failure_state.get("counts") or {}
            margin_failures = (
                int(counts.get("insufficient_margin", 0) or 0)
                + int(counts.get("insufficient_margin_pruned", 0) or 0)
                + int(counts.get("insufficient_margin_guard", 0) or 0)
            )
            if margin_failures > 0:
                opening_order_cap = self._learn_scalp_opening_order_cap(
                    bot=bot,
                    opening_order_count=current_opening_order_count,
                    requested_cap=MAX_SCALP_ORDERS,
                    now_iso=now_iso,
                    reason="cooldown_seed",
                )
        trimmed_ids = self._trim_opening_orders_to_cap(
            symbol=symbol,
            last_price=last_price,
            existing_orders_with_ids=existing_orders_with_ids,
            max_open_orders=opening_order_cap,
        )
        if trimmed_ids:
            order_list = [
                order for order in order_list if order.get("orderId") not in trimmed_ids
            ]
            order_snapshot = self._snapshot_open_orders(order_list, tick_size)
            existing_order_prices = order_snapshot["existing_order_prices"]
            existing_order_prices_list = order_snapshot["existing_order_prices_list"]
            existing_orders_with_ids = order_snapshot["existing_orders_with_ids"]
            current_order_count = order_snapshot["current_order_count"]
            current_opening_order_count = order_snapshot["current_opening_order_count"]
            current_opening_buy_count = order_snapshot["current_opening_buy_count"]
            current_opening_sell_count = order_snapshot["current_opening_sell_count"]

        available_slots = max(0, MAX_SCALP_ORDERS - current_order_count)

        # =============================================================================
        # FIXED GRID LEVELS: Use stored center price, only recenter when price moves
        # This makes scalp_pnl behave like other modes with fixed grid replacement
        # =============================================================================
        scalp_center = bot.get("scalp_grid_center", 0)

        # Dynamic recenter threshold based on grid distance
        # Recenter when price moves materially, with cooldown to avoid scalp churn.
        recommended_dist = market_analysis.get("recommended_grid_distance", 0.0012)
        SCALP_RECENTER_THRESHOLD = max(
            SCALP_RECENTER_MIN_DEVIATION_PCT,
            recommended_dist * SCALP_RECENTER_GRID_MULTIPLIER,
        )

        # Force recenter if we just closed a position (capture new range)
        if positions_closed > 0:
            logger.info(
                f"[{symbol}] Scalp recenter triggered by position close (resetting grid center)"
            )
            bot["scalp_grid_center"] = 0
            scalp_center = 0

        # Initialize or recenter grid
        if scalp_center <= 0:
            # First run - set center to current price
            scalp_center = last_price
            bot["scalp_grid_center"] = scalp_center
            logger.info(
                f"[{symbol}] Scalp grid initialized at center ${scalp_center:.6f}"
            )
        else:
            # Check if price moved too far from center
            price_move_pct = abs(last_price - scalp_center) / scalp_center
            recenter_cooldown_active = False
            last_scalp_recenter_at = bot.get("last_scalp_recenter_at")
            if last_scalp_recenter_at:
                try:
                    last_recenter_dt = datetime.fromisoformat(
                        str(last_scalp_recenter_at).replace("Z", "+00:00")
                    )
                    elapsed = (
                        datetime.now(timezone.utc) - last_recenter_dt
                    ).total_seconds()
                    recenter_cooldown_active = elapsed < SCALP_RECENTER_COOLDOWN_SEC
                except Exception:
                    recenter_cooldown_active = False
            # ONLY recenter if NO position is open to prevent moving the grid while in a trade
            if (
                price_move_pct >= SCALP_RECENTER_THRESHOLD
                and total_long == 0
                and total_short == 0
                and not recenter_cooldown_active
            ):
                old_center = scalp_center
                candidate_center = last_price

                # Cancel ALL orders for THIS bot from old grid to ensure a clean slate
                # This prevents orphaned orders from blocking new tight grid placement
                logger.info(
                    f"[{symbol}] Scalp recenter: Purging bot orders for clean slate"
                )
                recenter_cancelled = self._cancel_bot_orders(
                    bot, symbol, cancel_all=True
                )

                # Rebuild the open-order snapshot from exchange state. Only adopt the
                # new center after the old ladder is actually gone.
                refreshed_orders_resp = self.client.get_open_orders(
                    symbol=symbol,
                    limit=200,
                    skip_cache=True,
                )
                if refreshed_orders_resp.get("success"):
                    order_list = refreshed_orders_resp.get("data", [])
                    if isinstance(order_list, dict):
                        order_list = order_list.get("list", [])
                    order_snapshot = self._snapshot_open_orders(order_list, tick_size)
                    existing_order_prices = order_snapshot["existing_order_prices"]
                    existing_order_prices_list = order_snapshot[
                        "existing_order_prices_list"
                    ]
                    existing_orders_with_ids = order_snapshot["existing_orders_with_ids"]
                    current_order_count = order_snapshot["current_order_count"]
                    current_opening_order_count = order_snapshot[
                        "current_opening_order_count"
                    ]
                    current_opening_buy_count = order_snapshot[
                        "current_opening_buy_count"
                    ]
                    current_opening_sell_count = order_snapshot[
                        "current_opening_sell_count"
                    ]
                else:
                    # If we cannot verify the cancel, keep the old center and assume
                    # there may still be orders live. That avoids stacking a second grid.
                    current_order_count = max(0, current_order_count - recenter_cancelled)
                    current_opening_order_count = max(
                        0, current_opening_order_count - recenter_cancelled
                    )
                    if current_order_count <= 0:
                        order_list = []
                        order_snapshot = self._snapshot_open_orders(order_list, tick_size)
                        existing_order_prices = order_snapshot["existing_order_prices"]
                        existing_order_prices_list = order_snapshot[
                            "existing_order_prices_list"
                        ]
                        existing_orders_with_ids = order_snapshot[
                            "existing_orders_with_ids"
                        ]
                        current_opening_order_count = order_snapshot[
                            "current_opening_order_count"
                        ]
                        current_opening_buy_count = order_snapshot[
                            "current_opening_buy_count"
                        ]
                        current_opening_sell_count = order_snapshot[
                            "current_opening_sell_count"
                        ]

                available_slots = max(0, MAX_SCALP_ORDERS - current_order_count)

                if current_order_count <= 0:
                    scalp_center = candidate_center
                    bot["scalp_grid_center"] = scalp_center
                    bot["last_scalp_recenter_at"] = now_iso
                    logger.info(
                        f"[{symbol}] Scalp grid recentered ${old_center:.6f} -> ${scalp_center:.6f} "
                        f"(price moved {price_move_pct * 100:.1f}%)"
                    )
                    if recenter_cancelled > 0:
                        logger.info(
                            f"[{symbol}] Cancelled {recenter_cancelled} orders from old grid "
                            f"(resetting for clean slate)"
                        )
                else:
                    scalp_center = old_center
                    bot["scalp_grid_center"] = old_center
                    logger.warning(
                        f"[{symbol}] Scalp recenter deferred: {current_order_count} orders "
                        f"still open after purge; keeping center ${old_center:.6f}"
                    )
            elif (
                price_move_pct >= SCALP_RECENTER_THRESHOLD
                and total_long == 0
                and total_short == 0
                and recenter_cooldown_active
            ):
                logger.debug(
                    f"[{symbol}] Scalp recenter cooldown active - price move "
                    f"{price_move_pct * 100:.2f}% exceeds threshold but cooldown not elapsed"
                )

        cleanup_result = self._cleanup_stale_scalp_orders(
            symbol=symbol,
            scalp_center=scalp_center,
            recommended_dist=recommended_dist,
            tick_size=tick_size,
            max_open_orders=MAX_SCALP_ORDERS,
            current_order_list=order_list,
        )
        orders_cancelled = cleanup_result["orders_cancelled"]
        order_list = cleanup_result["order_list"]
        order_snapshot = cleanup_result["order_snapshot"]
        existing_order_prices = order_snapshot["existing_order_prices"]
        existing_order_prices_list = order_snapshot["existing_order_prices_list"]
        existing_orders_with_ids = order_snapshot["existing_orders_with_ids"]
        current_order_count = order_snapshot["current_order_count"]
        current_opening_order_count = order_snapshot["current_opening_order_count"]
        current_opening_buy_count = order_snapshot["current_opening_buy_count"]
        current_opening_sell_count = order_snapshot["current_opening_sell_count"]
        available_slots = cleanup_result["available_slots"]

        flat_position = total_long <= 0.0 and total_short <= 0.0

        buy_levels, sell_levels = self._resolve_locked_scalp_grid_levels(
            bot=bot,
            symbol=symbol,
            scalp_center=scalp_center,
            market_analysis=market_analysis,
            tick_size=tick_size,
            grid_count=MAX_SCALP_ORDERS,
            force_balanced=flat_position
            and not bool(market_analysis.get("should_follow_trend", True)),
            now_iso=now_iso,
        )
        buy_levels, sell_levels = self._cap_levels_by_proximity(
            buy_levels=buy_levels,
            sell_levels=sell_levels,
            last_price=last_price,
            max_total=MAX_SCALP_ORDERS,
        )

        SCALP_ORDER_TOLERANCE_PCT = self._get_scalp_order_tolerance_pct(
            recommended_dist
        )

        buy_levels_needed = []
        for lvl in buy_levels:
            rounded_lvl = self._round_to_step(lvl, tick_size, round_down=False)
            has_exact = rounded_lvl in existing_order_prices
            has_near = self._has_order_near_level(
                lvl, existing_order_prices_list, SCALP_ORDER_TOLERANCE_PCT
            )
            if not has_exact and not has_near:
                buy_levels_needed.append(lvl)

        sell_levels_needed = []
        for lvl in sell_levels:
            rounded_lvl = self._round_to_step(lvl, tick_size, round_down=False)
            has_exact = rounded_lvl in existing_order_prices
            has_near = self._has_order_near_level(
                lvl, existing_order_prices_list, SCALP_ORDER_TOLERANCE_PCT
            )
            if not has_exact and not has_near:
                sell_levels_needed.append(lvl)

        # Log grid status with detailed breakdown
        total_generated = len(buy_levels) + len(sell_levels)
        total_levels_needed = len(buy_levels_needed) + len(sell_levels_needed)
        logger.info(
            f"[{symbol}] Scalp grid - generated={total_generated} levels "
            f"(buys={len(buy_levels)}, sells={len(sell_levels)}), "
            f"needed={total_levels_needed} (buys={len(buy_levels_needed)}, sells={len(sell_levels_needed)}), "
            f"current_orders={current_order_count}, opening_orders={current_opening_order_count}/{opening_order_cap}, "
            f"available_slots={available_slots}, grid_count={grid_count}"
        )

        # Debug: Log existing orders and generated levels
        if existing_order_prices_list:
            logger.debug(
                f"[{symbol}] Existing order prices: {sorted(existing_order_prices_list)[:10]}..."
            )
        logger.debug(
            f"[{symbol}] Buy levels generated: {[f'{p:.6f}' for p in buy_levels[:5]]}..."
        )
        logger.debug(
            f"[{symbol}] Sell levels generated: {[f'{p:.6f}' for p in sell_levels[:5]]}..."
        )

        structure_entry_blocks = self._evaluate_structure_entry_blocks(
            bot=bot,
            symbol=symbol,
            last_price=last_price,
            fast_indicators=fast_indicators,
            allow_buy=bool(buy_levels_needed),
            allow_sell=bool(sell_levels_needed),
        )
        structure_entry_skip_buys = structure_entry_blocks.get("skip_buy", False)
        structure_entry_skip_sells = structure_entry_blocks.get("skip_sell", False)
        structure_buy_reason = structure_entry_blocks.get("buy_reason", "")
        structure_sell_reason = structure_entry_blocks.get("sell_reason", "")

        # Calculate position size per order
        # For scalp mode, use smaller sizes to allow more frequent trades

        # 1. Unified Reserve Check
        available_balance = self._get_usdt_available_balance()
        reserve_usd, usable_investment = self._calculate_auto_margin_reserve(
            bot, investment, available_balance
        )
        effective_capital = usable_investment * leverage
        num_levels = max(len(buy_levels) + len(sell_levels), 4)  # At least 4 levels
        position_size = (effective_capital / num_levels) / last_price
        position_size *= self._safe_float(bot.get("volatility_derisk_size_mult"), 1.0)
        raw_position_size = position_size
        position_size = self._normalize_order_qty(
            bot=bot,
            symbol=symbol,
            side="Buy",
            raw_qty=position_size,
            price=last_price,
            reduce_only=False,
        )
        if not position_size:
            warning = self._activate_capital_starved_opening_block(
                bot,
                symbol=symbol,
                reason="qty_below_min",
                side="Buy",
                action="scalp_grid_order",
                opening_kind="refill",
                attempted_qty=raw_position_size,
                price=last_price,
                min_qty=instrument.get("min_order_qty"),
                min_notional_value=instrument.get("min_notional_value", 5.0),
                leverage=leverage,
                available_balance=available_balance,
                reserve_usd=reserve_usd,
            )
            bot["last_run_at"] = now_iso
            self._set_bot_current_price(bot, last_price, symbol=symbol)
            bot["last_skip_reason"] = "qty_below_min"
            min_order_qty = self._safe_float(instrument.get("min_order_qty"), 0.0)
            if min_order_qty > 0:
                bot["last_warning"] = warning
                bot["scalp_status"] = (
                    f"Waiting: qty {raw_position_size:.6f} < min {min_order_qty:.6f}"
                )
            else:
                bot["last_warning"] = warning
                bot["scalp_status"] = (
                    "Waiting: position size too small after normalization"
                )
            bot["last_error"] = None
            self.bot_storage.save_bot(bot)
            return bot

        min_notional_value = instrument.get("min_notional_value", 5.0)
        removed_buy_levels = 0
        removed_sell_levels = 0
        if min_notional_value:
            buy_levels, removed_buy_levels = self._filter_levels_below_min_notional(
                buy_levels, position_size, min_notional_value
            )
            sell_levels, removed_sell_levels = self._filter_levels_below_min_notional(
                sell_levels, position_size, min_notional_value
            )
            buy_levels_needed, removed_buy_needed = (
                self._filter_levels_below_min_notional(
                    buy_levels_needed, position_size, min_notional_value
                )
            )
            sell_levels_needed, removed_sell_needed = (
                self._filter_levels_below_min_notional(
                    sell_levels_needed, position_size, min_notional_value
                )
            )
            removed_buy_levels = max(removed_buy_levels, removed_buy_needed)
            removed_sell_levels = max(removed_sell_levels, removed_sell_needed)
            if removed_buy_levels or removed_sell_levels:
                logger.info(
                    f"[{symbol}] Scalp min-notional filter removed "
                    f"{removed_buy_levels} buy / {removed_sell_levels} sell levels "
                    f"at qty={position_size:.4f} (min=${min_notional_value:.2f})"
                )
                total_generated = len(buy_levels) + len(sell_levels)
                total_levels_needed = len(buy_levels_needed) + len(sell_levels_needed)

        skip_one_sided_min_notional, missing_side = (
            self._should_skip_flat_scalp_one_sided_grid(
                flat_position=flat_position,
                current_opening_buy_count=current_opening_buy_count,
                current_opening_sell_count=current_opening_sell_count,
                buy_levels_needed=buy_levels_needed,
                sell_levels_needed=sell_levels_needed,
            )
        )
        if skip_one_sided_min_notional:
            self._register_failure_breaker_event(
                bot, "one_sided_grid_prevented", now_ts=now_ts
            )
            cancelled_opening_orders = 0
            try:
                cancelled_opening_orders = self._cancel_opening_orders_only(bot, symbol)
            except Exception as cancel_err:
                logger.warning(
                    f"[{symbol}] Failed to cancel opening orders during min-notional one-sided guard: {cancel_err}"
                )
            survivor_side = "sell" if missing_side == "buy" else "buy"
            logger.warning(
                f"[{symbol}] SKIPPING {survivor_side} orders - min notional removed all "
                f"{missing_side} levels for a flat scalp grid. Preventing one-sided ladder."
            )
            bot["last_run_at"] = now_iso
            self._set_bot_current_price(bot, last_price, symbol=symbol)
            bot["last_skip_reason"] = "min_notional_one_sided_guard"
            bot["last_warning"] = (
                f"Flat scalp grid blocked: {missing_side} side below min notional"
            )
            bot["last_error"] = (
                "Min notional removed one side of flat scalp grid - opening orders skipped"
            )
            bot["scalp_status"] = (
                f"Waiting: {missing_side} side below min notional for balanced scalp grid"
            )
            if cancelled_opening_orders > 0:
                logger.info(
                    f"[{symbol}] Cancelled {cancelled_opening_orders} opening orders while blocking one-sided scalp grid"
                )
            self.bot_storage.save_bot(bot)
            return bot

        # Determine recommended side based on momentum
        recommended_side = self.scalp_pnl_service.get_recommended_side(market_analysis)

        orders_placed = 0
        skipped_reasons = {}
        buy_orders_placed = 0
        sell_orders_placed = 0
        buy_orders_failed_balance = 0
        import time as time_module

        cycle_ts = int(time_module.time() * 1000) % 1000000000
        seq = 0

        # Margin buffer check setup for scalp PnL mode
        available_balance = self._get_usdt_available_balance()
        margin_used = 0.0
        # 1. Unified Reserve Check for Margin Buffer
        reserve_usd, _ = self._calculate_auto_margin_reserve(
            bot, investment, available_balance
        )

        margin_per_order = (position_size * last_price) / max(leverage, 1.0)
        from config.strategy_config import MARGIN_BUFFER_ENABLED

        margin_buffer_active = MARGIN_BUFFER_ENABLED and available_balance > 0
        opening_order_margin_exhausted = False
        had_insufficient_margin = False
        orders_cancelled_for_margin = 0
        live_opening_order_count = current_opening_order_count
        far_orders = sorted(
            [
                (price, oid, side)
                for price, oid, side, is_ro in existing_orders_with_ids
                if not is_ro
            ],
            key=lambda x: abs(x[0] - last_price),
            reverse=True,
        )
        far_order_idx = 0

        # Place BUY orders
        # Logic:
        # 1. If we have a SHORT position, some BUY levels become EXITs (reduce_only=True)
        # 2. Remaining BUY levels are ENTRYs (reduce_only=False)
        # 3. If market strongly favors shorts, avoid new long entries (only allow exits)

        # Position-aware replacement counters
        pending_short_to_close = total_short

        # Determine global bias
        strong_short_bias = (
            not flat_position
            and
            recommended_side == "Sell"
            and market_analysis.get("momentum_strength", 0) > 0.6
        )

        side_open_margin_budget = None
        buy_margin_used = 0.0
        sell_margin_used = 0.0
        if (
            flat_position
            and margin_buffer_active
            and buy_levels_needed
            and sell_levels_needed
        ):
            side_open_margin_budget = max(
                0.0, (available_balance - reserve_usd) / 2.0
            )

        capital_starved_warning = None
        has_scalp_opening_candidates = bool(buy_levels_needed or sell_levels_needed)
        if has_scalp_opening_candidates and position_size > 0:
            opening_margin_budget = (
                side_open_margin_budget
                if flat_position
                and buy_levels_needed
                and sell_levels_needed
                and side_open_margin_budget is not None
                else max(0.0, available_balance - reserve_usd)
            )
            if margin_per_order > 0 and opening_margin_budget + 1e-9 < margin_per_order:
                margin_guard_reason = self._get_opening_margin_guard_reason(
                    available_balance=available_balance,
                    reserve_usd=reserve_usd,
                    required_margin=margin_per_order,
                )
                capital_starved_warning = self._activate_capital_starved_opening_block(
                    bot,
                    symbol=symbol,
                    reason=margin_guard_reason,
                    side="Buy" if buy_levels_needed else "Sell",
                    action="scalp_grid_order",
                    opening_kind="refill",
                    attempted_qty=position_size,
                    price=last_price,
                    min_qty=min_order_qty,
                    min_notional_value=min_notional_value,
                    leverage=leverage,
                    available_balance=available_balance,
                    reserve_usd=reserve_usd,
                    opening_order_cap=opening_order_cap,
                    current_order_count=current_order_count,
                    opening_order_count=current_opening_order_count,
                )
                opening_order_margin_exhausted = True
                skipped_reasons["capital_starved"] = (
                    skipped_reasons.get("capital_starved", 0) + 1
                )
            else:
                self._clear_capital_starved_opening_block(bot)
        else:
            self._clear_capital_starved_opening_block(bot)

        for level in buy_levels_needed:
            if orders_placed >= available_slots:
                break

            # Determine if this specific Buy is an EXIT or ENTRY
            is_exit = False
            if pending_short_to_close >= (position_size * 0.9):  # Allow 10% tolerance
                is_exit = True
                pending_short_to_close -= position_size

            # Use global bias if NOT an exit (i.e. if it's an entry)
            buy_reduce_only = is_exit or strong_short_bias

            if structure_entry_skip_buys and not buy_reduce_only:
                skipped_reasons[structure_buy_reason or "nearby resistance"] = (
                    skipped_reasons.get(structure_buy_reason or "nearby resistance", 0)
                    + 1
                )
                continue

            if opening_order_margin_exhausted and not buy_reduce_only:
                skipped_reasons["insufficient_margin_guard"] = (
                    skipped_reasons.get("insufficient_margin_guard", 0) + 1
                )
                continue
            if not buy_reduce_only and live_opening_order_count >= opening_order_cap:
                skipped_reasons["fundable_open_cap"] = (
                    skipped_reasons.get("fundable_open_cap", 0) + 1
                )
                continue

            # Check margin buffer for non-reduce_only orders
            if not buy_reduce_only and margin_buffer_active:
                if side_open_margin_budget is not None:
                    if buy_margin_used + margin_per_order > side_open_margin_budget:
                        logger.info(
                            f"[{symbol}] Scalp: Skipping Buy at {level:.6f} - buy-side margin budget exhausted"
                        )
                        buy_orders_failed_balance += 1
                        continue
                    buy_margin_used += margin_per_order
                    margin_used = buy_margin_used + sell_margin_used
                else:
                    remaining_balance = available_balance - margin_used
                    if remaining_balance - margin_per_order < reserve_usd:
                        logger.info(
                            f"[{symbol}] Scalp: Skipping Buy at {level:.6f} - margin buffer (remaining=${remaining_balance:.2f})"
                        )
                        buy_orders_failed_balance += 1
                        continue
                    margin_used += margin_per_order

            seq += 1
            # Build orderLinkId v2 with full bot UUID and intent
            intent = "close" if buy_reduce_only else "open"
            order_link_id = self._build_order_link_id(
                bot_id=bot_id,
                symbol=symbol,
                cycle_ts=cycle_ts,
                seq=seq,
                side="Buy",
                intent=intent,
            )

            price = self._round_price_for_order(level, tick_size, side="buy")

            # SPREAD CHECK: Prevent immediate fill/stacking
            if price >= last_price:
                adjusted_price = self._round_price_for_order(
                    last_price - tick_size, tick_size, side="buy"
                )
                if adjusted_price <= 0 or adjusted_price >= last_price:
                    logger.debug(
                        f"[{symbol}] Scalp: Skipping Buy at {price} - would cross spread (last=${last_price})"
                    )
                    skipped_reasons["spread_check"] = (
                        skipped_reasons.get("spread_check", 0) + 1
                    )
                    continue
                logger.debug(
                    f"[{symbol}] Scalp: Repriced Buy {price} -> {adjusted_price} (last=${last_price})"
                )
                price = adjusted_price

            result = self._create_order_checked(
                bot=bot,
                symbol=symbol,
                side="Buy",
                qty=position_size,
                order_type="Limit",
                price=price,
                reduce_only=buy_reduce_only,
                time_in_force="GTC",
                order_link_id=order_link_id,
                diagnostic_context={
                    "action": "scalp_grid_order",
                    "opening_kind": None if buy_reduce_only else "refill",
                },
            )

            if result.get("success"):
                orders_placed += 1
                buy_orders_placed += 1
                if not buy_reduce_only:
                    live_opening_order_count += 1
            elif result.get("skipped"):
                if not buy_reduce_only and margin_buffer_active:
                    if side_open_margin_budget is not None:
                        buy_margin_used = max(0.0, buy_margin_used - margin_per_order)
                        margin_used = buy_margin_used + sell_margin_used
                    else:
                        margin_used = max(0.0, margin_used - margin_per_order)
                skip_reason = (
                    result.get("skip_reason")
                    or result.get("error")
                    or "skipped"
                )
                skipped_reasons[skip_reason] = (
                    skipped_reasons.get(skip_reason, 0) + 1
                )
                continue
            else:
                if not buy_reduce_only and margin_buffer_active:
                    if side_open_margin_budget is not None:
                        buy_margin_used = max(0.0, buy_margin_used - margin_per_order)
                        margin_used = buy_margin_used + sell_margin_used
                    else:
                        margin_used = max(0.0, margin_used - margin_per_order)
                error_msg = result.get("error", "")
                if not buy_reduce_only and self._is_insufficient_margin_result(result):
                    had_insufficient_margin = True
                    self._record_insufficient_margin_event(
                        bot,
                        symbol=symbol,
                        side="Buy",
                        action="scalp_grid_order",
                        attempted_qty=position_size,
                        price=price,
                        available_balance=available_balance,
                        reserve_usd=reserve_usd,
                        margin_per_order=margin_per_order,
                        current_order_count=current_order_count,
                        opening_order_count=live_opening_order_count,
                        opening_order_cap=opening_order_cap,
                    )
                    self._register_failure_breaker_event(
                        bot, "insufficient_margin", now_ts=now_ts
                    )
                    buy_orders_failed_balance += 1
                    pruned_count, far_order_idx = self._prune_far_orders_for_margin(
                        symbol=symbol,
                        far_orders=far_orders,
                        start_idx=far_order_idx,
                        last_price=last_price,
                        target_level=level,
                    )
                    if pruned_count > 0:
                        live_opening_order_count = max(
                            0, live_opening_order_count - pruned_count
                        )
                        orders_cancelled_for_margin += pruned_count
                        refreshed_balance = self._get_usdt_available_balance()
                        if refreshed_balance > 0:
                            available_balance = refreshed_balance
                        skipped_reasons["insufficient_margin_pruned"] = (
                            skipped_reasons.get("insufficient_margin_pruned", 0) + 1
                        )
                        bot["last_skip_reason"] = "insufficient_margin_pruned"
                        continue
                    opening_order_margin_exhausted = True
                    learned_open_cap = self._learn_scalp_opening_order_cap(
                        bot=bot,
                        opening_order_count=live_opening_order_count,
                        requested_cap=MAX_SCALP_ORDERS,
                        now_iso=now_iso,
                        reason="insufficient_margin",
                    )
                    bot["last_skip_reason"] = "insufficient_margin"
                    bot["last_warning"] = "Scalp opening margin exhausted"
                    bot["last_error"] = (
                        "Insufficient available balance for new scalp entry orders"
                    )
                    skipped_reasons["insufficient_margin"] = (
                        skipped_reasons.get("insufficient_margin", 0) + 1
                    )
                    logger.warning(
                        f"[{symbol}] Margin exhausted for new scalp BUY entries - stopping further opening orders this cycle"
                    )
                    logger.info(
                        f"[{symbol}] Learned funded scalp opening cap: {learned_open_cap}"
                    )
                logger.debug(f"[{symbol}] Failed scalp Buy at {price}: {error_msg}")

        # CRITICAL: If ALL buy orders failed due to balance, skip sell orders to prevent one-sided grid
        if (
            len(buy_levels_needed) > 0
            and buy_orders_placed == 0
            and buy_orders_failed_balance > 0
        ):
            self._register_failure_breaker_event(
                bot, "one_sided_grid_prevented", now_ts=now_ts
            )
            logger.warning(
                f"[{symbol}] SKIPPING sell orders - all {buy_orders_failed_balance} buy orders failed "
                f"due to insufficient balance. One-sided grid would cause losses!"
            )
            bot["last_error"] = (
                "Insufficient balance for balanced grid - skipping orders"
            )
            # Still continue to log and save, but skip sell order placement
            total_levels_needed = len(buy_levels_needed)  # For logging
        else:
            # Place SELL orders
            # Logic:
            # 1. If we have a LONG position, some SELL levels become EXITs (reduce_only=True)
            # 2. Remaining SELL levels are ENTRYs (reduce_only=False)

            # Position-aware replacement counters
            pending_long_to_close = total_long

            # Determine global bias
            strong_long_bias = (
                not flat_position
                and
                recommended_side == "Buy"
                and market_analysis.get("momentum_strength", 0) > 0.6
            )

            for level in sell_levels_needed:
                if orders_placed >= available_slots:
                    break

                # Determine if this specific Sell is an EXIT or ENTRY
                is_exit = False
                if pending_long_to_close >= (
                    position_size * 0.9
                ):  # Allow 10% tolerance
                    is_exit = True
                    pending_long_to_close -= position_size

                # Use global bias if NOT an exit (i.e. if it's an entry)
                sell_reduce_only = is_exit or strong_long_bias

                if structure_entry_skip_sells and not sell_reduce_only:
                    skipped_reasons[structure_sell_reason or "nearby support"] = (
                        skipped_reasons.get(
                            structure_sell_reason or "nearby support", 0
                        )
                        + 1
                    )
                    continue

                if opening_order_margin_exhausted and not sell_reduce_only:
                    skipped_reasons["insufficient_margin_guard"] = (
                        skipped_reasons.get("insufficient_margin_guard", 0) + 1
                    )
                    continue
                if not sell_reduce_only and live_opening_order_count >= opening_order_cap:
                    skipped_reasons["fundable_open_cap"] = (
                        skipped_reasons.get("fundable_open_cap", 0) + 1
                    )
                    continue

                # Check margin buffer for non-reduce_only orders
                if not sell_reduce_only and margin_buffer_active:
                    if side_open_margin_budget is not None:
                        if sell_margin_used + margin_per_order > side_open_margin_budget:
                            logger.info(
                                f"[{symbol}] Scalp: Skipping Sell at {level:.6f} - sell-side margin budget exhausted"
                            )
                            continue
                        sell_margin_used += margin_per_order
                        margin_used = buy_margin_used + sell_margin_used
                    else:
                        remaining_balance = available_balance - margin_used
                        if remaining_balance - margin_per_order < reserve_usd:
                            logger.info(
                                f"[{symbol}] Scalp: Skipping Sell at {level:.6f} - margin buffer (remaining=${remaining_balance:.2f})"
                            )
                            continue
                        margin_used += margin_per_order

                seq += 1
                # Build orderLinkId v2 with full bot UUID and intent
                intent = "close" if sell_reduce_only else "open"
                order_link_id = self._build_order_link_id(
                    bot_id=bot_id,
                    symbol=symbol,
                    cycle_ts=cycle_ts,
                    seq=seq,
                    side="Sell",
                    intent=intent,
                )

                price = self._round_price_for_order(level, tick_size, side="sell")

                # SPREAD CHECK: Prevent immediate fill/stacking
                if price <= last_price:
                    adjusted_price = self._round_price_for_order(
                        last_price + tick_size, tick_size, side="sell"
                    )
                    if adjusted_price <= last_price:
                        logger.debug(
                            f"[{symbol}] Scalp: Skipping Sell at {price} - would cross spread (last=${last_price})"
                        )
                        skipped_reasons["spread_check"] = (
                            skipped_reasons.get("spread_check", 0) + 1
                        )
                        continue
                    logger.debug(
                        f"[{symbol}] Scalp: Repriced Sell {price} -> {adjusted_price} (last=${last_price})"
                    )
                    price = adjusted_price

                result = self._create_order_checked(
                    bot=bot,
                    symbol=symbol,
                    side="Sell",
                    qty=position_size,
                    order_type="Limit",
                    price=price,
                    reduce_only=sell_reduce_only,
                    time_in_force="GTC",
                    order_link_id=order_link_id,
                    diagnostic_context={
                        "action": "scalp_grid_order",
                        "opening_kind": None if sell_reduce_only else "refill",
                    },
                )

                if result.get("success"):
                    orders_placed += 1
                    sell_orders_placed += 1
                    if not sell_reduce_only:
                        live_opening_order_count += 1
                elif result.get("skipped"):
                    if not sell_reduce_only and margin_buffer_active:
                        if side_open_margin_budget is not None:
                            sell_margin_used = max(
                                0.0, sell_margin_used - margin_per_order
                            )
                            margin_used = buy_margin_used + sell_margin_used
                        else:
                            margin_used = max(0.0, margin_used - margin_per_order)
                    skip_reason = (
                        result.get("skip_reason")
                        or result.get("error")
                        or "skipped"
                    )
                    skipped_reasons[skip_reason] = (
                        skipped_reasons.get(skip_reason, 0) + 1
                    )
                    continue
                else:
                    if not sell_reduce_only and margin_buffer_active:
                        if side_open_margin_budget is not None:
                            sell_margin_used = max(
                                0.0, sell_margin_used - margin_per_order
                            )
                            margin_used = buy_margin_used + sell_margin_used
                        else:
                            margin_used = max(0.0, margin_used - margin_per_order)
                    error_msg = result.get("error", "")
                    if not sell_reduce_only and self._is_insufficient_margin_result(
                        result
                    ):
                        had_insufficient_margin = True
                        self._record_insufficient_margin_event(
                            bot,
                            symbol=symbol,
                            side="Sell",
                            action="scalp_grid_order",
                            attempted_qty=position_size,
                            price=price,
                            available_balance=available_balance,
                            reserve_usd=reserve_usd,
                            margin_per_order=margin_per_order,
                            current_order_count=current_order_count,
                            opening_order_count=live_opening_order_count,
                            opening_order_cap=opening_order_cap,
                        )
                        self._register_failure_breaker_event(
                            bot, "insufficient_margin", now_ts=now_ts
                        )
                        pruned_count, far_order_idx = self._prune_far_orders_for_margin(
                            symbol=symbol,
                            far_orders=far_orders,
                            start_idx=far_order_idx,
                            last_price=last_price,
                            target_level=level,
                        )
                        if pruned_count > 0:
                            live_opening_order_count = max(
                                0, live_opening_order_count - pruned_count
                            )
                            orders_cancelled_for_margin += pruned_count
                            refreshed_balance = self._get_usdt_available_balance()
                            if refreshed_balance > 0:
                                available_balance = refreshed_balance
                            skipped_reasons["insufficient_margin_pruned"] = (
                                skipped_reasons.get("insufficient_margin_pruned", 0) + 1
                            )
                            bot["last_skip_reason"] = "insufficient_margin_pruned"
                            continue
                        opening_order_margin_exhausted = True
                        learned_open_cap = self._learn_scalp_opening_order_cap(
                            bot=bot,
                            opening_order_count=live_opening_order_count,
                            requested_cap=MAX_SCALP_ORDERS,
                            now_iso=now_iso,
                            reason="insufficient_margin",
                        )
                        bot["last_skip_reason"] = "insufficient_margin"
                        bot["last_warning"] = "Scalp opening margin exhausted"
                        bot["last_error"] = (
                            "Insufficient available balance for new scalp entry orders"
                        )
                        skipped_reasons["insufficient_margin"] = (
                            skipped_reasons.get("insufficient_margin", 0) + 1
                        )
                        logger.warning(
                            f"[{symbol}] Margin exhausted for new scalp SELL entries - stopping further opening orders this cycle"
                        )
                        logger.info(
                            f"[{symbol}] Learned funded scalp opening cap: {learned_open_cap}"
                        )
                    logger.debug(
                        f"[{symbol}] Failed scalp Sell at {price}: {error_msg}"
                    )

        # Log final placement summary with position details
        logger.info(
            f"[{symbol}] Scalp orders placed this cycle: {orders_placed}/{total_levels_needed} "
            f"(buys={buy_orders_placed}, sells={sell_orders_placed}, pos_L={total_long:.2f}, pos_S={total_short:.2f})"
        )
        if not had_insufficient_margin:
            opening_order_cap = self._maybe_relax_scalp_opening_order_cap(
                bot=bot,
                current_opening_order_count=live_opening_order_count,
                requested_cap=MAX_SCALP_ORDERS,
                available_balance=available_balance,
                reserve_usd=reserve_usd,
                margin_per_order=margin_per_order,
                now_iso=now_iso,
            )
        if orders_placed > 0 or positions_closed > 0:
            self._clear_failure_breaker(bot)
        if skipped_reasons:
            reasons_str = ", ".join([f"{k}:{v}" for k, v in skipped_reasons.items()])
            logger.info(f"[{symbol}] ⏭️ Scalp skips: [{reasons_str}]")

        # Log summary
        if orders_placed > 0 or positions_closed > 0 or orders_cancelled > 0:
            logger.info(
                f"[{symbol}] Scalp cycle complete - "
                f"closed={positions_closed}, placed={orders_placed}, cancelled={orders_cancelled}, "
                f"condition={market_condition.value}"
            )

        # =============================================================================
        # TREND PROTECTION (NEW - Feature #5)
        # =============================================================================
        # Detect strong trends and close opposite-direction positions
        if (
            self.trend_protection_service
            and current_mode in ("neutral", "long", "short")
            and bot.get("trend_protection_enabled", True)
        ):
            try:
                from config.strategy_config import ENABLE_TREND_PROTECTION

                if ENABLE_TREND_PROTECTION:
                    # Detect trend using multi-indicator confidence scoring
                    trend_result = self.trend_protection_service.detect_trend(
                        symbol=symbol,
                        indicators=fast_indicators,
                    )

                    trend_direction = trend_result.get("trend_direction")
                    confidence_score = trend_result.get("confidence_score", 0)
                    should_act = trend_result.get("should_act", False)

                    # Log trend detection
                    if should_act:
                        logger.info(
                            f"[{symbol}] 🔍 Strong {trend_direction}trend detected "
                            f"(confidence={confidence_score}/100, signals={trend_result.get('signals')})"
                        )

                    # Check if we have a position that opposes the trend
                    positions_resp = self.client.get_positions()
                    if positions_resp.get("success"):
                        positions = positions_resp.get("data", {}).get("list", []) or []
                        symbol_position = next(
                            (p for p in positions if p.get("symbol") == symbol), None
                        )

                        if symbol_position:
                            position_size = self._safe_float(
                                symbol_position.get("size"), 0
                            )
                            if position_size > 0:
                                position_side = symbol_position.get(
                                    "side"
                                )  # "Buy" or "Sell"
                                unrealized_pnl = self._safe_float(
                                    symbol_position.get("unrealisedPnl"), 0
                                )

                                # Check if position should be closed due to trend
                                close_decision = (
                                    self.trend_protection_service.should_close_position(
                                        trend_result=trend_result,
                                        position_side=position_side,
                                        position_unrealized_pnl=unrealized_pnl,
                                    )
                                )

                                if close_decision.get("should_close"):
                                    logger.warning(
                                        f"[{symbol}] ⚠️ TREND PROTECTION TRIGGERED - {close_decision.get('reason')}"
                                    )

                                    # Close the position via market order
                                    close_resp = self._close_position_or_hard_fail(
                                        bot, symbol, "trend_protection"
                                    )
                                    if close_resp.get("success"):
                                        positions_closed += 1
                                        logger.info(
                                            f"[{symbol}] ✅ Closed {position_side} position due to trend protection "
                                            f"(PnL=${unrealized_pnl:.2f}, trend={trend_direction}, confidence={confidence_score})"
                                        )

                                        # Update bot state
                                        bot["trend_protection_triggered"] = True
                                        bot["trend_protection_reason"] = (
                                            close_decision.get("reason")
                                        )
                                        bot["trend_protection_pnl"] = unrealized_pnl
                                    else:
                                        logger.error(
                                            f"[{symbol}] ❌ Failed to close position via trend protection: "
                                            f"{close_resp.get('error')}"
                                        )
                                else:
                                    # Position aligned with trend or confidence too low
                                    logger.debug(
                                        f"[{symbol}] {close_decision.get('reason')}"
                                    )

            except Exception as e:
                if isinstance(e, RuntimeError):
                    raise
                logger.warning(f"[{symbol}] Trend protection check failed: {e}")

        # =============================================================================
        # QUICK PROFIT CHECK for Dynamic/Trailing Modes (Long, Short, Neutral)
        # =============================================================================
        # Check for quick profit opportunity before full TP check
        # This allows partial position closes for small gains ($0.10-$0.20)
        try:
            self._run_quick_profit_check(
                bot=bot,
                symbol=symbol,
                last_price=last_price,
                fast_indicators=fast_indicators,
            )
        except Exception as e:
            logger.warning(f"[{symbol}] Quick profit check failed: {e}")

        # =============================================================================
        # Feature #8: Smart Take-Profit Service
        # =============================================================================
        # Calculate and monitor automatic take-profit targets based on volatility, mode, and profile
        if (
            self.take_profit_service
            and current_mode in ("neutral", "long", "short")
            and bot.get("auto_take_profit_enabled", True)
        ):
            try:
                from config.strategy_config import ENABLE_AUTOMATIC_TAKE_PROFIT

                if ENABLE_AUTOMATIC_TAKE_PROFIT:
                    # Calculate TP target based on volatility, mode, and profile
                    tp_result = self.take_profit_service.calculate_take_profit(
                        symbol=symbol,
                        mode=current_mode,
                        current_price=last_price,
                        grid_lower=lower_bound,
                        grid_upper=upper_bound,
                        atr_pct=atr_pct,
                        bbw_pct=bbw_pct,
                        profile=profile,
                        bot_investment=investment,
                        bot_leverage=leverage,
                    )

                    if tp_result.get("enabled"):
                        # Calculate absolute TP target in USDT
                        tp_target_usdt = (
                            self.take_profit_service.calculate_tp_usdt_target(
                                bot_investment=investment,
                                tp_pct=tp_result.get("tp_pct", 0),
                            )
                        )

                        # Store TP info in bot state for monitoring
                        bot["tp_target_usdt"] = tp_target_usdt
                        bot["tp_pct"] = tp_result.get("tp_pct")
                        bot["tp_price_distance_pct"] = tp_result.get(
                            "tp_price_distance_pct"
                        )
                        bot["tp_method"] = tp_result.get("tp_method")

                        # Log TP calculation (only once or when significant change)
                        if (
                            not bot.get("tp_logged")
                            or abs(tp_target_usdt - bot.get("tp_target_usdt_prev", 0))
                            > 0.1
                        ):
                            logger.info(
                                f"[{symbol}] 💰 TP target ${tp_target_usdt:.2f} "
                                f"({float(tp_result.get('tp_pct') or 0) * 100:.2f}% of investment, "
                                f"{float(tp_result.get('tp_price_distance_pct') or 0) * 100:.3f}% price move, "
                                f"method={tp_result.get('tp_method')})"
                            )
                            bot["tp_logged"] = True
                            bot["tp_target_usdt_prev"] = tp_target_usdt

                        # Check if we have a position to monitor for TP
                        positions_resp = self.client.get_positions()
                        if positions_resp.get("success"):
                            positions = (
                                positions_resp.get("data", {}).get("list", []) or []
                            )
                            symbol_position = next(
                                (p for p in positions if p.get("symbol") == symbol),
                                None,
                            )

                            if symbol_position:
                                position_size = self._safe_float(
                                    symbol_position.get("size"), 0
                                )
                                if position_size > 0:
                                    position_side = symbol_position.get(
                                        "side"
                                    )  # "Buy" or "Sell"
                                    unrealized_pnl = self._safe_float(
                                        symbol_position.get("unrealisedPnl"), 0
                                    )
                                    entry_price = self._safe_float(
                                        symbol_position.get("avgPrice"), 0
                                    )

                                    # Calculate how much price has moved from entry
                                    if entry_price > 0:
                                        price_moved_pct = (
                                            abs(last_price - entry_price) / entry_price
                                        )
                                    else:
                                        price_moved_pct = 0

                                    # =============================================================
                                    # Partial Take-Profit (scale out of position gradually)
                                    # =============================================================
                                    from config.strategy_config import (
                                        ENABLE_PARTIAL_TAKE_PROFIT,
                                        PARTIAL_TP_LEVELS,
                                        PARTIAL_TP_MIN_POSITION_USDT,
                                        PARTIAL_TP_COOLDOWN_SECONDS,
                                    )

                                    partial_tp_triggered = False
                                    if ENABLE_PARTIAL_TAKE_PROFIT:
                                        # Get position value in USDT
                                        position_value = self._safe_float(
                                            symbol_position.get("positionValue"), 0
                                        )

                                        # Get/init partial TP state from bot
                                        partial_tp_state = bot.get("partial_tp_state")

                                        # Check for partial TP
                                        partial_result = self.take_profit_service.calculate_partial_take_profit(
                                            entry_price=entry_price,
                                            current_price=last_price,
                                            position_side=position_side,
                                            position_size=position_size,
                                            position_value_usdt=position_value,
                                            partial_tp_state=partial_tp_state,
                                            tp_levels=bot.get("_atr_adaptive_tp_levels", PARTIAL_TP_LEVELS),
                                            min_position_usdt=PARTIAL_TP_MIN_POSITION_USDT,
                                            cooldown_seconds=PARTIAL_TP_COOLDOWN_SECONDS,
                                        )

                                        if partial_result.get("should_close"):
                                            close_qty = partial_result.get(
                                                "close_qty", 0
                                            )
                                            level_hit = (
                                                partial_result.get("level_hit", 0) + 1
                                            )
                                            close_pct = (
                                                partial_result.get("close_pct", 0) * 100
                                            )

                                            logger.info(
                                                f"[{symbol}] 📊 PARTIAL TP Level {level_hit} - "
                                                f"Closing {close_pct:.0f}% ({close_qty:.6f}) at "
                                                f"{partial_result.get('profit_pct', 0) * 100:.2f}% profit"
                                            )

                                            # Close partial position
                                            close_side = (
                                                "Sell"
                                                if position_side == "Buy"
                                                else "Buy"
                                            )
                                            partial_close_resp = self._create_order_checked(
                                                bot=bot,
                                                symbol=symbol,
                                                side=close_side,
                                                qty=close_qty,
                                                order_type="Market",
                                                price=last_price,
                                                reduce_only=True,
                                                time_in_force="GTC",
                                                order_link_id=self._build_close_order_link_id(bot_id, "FLAT"),
                                                full_close_qty=position_size,
                                            )

                                            if self._is_position_empty_close_result(
                                                partial_close_resp
                                            ):
                                                partial_tp_triggered = True
                                                positions_closed += 1
                                                bot["partial_tp_state"] = None
                                                logger.info(
                                                    "[%s] Partial TP close skipped: position already flat",
                                                    symbol,
                                                )
                                            elif partial_close_resp.get("success"):
                                                partial_tp_triggered = True
                                                positions_closed += 1
                                                logger.info(
                                                    f"[{symbol}] ✅ Partial TP executed - "
                                                    f"{partial_result.get('reason')}"
                                                )

                                                # Update bot state with new partial TP state
                                                bot["partial_tp_state"] = (
                                                    partial_result.get("new_state")
                                                )
                                                bot["last_partial_tp_level"] = level_hit
                                                bot["last_partial_tp_profit_pct"] = (
                                                    partial_result.get("profit_pct")
                                                )
                                            elif self._is_ambiguous_order_result(
                                                partial_close_resp
                                            ):
                                                logger.warning(
                                                    "[%s] Partial TP close AMBIGUOUS bot_id=%s: %s",
                                                    symbol,
                                                    bot.get("id"),
                                                    partial_close_resp.get("error")
                                                    or partial_close_resp.get("status")
                                                    or "unknown",
                                                )
                                                bot["_block_opening_orders"] = True
                                            else:
                                                self._hard_fail_close(
                                                    bot,
                                                    symbol,
                                                    "partial_tp",
                                                    partial_close_resp.get("error"),
                                                )
                                        else:
                                            # Update state even when not closing (tracks state)
                                            bot["partial_tp_state"] = (
                                                partial_result.get("new_state")
                                            )

                                    # Check if should take FULL profit (skip if partial TP just triggered)
                                    if not partial_tp_triggered:
                                        tp_decision = (
                                            self.take_profit_service.should_take_profit(
                                                unrealized_pnl=unrealized_pnl,
                                                tp_target_usdt=tp_target_usdt,
                                                price_moved_pct=price_moved_pct,
                                                tp_price_distance_pct=tp_result.get(
                                                    "tp_price_distance_pct", 0
                                                ),
                                                allow_early_exit=True,
                                                require_positive_pnl=True,
                                            )
                                        )

                                        if tp_decision.get("should_close"):
                                            logger.info(
                                                f"[{symbol}] 🎯 TAKE-PROFIT TRIGGERED - {tp_decision.get('reason')}"
                                            )

                                            # Close the position via market order
                                            close_resp = (
                                                self._close_position_or_hard_fail(
                                                    bot, symbol, "take_profit"
                                                )
                                            )
                                            if close_resp.get("success"):
                                                positions_closed += 1
                                                logger.info(
                                                    f"[{symbol}] ✅ Closed {position_side} position at TP "
                                                    f"(PnL=${unrealized_pnl:.2f}, target=${tp_target_usdt:.2f})"
                                                )
                                                self._record_exit_reason(
                                                    bot,
                                                    symbol=symbol,
                                                    mode=current_mode,
                                                    reason="take_profit",
                                                    unrealized_pnl=unrealized_pnl,
                                                    tp_target_usdt=tp_target_usdt,
                                                    tp_decision_reason=tp_decision.get("reason"),
                                                )

                                                # Update bot state
                                                bot["tp_triggered"] = True
                                                bot["tp_trigger_reason"] = (
                                                    tp_decision.get("reason")
                                                )
                                                bot["tp_actual_pnl"] = unrealized_pnl

                                                # Reset partial TP state when position fully closed
                                                bot["partial_tp_state"] = None
                                            else:
                                                logger.error(
                                                    f"[{symbol}] ❌ Failed to close position at TP: "
                                                    f"{close_resp.get('error')}"
                                                )
                                        else:
                                            # Not yet at TP target
                                            logger.debug(
                                                f"[{symbol}] {tp_decision.get('reason')}"
                                            )

            except Exception as e:
                if isinstance(e, RuntimeError):
                    raise
                logger.warning(f"[{symbol}] Take-profit check failed: {e}")

        # =============================================================================
        # AUTOMATIC ADAPTIVE STOP-LOSS (NEW - Feature #4)
        # =============================================================================
        # Calculate and set stop-loss automatically based on volatility + grid range
        if (
            self.stop_loss_service
            and current_mode in ("neutral", "long", "short")
            and bot.get("auto_stop_loss_enabled", True)
        ):
            try:
                from config.strategy_config import (
                    ENABLE_AUTOMATIC_STOP_LOSS,
                    SL_UPDATE_THRESHOLD_PCT,
                )

                if ENABLE_AUTOMATIC_STOP_LOSS:
                    # Get current position to check if SL needed
                    positions_resp = self.client.get_positions()
                    if positions_resp.get("success"):
                        positions = positions_resp.get("data", {}).get("list", []) or []
                        symbol_position = next(
                            (p for p in positions if p.get("symbol") == symbol), None
                        )

                        if symbol_position:
                            position_size = self._safe_float(
                                symbol_position.get("size"), 0
                            )
                            position_side = symbol_position.get(
                                "side"
                            )  # "Buy" or "Sell"

                            if position_size > 0:
                                # Calculate SL based on volatility, grid bounds, and profile
                                sl_result = self.stop_loss_service.calculate_stop_loss(
                                    symbol=symbol,
                                    mode=current_mode,
                                    current_price=last_price,
                                    grid_lower=lower_bound,
                                    grid_upper=upper_bound,
                                    atr_pct=atr_pct,
                                    bbw_pct=bbw_pct,
                                    profile=profile,
                                    bot_investment=investment,
                                    bot_leverage=leverage,
                                    account_equity=0,
                                    position_side=position_side,
                                    actual_entry_price=float(bot.get("actual_entry_price") or 0),
                                )

                                if sl_result.get("enabled"):
                                    new_sl_price = sl_result.get("sl_price")
                                    current_sl = bot.get("stop_loss_price")

                                    # Check if SL should be updated
                                    should_update = (
                                        self.stop_loss_service.should_update_stop_loss(
                                            current_sl=current_sl,
                                            new_sl=new_sl_price,
                                            current_price=last_price,
                                            threshold_pct=SL_UPDATE_THRESHOLD_PCT,
                                        )
                                    )

                                    if should_update:
                                        # Get tick size for rounding
                                        instrument = self._get_instrument_info(symbol)
                                        tick_size = (
                                            instrument.get("tick_size", 0.01)
                                            if instrument
                                            else 0.01
                                        )

                                        # Set SL via Bybit API
                                        sl_set_result = (
                                            self.stop_loss_service.set_stop_loss(
                                                symbol=symbol,
                                                position_side=position_side,
                                                sl_price=new_sl_price,
                                                tick_size=tick_size,
                                            )
                                        )

                                        if sl_set_result.get("success"):
                                            bot["stop_loss_price"] = sl_set_result.get(
                                                "sl_price"
                                            )
                                            bot["stop_loss_method"] = sl_result.get(
                                                "sl_method"
                                            )
                                            bot["stop_loss_distance_pct"] = (
                                                sl_result.get("sl_distance_pct")
                                            )
                                            bot["_sl_rejection_count"] = 0
                                            logger.info(
                                                f"[{symbol}] ✅ Updated SL to ${bot['stop_loss_price']:.8f} "
                                                f"({bot['stop_loss_distance_pct'] * 100:.2f}% from price, method={bot['stop_loss_method']})"
                                            )
                                        else:
                                            sl_rej = int(bot.get("_sl_rejection_count") or 0) + 1
                                            bot["_sl_rejection_count"] = sl_rej
                                            bot["_sl_last_rejection_at"] = time.time()
                                            sl_err = str(sl_set_result.get("error") or "unknown")[:120]
                                            bot["_sl_last_rejection_reason"] = sl_err
                                            if sl_rej >= strategy_cfg.SL_REJECTION_CRITICAL_THRESHOLD:
                                                self._emit_sl_failure_watchdog(
                                                    bot, symbol, sl_rej, "CRITICAL", sl_err,
                                                )
                                            logger.warning(
                                                f"[{symbol}] ⚠️ Failed to set SL: {sl_set_result.get('error')} (rejection #{sl_rej})"
                                            )
                                    else:
                                        logger.debug(
                                            f"[{symbol}] SL unchanged (current=${current_sl:.8f}, new=${new_sl_price:.8f})"
                                        )
                                else:
                                    logger.debug(
                                        f"[{symbol}] SL disabled - {sl_result.get('sl_method')}"
                                    )

            except Exception as e:
                logger.warning(f"[{symbol}] Stop-loss calculation/update failed: {e}")

        # =============================================================================
        # TRAILING STOP-LOSS (NEW - Smart Feature #14)
        # =============================================================================
        # Trail stop-loss behind price as position profits, locking in gains
        if self.stop_loss_service and current_mode in ("neutral", "long", "short"):
            try:
                from config.strategy_config import ENABLE_TRAILING_STOP_LOSS

                # Check if trailing SL is enabled globally and for this bot
                bot_trailing_enabled = bot.get(
                    "trailing_sl_enabled", True
                )  # Default: enabled

                if ENABLE_TRAILING_STOP_LOSS and bot_trailing_enabled:
                    # Get current position
                    positions_resp = self.client.get_positions()
                    if positions_resp.get("success"):
                        positions = positions_resp.get("data", {}).get("list", []) or []
                        symbol_position = next(
                            (p for p in positions if p.get("symbol") == symbol), None
                        )

                        if symbol_position:
                            position_size = self._safe_float(
                                symbol_position.get("size"), 0
                            )
                            position_side = symbol_position.get(
                                "side"
                            )  # "Buy" or "Sell"
                            entry_price = self._safe_float(
                                symbol_position.get("avgPrice"), 0
                            )
                            current_sl = self._safe_float(
                                symbol_position.get("stopLoss"), 0
                            )

                            if position_size > 0 and entry_price > 0:
                                # Get per-bot trailing SL config (overrides global)
                                trailing_config = {
                                    "activation_pct": bot.get(
                                        "trailing_sl_activation_pct"
                                    ),
                                    "distance_pct": bot.get("trailing_sl_distance_pct"),
                                }

                                # ATR-Based Dynamic Distance Optimization (Part of Audit)
                                # If no specific distance is set, use 1.2x ATR% for dynamic tracking
                                if (
                                    trailing_config.get("distance_pct") is None
                                    and atr_pct
                                ):
                                    dynamic_dist = atr_pct * 1.2
                                    # Clamp to sane bounds (0.1% to 2.0%)
                                    trailing_config["distance_pct"] = max(
                                        0.001, min(0.02, dynamic_dist)
                                    )
                                    logger.debug(
                                        f"[{symbol}] Trailing SL using ATR-dynamic distance: {trailing_config['distance_pct']:.4f}"
                                    )

                                # Remove None values so defaults are used
                                trailing_config = {
                                    k: v
                                    for k, v in trailing_config.items()
                                    if v is not None
                                }

                                # Calculate trailing SL
                                trailing_result = (
                                    self.stop_loss_service.calculate_trailing_stop_loss(
                                        symbol=symbol,
                                        position_side=position_side,
                                        entry_price=entry_price,
                                        current_price=last_price,
                                        current_sl=current_sl
                                        if current_sl > 0
                                        else None,
                                        atr_pct=atr_pct,
                                        config=trailing_config
                                        if trailing_config
                                        else None,
                                    )
                                )

                                if trailing_result.get("should_update"):
                                    new_sl_price = trailing_result.get("new_sl_price")

                                    # Get tick size for rounding
                                    instrument = self._get_instrument_info(symbol)
                                    tick_size = (
                                        instrument.get("tick_size", 0.01)
                                        if instrument
                                        else 0.01
                                    )

                                    # Set trailing SL via Bybit API
                                    sl_set_result = (
                                        self.stop_loss_service.set_stop_loss(
                                            symbol=symbol,
                                            position_side=position_side,
                                            sl_price=new_sl_price,
                                            tick_size=tick_size,
                                        )
                                    )

                                    if sl_set_result.get("success"):
                                        bot["trailing_sl_price"] = sl_set_result.get(
                                            "sl_price"
                                        )
                                        bot["trailing_sl_activated"] = True
                                        bot["stop_loss_price"] = sl_set_result.get(
                                            "sl_price"
                                        )
                                        bot["_sl_rejection_count"] = 0
                                        logger.info(
                                            f"[{symbol}] 📈 TRAILING SL updated to ${bot['trailing_sl_price']:.4f} "
                                            f"(profit: {trailing_result['profit_pct'] * 100:.2f}%, {trailing_result['reason']})"
                                        )
                                    else:
                                        sl_rej = int(bot.get("_sl_rejection_count") or 0) + 1
                                        bot["_sl_rejection_count"] = sl_rej
                                        bot["_sl_last_rejection_at"] = time.time()
                                        sl_err = str(sl_set_result.get("error") or "unknown")[:120]
                                        bot["_sl_last_rejection_reason"] = sl_err
                                        if sl_rej >= strategy_cfg.SL_REJECTION_CRITICAL_THRESHOLD:
                                            self._emit_sl_failure_watchdog(
                                                bot, symbol, sl_rej, "CRITICAL", sl_err,
                                            )
                                        logger.warning(
                                            f"[{symbol}] ⚠️ Failed to set trailing SL: {sl_set_result.get('error')} (rejection #{sl_rej})"
                                        )
                                else:
                                    logger.debug(
                                        f"[{symbol}] Trailing SL not updated - {trailing_result.get('reason')}"
                                    )

            except Exception as e:
                logger.warning(f"[{symbol}] Trailing stop-loss check failed: {e}")

        # Sync PnL
        try:
            self.pnl_service.sync_closed_pnl(symbol)
        except Exception as e:
            logger.warning(f"[{symbol}] PnL sync failed: {e}")

        # Update bot state (but preserve user's grid_count setting)
        bot["last_run_at"] = now_iso
        bot["last_error"] = None
        self._set_bot_current_price(bot, last_price, symbol=symbol)
        bot["orders_placed"] = orders_placed
        bot["positions_closed"] = positions_closed
        # Note: Do NOT override grid_count - it's a user setting, not a calculated value
        # bot["grid_count"] should remain as user set it (e.g., 17)

        self.bot_storage.save_bot(bot)
        return bot

    def _place_initial_entry(
        self,
        bot: Dict[str, Any],
        symbol: str,
        last_price: float,
        mode: str,
        now_iso: str,
    ) -> bool:
        """
        Place an initial market order at current price when bot starts.

        This allows entering a position immediately instead of waiting for
        price to reach a grid level.

        Args:
            bot: Bot configuration
            symbol: Trading symbol
            last_price: Current market price
            mode: Trading mode (long/short)
            now_iso: Current timestamp

        Returns:
            True if order was placed successfully, False otherwise
        """
        bot_id = bot.get("id", "unknown")
        investment = self._safe_float(bot.get("investment"), DEFAULT_INVESTMENT_USDT)
        leverage = self._safe_float(bot.get("leverage"), DEFAULT_LEVERAGE)

        try:
            # Get instrument info for quantity calculations
            instruments = self.client.get_instruments_info(symbol)
            inst_list = instruments.get("data", {}).get("list", [])
            if not inst_list:
                logger.error(f"[{symbol}] No instrument info for {symbol}")
                return False

            inst = inst_list[0]
            lot_filter = inst.get("lotSizeFilter", {})

            def _to_positive(value):
                try:
                    num = float(value)
                except (TypeError, ValueError):
                    return None
                return num if num > 0 else None

            qty_step = _to_positive(lot_filter.get("qtyStep"))
            min_qty = _to_positive(lot_filter.get("minOrderQty"))
            min_notional = float(
                lot_filter.get("minNotionalValue")
                or lot_filter.get("minOrderAmt")
                or 5.0
            )
            if not qty_step or not min_qty:
                logger.error(
                    f"[{symbol}] Missing qty filters (minQty={min_qty}, step={qty_step})"
                )
                return False

            # Calculate: Unified Reserve Check
            available_balance = self._get_usdt_available_balance()
            reserve_usd, usable_investment = self._calculate_auto_margin_reserve(
                bot, investment, available_balance
            )
            grid_count = max(int(bot.get("grid_count") or 8), 1)
            effective_capital = usable_investment * max(leverage, 1.0) / grid_count
            position_qty = effective_capital / last_price

            # Determine side based on mode
            entry_side = "Buy" if mode == "long" else "Sell"
            opening_qty_adjustment = self._cap_directional_opening_qty_to_affordability(
                mode=mode,
                planned_qty=position_qty,
                price=last_price,
                leverage=leverage,
                qty_step=qty_step,
                min_qty=min_qty,
                min_notional_value=min_notional,
                available_balance=available_balance,
                reserve_usd=reserve_usd,
            )
            opening_sizing = self._build_directional_opening_sizing_fields(
                planned_qty=position_qty,
                price=last_price,
                leverage=leverage,
                opening_qty_adjustment=opening_qty_adjustment,
            )
            if opening_qty_adjustment.get("adjusted"):
                logger.info(
                    "[%s] Initial entry qty capped by affordability: %.8f -> %.8f "
                    "(notional %.2f -> %.2f, opening_margin %.2f)",
                    symbol,
                    position_qty,
                    opening_qty_adjustment["qty"],
                    opening_qty_adjustment["planned_notional"],
                    opening_qty_adjustment["candidate_notional"],
                    opening_qty_adjustment["available_opening_margin"],
                )
                position_qty = opening_qty_adjustment["qty"]
            elif opening_qty_adjustment.get("blocked_reason"):
                blocked_reason = str(opening_qty_adjustment.get("blocked_reason") or "")
                self._activate_capital_starved_opening_block(
                    bot,
                    symbol=symbol,
                    reason=blocked_reason,
                    side=entry_side,
                    action="initial_entry",
                    opening_kind="initial_opening",
                    attempted_qty=opening_qty_adjustment.get("candidate_qty"),
                    price=last_price,
                    min_qty=min_qty,
                    min_notional_value=min_notional,
                    leverage=leverage,
                    available_balance=available_balance,
                    reserve_usd=reserve_usd,
                    opening_order_cap=int(
                        self._safe_float(bot.get("runtime_open_order_cap_total"), 0) or 0
                    )
                    or None,
                    opening_sizing=opening_sizing,
                )
                logger.warning(
                    "[%s] Initial entry blocked before order submit: %s",
                    symbol,
                    blocked_reason,
                )
                return False

            position_qty = self._normalize_order_qty(
                bot=bot,
                symbol=symbol,
                side=entry_side,
                raw_qty=position_qty,
                price=last_price,
                reduce_only=False,
            )
            if not position_qty:
                self._activate_capital_starved_opening_block(
                    bot,
                    symbol=symbol,
                    reason="qty_below_min",
                    side=entry_side,
                    action="initial_entry",
                    opening_kind="initial_opening",
                    attempted_qty=effective_capital / last_price if last_price > 0 else 0.0,
                    price=last_price,
                    min_qty=min_qty,
                    min_notional_value=min_notional,
                    leverage=leverage,
                    available_balance=available_balance,
                    reserve_usd=reserve_usd,
                    opening_order_cap=int(
                        self._safe_float(bot.get("runtime_open_order_cap_total"), 0) or 0
                    )
                    or None,
                    opening_sizing=self._augment_directional_opening_sizing_fields(
                        opening_sizing,
                        final_blocker_reason="qty_below_min",
                    ),
                )
                logger.warning(
                    f"[{symbol}] Initial entry qty below min after normalization"
                )
                return False

            # Validate minimum order value (symbol-specific from Bybit)
            order_value = position_qty * last_price
            if order_value < min_notional:
                self._activate_capital_starved_opening_block(
                    bot,
                    symbol=symbol,
                    reason="notional_below_min",
                    side=entry_side,
                    action="initial_entry",
                    opening_kind="initial_opening",
                    attempted_qty=position_qty,
                    price=last_price,
                    min_qty=min_qty,
                    min_notional_value=min_notional,
                    leverage=leverage,
                    available_balance=available_balance,
                    reserve_usd=reserve_usd,
                    opening_order_cap=int(
                        self._safe_float(bot.get("runtime_open_order_cap_total"), 0) or 0
                    )
                    or None,
                    opening_sizing=self._augment_directional_opening_sizing_fields(
                        opening_sizing,
                        final_blocker_reason="notional_below_min",
                    ),
                )
                logger.warning(
                    f"[{symbol}] Initial entry value ${order_value:.2f} below min ${min_notional:.2f}"
                )
                return False

            required_margin = order_value / max(leverage, 1.0)
            available_opening_margin = max(0.0, available_balance - reserve_usd)
            if required_margin > 0 and available_opening_margin + 1e-9 < required_margin:
                margin_guard_reason = self._get_opening_margin_guard_reason(
                    available_balance=available_balance,
                    reserve_usd=reserve_usd,
                    required_margin=required_margin,
                )
                self._activate_capital_starved_opening_block(
                    bot,
                    symbol=symbol,
                    reason=margin_guard_reason,
                    side=entry_side,
                    action="initial_entry",
                    opening_kind="initial_opening",
                    attempted_qty=position_qty,
                    price=last_price,
                    min_qty=min_qty,
                    min_notional_value=min_notional,
                    leverage=leverage,
                    available_balance=available_balance,
                    reserve_usd=reserve_usd,
                    opening_order_cap=int(
                        self._safe_float(bot.get("runtime_open_order_cap_total"), 0) or 0
                    )
                    or None,
                    opening_sizing=self._augment_directional_opening_sizing_fields(
                        opening_sizing,
                        final_blocker_reason=margin_guard_reason,
                    ),
                )
                logger.warning(
                    f"[{symbol}] Initial entry blocked by opening margin viability "
                    f"(need ${required_margin:.2f}, have ${available_opening_margin:.2f})"
                )
                return False

            self._clear_capital_starved_opening_block(bot)

            positions_resp = self.client.get_positions(skip_cache=True)
            if positions_resp.get("success"):
                for pos in (positions_resp.get("data", {}) or {}).get("list", []) or []:
                    if pos.get("symbol") != symbol:
                        continue
                    existing_size = self._safe_float(pos.get("size"), 0.0)
                    if existing_size <= 0:
                        continue
                    logger.warning(
                        f"[{symbol}] Initial entry skipped - fresh position already exists "
                        f"(side={pos.get('side')}, size={existing_size})"
                    )
                    return False

            # Build orderLinkId v2 with full bot UUID and intent=open
            import time as time_module

            order_link_id = self._build_order_link_id(
                bot_id=bot_id,
                symbol=symbol,
                cycle_ts=int(time_module.time()),
                seq=0,
                side=entry_side,
                intent="open",
            )

            # Place market order
            logger.info(
                f"[{symbol}] Placing initial {mode.upper()} entry - "
                f"{entry_side} {position_qty} {symbol} at market (~{last_price})"
            )

            result = self._create_order_checked(
                bot=bot,
                symbol=symbol,
                side=entry_side,
                qty=position_qty,
                order_type="Market",
                price=None,
                reduce_only=False,
                time_in_force="GTC",
                order_link_id=order_link_id,
                diagnostic_context={
                    "action": "initial_entry",
                    "opening_kind": "initial_opening",
                    "opening_sizing": opening_sizing,
                },
            )

            if result.get("retCode") == 0:
                order_id = result.get("data", {}).get("orderId", "unknown")
                self._record_trade_forensic_position_opened(
                    bot=bot,
                    symbol=symbol,
                    mode=mode,
                    side=entry_side,
                    decision_type="initial_entry",
                    order_id=order_id,
                    order_link_id=order_link_id,
                    qty=position_qty,
                    price=last_price,
                    opening_sizing=result.get("opening_sizing"),
                    entry_story=result.get("entry_story"),
                )
                self._mark_audit_actual_entry(
                    bot,
                    opening_kind="initial_opening",
                    opening_sizing=result.get("opening_sizing"),
                )
                self._mark_breakout_entry_context(
                    bot,
                    mode,
                    bot.get("_breakout_gate_context"),
                )
                self._record_audit_cycle(
                    bot,
                    symbol=symbol,
                    mode=mode,
                    last_price=last_price,
                    lower_price=bot.get("lower_price") or bot.get("grid_lower_price"),
                    upper_price=bot.get("upper_price") or bot.get("grid_upper_price"),
                    blocker_stack=[],
                    setup_quality=None,
                    skipped_reason=None,
                    event="initial_entry_placed",
                )
                logger.info(
                    f"[{symbol}] Initial entry SUCCESS - Order {order_id}, "
                    f"{entry_side} {position_qty} {symbol}"
                )
                return True
            else:
                error_msg = result.get("retMsg", "Unknown error")
                logger.error(f"[{symbol}] Initial entry FAILED - {error_msg}")
                return False

        except Exception as e:
            logger.error(f"[{symbol}] Initial entry exception - {str(e)}")
            return False

    def _run_scalp_market_cycle(
        self,
        bot: Dict[str, Any],
        symbol: str,
        last_price: float,
        fast_indicators: Dict[str, Any],
        now_iso: str,
    ) -> Optional[Dict[str, Any]]:
        """
        Run a scalp market cycle - fast market order scalping.

        This mode:
        1. Checks for strong momentum signals
        2. Enters with MARKET orders (instant execution)
        3. Monitors position for TP/SL targets
        4. Exits with MARKET orders when targets hit
        5. Enforces cooldown between trades

        Args:
            bot: Bot configuration dict
            symbol: Trading symbol
            last_price: Current market price
            fast_indicators: 15m indicators dict
            now_iso: Current timestamp ISO string

        Returns:
            Updated bot dict, or None if regular cycle should continue
        """
        bot_id = bot.get("id")
        investment = self._get_effective_investment(
            bot, self._safe_float(bot.get("investment"), DEFAULT_INVESTMENT_USDT)
        )
        leverage = self._safe_float(bot.get("leverage"), DEFAULT_LEVERAGE)
        now_ts = time.time()
        failure_breaker_skip_opening_orders, failure_breaker_reason = (
            self._failure_breaker_skip_opening_orders(bot, now_ts)
        )
        # 1. Unified Reserve Check
        available_balance = self._get_usdt_available_balance()
        reserve_usd, usable_investment = self._calculate_auto_margin_reserve(
            bot, investment, available_balance
        )
        effective_capital = usable_investment * leverage

        # Get instrument info
        instrument = self._get_instrument_info(symbol)
        if not instrument:
            return self._set_error(bot, f"Failed to fetch instrument info for {symbol}")

        qty_step = instrument.get("qty_step")
        min_order_qty = instrument.get("min_order_qty")
        min_notional_value = instrument.get("min_notional_value", 5.0)
        if not qty_step or not min_order_qty:
            return self._set_error(bot, f"Missing instrument sizing for {symbol}")

        # =============================================================================
        # CHECK COOLDOWN - Don't trade too frequently
        # =============================================================================
        last_trade_time = bot.get("last_scalp_trade_time")
        if last_trade_time:
            try:
                last_trade_dt = datetime.fromisoformat(
                    last_trade_time.replace("Z", "+00:00")
                )
                now_dt = datetime.now(timezone.utc)
                elapsed_sec = (now_dt - last_trade_dt).total_seconds()
                if elapsed_sec < SCALP_MARKET_COOLDOWN_SEC:
                    logger.debug(
                        f"[{symbol}] Scalp market cooldown ({elapsed_sec:.0f}s < {SCALP_MARKET_COOLDOWN_SEC}s)"
                    )
                    bot["last_run_at"] = now_iso
                    bot["scalp_status"] = (
                        f"Cooldown ({SCALP_MARKET_COOLDOWN_SEC - int(elapsed_sec)}s)"
                    )
                    self.bot_storage.save_bot(bot)
                    return bot
            except Exception:
                pass

        # =============================================================================
        # CALCULATE SIGNAL FIRST - Need this for both position management and entry
        # =============================================================================
        signal_score, signal_direction, signal_reasons = self._calculate_scalp_signal(
            fast_indicators=fast_indicators,
            bot_id=bot_id,
        )

        # Detect candle color (green = bullish, red = bearish)
        candle_color = self._detect_candle_color(fast_indicators)

        bot["scalp_signal_score"] = signal_score
        bot["scalp_signal_direction"] = signal_direction
        bot["candle_color"] = candle_color

        # =============================================================================
        # CHECK EXISTING POSITION - Manage TP/SL AND Close if Against Market
        # =============================================================================
        positions_resp = self.client.get_positions(skip_cache=True)
        has_position = False
        position_side = None
        position_size = 0.0
        position_unrealized_pnl = 0.0
        position_entry_price = 0.0

        if positions_resp.get("success"):
            positions = positions_resp.get("data", {}).get("list", []) or []
            for pos in positions:
                if pos.get("symbol") != symbol:
                    continue
                size = self._safe_float(pos.get("size"), 0.0)
                if size > 0:
                    has_position = True
                    position_side = pos.get("side")
                    position_size = size
                    position_unrealized_pnl = self._safe_float(
                        pos.get("unrealisedPnl"), 0.0
                    )
                    position_entry_price = self._safe_float(pos.get("avgPrice"), 0.0)
                    break

        # =============================================================================
        # IF HAS POSITION: Check TP/SL AND Close if Against Market Direction
        # =============================================================================
        if has_position:
            # Calculate TP/SL in USD based on position size
            tp_usd = max(SCALP_MARKET_TP_USD, effective_capital * SCALP_MARKET_TP_PCT)
            sl_usd = max(SCALP_MARKET_SL_USD, effective_capital * SCALP_MARKET_SL_PCT)

            should_close = False
            close_reason = ""

            # =============================================================================
            # CRITICAL: Close immediately if position is AGAINST market direction
            # - Sell position + bullish signal = CLOSE (market going up, we're short)
            # - Buy position + bearish signal = CLOSE (market going down, we're long)
            # =============================================================================
            position_against_market = False
            if position_side == "Sell" and signal_score > 0:  # Short but market bullish
                position_against_market = True
                close_reason = f"⚠️ AGAINST MARKET: Sell position but bullish signal ({signal_score})"
            elif position_side == "Buy" and signal_score < 0:  # Long but market bearish
                position_against_market = True
                close_reason = f"⚠️ AGAINST MARKET: Buy position but bearish signal ({signal_score})"

            # Also check candle color for stronger confirmation
            if not position_against_market:
                if (
                    position_side == "Sell"
                    and candle_color == "green"
                    and signal_score >= 15
                ):
                    position_against_market = True
                    close_reason = f"⚠️ AGAINST CANDLE: Sell position but green candle + bullish ({signal_score})"
                elif (
                    position_side == "Buy"
                    and candle_color == "red"
                    and signal_score <= -15
                ):
                    position_against_market = True
                    close_reason = f"⚠️ AGAINST CANDLE: Buy position but red candle + bearish ({signal_score})"

            if position_against_market:
                should_close = True
                logger.warning(f"[{symbol}] Position against market - {close_reason}")
            # Check Take Profit
            elif position_unrealized_pnl >= tp_usd:
                should_close = True
                close_reason = (
                    f"TP hit: +${position_unrealized_pnl:.2f} >= ${tp_usd:.2f}"
                )
            # Check Stop Loss
            elif position_unrealized_pnl <= -sl_usd:
                should_close = True
                close_reason = (
                    f"SL hit: ${position_unrealized_pnl:.2f} <= -${sl_usd:.2f}"
                )

            if should_close:
                logger.info(f"[{symbol}] SCALP MARKET EXIT - {close_reason}")

                # Close with market order
                close_side = "Sell" if position_side == "Buy" else "Buy"

                # Resolve position_idx for hedge mode safety
                pidx = self._resolve_position_idx(
                    bot, symbol, close_side, reduce_only=True
                )

                close_result = self._create_order_checked(
                    bot=bot,
                    symbol=symbol,
                    side=close_side,
                    qty=position_size,
                    order_type="Market",
                    price=last_price,
                    reduce_only=True,
                    time_in_force="GTC",
                    order_link_id=self._build_close_order_link_id(bot_id, "CLOS"),
                    position_idx=pidx,
                )

                if self._is_position_empty_close_result(close_result):
                    bot["scalp_status"] = f"Already flat: {close_reason}"
                    logger.info(
                        "[%s] Scalp market close skipped: position already flat",
                        symbol,
                    )
                elif close_result.get("success"):
                    # Update realized PnL (approximate until update_bots_realized_pnl
                    # corrects with exchange closedPnl; deduct estimated taker fee)
                    close_notional = position_size * last_price if last_price else 0.0
                    estimated_fee = close_notional * 0.00055
                    current_realized = self._safe_float(bot.get("realized_pnl"), 0.0)
                    bot["realized_pnl"] = current_realized + position_unrealized_pnl - estimated_fee
                    bot["last_scalp_trade_time"] = now_iso
                    bot["scalp_status"] = f"Closed: {close_reason}"
                    logger.info(
                        f"[{symbol}] Scalp market closed, PnL=${position_unrealized_pnl:.2f} (est fee=${estimated_fee:.4f}), total=${bot['realized_pnl']:.2f}"
                    )
                elif self._is_ambiguous_order_result(close_result):
                    logger.warning(
                        "[%s] Scalp market exit AMBIGUOUS bot_id=%s: %s",
                        symbol,
                        bot.get("id"),
                        close_result.get("error")
                        or close_result.get("status")
                        or "unknown",
                    )
                    bot["_block_opening_orders"] = True
                    bot["scalp_status"] = f"Close ambiguous: {close_result.get('error')}"
                else:
                    self._hard_fail_close(
                        bot,
                        symbol,
                        "scalp_market_exit",
                        close_result.get("error"),
                    )
                    bot["scalp_status"] = f"Close failed: {close_result.get('error')}"
            else:
                # Position open, waiting for TP/SL (aligned with market)
                market_align = (
                    "✓ aligned"
                    if (
                        (position_side == "Buy" and signal_score >= 0)
                        or (position_side == "Sell" and signal_score <= 0)
                    )
                    else "watching"
                )
                bot["scalp_status"] = (
                    f"Holding {position_side} ({market_align}): PnL ${position_unrealized_pnl:.2f}"
                )
                logger.debug(
                    f"[{symbol}] Scalp position open, PnL=${position_unrealized_pnl:.2f}"
                )

            bot["last_run_at"] = now_iso
            self._set_bot_current_price(bot, last_price, symbol=symbol)
            self.bot_storage.save_bot(bot)
            return bot

        # =============================================================================
        # NO POSITION: Check for entry signal
        # =============================================================================
        if ai_block_opening_orders or bot.get("_volatility_block_opening_orders") or failure_breaker_skip_opening_orders:
            bot["last_run_at"] = now_iso
            self._set_bot_current_price(bot, last_price, symbol=symbol)
            if ai_block_opening_orders:
                bot["scalp_status"] = "Opening guard: opening orders blocked"
            elif bot.get("_volatility_block_opening_orders"):
                bot["scalp_status"] = (
                    f"Volatility de-risk ({bot.get('volatility_derisk_tier')})"
                )
            else:
                bot["scalp_status"] = failure_breaker_reason or "Failure breaker cooldown"
            self.bot_storage.save_bot(bot)
            return bot

        # =============================================================================
        # Check candle alignment for better entry timing
        # Green candle + bullish signal = stronger buy entry
        # Red candle + bearish signal = stronger sell entry
        # =============================================================================
        candle_aligned = (candle_color == "green" and signal_score > 0) or (
            candle_color == "red" and signal_score < 0
        )

        # Lower threshold if candle aligns with signal direction
        effective_min_signal = SCALP_MARKET_MIN_SIGNAL
        if candle_aligned:
            effective_min_signal = int(
                SCALP_MARKET_MIN_SIGNAL * 0.7
            )  # 30% lower threshold
            logger.debug(
                f"[{symbol}] Candle aligned ({candle_color}), threshold={effective_min_signal}"
            )

        # Only enter if signal is strong enough
        if abs(signal_score) < effective_min_signal:
            bot["last_run_at"] = now_iso
            self._set_bot_current_price(bot, last_price, symbol=symbol)
            candle_info = f", candle={candle_color}" if candle_color else ""
            bot["scalp_status"] = (
                f"Waiting (score={signal_score}, need={effective_min_signal}{candle_info})"
            )
            self.bot_storage.save_bot(bot)
            return bot

        # =============================================================================
        # ENTER POSITION with Market Order
        # Prefer direction that aligns with candle color
        # =============================================================================
        # If candle is green, prefer Buy. If red, prefer Sell.
        # But only override if signal is weak (between threshold and 2x threshold)
        entry_side = "Buy" if signal_score > 0 else "Sell"

        structure_entry_blocks = self._evaluate_structure_entry_blocks(
            bot=bot,
            symbol=symbol,
            last_price=last_price,
            fast_indicators=fast_indicators,
            allow_buy=entry_side == "Buy",
            allow_sell=entry_side == "Sell",
        )
        if (
            (entry_side == "Buy" and structure_entry_blocks.get("skip_buy"))
            or (entry_side == "Sell" and structure_entry_blocks.get("skip_sell"))
        ):
            blocked_reason = (
                structure_entry_blocks.get("buy_reason")
                if entry_side == "Buy"
                else structure_entry_blocks.get("sell_reason")
            ) or "unsafe nearby structure"
            bot["last_run_at"] = now_iso
            self._set_bot_current_price(bot, last_price, symbol=symbol)
            bot["scalp_status"] = f"Waiting: {blocked_reason}"
            self.bot_storage.save_bot(bot)
            return bot

        # Boost entry confidence with candle alignment
        candle_boost = ""
        if candle_aligned:
            candle_boost = f" 🕯️{candle_color}"

        # Calculate position size
        position_size_usd = effective_capital
        position_qty = position_size_usd / last_price
        position_qty = self._normalize_order_qty(
            bot=bot,
            symbol=symbol,
            side=entry_side,
            raw_qty=position_qty,
            price=last_price,
            reduce_only=False,
        )
        if not position_qty:
            warning = self._activate_capital_starved_opening_block(
                bot,
                symbol=symbol,
                reason="qty_below_min",
                side=entry_side,
                action="scalp_market_entry",
                opening_kind="initial_opening",
                attempted_qty=position_size_usd / last_price if last_price > 0 else 0.0,
                price=last_price,
                min_qty=min_order_qty,
                min_notional_value=min_notional_value,
                leverage=leverage,
                available_balance=available_balance,
                reserve_usd=reserve_usd,
                opening_order_cap=int(
                    self._safe_float(bot.get("runtime_open_order_cap_total"), 0) or 0
                )
                or None,
            )
            bot["last_run_at"] = now_iso
            bot["scalp_status"] = warning
            self.bot_storage.save_bot(bot)
            return bot

        # Check minimum order value (symbol-specific from Bybit)
        order_value = position_qty * last_price
        if order_value < min_notional_value:
            warning = self._activate_capital_starved_opening_block(
                bot,
                symbol=symbol,
                reason="notional_below_min",
                side=entry_side,
                action="scalp_market_entry",
                opening_kind="initial_opening",
                attempted_qty=position_qty,
                price=last_price,
                min_qty=min_order_qty,
                min_notional_value=min_notional_value,
                leverage=leverage,
                available_balance=available_balance,
                reserve_usd=reserve_usd,
                opening_order_cap=int(
                    self._safe_float(bot.get("runtime_open_order_cap_total"), 0) or 0
                )
                or None,
            )
            bot["last_run_at"] = now_iso
            bot["scalp_status"] = warning
            self.bot_storage.save_bot(bot)
            return bot

        required_margin = order_value / max(leverage, 1.0)
        available_opening_margin = max(0.0, available_balance - reserve_usd)
        if required_margin > 0 and available_opening_margin + 1e-9 < required_margin:
            margin_guard_reason = self._get_opening_margin_guard_reason(
                available_balance=available_balance,
                reserve_usd=reserve_usd,
                required_margin=required_margin,
            )
            warning = self._activate_capital_starved_opening_block(
                bot,
                symbol=symbol,
                reason=margin_guard_reason,
                side=entry_side,
                action="scalp_market_entry",
                opening_kind="initial_opening",
                attempted_qty=position_qty,
                price=last_price,
                min_qty=min_order_qty,
                min_notional_value=min_notional_value,
                leverage=leverage,
                available_balance=available_balance,
                reserve_usd=reserve_usd,
                opening_order_cap=int(
                    self._safe_float(bot.get("runtime_open_order_cap_total"), 0) or 0
                )
                or None,
            )
            bot["last_run_at"] = now_iso
            self._set_bot_current_price(bot, last_price, symbol=symbol)
            bot["scalp_status"] = warning
            self.bot_storage.save_bot(bot)
            return bot

        self._clear_capital_starved_opening_block(bot)

        logger.info(
            f"[{symbol}] SCALP MARKET ENTRY - {entry_side} {position_qty} {symbol} @ market "
            f"(signal={signal_score}{candle_boost}, reasons={signal_reasons})"
        )

        # Build orderLinkId v2 with full bot UUID and intent=open
        order_link_id = self._build_order_link_id(
            bot_id=bot_id,
            symbol=symbol,
            cycle_ts=int(time.time()),
            seq=0,
            side=entry_side,
            intent="open",
        )

        # Resolve position_idx for hedge mode safety
        pidx = self._resolve_position_idx(bot, symbol, entry_side, reduce_only=False)

        # Place market order
        entry_result = self._create_order_checked(
            bot=bot,
            symbol=symbol,
            side=entry_side,
            qty=position_qty,
            order_type="Market",
            price=None,
            reduce_only=False,
            time_in_force="GTC",
            order_link_id=order_link_id,
            position_idx=pidx,
            diagnostic_context={
                "action": "scalp_market_entry",
                "opening_kind": "initial_opening",
            },
        )

        if entry_result.get("success"):
            self._clear_failure_breaker(bot)
            bot["last_scalp_trade_time"] = now_iso
            bot["scalp_status"] = (
                f"Entered {entry_side} @ ${last_price:.4f} (signal={signal_score})"
            )
            bot["scalp_entry_price"] = last_price
            logger.info(f"[{symbol}] Scalp market entry successful")
        else:
            error_msg = entry_result.get("error", "unknown")
            if self._is_insufficient_margin_result(entry_result):
                self._record_insufficient_margin_event(
                    bot,
                    symbol=symbol,
                    side=entry_side,
                    action="scalp_market_entry",
                    attempted_qty=position_qty,
                    price=last_price,
                    opening_order_cap=int(
                        self._safe_float(bot.get("runtime_open_order_cap_total"), 0) or 0
                    )
                    or None,
                )
                self._register_failure_breaker_event(
                    bot, "insufficient_margin", now_ts=now_ts
                )
            bot["scalp_status"] = f"Entry failed: {error_msg}"
            logger.warning(f"[{symbol}] Scalp market entry failed: {error_msg}")

        # Sync PnL
        try:
            self.pnl_service.sync_closed_pnl(symbol)
        except Exception as e:
            logger.warning(f"[{symbol}] PnL sync failed: {e}")

        bot["last_run_at"] = now_iso
        self._set_bot_current_price(bot, last_price, symbol=symbol)
        self.bot_storage.save_bot(bot)
        return bot

    def _calculate_scalp_signal(
        self,
        fast_indicators: Dict[str, Any],
        bot_id: Optional[str] = None,
    ) -> Tuple[int, str, List[str]]:
        """
        Calculate scalp entry signal score based on momentum indicators.

        Returns:
            Tuple of (score, direction, reasons)
            - score: -100 to +100 (positive = bullish, negative = bearish)
            - direction: "long", "short", or "neutral"
            - reasons: List of signal reasons
        """
        score = 0
        reasons = []

        # RSI (Weight: 30 points)
        rsi = fast_indicators.get("rsi")
        if rsi is not None:
            if rsi >= 60:
                score += 25
                reasons.append(f"RSI={rsi:.0f}↑")
            elif rsi >= 55:
                score += 15
            elif rsi <= 40:
                score -= 25
                reasons.append(f"RSI={rsi:.0f}↓")
            elif rsi <= 45:
                score -= 15

        # MACD Cross (Weight: 25 points)
        macd_cross = fast_indicators.get("macd_cross")
        if macd_cross == "bullish":
            score += 25
            reasons.append("MACD🔼")
        elif macd_cross == "bearish":
            score -= 25
            reasons.append("MACD🔽")

        # EMA Cross (Weight: 25 points)
        ema_cross = fast_indicators.get("ema_cross")
        if ema_cross == "bullish":
            score += 25
            reasons.append("EMA🔼")
        elif ema_cross == "bearish":
            score -= 25
            reasons.append("EMA🔽")

        # Price vs EMA (Weight: 10 points)
        price_vs_ema = fast_indicators.get("price_vs_ema")
        if price_vs_ema == "above":
            score += 10
        elif price_vs_ema == "below":
            score -= 10

        # Volume confirmation (Weight: 15 points)
        volume_trend = fast_indicators.get("volume_trend")
        if volume_trend == "high":
            if score > 0:
                score += 15
                reasons.append("VOL↑")
            elif score < 0:
                score -= 15
                reasons.append("VOL↑")

        # Determine direction
        if score >= SCALP_MARKET_MIN_SIGNAL:
            direction = "long"
        elif score <= -SCALP_MARKET_MIN_SIGNAL:
            direction = "short"
        else:
            direction = "neutral"

        logger.debug(
            f"[{symbol}] Scalp signal score={score}, direction={direction}, reasons={reasons}"
        )

        return score, direction, reasons

    def _extend_trailing_grid(
        self,
        levels: List[float],
        last_price: float,
        existing_order_prices: List[float],
        mode: str,
        step_pct: float,
        bot_id: str,
        symbol: str = "?",
        indicators: Optional[Dict[str, Any]] = None,
    ) -> List[float]:
        """
        Extend grid levels when orders are filled to maintain grid density.

        For LONG mode:
        - Extend BUY levels downward when buys fill (accumulate on dips)
        - Extend SELL levels upward for take profit as price rises

        For SHORT mode:
        - Extend SELL levels upward when sells fill (short rallies)
        - Extend BUY levels downward for take profit as price drops

        For NEUTRAL mode:
        - Extend BOTH buy levels below AND sell levels above
        - Maintains symmetric grid for range-bound trading

        Args:
            levels: Current grid levels
            last_price: Current market price
            existing_order_prices: Prices of currently open orders
            mode: Trading mode (long/short/neutral)
            step_pct: Grid step percentage
            bot_id: Bot ID for logging
            symbol: Trading symbol for logging

        Returns:
            Extended list of grid levels
        """
        if not levels or last_price <= 0:
            return levels

        # Desired number of levels on each side
        # Increased for major coins to maintain depth with tighter spacing
        is_major = symbol in TRAILING_MAJOR_SYMBOLS
        TARGET_LEVELS_PER_SIDE = 8 if is_major else 4
        new_levels = list(levels)
        extensions_made = []

        if mode == "long":
            # =========================================================
            # LONG MODE: Extend BOTH buy levels below AND sell levels above
            # =========================================================

            # --- Extend BUY levels downward (for DCA accumulation) ---
            existing_buys = sorted([p for p in existing_order_prices if p < last_price])
            buy_levels_with_orders = len(existing_buys)

            # =========================================================
            # MOMENTUM-AWARE DCA (#29)
            # Avoid adding new DCA buy orders during extreme downward momentum
            # =========================================================
            momentum_blocked_long = False
            if MOMENTUM_DCA_ENABLED and indicators and mode == "long":
                adx = indicators.get("adx", 0)
                rsi = indicators.get("rsi", 50)
                # Falling knife check: ADX high + RSI extremely low
                if (
                    adx >= MOMENTUM_DCA_ADX_THRESHOLD
                    and rsi <= MOMENTUM_DCA_RSI_LONG_MIN
                ):
                    momentum_blocked_long = True
                    logger.debug(
                        f"[{symbol}] Long DCA blocked (falling knife): ADX {adx:.1f} >= {MOMENTUM_DCA_ADX_THRESHOLD}, RSI {rsi:.1f} <= {MOMENTUM_DCA_RSI_LONG_MIN}"
                    )

            if not momentum_blocked_long:
                if buy_levels_with_orders < TARGET_LEVELS_PER_SIDE:
                    lowest_level = min(new_levels)
                    # Smart Feature #27-B: Scale DCA step with volatility + coin category
                    # Use tighter DCA for major coins (high liquidity, slower moves)
                    is_major = symbol in TRAILING_MAJOR_SYMBOLS
                    base_dca_step = (
                        DCA_STEP_MAJOR_PCT if is_major else DCA_STEP_MEME_PCT
                    )
                    effective_dca_step = base_dca_step

                    if VOLATILITY_DYNAMIC_SPACING_ENABLED and step_pct > 0:
                        # Scale DCA relative to the grid step (DCA is usually wider)
                        dca_ratio = (
                            base_dca_step / GRID_STEP_PCT if GRID_STEP_PCT > 0 else 2.0
                        )
                        effective_dca_step = step_pct * dca_ratio

                    step_down = 1.0 - effective_dca_step
                    buy_levels_to_add = TARGET_LEVELS_PER_SIDE - buy_levels_with_orders

                    for _ in range(buy_levels_to_add):
                        new_level = lowest_level * step_down
                        new_levels.append(new_level)
                        lowest_level = new_level

                    if buy_levels_to_add > 0:
                        extensions_made.append(f"{buy_levels_to_add} buy levels below")
            else:
                logger.debug(
                    f"[{symbol}] Long DCA accumulation skipped due to extreme momentum."
                )

            # --- Extend SELL levels upward (for take profit) ---
            existing_sells = sorted(
                [p for p in existing_order_prices if p > last_price]
            )
            sell_levels_with_orders = len(existing_sells)

            if sell_levels_with_orders < TARGET_LEVELS_PER_SIDE:
                highest_level = max(new_levels)
                step_up = 1.0 + step_pct
                sell_levels_to_add = TARGET_LEVELS_PER_SIDE - sell_levels_with_orders

                for _ in range(sell_levels_to_add):
                    new_level = highest_level * step_up
                    new_levels.append(new_level)
                    highest_level = new_level

                if sell_levels_to_add > 0:
                    extensions_made.append(f"{sell_levels_to_add} sell levels above")

            if extensions_made:
                logger.info(
                    f"[{symbol}] Trailing LONG - extended grid with {', '.join(extensions_made)}"
                )

            return sorted(new_levels)

        elif mode == "short":
            # =========================================================
            # SHORT MODE: Extend BOTH sell levels above AND buy levels below
            # =========================================================

            # --- Extend SELL levels upward (for shorting) ---
            existing_sells = sorted(
                [p for p in existing_order_prices if p > last_price]
            )
            sell_levels_with_orders = len(existing_sells)

            # =========================================================
            # MOMENTUM-AWARE DCA (#29)
            # Avoid adding new DCA sell orders during extreme upward momentum
            # =========================================================
            momentum_blocked_short = False
            if MOMENTUM_DCA_ENABLED and indicators and mode == "short":
                adx = indicators.get("adx", 0)
                rsi = indicators.get("rsi", 50)
                # Rocket check: ADX high + RSI extremely high
                if (
                    adx >= MOMENTUM_DCA_ADX_THRESHOLD
                    and rsi >= MOMENTUM_DCA_RSI_SHORT_MAX
                ):
                    momentum_blocked_short = True
                    logger.debug(
                        f"[{symbol}] Short DCA blocked (rocket): ADX {adx:.1f} >= {MOMENTUM_DCA_ADX_THRESHOLD}, RSI {rsi:.1f} >= {MOMENTUM_DCA_RSI_SHORT_MAX}"
                    )

            if not momentum_blocked_short:
                if sell_levels_with_orders < TARGET_LEVELS_PER_SIDE:
                    highest_level = max(new_levels)
                    # Use coin-category specific DCA step for short mode (like long mode)
                    is_major = symbol in TRAILING_MAJOR_SYMBOLS
                    base_dca_step = (
                        DCA_STEP_MAJOR_PCT if is_major else DCA_STEP_MEME_PCT
                    )
                    effective_dca_step = base_dca_step

                    if VOLATILITY_DYNAMIC_SPACING_ENABLED and step_pct > 0:
                        dca_ratio = (
                            base_dca_step / GRID_STEP_PCT if GRID_STEP_PCT > 0 else 2.0
                        )
                        effective_dca_step = step_pct * dca_ratio

                    step_up = 1.0 + effective_dca_step
                    sell_levels_to_add = (
                        TARGET_LEVELS_PER_SIDE - sell_levels_with_orders
                    )

                    for _ in range(sell_levels_to_add):
                        new_level = highest_level * step_up
                        new_levels.append(new_level)
                        highest_level = new_level

                    if sell_levels_to_add > 0:
                        extensions_made.append(
                            f"{sell_levels_to_add} sell levels above"
                        )
            else:
                logger.debug(
                    f"[{symbol}] Short DCA accumulation skipped due to extreme momentum."
                )

            # --- Extend BUY levels downward (for take profit / cover) ---
            existing_buys = sorted([p for p in existing_order_prices if p < last_price])
            buy_levels_with_orders = len(existing_buys)

            if buy_levels_with_orders < TARGET_LEVELS_PER_SIDE:
                lowest_level = min(new_levels)
                step_down = 1.0 - step_pct
                buy_levels_to_add = TARGET_LEVELS_PER_SIDE - buy_levels_with_orders

                for _ in range(buy_levels_to_add):
                    new_level = lowest_level * step_down
                    new_levels.append(new_level)
                    lowest_level = new_level

                if buy_levels_to_add > 0:
                    extensions_made.append(f"{buy_levels_to_add} buy levels below")

            if extensions_made:
                logger.info(
                    f"[{symbol}] Trailing SHORT - extended grid with {', '.join(extensions_made)}"
                )

            return sorted(new_levels)

        elif mode == "neutral":
            # =========================================================
            # NEUTRAL MODE: Extend BOTH buy levels below AND sell levels above
            # Maintains symmetric grid for range-bound trading
            # =========================================================

            # --- Extend BUY levels downward ---
            existing_buys = sorted([p for p in existing_order_prices if p < last_price])
            buy_levels_with_orders = len(existing_buys)

            if buy_levels_with_orders < TARGET_LEVELS_PER_SIDE:
                lowest_level = min(new_levels)
                step_down = 1.0 - step_pct
                buy_levels_to_add = TARGET_LEVELS_PER_SIDE - buy_levels_with_orders

                for _ in range(buy_levels_to_add):
                    new_level = lowest_level * step_down
                    new_levels.append(new_level)
                    lowest_level = new_level

                if buy_levels_to_add > 0:
                    extensions_made.append(f"{buy_levels_to_add} buy levels below")

            # --- Extend SELL levels upward ---
            existing_sells = sorted(
                [p for p in existing_order_prices if p > last_price]
            )
            sell_levels_with_orders = len(existing_sells)

            if sell_levels_with_orders < TARGET_LEVELS_PER_SIDE:
                highest_level = max(new_levels)
                step_up = 1.0 + step_pct
                sell_levels_to_add = TARGET_LEVELS_PER_SIDE - sell_levels_with_orders

                for _ in range(sell_levels_to_add):
                    new_level = highest_level * step_up
                    new_levels.append(new_level)
                    highest_level = new_level

                if sell_levels_to_add > 0:
                    extensions_made.append(f"{sell_levels_to_add} sell levels above")

            if extensions_made:
                logger.info(
                    f"[{symbol}] NEUTRAL - extended grid with {', '.join(extensions_made)}"
                )

            return sorted(new_levels)

        return levels

    def _detect_candle_color(self, indicators: Dict[str, Any]) -> str:
        """
        Detect if the current/recent candle is green (bullish) or red (bearish).

        Uses multiple signals to determine candle direction:
        1. Candle pattern from indicators
        2. Price vs EMA relationship
        3. Short-term momentum

        Args:
            indicators: Dictionary of indicator values

        Returns:
            "green" for bullish candle, "red" for bearish, "neutral" if unclear
        """
        bullish_signals = 0
        bearish_signals = 0

        # Check candle pattern
        candle_pattern = indicators.get("candle_pattern", "")
        candle_signal = indicators.get("candle_signal", "")

        if candle_signal == "bullish" or "bullish" in str(candle_pattern).lower():
            bullish_signals += 2
        elif candle_signal == "bearish" or "bearish" in str(candle_pattern).lower():
            bearish_signals += 2

        # Check if specific bullish patterns
        bullish_patterns = [
            "hammer",
            "bullish_engulfing",
            "morning_star",
            "piercing_line",
            "three_white_soldiers",
            "dragonfly_doji",
            "inverted_hammer",
        ]
        bearish_patterns = [
            "hanging_man",
            "bearish_engulfing",
            "evening_star",
            "dark_cloud_cover",
            "three_black_crows",
            "gravestone_doji",
            "shooting_star",
        ]

        if candle_pattern in bullish_patterns:
            bullish_signals += 3
        elif candle_pattern in bearish_patterns:
            bearish_signals += 3

        # Check price vs EMA (indicates recent direction)
        price_vs_ema = indicators.get("price_vs_ema", "")
        if price_vs_ema == "above":
            bullish_signals += 1
        elif price_vs_ema == "below":
            bearish_signals += 1

        # Check MACD histogram direction (positive = green momentum)
        macd_histogram = indicators.get("macd_histogram")
        if macd_histogram is not None:
            if macd_histogram > 0:
                bullish_signals += 1
            elif macd_histogram < 0:
                bearish_signals += 1

        # Check RSI direction
        rsi = indicators.get("rsi")
        if rsi is not None:
            if rsi > 55:
                bullish_signals += 1
            elif rsi < 45:
                bearish_signals += 1

        # Determine color based on signals
        if bullish_signals > bearish_signals + 1:
            return "green"
        elif bearish_signals > bullish_signals + 1:
            return "red"
        else:
            return "neutral"

    def _build_biased_levels(
        self,
        levels: List[float],
        last_price: float,
        mode: str,
        tick_size: float,
        existing_order_prices: Optional[set] = None,
        fast_indicators: Optional[Dict[str, Any]] = None,
        range_mode: str = "fixed",
    ) -> Tuple[List[float], List[float]]:
        """
        Build buy and sell level lists with directional bias that follows candle direction.

        All modes now follow trend direction:
        - Uptrend/Green candles (bullish): Place BUY grids BELOW price to catch dips & ride up
        - Downtrend/Red candles (bearish): Place SELL grids ABOVE price to short rallies & ride down
        - Neutral mode: Detects candle direction and places grids accordingly
        - Long mode: Emphasizes buying dips when bullish (buys below price)
        - Short mode: Emphasizes shorting rallies when bearish (sells above price)

        Args:
            levels: Raw sorted list of grid levels
            last_price: Current market price
            mode: Trading mode (neutral/long/short)
            tick_size: Price tick size for rounding
            existing_order_prices: Set of prices where orders already exist
            fast_indicators: Indicator data for candle direction detection
            range_mode: Range mode (fixed/dynamic/trailing) - affects TP offset

        Returns:
            Tuple of (buy_levels, sell_levels)
        """
        buy_levels: List[float] = []
        sell_levels: List[float] = []

        if last_price <= 0 or not levels:
            return buy_levels, sell_levels

        existing_prices = existing_order_prices or set()

        # Detect current candle direction/trend
        candle_color = "neutral"
        if fast_indicators:
            candle_color = self._detect_candle_color(fast_indicators)

        is_uptrend = candle_color == "green"
        is_downtrend = candle_color == "red"

        # =============================================================================
        # NEUTRAL MODE - Follows candle direction
        # Green candles (bullish): Buy orders BELOW price to catch dips in uptrend
        # Red candles (bearish): Sell orders ABOVE price to short peaks in downtrend
        # =============================================================================
        if mode == "neutral":
            if is_uptrend:
                # UPTREND (GREEN CANDLES): Place BUY grids BELOW price to buy dips
                for level in levels:
                    if level < last_price:
                        buy_levels.append(level)
                # Sell orders above for take-profit
                for level in levels:
                    if level > last_price:
                        sell_levels.append(level)
            elif is_downtrend:
                # DOWNTREND (RED CANDLES): Place SELL grids ABOVE price to short rallies
                for level in levels:
                    if level > last_price:
                        sell_levels.append(level)
                # Buy orders below for covering
                for level in levels:
                    if level < last_price:
                        buy_levels.append(level)
            else:
                # Neutral/unclear - traditional symmetric behavior
                for level in levels:
                    if level < last_price:
                        buy_levels.append(level)
                    elif level > last_price:
                        sell_levels.append(level)

        # =============================================================================
        # LONG MODE - Emphasizes upward grids, follows green candles
        # Green candles: BUY grids BELOW price to accumulate on dips
        # Red candles: Conservative buying on deeper dips
        # IMPORTANT: Sell orders (take profit) must be far enough above price for profit
        # =============================================================================
        elif mode == "long":
            # Determine minimum TP offset based on range mode
            # Trailing mode needs larger offset to ensure meaningful profit per trade
            tp_offset = (
                TRAILING_TP_MIN_OFFSET_PCT
                if range_mode == "trailing"
                else OPPOSITE_MIN_OFFSET_PCT
            )
            tp_threshold = last_price * (1.0 + tp_offset)

            # Buy grids BELOW price (entry points)
            for level in levels:
                if level < last_price:
                    buy_levels.append(level)

            # Sell grids (take profit) - ALWAYS apply minimum offset for profit
            for level in levels:
                if level >= tp_threshold:
                    sell_levels.append(level)

            # Sort and dedupe
            buy_levels = sorted(set(buy_levels), reverse=True)
            sell_levels = sorted(set(sell_levels))

        # =============================================================================
        # SHORT MODE - Emphasizes downward grids
        # Dynamic: keep one continuation sell close to price so the short ladder
        # follows downtrends more like long dynamic follows uptrends.
        # Trailing/fixed: keep the conservative "short rallies" behavior.
        # IMPORTANT: Buy orders (cover) must be far enough below price for profit
        # =============================================================================
        elif mode == "short":
            # Determine minimum TP offset based on range mode
            # Trailing mode needs larger offset to ensure meaningful profit per trade
            tp_offset = (
                TRAILING_TP_MIN_OFFSET_PCT
                if range_mode == "trailing"
                else OPPOSITE_MIN_OFFSET_PCT
            )
            tp_threshold = last_price * (1.0 - tp_offset)

            # Sell grids (entry points for shorts)
            # Dynamic mode is allowed one "continuation" entry from a tight near-price
            # band just below price so new short entries can keep following a falling
            # market. Order placement will reprice that one level just above the spread.
            continuation_sell_floor = last_price * (1.0 - DIRECTION_NEAR_BAND_PCT)
            nearest_dynamic_sell = None
            if range_mode == "dynamic":
                continuation_candidates = [
                    level
                    for level in levels
                    if continuation_sell_floor <= level <= last_price
                ]
                if continuation_candidates:
                    nearest_dynamic_sell = max(continuation_candidates)

            for level in levels:
                if level > last_price:
                    sell_levels.append(level)
            if nearest_dynamic_sell is not None:
                sell_levels.append(nearest_dynamic_sell)

            # Buy grids (cover/take profit) - ALWAYS apply minimum offset for profit
            for level in levels:
                if level <= tp_threshold:
                    buy_levels.append(level)

            # Sort and dedupe
            sell_levels = sorted(set(sell_levels))
            buy_levels = sorted(set(buy_levels), reverse=True)

        else:
            # Unknown mode - fallback to traditional behavior
            for level in levels:
                if level < last_price:
                    buy_levels.append(level)
                elif level > last_price:
                    sell_levels.append(level)

        return buy_levels, sell_levels

    def get_auto_direction_analysis(
        self,
        symbol: str,
        current_mode: str,
        fast_indicators: Optional[Dict[str, Any]] = None,
        slow_indicators: Optional[Dict[str, Any]] = None,
        current_price: Optional[float] = None,
        bot_id: Optional[str] = None,
        bot: Optional[Dict[str, Any]] = None,
        apply_mode_guards: bool = True,
    ) -> Dict[str, Any]:
        """
        Analyze auto-direction signals and return the resulting mode decision.

        Uses weighted scoring from:
        - RSI (multi-timeframe)
        - ADX (trend strength)
        - EMA crossovers
        - MACD
        - Volume analysis
        - Candlestick patterns

        Args:
            symbol: Trading symbol
            current_mode: Current bot mode (neutral/long/short)
            fast_indicators: Optional pre-fetched 15m indicators dict
            slow_indicators: Optional pre-fetched 1h indicators dict
            current_price: Optional pre-fetched last price
            bot_id: Bot ID for logging
            bot: Bot dict for accessing mode_entered_at timestamp
            apply_mode_guards: Apply hold-time and ADX mode-change guards

        Returns:
            Dict with target_mode, score, signals, and metadata
        """
        # Import hysteresis config
        from config.strategy_config import (
            MODE_ENTER_LONG_THRESHOLD,
            MODE_ENTER_SHORT_THRESHOLD,
            MODE_EXIT_LONG_THRESHOLD,
            MODE_EXIT_SHORT_THRESHOLD,
            MODE_STAY_LONG_THRESHOLD,
            MODE_STAY_SHORT_THRESHOLD,
            MODE_NEUTRAL_BAND_WIDTH,
            MODE_MIN_HOLD_SECONDS,
            MODE_REQUIRE_ADX_FOR_CHANGE,
            MODE_ADX_MIN_FOR_CHANGE,
        )

        # Scoring system: positive = bullish, negative = bearish
        # Range roughly -100 to +100
        score = 0
        signals: List[str] = []

        if fast_indicators is None:
            try:
                fast_indicators = self.indicator_service.compute_indicators(
                    symbol, interval="15", limit=200
                )
            except Exception as e:
                logger.warning(f"[{symbol}] Failed to fetch 15m indicators: {e}")
                return {
                    "analysis_ok": False,
                    "target_mode": current_mode,
                    "score": 0,
                    "signals": [],
                    "signals_str": "No signals",
                    "adx": None,
                    "current_mode": current_mode,
                }

        if current_price is None:
            current_price = self._get_last_price(symbol)

        if slow_indicators is None:
            slow_indicators = {}
            try:
                slow_indicators = self.indicator_service.compute_indicators(
                    symbol, interval="60", limit=200
                )
            except Exception as e:
                logger.warning(f"[{symbol}] Failed to fetch 1h indicators: {e}")
                return {
                    "analysis_ok": False,
                    "target_mode": current_mode,
                    "score": 0,
                    "signals": [],
                    "signals_str": "No signals",
                    "adx": None,
                    "current_mode": current_mode,
                }

        # =============================================================================
        # 1. RSI ANALYSIS (Weight: 25 points max)
        # =============================================================================
        rsi_fast = fast_indicators.get("rsi")
        rsi_slow = slow_indicators.get("rsi")

        if rsi_fast is not None:
            if rsi_fast >= 60:
                score += 15
                signals.append(f"RSI15m={rsi_fast:.0f}↑")
            elif rsi_fast >= 55:
                score += 8
            elif rsi_fast <= 40:
                score -= 15
                signals.append(f"RSI15m={rsi_fast:.0f}↓")
            elif rsi_fast <= 45:
                score -= 8

        if rsi_slow is not None:
            if rsi_slow >= 58:
                score += 10
                signals.append(f"RSI1h={rsi_slow:.0f}↑")
            elif rsi_slow >= 53:
                score += 5
            elif rsi_slow <= 42:
                score -= 10
                signals.append(f"RSI1h={rsi_slow:.0f}↓")
            elif rsi_slow <= 47:
                score -= 5

        # =============================================================================
        # 2. ADX ANALYSIS (Weight: 15 points - trend strength modifier)
        # =============================================================================
        adx_slow = slow_indicators.get("adx")
        is_trending = False

        # Pre-check EMA crosses for trend override (bypass choppy reduction if both agree)
        ema_cross_pre = fast_indicators.get("ema_cross")  # 15m
        ema_cross_slow_pre = slow_indicators.get("ema_cross")  # 1h
        ema_trend_aligned = (
            ema_cross_pre == "bullish" and ema_cross_slow_pre == "bullish"
        ) or (ema_cross_pre == "bearish" and ema_cross_slow_pre == "bearish")

        if adx_slow is not None:
            if adx_slow >= ADX_TREND_MIN:
                is_trending = True
                # ADX amplifies the current score direction
                if score > 0:
                    score += 10
                elif score < 0:
                    score -= 10
                signals.append(f"ADX={adx_slow:.0f}🔥")
            elif adx_slow <= ADX_CHOP_MAX:
                if ema_trend_aligned:
                    # EMA trend override: clear trend despite low ADX, skip reduction
                    signals.append(f"ADX={adx_slow:.0f}📈EMA")
                else:
                    # No clear EMA trend, apply choppy reduction
                    score = int(score * 0.5)
                    signals.append(f"ADX={adx_slow:.0f}😴")

        # =============================================================================
        # 3. EMA CROSSOVER ANALYSIS (Weight: 20 points max)
        # =============================================================================
        ema_cross = fast_indicators.get("ema_cross")
        price_vs_ema = fast_indicators.get("price_vs_ema")
        ema_cross_slow = slow_indicators.get("ema_cross")

        if ema_cross == "bullish":
            score += 15
            signals.append("EMA9/21🔼")
        elif ema_cross == "bearish":
            score -= 15
            signals.append("EMA9/21🔽")

        if ema_cross_slow == "bullish":
            score += 10
            signals.append("EMA1h🔼")
        elif ema_cross_slow == "bearish":
            score -= 10
            signals.append("EMA1h🔽")

        if price_vs_ema == "above":
            score += 5
        elif price_vs_ema == "below":
            score -= 5

        # =============================================================================
        # 4. MACD ANALYSIS (Weight: 20 points max)
        # =============================================================================
        macd_cross = fast_indicators.get("macd_cross")
        macd_histogram = fast_indicators.get("macd_histogram")
        macd_cross_slow = slow_indicators.get("macd_cross")

        if macd_cross == "bullish":
            score += 15
            signals.append("MACD🔼")
        elif macd_cross == "bearish":
            score -= 15
            signals.append("MACD🔽")

        if macd_cross_slow == "bullish":
            score += 10
        elif macd_cross_slow == "bearish":
            score -= 10

        # Histogram direction
        if macd_histogram is not None:
            if macd_histogram > 0:
                score += 5
            elif macd_histogram < 0:
                score -= 5

        # =============================================================================
        # 5. VOLUME ANALYSIS (Weight: 10 points max)
        # =============================================================================
        volume_trend = fast_indicators.get("volume_trend")
        volume_ratio = fast_indicators.get("volume_ratio")

        if volume_trend == "high" and volume_ratio:
            # High volume confirms the move
            if score > 0:
                score += 10
                signals.append(f"VOL↑{volume_ratio:.1f}x")
            elif score < 0:
                score -= 10
                signals.append(f"VOL↑{volume_ratio:.1f}x")
        elif volume_trend == "low":
            # Low volume = less conviction
            score = int(score * 0.7)
            signals.append("VOL↓")

        # =============================================================================
        # 6. CANDLESTICK PATTERNS (Weight: 25 points max - increased for better detection)
        # =============================================================================
        candle_pattern = fast_indicators.get("candle_pattern")
        candle_signal = fast_indicators.get("candle_signal")

        if candle_pattern and candle_signal:
            pattern_scores = {
                # Strong patterns (increased weight)
                "bullish_engulfing": 25,
                "bearish_engulfing": -25,
                "morning_star": 25,
                "evening_star": -25,
                "three_white_soldiers": 25,
                "three_black_crows": -25,
                # Medium patterns (increased weight)
                "hammer": 15,
                "hanging_man": -15,
                "inverted_hammer": 12,
                "shooting_star": -15,
                "piercing_line": 15,
                "dark_cloud_cover": -15,
                # Weak patterns
                "dragonfly_doji": 8,
                "gravestone_doji": -8,
            }
            pattern_score = pattern_scores.get(candle_pattern, 0)
            if pattern_score != 0:
                score += pattern_score
                signals.append(f"🕯️{candle_pattern}")

        # =============================================================================
        # 7. ADVANCED PRICE PREDICTION (Weight: up to 90 points from patterns, S/R, divergence, MTF)
        # =============================================================================
        try:
            if self.price_prediction_service:
                prediction = self.price_prediction_service.predict(
                    symbol, timeframe="15"
                )

                # Add prediction score to the overall score
                # Prediction score includes: patterns(30), divergence(25), S/R(15), structure(15), MTF(20)
                prediction_score = prediction.score

                # Cap the prediction contribution to avoid overwhelming other signals
                prediction_score = max(-60, min(60, prediction_score))
                score += prediction_score

                # Add key signals from prediction
                if prediction.direction in ("STRONG_LONG", "LONG"):
                    signals.append(
                        f"🎯{prediction.direction}({prediction.confidence}%)"
                    )
                elif prediction.direction in ("STRONG_SHORT", "SHORT"):
                    signals.append(
                        f"🎯{prediction.direction}({prediction.confidence}%)"
                    )

                # Log individual prediction components for debugging
                if prediction.pattern_signals:
                    for pname in list(prediction.pattern_signals.keys())[:2]:
                        signals.append(f"📊{pname}")

                if prediction.divergence_signals and prediction.divergence_signals.get(
                    "type"
                ):
                    div_type = prediction.divergence_signals.get("type", "")
                    if "bullish" in div_type:
                        signals.append("📈DIV↑")
                    elif "bearish" in div_type:
                        signals.append("📉DIV↓")

                if prediction.sr_levels:
                    if prediction.sr_levels.get("nearest_support"):
                        sup = prediction.sr_levels["nearest_support"]
                        if sup.get("distance_pct", 1) < 0.015:  # Within 1.5%
                            signals.append(f"🛡️S@{sup.get('price', 0):.2f}")
                    if prediction.sr_levels.get("nearest_resistance"):
                        res = prediction.sr_levels["nearest_resistance"]
                        if res.get("distance_pct", 1) < 0.015:
                            signals.append(f"🚧R@{res.get('price', 0):.2f}")

                # Add MTF alignment if strong
                if prediction.timeframe_alignment:
                    alignment = prediction.timeframe_alignment.get("alignment", "MIXED")
                    if alignment in ("STRONG_BULLISH", "STRONG_BEARISH"):
                        signals.append(f"📡MTF:{alignment[:6]}")

        except Exception as e:
            logger.debug(f"[{symbol}] Price prediction failed (non-critical): {e}")

        # =============================================================================
        # FUNDING RATE INTELLIGENCE (Smart Feature #15)
        # =============================================================================
        # Use perpetual funding rates as contrarian signal
        # High positive funding = longs crowded = bearish signal
        # High negative funding = shorts crowded = bullish signal
        try:
            from config.strategy_config import (
                ENABLE_FUNDING_RATE_SIGNAL,
                FUNDING_RATE_EXTREME_POSITIVE,
                FUNDING_RATE_HIGH_POSITIVE,
                FUNDING_RATE_EXTREME_NEGATIVE,
                FUNDING_RATE_HIGH_NEGATIVE,
                FUNDING_RATE_MAX_SCORE,
            )

            if (
                ENABLE_FUNDING_RATE_SIGNAL
                and hasattr(self, "funding_rate_service")
                and self.funding_rate_service
            ):
                funding_result = self.funding_rate_service.get_funding_signal(
                    symbol=symbol,
                    extreme_positive=FUNDING_RATE_EXTREME_POSITIVE,
                    high_positive=FUNDING_RATE_HIGH_POSITIVE,
                    extreme_negative=FUNDING_RATE_EXTREME_NEGATIVE,
                    high_negative=FUNDING_RATE_HIGH_NEGATIVE,
                    max_score=FUNDING_RATE_MAX_SCORE,
                )

                funding_score = funding_result.get("score", 0)
                funding_signal = funding_result.get("signal", "NEUTRAL")
                funding_rate_pct = funding_result.get("funding_rate_pct", 0)

                # Store funding rate data in bot for dashboard display
                if bot:
                    bot["funding_rate_pct"] = funding_rate_pct
                    bot["funding_signal"] = funding_signal
                    bot["funding_score"] = funding_score

                if funding_score != 0:
                    score += funding_score
                    signals.append(
                        f"💰FR:{funding_rate_pct:.3f}%({funding_signal[:4]})"
                    )
                    logger.debug(
                        f"[{symbol}] Funding rate signal: {funding_signal} "
                        f"(rate={funding_rate_pct:.4f}%, score={funding_score:+.1f})"
                    )

        except Exception as e:
            logger.debug(f"[{symbol}] Funding rate signal failed (non-critical): {e}")

        # =============================================================================
        # VOLUME PROFILE SIGNAL (NEW - Smart Feature #18)
        # =============================================================================
        # Use volume-weighted support/resistance for direction bias
        try:
            from config.strategy_config import (
                VOLUME_PROFILE_ENABLED,
                VOLUME_PROFILE_LOOKBACK,
                VOLUME_PROFILE_MAX_SCORE,
            )

            if (
                VOLUME_PROFILE_ENABLED
                and hasattr(self, "volume_profile_service")
                and self.volume_profile_service
            ):
                vol_result = self.volume_profile_service.get_volume_signal(
                    symbol=symbol,
                    current_price=current_price,
                    lookback=VOLUME_PROFILE_LOOKBACK,
                    max_score=VOLUME_PROFILE_MAX_SCORE,
                )

                vol_score = vol_result.get("score", 0)
                vol_signal = vol_result.get("signal", "NEUTRAL")
                vol_reason = vol_result.get("reason", "")

                # Store in bot for dashboard display
                if bot:
                    bot["volume_profile_signal"] = vol_signal
                    bot["volume_profile_score"] = vol_score
                    bot["volume_profile_poc"] = vol_result.get("poc", 0)

                if vol_score != 0:
                    score += vol_score
                    signals.append(f"📊VP:{vol_signal[:4]}")
                    logger.debug(
                        f"[{symbol}] Volume profile signal: {vol_signal} "
                        f"(score={vol_score:+.1f}, {vol_reason})"
                    )

        except Exception as e:
            logger.debug(f"[{symbol}] Volume profile signal failed (non-critical): {e}")

        # =============================================================================
        # OPEN INTEREST SIGNAL (NEW - Smart Feature #19)
        # =============================================================================
        # OI + Price direction analysis for trend confirmation:
        # - Rising OI + Rising Price = Strong uptrend (new longs)
        # - Rising OI + Falling Price = Strong downtrend (new shorts)
        # - Falling OI + Rising Price = Weak rally (short covering)
        # - Falling OI + Falling Price = Weak selloff (liquidations)
        try:
            from config.strategy_config import (
                OI_ANALYSIS_ENABLED,
                OI_LOOKBACK_PERIODS,
                OI_CHANGE_THRESHOLD,
                OI_STRONG_THRESHOLD,
                OI_MAX_SCORE,
            )

            has_oi_service = (
                hasattr(self, "open_interest_service")
                and self.open_interest_service is not None
            )
            if OI_ANALYSIS_ENABLED and has_oi_service:
                # Calculate price change over lookback period using candle data
                candles = self.indicator_service.get_ohlcv(
                    symbol, "15", limit=OI_LOOKBACK_PERIODS + 1
                )
                price_change_pct = 0.0
                if candles and len(candles) >= 2:
                    newest_close = candles[-1]["close"]
                    oldest_close = candles[0]["close"]
                    if oldest_close > 0:
                        price_change_pct = (newest_close - oldest_close) / oldest_close

                oi_result = self.open_interest_service.analyze_oi_trend(
                    symbol=symbol,
                    current_price=current_price,
                    price_change_pct=price_change_pct,
                    lookback_periods=OI_LOOKBACK_PERIODS,
                    change_threshold=OI_CHANGE_THRESHOLD,
                    strong_threshold=OI_STRONG_THRESHOLD,
                    max_score=OI_MAX_SCORE,
                )

                oi_score = oi_result.get("score", 0)
                oi_signal = oi_result.get("signal", "NEUTRAL")
                oi_reason = oi_result.get("reason", "")
                oi_change = oi_result.get("oi_change_pct", 0)

                # Store in bot for dashboard display
                if bot:
                    bot["oi_signal"] = oi_signal
                    bot["oi_score"] = oi_score
                    bot["oi_change_pct"] = oi_change * 100  # Store as percentage
                    bot["oi_direction"] = oi_result.get("oi_direction", "stable")

                if oi_score != 0:
                    score += oi_score
                    # Short signal labels: 📈OI:BULL or 📉OI:BEAR
                    oi_icon = "📈" if oi_score > 0 else "📉"
                    signals.append(f"{oi_icon}OI:{oi_signal[:4]}")
                    logger.debug(
                        f"[{symbol}] Open Interest signal: {oi_signal} "
                        f"(score={oi_score:+.1f}, OI change={oi_change * 100:.2f}%, {oi_reason})"
                    )
            else:
                # Store defaults when OI is disabled or unavailable
                if bot:
                    bot["oi_signal"] = "DISABLED"
                    bot["oi_score"] = 0

        except Exception as e:
            logger.warning(f"[{symbol}] Open Interest signal failed: {e}")
            if bot:
                bot["oi_signal"] = "ERROR"
                bot["oi_score"] = 0

        # =============================================================================
        # ORDER BOOK IMBALANCE SIGNAL (NEW - Smart Feature #22)
        # =============================================================================
        # Analyzes bid/ask depth ratio for buying/selling pressure
        # Heavy bids = bullish, Heavy asks = bearish
        try:
            from config.strategy_config import (
                ORDERBOOK_ENABLED,
                ORDERBOOK_DEPTH_LEVELS,
                ORDERBOOK_WEAK_THRESHOLD,
                ORDERBOOK_STRONG_THRESHOLD,
                ORDERBOOK_EXTREME_THRESHOLD,
                ORDERBOOK_MAX_SCORE,
            )

            if (
                ORDERBOOK_ENABLED
                and hasattr(self, "orderbook_service")
                and self.orderbook_service
            ):
                ob_result = self.orderbook_service.get_imbalance_signal(
                    symbol=symbol,
                    depth_levels=ORDERBOOK_DEPTH_LEVELS,
                    weak_threshold=ORDERBOOK_WEAK_THRESHOLD,
                    strong_threshold=ORDERBOOK_STRONG_THRESHOLD,
                    extreme_threshold=ORDERBOOK_EXTREME_THRESHOLD,
                    max_score=ORDERBOOK_MAX_SCORE,
                )

                ob_score = ob_result.get("score", 0)
                ob_signal = ob_result.get("signal", "NEUTRAL")
                ob_imbalance = ob_result.get("imbalance_pct", 0)
                ob_reason = ob_result.get("reason", "")

                # Store in bot for dashboard display
                if bot:
                    bot["orderbook_signal"] = ob_signal
                    bot["orderbook_score"] = ob_score
                    bot["orderbook_imbalance"] = ob_imbalance
                    bot["orderbook_bid_ask_ratio"] = ob_result.get("bid_ask_ratio", 1)

                if ob_score != 0:
                    score += ob_score
                    # Short signal labels: 📗OB:BULL or 📕OB:BEAR
                    ob_icon = "📗" if ob_score > 0 else "📕"
                    signals.append(f"{ob_icon}OB:{ob_signal[:4]}")
                    logger.debug(
                        f"[{symbol}] Order book signal: {ob_signal} "
                        f"(score={ob_score:+.1f}, imbalance={ob_imbalance:.1f}%, {ob_reason})"
                    )

        except Exception as e:
            logger.debug(f"[{symbol}] Order book signal failed (non-critical): {e}")

        # =============================================================================
        # LIQUIDATION LEVEL AWARENESS SIGNAL (NEW - Smart Feature #23)
        # =============================================================================
        # Identifies liquidation clusters to predict bounce/dump zones
        # Near long liq clusters = potential bounce, near short liq = potential dump
        try:
            from config.strategy_config import (
                LIQUIDATION_ENABLED,
                LIQUIDATION_LOOKBACK_CANDLES,
                LIQUIDATION_DANGER_ZONE_PCT,
                LIQUIDATION_TARGET_ZONE_PCT,
                LIQUIDATION_MAX_SCORE,
            )

            if (
                LIQUIDATION_ENABLED
                and hasattr(self, "liquidation_service")
                and self.liquidation_service
            ):
                liq_result = self.liquidation_service.get_liquidation_signal(
                    symbol=symbol,
                    current_price=current_price,
                    danger_zone_pct=LIQUIDATION_DANGER_ZONE_PCT,
                    target_zone_pct=LIQUIDATION_TARGET_ZONE_PCT,
                    max_score=LIQUIDATION_MAX_SCORE,
                )

                liq_score = liq_result.get("score", 0)
                liq_signal = liq_result.get("signal", "NEUTRAL")
                liq_reason = liq_result.get("reason", "")

                # Store in bot for dashboard display
                if bot:
                    bot["liquidation_signal"] = liq_signal
                    bot["liquidation_score"] = liq_score
                    bot["liquidation_long_clusters"] = len(
                        liq_result.get("long_clusters", [])
                    )
                    bot["liquidation_short_clusters"] = len(
                        liq_result.get("short_clusters", [])
                    )

                if liq_score != 0:
                    score += liq_score
                    # Short signal labels: 💧LIQ:BULL or 💧LIQ:BEAR
                    liq_icon = "💧" if liq_score > 0 else "🔥"
                    signals.append(f"{liq_icon}LIQ:{liq_signal[:4]}")
                    logger.debug(
                        f"[{symbol}] Liquidation signal: {liq_signal} "
                        f"(score={liq_score:+.1f}, {liq_reason})"
                    )

        except Exception as e:
            logger.debug(f"[{symbol}] Liquidation signal failed (non-critical): {e}")

        # =============================================================================
        # SESSION-BASED TRADING SIGNAL (NEW - Smart Feature #24)
        # =============================================================================
        # Adjusts confidence based on current trading session
        # EU/US overlap = high confidence, Weekend = lower confidence
        try:
            from config.strategy_config import (
                SESSION_TRADING_ENABLED,
                SESSION_MAX_SCORE,
            )

            if (
                SESSION_TRADING_ENABLED
                and hasattr(self, "session_service")
                and self.session_service
            ):
                session_result = self.session_service.get_session_signal(
                    max_score=SESSION_MAX_SCORE,
                )

                session_score = session_result.get("score", 0)
                session_signal = session_result.get("signal", "NEUTRAL")
                session_name = session_result.get("session", "Unknown")
                session_modifier = session_result.get("modifier", 0)

                # Store in bot for dashboard display
                if bot:
                    bot["session_name"] = session_name
                    bot["session_signal"] = session_signal
                    bot["session_modifier"] = session_modifier
                    bot["is_weekend"] = session_result.get("is_weekend", False)
                    bot["is_overlap"] = session_result.get("is_overlap", False)

                if session_score != 0:
                    score += session_score
                    # Short signal labels: 🌍SES:FAV or 🌍SES:UNF
                    ses_icon = "🌍" if session_score >= 0 else "🌙"
                    signals.append(f"{ses_icon}SES:{session_signal[:3]}")
                    logger.debug(
                        f"[{symbol}] Session signal: {session_signal} "
                        f"(score={session_score:+.1f}, session={session_name}, modifier={session_modifier:+.2f})"
                    )

        except Exception as e:
            logger.debug(f"[{symbol}] Session signal failed (non-critical): {e}")

        # =============================================================================
        # MEAN REVERSION SIGNAL (NEW - Smart Feature #25)
        # =============================================================================
        # Detects overextended price deviations from moving averages
        # Price far above mean = bearish (expect pullback), below = bullish (expect bounce)
        try:
            from config.strategy_config import (
                MEAN_REVERSION_ENABLED,
                MEAN_REVERSION_MAX_SCORE,
            )

            if (
                MEAN_REVERSION_ENABLED
                and hasattr(self, "mean_reversion_service")
                and self.mean_reversion_service
            ):
                mr_result = self.mean_reversion_service.get_mean_reversion_signal(
                    symbol=symbol,
                    current_price=current_price,
                    max_score=MEAN_REVERSION_MAX_SCORE,
                )

                mr_score = mr_result.get("score", 0)
                mr_signal = mr_result.get("signal", "NEUTRAL")
                mr_deviation = mr_result.get("avg_deviation_pct", 0)
                mr_extension = mr_result.get("extension_level", "normal")
                mr_reason = mr_result.get("reason", "")

                # Store in bot for dashboard display
                if bot:
                    bot["mean_reversion_signal"] = mr_signal
                    bot["mean_reversion_score"] = mr_score
                    bot["mean_reversion_deviation"] = mr_deviation
                    bot["mean_reversion_extension"] = mr_extension

                if mr_score != 0:
                    score += mr_score
                    # Short signal labels: 📊MR:BULL or 📊MR:BEAR
                    mr_icon = "📊" if mr_score > 0 else "📉"
                    signals.append(f"{mr_icon}MR:{mr_signal[:4]}")
                    logger.debug(
                        f"[{symbol}] Mean reversion signal: {mr_signal} "
                        f"(score={mr_score:+.1f}, deviation={mr_deviation:.2f}%, {mr_reason})"
                    )

        except Exception as e:
            logger.debug(f"[{symbol}] Mean reversion signal failed (non-critical): {e}")

        # =============================================================================
        # WHALE ORDER DETECTION (NEW - Smart Feature #26)
        # =============================================================================
        # Detects large orders (walls) on the order book that may act as S/R
        # Large bid walls = support (bullish), large ask walls = resistance (bearish)
        try:
            from config.strategy_config import (
                WHALE_DETECTION_ENABLED,
                WHALE_THRESHOLD_USD,
                WHALE_PROXIMITY_PCT,
                WHALE_MAX_SCORE,
            )

            if (
                WHALE_DETECTION_ENABLED
                and hasattr(self, "whale_detection_service")
                and self.whale_detection_service
            ):
                whale_result = self.whale_detection_service.detect_whale_orders(
                    symbol=symbol,
                    current_price=current_price,
                    whale_threshold_usd=WHALE_THRESHOLD_USD,
                    proximity_pct=WHALE_PROXIMITY_PCT,
                    max_score=WHALE_MAX_SCORE,
                )

                whale_score = whale_result.get("score", 0)
                whale_signal = whale_result.get("signal", "NEUTRAL")
                whale_reason = whale_result.get("reason", "")
                bid_walls = whale_result.get("bid_walls", [])
                ask_walls = whale_result.get("ask_walls", [])

                # Store in bot for dashboard display
                if bot:
                    bot["whale_signal"] = whale_signal
                    bot["whale_score"] = whale_score
                    bot["whale_bid_walls"] = len(bid_walls)
                    bot["whale_ask_walls"] = len(ask_walls)
                    bot["whale_reason"] = whale_reason

                if whale_score != 0:
                    score += whale_score
                    whale_icon = (
                        "🐋" if abs(whale_score) >= WHALE_MAX_SCORE * 0.5 else "🐟"
                    )
                    signals.append(f"{whale_icon}WHALE:{whale_signal[:4]}")
                    logger.debug(
                        f"[{symbol}] Whale detection: {whale_signal} "
                        f"(score={whale_score:+.1f}, bids={len(bid_walls)}, asks={len(ask_walls)}, {whale_reason})"
                    )

        except Exception as e:
            logger.debug(f"[{symbol}] Whale detection failed (non-critical): {e}")
            if bot:
                bot["whale_score"] = 0

        # =============================================================================
        # FINAL DECISION WITH HYSTERESIS (Enhanced - Smart Feature #13)
        # =============================================================================
        # Uses configurable thresholds from strategy_config.py with:
        # - Stronger entry thresholds (harder to enter a mode)
        # - Weaker exit thresholds (easier to stay in a mode)
        # - Minimum hold time before mode switching
        # - ADX requirement for mode changes
        target_mode = current_mode

        # Apply hysteresis thresholds from config
        if current_mode == "long":
            if score >= MODE_STAY_LONG_THRESHOLD:
                target_mode = "long"
            elif score <= MODE_EXIT_LONG_THRESHOLD:
                if score <= MODE_ENTER_SHORT_THRESHOLD:
                    target_mode = "short"
                else:
                    target_mode = "neutral"
            elif abs(score) <= MODE_NEUTRAL_BAND_WIDTH and not is_trending:
                target_mode = "neutral"
        elif current_mode == "short":
            if score <= MODE_STAY_SHORT_THRESHOLD:
                target_mode = "short"
            elif score >= MODE_EXIT_SHORT_THRESHOLD:
                if score >= MODE_ENTER_LONG_THRESHOLD:
                    target_mode = "long"
                else:
                    target_mode = "neutral"
            elif abs(score) <= MODE_NEUTRAL_BAND_WIDTH and not is_trending:
                target_mode = "neutral"
        else:
            if score >= MODE_ENTER_LONG_THRESHOLD:
                target_mode = "long"
            elif score <= MODE_ENTER_SHORT_THRESHOLD:
                target_mode = "short"

        adx = slow_indicators.get("adx") or fast_indicators.get("adx")
        blocked_mode_change = False
        if apply_mode_guards and target_mode != current_mode:
            if bot and current_mode in ("long", "short"):
                mode_entered_at = bot.get("mode_entered_at")
                if mode_entered_at:
                    try:
                        entered_dt = datetime.fromisoformat(
                            mode_entered_at.replace("Z", "+00:00")
                        )
                        time_in_mode = (
                            datetime.now(timezone.utc) - entered_dt
                        ).total_seconds()
                        if time_in_mode < MODE_MIN_HOLD_SECONDS:
                            logger.debug(
                                f"[{symbol}] Mode hold time {time_in_mode:.0f}s < {MODE_MIN_HOLD_SECONDS}s, "
                                f"keeping {current_mode}"
                            )
                            target_mode = current_mode
                            blocked_mode_change = True
                    except Exception:
                        pass

            if (
                not blocked_mode_change
                and MODE_REQUIRE_ADX_FOR_CHANGE
                and adx is not None
                and adx < MODE_ADX_MIN_FOR_CHANGE
            ):
                logger.debug(
                    f"[{symbol}] ADX {adx:.1f} < {MODE_ADX_MIN_FOR_CHANGE}, keeping {current_mode}"
                )
                target_mode = current_mode
                blocked_mode_change = True

        signals_str = " | ".join(signals) if signals else "No signals"
        adx_str = f"{adx:.1f}" if adx is not None else "N/A"
        if target_mode != current_mode:
            logger.info(
                f"[{symbol}] MODE CHANGE {current_mode}→{target_mode} "
                f"(score={score}, ADX={adx_str}) [{signals_str}]"
            )
        else:
            logger.debug(
                f"[{symbol}] Direction score={score}, mode={current_mode} [{signals_str}]"
            )

        if bot:
            bot["direction_score"] = score
            bot["direction_signals"] = signals_str

        return {
            "analysis_ok": True,
            "target_mode": target_mode,
            "score": score,
            "signals": signals,
            "signals_str": signals_str,
            "adx": adx,
            "current_mode": current_mode,
            "blocked_mode_change": blocked_mode_change,
        }

    def _compute_smart_auto_direction(
        self,
        symbol: str,
        current_mode: str,
        fast_indicators: Dict[str, Any],
        bot_id: Optional[str] = None,
        bot: Optional[Dict[str, Any]] = None,
        current_price: Optional[float] = None,
    ) -> str:
        # Don't switch mode while watching for pullback re-entry
        if (
            bot
            and bot.get("_pullback_watch_active")
            and bot.get("_pullback_watch_direction") == current_mode
        ):
            return current_mode
        analysis = self.get_auto_direction_analysis(
            symbol=symbol,
            current_mode=current_mode,
            fast_indicators=fast_indicators,
            current_price=current_price,
            bot_id=bot_id,
            bot=bot,
        )
        return analysis.get("target_mode", current_mode)

    def _compute_auto_range_mode(
        self,
        bot: Dict[str, Any],
        symbol: str,
        current_mode: str,
        current_range_mode: str,
        indicators: Dict[str, Any],
    ) -> Optional[str]:
        """
        Compute optimal range_mode based on market regime (Smart Feature #29).

        Logic:
        - Strong trend (ADX >= 30, wide BBW) → trailing (follow the trend)
        - Range-bound (ADX <= 20, narrow BBW) → dynamic (grid trading)
        - Uncertain → keep current or default to dynamic

        Args:
            bot: Bot dict
            symbol: Trading symbol
            current_mode: Current mode (long/short/neutral)
            current_range_mode: Current range_mode
            indicators: Indicator data with ADX, BBW

        Returns:
            New range_mode or None if no change needed
        """
        try:
            from config.strategy_config import (
                AUTO_RANGE_MODE_ENABLED,
                AUTO_RANGE_MODE_ADX_TREND,
                AUTO_RANGE_MODE_ADX_RANGE,
                AUTO_RANGE_MODE_BBW_NARROW,
                AUTO_RANGE_MODE_BBW_WIDE,
                AUTO_RANGE_MODE_COOLDOWN,
                AUTO_RANGE_MODE_DEFAULT,
            )

            if not AUTO_RANGE_MODE_ENABLED:
                return None

            # Check cooldown
            last_range_change = bot.get("_last_range_mode_change", 0)
            now = self.client._get_now_ts()
            if now - last_range_change < AUTO_RANGE_MODE_COOLDOWN:
                return None

            # Get indicators
            adx = indicators.get("adx")
            bbw_pct = indicators.get("bbw_pct")

            if adx is None:
                return None

            # Determine market regime
            is_trending = False
            is_ranging = False
            regime_reason = ""

            # Check ADX for trend strength
            if adx >= AUTO_RANGE_MODE_ADX_TREND:
                is_trending = True
                regime_reason = (
                    f"ADX {adx:.1f} >= {AUTO_RANGE_MODE_ADX_TREND} (strong trend)"
                )
            elif adx <= AUTO_RANGE_MODE_ADX_RANGE:
                is_ranging = True
                regime_reason = (
                    f"ADX {adx:.1f} <= {AUTO_RANGE_MODE_ADX_RANGE} (range-bound)"
                )

            # Confirm with BBW if available
            if bbw_pct is not None:
                if bbw_pct >= AUTO_RANGE_MODE_BBW_WIDE and is_trending:
                    regime_reason += f", BBW {bbw_pct:.1f}% >= {AUTO_RANGE_MODE_BBW_WIDE}% (volatile)"
                elif bbw_pct <= AUTO_RANGE_MODE_BBW_NARROW and is_ranging:
                    regime_reason += (
                        f", BBW {bbw_pct:.1f}% <= {AUTO_RANGE_MODE_BBW_NARROW}% (tight)"
                    )
                # BBW can override ADX in extreme cases
                elif bbw_pct >= AUTO_RANGE_MODE_BBW_WIDE * 1.5:
                    is_trending = True
                    is_ranging = False
                    regime_reason = f"BBW {bbw_pct:.1f}% very wide (volatile market)"
                elif bbw_pct <= AUTO_RANGE_MODE_BBW_NARROW * 0.5:
                    is_ranging = True
                    is_trending = False
                    regime_reason = f"BBW {bbw_pct:.1f}% very narrow (consolidating)"

            # Determine target range_mode
            target_range_mode = current_range_mode

            if is_trending and current_mode in ("long", "short"):
                # Strong trend + directional mode → trailing
                target_range_mode = "trailing"
            elif is_ranging:
                # Range-bound → dynamic (better for grid trading)
                target_range_mode = "dynamic"
            elif current_mode == "neutral":
                # Neutral mode works best with dynamic
                target_range_mode = "dynamic"

            # Check if change is needed
            if target_range_mode == current_range_mode:
                return None

            # Don't switch from trailing to dynamic if in strong profit
            # (let trailing ride the trend)
            if current_range_mode == "trailing" and target_range_mode == "dynamic":
                unrealized_pnl = bot.get("unrealized_pnl", 0)
                try:
                    positions_resp = self.client.get_positions()
                    if positions_resp.get("success"):
                        pos_list = (positions_resp.get("data", {}) or {}).get("list", []) or []
                        for pos in pos_list:
                            if pos.get("symbol") == symbol:
                                unrealized_pnl = float(pos.get("unrealisedPnl", 0) or 0)
                                break
                except Exception as e:
                    logger.debug(f"[{symbol}] Failed to fetch live PnL for auto-range mode: {e}")

                if unrealized_pnl > 0:
                    logger.debug(
                        f"[{symbol}] Keeping trailing mode - position in profit ${unrealized_pnl:.2f}"
                    )
                    return None

            logger.info(
                f"[{symbol}] 🔄 AUTO RANGE MODE: {current_range_mode} → {target_range_mode} "
                f"({regime_reason})"
            )

            return target_range_mode

        except Exception as e:
            logger.debug(f"[{symbol}] Auto range mode calculation failed: {e}")
            return None

    def _check_choppy_resume(self, bot: Dict[str, Any]) -> Dict[str, Any]:
        """
        Check if a choppy-paused neutral dynamic bot should resume.

        Resumes when:
        - ADX >= 25 (clear trend emerging)
        - OR RSI < 40 or RSI > 60 (directional momentum)
        - AND at least 2 minutes have passed since pause
        """
        bot_id = bot.get("id", "unknown")
        symbol = bot.get("symbol")

        if not symbol:
            return bot

        # Check minimum pause time (2 minutes)
        choppy_at = bot.get("choppy_detected_at")
        if choppy_at:
            try:
                pause_dt = datetime.fromisoformat(choppy_at.replace("Z", "+00:00"))
                elapsed = (datetime.now(timezone.utc) - pause_dt).total_seconds()
                if elapsed < 120:  # 2 minutes minimum pause
                    return bot
            except Exception:
                pass

        # Fetch fresh indicators
        try:
            indicators = self.indicator_service.compute_indicators(
                symbol, interval="15", limit=200
            )
            adx = indicators.get("adx")
            rsi = indicators.get("rsi")

            should_resume = False
            resume_reason = ""

            # Check for trend strength (ADX >= 25)
            if adx is not None and adx >= 25:
                should_resume = True
                resume_reason = f"ADX={adx:.1f}>=25 (trending)"

            # Check for directional RSI
            if not should_resume and rsi is not None:
                if rsi < 38:
                    should_resume = True
                    resume_reason = f"RSI={rsi:.1f}<38 (oversold momentum)"
                elif rsi > 62:
                    should_resume = True
                    resume_reason = f"RSI={rsi:.1f}>62 (overbought momentum)"

            if should_resume:
                logger.info(
                    f"[{symbol}] AUTO-RESUME - Market trending again ({resume_reason})"
                )
                bot["status"] = "running"
                bot["last_error"] = None
                bot["choppy_detected_at"] = None
                bot = self.bot_storage.save_bot(bot)

        except Exception as e:
            logger.debug(f"[{symbol}] Choppy resume check error: {e}")

        return bot

    def _set_error(self, bot: Dict[str, Any], error_msg: str) -> Dict[str, Any]:
        """Set bot to error status and save."""
        bot_id = bot.get("id")
        symbol = bot.get("symbol", "?")
        if bot_id:
            if hasattr(self.bot_storage, "get_bot"):
                current_bot = self.bot_storage.get_bot(bot_id)
                if current_bot and current_bot.get("status") not in (
                    "running",
                    "error",
                ):
                    return current_bot

        now_iso = datetime.now(timezone.utc).isoformat()
        bot["status"] = "error"
        bot["last_error"] = error_msg
        bot["last_run_at"] = now_iso
        self.bot_storage.save_bot(bot)
        logger.error(f"[{symbol}] {error_msg}")
        return bot

    def _safe_float(self, value: Any, default: float = 0.0) -> float:
        """Safely convert value to float."""
        if value is None:
            return default
        try:
            return float(value)
        except (TypeError, ValueError):
            return default

    def _get_existing_order_count(self, symbol: str) -> int:
        """Get actual count of open orders for a symbol."""
        response = self.client.get_open_orders(symbol, skip_cache=True)
        if not response.get("success"):
            return 0
        try:
            data = response.get("data", {})
            order_list = data.get("list", [])
            return len(order_list)
        except (KeyError, TypeError, ValueError):
            return 0

    def _get_existing_order_prices(self, symbol: str, tick_size: float) -> set:
        """Get set of price levels that already have open orders."""
        response = self.client.get_open_orders(symbol, skip_cache=True)
        if not response.get("success"):
            return set()
        try:
            data = response.get("data", {})
            order_list = data.get("list", [])
            prices = set()
            for order in order_list:
                price = float(order.get("price", 0) or 0)
                if price > 0:
                    rounded_price = self._round_to_step(
                        price, tick_size, round_down=False
                    )
                    prices.add(rounded_price)
            return prices
        except (KeyError, TypeError, ValueError):
            return set()

    def _get_existing_order_prices_list(self, symbol: str) -> List[float]:
        """Get list of actual order prices (not rounded) for tolerance-based matching."""
        response = self.client.get_open_orders(symbol, skip_cache=True)
        if not response.get("success"):
            return []
        try:
            data = response.get("data", {})
            order_list = data.get("list", [])
            prices = []
            for order in order_list:
                price = float(order.get("price", 0) or 0)
                if price > 0:
                    prices.append(price)
            return prices
        except (KeyError, TypeError, ValueError):
            return []


    def _has_order_near_level(
        self,
        level: float,
        existing_prices: List[float],
        tolerance_pct: float = 0.003,
    ) -> bool:
        """
        Check if there's already an order near the target level (within tolerance).

        Args:
            level: Target price level
            existing_prices: List of existing order prices
            tolerance_pct: Price tolerance percentage (default 0.3%)

        Returns:
            True if an order exists within tolerance of the level
        """
        if level <= 0:
            return False
        for existing_price in existing_prices:
            if existing_price <= 0:
                continue
            price_diff_pct = abs(existing_price - level) / level
            if price_diff_pct <= tolerance_pct:
                return True
        return False

    def _get_last_price(self, symbol: str, skip_cache: bool = False) -> Optional[float]:
        """Fetch the last price for a symbol."""
        normalized_symbol = str(symbol or "").strip().upper()
        stream_service = getattr(self.client, "stream_service", None) or getattr(
            self,
            "stream_service",
            None,
        )
        if normalized_symbol and stream_service and hasattr(
            stream_service,
            "get_last_price_metadata",
        ):
            try:
                metadata = stream_service.get_last_price_metadata(
                    normalized_symbol,
                    max_age_sec=0.1 if skip_cache else None,
                )
            except Exception:
                metadata = None
            remembered = self._remember_last_price_snapshot(
                normalized_symbol,
                metadata,
                fallback_source="stream_ticker",
                fallback_transport="stream_ticker",
            )
            if remembered:
                return remembered.get("price")

        response_received_at = time.time()
        response = self.client.get_tickers(symbol, skip_cache=skip_cache)
        if not response.get("success"):
            return None
        try:
            data = response.get("data", {})
            ticker_list = data.get("list", [])
            if not ticker_list:
                return None
            ticker = ticker_list[0]
            last_price = float(ticker.get("lastPrice", 0))
            if last_price <= 0:
                return None
            exchange_ts = None
            for key in ("ts", "time", "timestamp"):
                try:
                    numeric = float(ticker.get(key) or 0.0)
                except (TypeError, ValueError):
                    continue
                if numeric > 10_000_000_000:
                    numeric /= 1000.0
                if numeric > 0:
                    exchange_ts = numeric
                    break
            self._remember_last_price_snapshot(
                normalized_symbol or str(ticker.get("symbol") or "").strip().upper(),
                {
                    "price": last_price,
                    "received_at": response_received_at,
                    "exchange_ts": exchange_ts,
                    "source": (
                        "stream_ticker"
                        if bool(response.get("from_stream"))
                        else "rest_ticker"
                    ),
                    "transport": (
                        "stream_ticker"
                        if bool(response.get("from_stream"))
                        else "rest_ticker"
                    ),
                },
                fallback_source="rest_ticker",
                fallback_transport="rest_ticker",
            )
            return last_price
        except (KeyError, TypeError, ValueError, IndexError):
            return None

    @staticmethod
    def _normalize_price_timestamp(value: Any) -> Optional[float]:
        try:
            numeric = float(value)
        except (TypeError, ValueError):
            return None
        if numeric > 10_000_000_000:
            numeric /= 1000.0
        return numeric if numeric > 0 else None

    @staticmethod
    def _isoformat_ts(value: Optional[float]) -> Optional[str]:
        try:
            numeric = float(value)
        except (TypeError, ValueError):
            return None
        if numeric <= 0:
            return None
        return datetime.fromtimestamp(numeric, tz=timezone.utc).isoformat()

    def _remember_last_price_snapshot(
        self,
        symbol: str,
        metadata: Optional[Dict[str, Any]],
        *,
        fallback_source: str,
        fallback_transport: str,
    ) -> Optional[Dict[str, Any]]:
        normalized_symbol = str(symbol or "").strip().upper()
        if not normalized_symbol or not isinstance(metadata, dict):
            return None
        price = self._safe_float(metadata.get("price"), 0.0)
        if price <= 0:
            return None
        received_at = self._normalize_price_timestamp(
            metadata.get("received_at")
            or metadata.get("timestamp")
            or metadata.get("ts")
            or time.time()
        )
        exchange_ts = self._normalize_price_timestamp(metadata.get("exchange_ts"))
        snapshot = {
            "symbol": normalized_symbol,
            "price": price,
            "received_at": received_at,
            "received_at_iso": self._isoformat_ts(received_at),
            "exchange_ts": exchange_ts,
            "exchange_at": self._isoformat_ts(exchange_ts),
            "source": str(metadata.get("source") or fallback_source),
            "transport": str(metadata.get("transport") or fallback_transport),
        }
        if not hasattr(self, '_last_price_metadata_by_symbol'):
            self._last_price_metadata_by_symbol = {}
        self._last_price_metadata_by_symbol[normalized_symbol] = snapshot
        return dict(snapshot)

    def _set_bot_current_price(
        self,
        bot: Dict[str, Any],
        price: Any,
        *,
        symbol: Optional[str] = None,
        metadata: Optional[Dict[str, Any]] = None,
    ) -> None:
        current_price = self._safe_float(price, 0.0)
        bot["current_price"] = current_price
        if current_price <= 0:
            self._clear_bot_current_price_metadata(bot)
            return

        normalized_symbol = str(symbol or bot.get("symbol") or "").strip().upper()
        snapshot = None
        if isinstance(metadata, dict):
            snapshot = self._remember_last_price_snapshot(
                normalized_symbol,
                metadata,
                fallback_source="runtime_cycle",
                fallback_transport="runtime_cycle",
            )
        elif normalized_symbol:
            snapshot = dict(getattr(self, '_last_price_metadata_by_symbol', {}).get(normalized_symbol) or {})

        received_at = self._normalize_price_timestamp(
            (snapshot or {}).get("received_at") or time.time()
        )
        exchange_ts = self._normalize_price_timestamp((snapshot or {}).get("exchange_ts"))
        bot["current_price_updated_at"] = self._isoformat_ts(received_at)
        bot["current_price_source"] = str(
            (snapshot or {}).get("source") or "runtime_cycle"
        )
        bot["current_price_transport"] = str(
            (snapshot or {}).get("transport") or "runtime_cycle"
        )
        bot["current_price_exchange_ts"] = exchange_ts
        bot["current_price_exchange_at"] = self._isoformat_ts(exchange_ts)

    @staticmethod
    def _clear_bot_current_price_metadata(bot: Dict[str, Any]) -> None:
        bot["current_price_updated_at"] = None
        bot["current_price_source"] = None
        bot["current_price_transport"] = None
        bot["current_price_exchange_ts"] = None
        bot["current_price_exchange_at"] = None

    def _persist_early_current_price_runtime(
        self,
        bot: Dict[str, Any],
        *,
        symbol: str,
        price: Any,
        write_reason: str,
        write_path: str,
        persisted_before_guard: bool = False,
        min_delta_ms: float = 250.0,
        force_persist: bool = False,
    ) -> bool:
        before_state = {
            "current_price": bot.get("current_price"),
            "current_price_updated_at": bot.get("current_price_updated_at"),
            "current_price_source": bot.get("current_price_source"),
            "current_price_transport": bot.get("current_price_transport"),
            "current_price_exchange_at": bot.get("current_price_exchange_at"),
        }
        previous_dt = GridBotService._parse_iso_datetime(
            before_state.get("current_price_updated_at")
        )
        previous_ts = self._normalize_price_timestamp(
            previous_dt.timestamp() if previous_dt is not None else None
        )

        self._set_bot_current_price(bot, price, symbol=symbol)

        after_state = {
            "current_price": bot.get("current_price"),
            "current_price_updated_at": bot.get("current_price_updated_at"),
            "current_price_source": bot.get("current_price_source"),
            "current_price_transport": bot.get("current_price_transport"),
            "current_price_exchange_at": bot.get("current_price_exchange_at"),
        }
        if after_state == before_state and not force_persist:
            return False

        parsed_after_dt = GridBotService._parse_iso_datetime(
            after_state.get("current_price_updated_at")
        )
        current_ts = (
            self._normalize_price_timestamp(parsed_after_dt.timestamp())
            if parsed_after_dt is not None
            else None
        )
        current_price = self._safe_float(after_state.get("current_price"), 0.0)
        previous_price = self._safe_float(before_state.get("current_price"), 0.0)
        source_changed = (
            after_state.get("current_price_source")
            != before_state.get("current_price_source")
        )
        transport_changed = (
            after_state.get("current_price_transport")
            != before_state.get("current_price_transport")
        )
        price_changed = abs(current_price - previous_price) > 1e-9
        delta_ms = (
            round(max((current_ts or 0.0) - previous_ts, 0.0) * 1000.0, 2)
            if current_ts is not None and previous_ts is not None
            else None
        )
        if (
            delta_ms is not None
            and delta_ms < max(float(min_delta_ms or 0.0), 0.0)
            and not source_changed
            and not transport_changed
            and not price_changed
            and not force_persist
        ):
            return False

        bot["price_metadata_written_early"] = True
        bot["price_metadata_write_reason"] = str(write_reason or "trusted_price_ready")
        bot["price_metadata_write_path"] = str(write_path or "active_cycle")
        bot["current_price_persist_delta_ms"] = delta_ms
        bot["current_price_persisted_before_guard"] = bool(persisted_before_guard)
        self._save_runtime_bot(bot)
        return True

    def _apply_reevaluation_runtime_context(
        self,
        bot: Dict[str, Any],
        *,
        now_ts: float,
    ) -> bool:
        trigger_ts = self._safe_float(bot.pop("_reevaluation_trigger_received_at", 0.0), 0.0)
        reason = str(bot.pop("_reevaluation_trigger_reason", "") or "").strip().lower()
        path = str(bot.pop("_reevaluation_trigger_path", "") or "").strip().lower()
        fast_path_requested = bool(bot.pop("_blocked_guarded_fast_path_requested", False))
        fresh_provider_seen = bool(bot.pop("_fresh_provider_seen_before_eval", False))
        deferred_reason = str(bot.pop("_evaluation_deferred_reason", "") or "").strip() or None

        if not (
            trigger_ts > 0.0
            or reason
            or path
            or fast_path_requested
            or deferred_reason
            or fresh_provider_seen
        ):
            return False

        if trigger_ts > 0.0:
            bot["provider_update_seen_at"] = datetime.fromtimestamp(
                trigger_ts,
                tz=timezone.utc,
            ).isoformat()
            bot["provider_update_to_eval_ms"] = round(
                max(now_ts - trigger_ts, 0.0) * 1000.0,
                2,
            )

        if reason:
            bot["reevaluation_trigger_reason"] = reason
        if path:
            bot["reevaluation_trigger_path"] = path
        if fast_path_requested:
            bot["blocked_guarded_fast_path_used"] = True
        if deferred_reason is not None:
            bot["evaluation_deferred_reason"] = deferred_reason
        if fresh_provider_seen or trigger_ts > 0.0:
            bot["fresh_provider_seen_before_eval"] = True
        return True

    def _get_instrument_info(self, symbol: str) -> Optional[Dict[str, Any]]:
        """Fetch and cache instrument specifications for a symbol."""
        if symbol in self._instrument_cache:
            return self._instrument_cache[symbol]

        response = self.client.get_instruments_info(symbol)
        if not response.get("success"):
            logger.warning(
                f"Failed to fetch instrument info for {symbol}: {response.get('error')}"
            )
            return None

        try:
            data = response.get("data", {})
            inst_list = data.get("list", [])
            if not inst_list:
                return None
            inst = inst_list[0]
            lot_size_filter = inst.get("lotSizeFilter", {})
            price_filter = inst.get("priceFilter", {})

            def _to_positive(value):
                try:
                    num = float(value)
                except (TypeError, ValueError):
                    return None
                return num if num > 0 else None

            # Get min notional value (minNotionalValue or minOrderAmt) - default to 5 USDT
            min_notional_value = _to_positive(lot_size_filter.get("minNotionalValue"))
            if min_notional_value is None or min_notional_value <= 0:
                min_notional_value = _to_positive(lot_size_filter.get("minOrderAmt"))
            if min_notional_value is None:
                min_notional_value = 5.0

            min_order_qty = _to_positive(lot_size_filter.get("minOrderQty"))
            qty_step = _to_positive(lot_size_filter.get("qtyStep"))
            if not min_order_qty or not qty_step:
                logger.warning(
                    f"Missing qty filters for {symbol} (minQty={min_order_qty}, step={qty_step})"
                )
                return None
            min_order_qty = max(min_order_qty, qty_step)

            info = {
                "min_order_qty": min_order_qty,
                "max_order_qty": _to_positive(lot_size_filter.get("maxOrderQty"))
                or 100000,
                "qty_step": qty_step,
                "tick_size": _to_positive(price_filter.get("tickSize")) or 0.0001,
                "min_price": _to_positive(price_filter.get("minPrice")) or 0,
                "max_price": _to_positive(price_filter.get("maxPrice")) or 0,
                "min_notional_value": min_notional_value,
            }

            self._instrument_cache[symbol] = info
            return info
        except (KeyError, TypeError, ValueError, IndexError) as e:
            logger.warning(f"Error parsing instrument info for {symbol}: {e}")
            return None

    def _round_to_step(
        self, value: float, step: float, round_down: bool = True
    ) -> float:
        """Round a value to the nearest step."""
        if step <= 0:
            return value

        step_decimal = Decimal(str(step))
        value_decimal = Decimal(str(value))
        precision = max(0, -step_decimal.as_tuple().exponent)
        rounding = ROUND_FLOOR if round_down else ROUND_HALF_UP
        result = float(
            (value_decimal / step_decimal).to_integral_value(rounding=rounding)
            * step_decimal
        )

        return round(result, precision)

    def _round_price_for_order(
        self, value: float, tick_size: float, side: str
    ) -> float:
        """
        Round price to tick size in a side-aware manner:
          - Buy limits: floor to avoid crossing the spread inadvertently
          - Sell limits: ceil to avoid placing below intended level
        """
        if tick_size <= 0:
            return value
        try:
            import math

            if side.lower() == "buy":
                stepped = math.floor(value / tick_size) * tick_size
            else:
                stepped = math.ceil(value / tick_size) * tick_size
            # Determine precision from tick_size
            step_str = f"{tick_size:.10f}".rstrip("0")
            precision = len(step_str.split(".")[1]) if "." in step_str else 0
            return round(stepped, precision)
        except Exception:
            # Fallback to previous rounding behavior if anything goes wrong
            return self._round_to_step(
                value, tick_size, round_down=(side.lower() == "buy")
            )

    def _set_runtime_mode_metadata(
        self,
        bot: Dict[str, Any],
        *,
        effective_mode: Optional[str],
        effective_range_mode: Optional[str] = None,
        source: Optional[str] = None,
        non_persistent: Optional[bool] = None,
    ) -> None:
        configured = configured_mode(bot)
        configured_range = configured_range_mode(bot)
        final_effective_mode = str(effective_mode or configured).strip().lower() or configured
        final_effective_range = (
            str(effective_range_mode or configured_range).strip().lower()
            or configured_range
        )
        bot["configured_mode"] = configured
        bot["configured_range_mode"] = configured_range
        bot["mode_policy"] = normalize_mode_policy(bot.get("mode_policy"), bot)
        bot["effective_runtime_mode"] = final_effective_mode
        bot["effective_runtime_range_mode"] = final_effective_range
        bot["runtime_mode_source"] = str(source or "").strip().lower() or None
        if non_persistent is None:
            non_persistent = runtime_auto_switch_allowed(bot) and (
                final_effective_mode != configured
                or final_effective_range != configured_range
            )
        bot["runtime_mode_non_persistent"] = bool(non_persistent)
        bot["runtime_mode_updated_at"] = datetime.now(timezone.utc).isoformat()

    def _clear_runtime_mode_metadata(self, bot: Dict[str, Any]) -> None:
        if not isinstance(bot, dict):
            return
        self._set_runtime_mode_metadata(
            bot,
            effective_mode=configured_mode(bot),
            effective_range_mode=configured_range_mode(bot),
            source=None,
            non_persistent=False,
        )

    def _maybe_auto_select_neutral_mode(
        self,
        bot: Dict[str, Any],
        symbol: str,
        fast_indicators: Dict[str, Any],
        atr_15m_pct: Optional[float] = None,
    ) -> Tuple[Dict[str, Any], bool]:
        """
        Auto-select between neutral_classic_bybit (fixed) and neutral (dynamic)
        based on ADX/ATR thresholds with cooldown and position safety.

        Returns: (bot, switched)
        """
        from config.strategy_config import (
            AUTO_NEUTRAL_MODE_ENABLED,
            AUTO_NEUTRAL_MODE_COOLDOWN_SEC,
            AUTO_NEUTRAL_CLASSIC_ADX_MAX,
            AUTO_NEUTRAL_CLASSIC_ATR_MAX,
            AUTO_NEUTRAL_DYNAMIC_ADX_MIN,
            AUTO_NEUTRAL_DYNAMIC_ATR_MIN,
        )

        if not AUTO_NEUTRAL_MODE_ENABLED:
            return bot, False
        if not bot.get("auto_neutral_mode_enabled", True):
            return bot, False

        configured = configured_mode(bot)
        current_effective_mode = str(
            bot.get("effective_runtime_mode") or bot.get("mode") or configured
        ).lower()
        if configured not in ("neutral", "neutral_classic_bybit") and current_effective_mode not in (
            "neutral",
            "neutral_classic_bybit",
        ):
            return bot, False

        adx = fast_indicators.get("adx")
        atr_pct = atr_15m_pct if atr_15m_pct is not None else fast_indicators.get(
            "atr_pct"
        )

        if adx is None and atr_pct is None:
            return bot, False

        now_ts = self.client._get_now_ts()
        last_switch = self._safe_float(bot.get("_neutral_mode_last_switch_ts"), 0.0)
        if (
            AUTO_NEUTRAL_MODE_COOLDOWN_SEC > 0
            and now_ts - last_switch < AUTO_NEUTRAL_MODE_COOLDOWN_SEC
        ):
            return bot, False

        # Skip switching if position is open
        try:
            positions_resp = self.client.get_positions()
            if positions_resp.get("success"):
                positions = positions_resp.get("data", {}).get("list", []) or []
                for pos in positions:
                    if pos.get("symbol") != symbol:
                        continue
                    if float(pos.get("size", 0) or 0) > 0:
                        bot["_neutral_mode_switch_skipped"] = "position_open"
                        return bot, False
        except Exception:
            return bot, False

        target_mode = None

        if adx is not None and atr_pct is not None:
            if (
                adx <= AUTO_NEUTRAL_CLASSIC_ADX_MAX
                and atr_pct <= AUTO_NEUTRAL_CLASSIC_ATR_MAX
            ):
                target_mode = "neutral_classic_bybit"
            elif adx >= AUTO_NEUTRAL_DYNAMIC_ADX_MIN or atr_pct >= AUTO_NEUTRAL_DYNAMIC_ATR_MIN:
                target_mode = "neutral"
        elif adx is not None:
            if adx <= AUTO_NEUTRAL_CLASSIC_ADX_MAX:
                target_mode = "neutral_classic_bybit"
            elif adx >= AUTO_NEUTRAL_DYNAMIC_ADX_MIN:
                target_mode = "neutral"
        elif atr_pct is not None:
            if atr_pct <= AUTO_NEUTRAL_CLASSIC_ATR_MAX:
                target_mode = "neutral_classic_bybit"
            elif atr_pct >= AUTO_NEUTRAL_DYNAMIC_ATR_MIN:
                target_mode = "neutral"

        if not target_mode:
            return bot, False

        target_range_mode = "fixed" if target_mode == "neutral_classic_bybit" else "dynamic"
        metadata_changed = (
            str(bot.get("effective_runtime_mode") or "").strip().lower() != target_mode
            or str(bot.get("effective_runtime_range_mode") or "").strip().lower() != target_range_mode
            or str(bot.get("runtime_mode_source") or "").strip().lower() != "auto_neutral"
            or not bool(bot.get("runtime_mode_non_persistent"))
        )

        self._set_runtime_mode_metadata(
            bot,
            effective_mode=target_mode,
            effective_range_mode=target_range_mode,
            source="auto_neutral",
            non_persistent=True,
        )

        if not runtime_auto_switch_allowed(bot):
            if metadata_changed:
                self.bot_storage.save_runtime_bot(bot)
            return bot, False

        if target_mode == "neutral_classic_bybit":
            bot["mode"] = "neutral_classic_bybit"
            bot["range_mode"] = target_range_mode
            grid_lower = bot.get("grid_lower_price") or bot.get("lower_price")
            grid_upper = bot.get("grid_upper_price") or bot.get("upper_price")
            if grid_lower is not None:
                bot["grid_lower_price"] = grid_lower
                bot["lower_price"] = grid_lower
            if grid_upper is not None:
                bot["grid_upper_price"] = grid_upper
                bot["upper_price"] = grid_upper
            grid_levels_total = bot.get("grid_levels_total") or bot.get(
                "grid_count", 10
            )
            bot["grid_levels_total"] = max(2, min(500, int(grid_levels_total)))
            bot["grid_count"] = bot["grid_levels_total"]
            bot["target_grid_count"] = bot["grid_levels_total"]
        else:
            bot["mode"] = "neutral"
            bot["range_mode"] = target_range_mode
            lower = bot.get("lower_price") or bot.get("grid_lower_price")
            upper = bot.get("upper_price") or bot.get("grid_upper_price")
            if lower is not None:
                bot["lower_price"] = lower
            if upper is not None:
                bot["upper_price"] = upper
            grid_levels_total = bot.get("grid_levels_total") or bot.get(
                "grid_count", 10
            )
            bot["grid_count"] = int(grid_levels_total)
        self._clear_directional_entry_runtime_state(bot)
        self._clear_directional_audit_runtime_state(bot)
        self._normalize_mode_range_state(bot)

        bot["_neutral_mode_last_switch_ts"] = now_ts
        bot["mode_entered_at"] = datetime.now(timezone.utc).isoformat()
        bot["mode_change_count"] = bot.get("mode_change_count", 0) + 1
        bot["neutral_grid"] = {}
        bot["neutral_grid_initialized"] = False
        bot["last_error"] = None

        if metadata_changed or target_mode != current_effective_mode:
            self.bot_storage.save_bot(bot)
        logger.info(
            "[%s] Auto-neutral mode switch: %s -> %s (adx=%s atr=%s)",
            symbol,
            current_effective_mode,
            target_mode,
            f"{adx:.2f}" if adx is not None else "n/a",
            f"{atr_pct:.4f}" if atr_pct is not None else "n/a",
        )

        return bot, target_mode != current_effective_mode

    def _get_position_mode(self, bot: Dict[str, Any], symbol: str) -> Optional[str]:
        """
        Fetch and cache position mode ("hedge" or "one_way"). Fail-safe returns None and sets bot error.
        """
        if not hasattr(self, "_position_mode_cache"):
            self._position_mode_cache = {}
        cache_entry = self._position_mode_cache.get(symbol)
        now = self.client._get_now_ts()
        if cache_entry and now - cache_entry.get("ts", 0) < 300:
            return cache_entry.get("mode")

        resp = self.client.get_position_mode(symbol=symbol)
        if resp.get("success") and resp.get("mode") in ("hedge", "one_way"):
            mode = resp.get("mode")
            self._position_mode_cache[symbol] = {"mode": mode, "ts": now}
            bot["_position_mode"] = mode
            bot["_position_mode_ts"] = now
            return mode

        # Detection failed - default to one_way (UTA accounts use one-way by default)
        # This prevents blocking all orders when no positions exist for a new symbol
        fallback_mode = "one_way"
        self._position_mode_cache[symbol] = {"mode": fallback_mode, "ts": now}
        bot["_position_mode"] = fallback_mode
        bot["_position_mode_ts"] = now
        logger.warning(
            "[%s] Position mode detection failed (%s) - defaulting to one_way",
            symbol,
            resp.get("error"),
        )
        return fallback_mode

    def _resolve_position_idx(
        self, bot: Dict[str, Any], symbol: str, side: str, reduce_only: bool
    ) -> Optional[int]:
        mode = bot.get("_position_mode")
        ts = bot.get("_position_mode_ts", 0)
        if not mode or (self.client._get_now_ts() - float(ts or 0) > 60):
            mode = self._get_position_mode(bot, symbol)
            if mode:
                bot["_position_mode"] = mode
                bot["_position_mode_ts"] = self.client._get_now_ts()
        if mode is None:
            return None
        return resolve_position_idx(mode, side, reduce_only)

    # =============================================================================
    # TREND REVERSAL PROTECTION (Smart Feature #17)
    # =============================================================================
    def _check_trend_reversal_protection(
        self,
        bot: Dict[str, Any],
        symbol: str,
        mode: str,
        indicators: Dict[str, Any],
        last_price: float,
    ) -> Dict[str, Any]:
        """
        Check if trend has reversed against current position and take protective action.

        When in LONG mode with position and market turns bearish → close position, switch to SHORT
        When in SHORT mode with position and market turns bullish → close position, switch to LONG

        Args:
            bot: Bot configuration dict
            symbol: Trading symbol
            mode: Current bot mode (long/short)
            indicators: Current indicator values
            last_price: Current market price

        Returns:
            Dict with:
            - reversal_detected: bool
            - action_taken: str (none/closed/switched)
            - new_mode: str (if switched)
            - reason: str
        """
        from config.strategy_config import (
            ENABLE_TREND_REVERSAL_PROTECTION,
            TREND_REVERSAL_ADX_MIN,
            TREND_REVERSAL_RSI_LONG,
            TREND_REVERSAL_RSI_SHORT,
            TREND_REVERSAL_USE_EMA,
            TREND_REVERSAL_CONFIRM_SECONDS,
            TREND_REVERSAL_CLOSE_POSITION,
            TREND_REVERSAL_SWITCH_MODE,
            TREND_REVERSAL_COOLDOWN_SECONDS,
        )

        bot_id = bot.get("id", "?")
        result = {
            "reversal_detected": False,
            "action_taken": "none",
            "new_mode": mode,
            "reason": "",
        }

        # Only applies to directional modes (long/short)
        if mode not in ("long", "short"):
            logger.debug(
                f"[{symbol}] Trend reversal - skipped (mode={mode} not directional)"
            )
            return result

        if not ENABLE_TREND_REVERSAL_PROTECTION:
            logger.debug(f"[{symbol}] Trend reversal - disabled in config")
            return result

        logger.info(
            f"[{symbol}] Trend reversal - protection enabled, checking position..."
        )

        # Check cooldown from last reversal action
        last_reversal_at = bot.get("last_trend_reversal_at")
        if last_reversal_at:
            try:
                last_dt = datetime.fromisoformat(
                    last_reversal_at.replace("Z", "+00:00")
                )
                elapsed = (datetime.now(timezone.utc) - last_dt).total_seconds()
                if elapsed < TREND_REVERSAL_COOLDOWN_SECONDS:
                    logger.info(
                        f"[{symbol}] Trend reversal COOLDOWN active ({elapsed:.0f}s < {TREND_REVERSAL_COOLDOWN_SECONDS}s)"
                    )
                    return result
            except Exception:
                pass

        # Get current position
        position_size = 0
        position_side = None
        try:
            pos_response = self.client.get_positions()  # Gets all positions
            if pos_response.get("success"):
                positions = pos_response.get("data", {}).get("list", []) or []
                for pos in positions:
                    if pos.get("symbol") == symbol:
                        size = float(pos.get("size", 0))
                        if size > 0:
                            position_size = size
                            position_side = pos.get("side", "").lower()
                            break
        except Exception as e:
            logger.warning(f"[{symbol}] Position fetch for trend reversal failed: {e}")
            return result

        logger.info(
            f"[{symbol}] Trend reversal - position_size={position_size}, position_side={position_side}"
        )

        # No position = no need for reversal protection
        if position_size == 0:
            # Clear any pending reversal detection
            if bot.get("trend_reversal_detected_at"):
                bot["trend_reversal_detected_at"] = None
            logger.debug(f"[{symbol}] Trend reversal - no position, skipping")
            return result

        # Get indicators
        rsi = indicators.get("rsi")
        adx = indicators.get("adx")
        ema20 = indicators.get("ema_20") or indicators.get("ema20")

        # Debug log to track indicator values
        rsi_str = f"{rsi:.1f}" if rsi is not None else "N/A"
        adx_str = f"{adx:.1f}" if adx is not None else "N/A"
        logger.info(
            f"[{symbol}] Trend reversal check - mode={mode}, pos_side={position_side}, "
            f"RSI={rsi_str}, ADX={adx_str}, "
            f"threshold_RSI_long={TREND_REVERSAL_RSI_LONG}, threshold_RSI_short={TREND_REVERSAL_RSI_SHORT}"
        )

        if rsi is None:
            return result

        # Check if ADX shows strong enough trend
        if adx is not None and adx < TREND_REVERSAL_ADX_MIN:
            # Weak trend, don't trigger reversal
            logger.debug(
                f"[{symbol}] ADX {adx:.1f} < {TREND_REVERSAL_ADX_MIN} - skipping reversal check"
            )
            return result

        # Determine if trend is against position
        trend_against_position = False
        reversal_reason = ""

        if mode == "short" and position_side == "sell":
            # SHORT position - check for bullish reversal
            if rsi > TREND_REVERSAL_RSI_LONG:
                # RSI showing bullish
                if TREND_REVERSAL_USE_EMA and ema20 and last_price > ema20:
                    # Price above EMA confirms uptrend
                    trend_against_position = True
                    reversal_reason = f"Bullish reversal: RSI={rsi:.1f}>{TREND_REVERSAL_RSI_LONG}, Price>{ema20:.5f}"
                elif not TREND_REVERSAL_USE_EMA:
                    trend_against_position = True
                    reversal_reason = (
                        f"Bullish reversal: RSI={rsi:.1f}>{TREND_REVERSAL_RSI_LONG}"
                    )

        elif mode == "long" and position_side == "buy":
            # LONG position - check for bearish reversal
            if rsi < TREND_REVERSAL_RSI_SHORT:
                # RSI showing bearish
                if TREND_REVERSAL_USE_EMA and ema20 and last_price < ema20:
                    # Price below EMA confirms downtrend
                    trend_against_position = True
                    reversal_reason = f"Bearish reversal: RSI={rsi:.1f}<{TREND_REVERSAL_RSI_SHORT}, Price<{ema20:.5f}"
                elif not TREND_REVERSAL_USE_EMA:
                    trend_against_position = True
                    reversal_reason = (
                        f"Bearish reversal: RSI={rsi:.1f}<{TREND_REVERSAL_RSI_SHORT}"
                    )

        if not trend_against_position:
            # Clear pending detection if trend no longer against us
            if bot.get("trend_reversal_detected_at"):
                bot["trend_reversal_detected_at"] = None
            return result

        # Trend is against position - check confirmation time
        now = datetime.now(timezone.utc)
        detected_at = bot.get("trend_reversal_detected_at")

        if not detected_at:
            # First detection - record time and wait for confirmation
            bot["trend_reversal_detected_at"] = now.isoformat()
            logger.warning(
                f"[{symbol}] ⚠️ Trend reversal DETECTED - {reversal_reason}. Waiting {TREND_REVERSAL_CONFIRM_SECONDS}s for confirmation..."
            )
            result["reversal_detected"] = True
            result["reason"] = f"Waiting for confirmation: {reversal_reason}"
            return result

        # Check if confirmation period has passed
        try:
            detected_dt = datetime.fromisoformat(detected_at.replace("Z", "+00:00"))
            elapsed = (now - detected_dt).total_seconds()

            if elapsed < TREND_REVERSAL_CONFIRM_SECONDS:
                # Still waiting for confirmation
                remaining = TREND_REVERSAL_CONFIRM_SECONDS - elapsed
                logger.info(
                    f"[{symbol}] Trend reversal pending - {remaining:.0f}s until action"
                )
                result["reversal_detected"] = True
                result["reason"] = (
                    f"Confirming ({elapsed:.0f}s/{TREND_REVERSAL_CONFIRM_SECONDS}s): {reversal_reason}"
                )
                return result

        except Exception:
            bot["trend_reversal_detected_at"] = now.isoformat()
            return result

        # Confirmation period passed - TAKE ACTION
        result["reversal_detected"] = True
        logger.warning(f"[{symbol}] 🔄 TREND REVERSAL CONFIRMED - {reversal_reason}")

        # Close position if enabled
        if TREND_REVERSAL_CLOSE_POSITION:
            try:
                close_result = self._close_position_or_hard_fail(
                    bot, symbol, "trend_reversal"
                )
                if close_result.get("success"):
                    logger.warning(
                        f"[{symbol}] ✅ Closed {position_side.upper()} position of {position_size} via market order"
                    )
                    result["action_taken"] = "closed"
            except Exception as e:
                if isinstance(e, RuntimeError):
                    raise
                logger.error(f"[{symbol}] Position close error: {e}")

        # Switch mode if enabled
        if TREND_REVERSAL_SWITCH_MODE:
            new_mode = "long" if mode == "short" else "short"
            bot["mode"] = new_mode
            bot["configured_mode"] = new_mode
            bot["configured_range_mode"] = bot.get("range_mode") or configured_range_mode(bot)
            self._clear_directional_entry_runtime_state(bot)
            self._clear_directional_audit_runtime_state(bot)
            self._normalize_mode_range_state(bot)
            self._clear_runtime_mode_metadata(bot)
            bot["mode_entered_at"] = now.isoformat()
            bot["mode_change_count"] = bot.get("mode_change_count", 0) + 1
            result["new_mode"] = new_mode
            if result["action_taken"] == "closed":
                result["action_taken"] = "closed_and_switched"
            else:
                result["action_taken"] = "switched"
            logger.warning(
                f"[{symbol}] 🔄 Switched mode from {mode.upper()} to {new_mode.upper()}"
            )

        # Record reversal action time and clear detection
        bot["last_trend_reversal_at"] = now.isoformat()
        bot["trend_reversal_detected_at"] = None
        result["reason"] = reversal_reason

        return result
